INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hack calf raise', 'hack calf raise. Secondary Muscles: hamstrings, glutes', 'Strength', 'Calves', 'Intermediate', 'Step:1 Step:1 Adjust the sled machine to a comfortable weight. Step:2 Step:2 Stand on the sled machine with your toes on the platform and your heels hanging off. Step:3 Step:3 Hold onto the handles for stability. Step:4 Step:4 Raise your heels as high as possible by pushing through the balls of your feet. Step:5 Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Sled Machine' LIMIT 1), 'sled machine');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45° leg press (side pov)', 'sled 45° leg press (side pov). Secondary Muscles: quadriceps, hamstrings, calves', 'Strength', 'Glutes', 'Intermediate', 'Step:1 Step:1 Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate. Step:2 Step:2 Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate. Step:3 Step:3 Grip the handles on the sides of the seat for stability. Step:4 Step:4 Push against the footplate to extend your legs, straightening them completely. Step:5 Step:5 Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Sled Machine' LIMIT 1), 'sled machine');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell front raise', 'dumbbell front raise. Secondary Muscles: biceps, trapezius', 'Strength', 'Delts', 'Intermediate', 'Step:1 Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Step:2 Step:2 Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level. Step:3 Step:3 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Step:4 Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell over bench revers wrist curl', 'dumbbell over bench revers wrist curl. Secondary Muscles: biceps, brachialis', 'Strength', 'Forearms', 'Intermediate', 'Step:1 Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down. Step:2 Step:2 Rest your forearms on the bench, allowing your wrists to hang off the edge. Step:3 Step:3 Slowly curl your wrists upward, bringing the dumbbells towards your body. Step:4 Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell incline bench press', 'barbell incline bench press. Secondary Muscles: shoulders, triceps', 'Strength', 'Pectorals', 'Intermediate', 'Step:1 Step:1 Set up an incline bench at a 45-degree angle. Step:2 Step:2 Lie down on the bench with your feet flat on the ground. Step:3 Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:4 Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle. Step:5 Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Barbell' LIMIT 1), 'barbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable squatting curl', 'cable squatting curl. Secondary Muscles: forearms', 'Strength', 'Biceps', 'Intermediate', 'Step:1 Step:1 Attach a cable handle to the lowest setting on a cable machine. Step:2 Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Step:3 Hold the cable handle with an underhand grip, palms facing up, and arms fully extended. Step:4 Step:4 Lower your body into a squat position, keeping your back straight and knees behind your toes. Step:5 Step:5 As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides. Step:6 Step:6 Pause for a moment at the top of the curl, squeezing your biceps. Step:7 Step:7 Slowly lower the cable handle back to the starting position, fully extending your arms. Step:8 Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Cable' LIMIT 1), 'cable');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm hammer preacher curl', 'dumbbell one arm hammer preacher curl. Secondary Muscles: forearms', 'Strength', 'Biceps', 'Intermediate', 'Step:1 Step:1 Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad. Step:2 Step:2 Hold the dumbbell with a neutral grip (palms facing your body). Step:3 Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Step:4 Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Step:5 Inhale and slowly lower the dumbbell back to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing close grip curl', 'barbell standing close grip curl. Secondary Muscles: forearms', 'Strength', 'Biceps', 'Intermediate', 'Step:1 Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together. Step:2 Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the movement. Step:3 Step:3 Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Step:4 Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Step:5 Inhale as you slowly begin to bring the barbell back to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Barbell' LIMIT 1), 'barbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell pistol squat', 'kettlebell pistol squat. Secondary Muscles: quadriceps, hamstrings, calves', 'Strength', 'Glutes', 'Intermediate', 'Step:1 Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands. Step:2 Step:2 Lift your left foot off the ground and extend it forward, keeping it parallel to the ground. Step:3 Step:3 Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended. Step:4 Step:4 Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position. Step:5 Step:5 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Kettlebell' LIMIT 1), 'kettlebell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('impossible dips', 'impossible dips. Secondary Muscles: chest, shoulders', 'Strength', 'Triceps', 'Intermediate', 'Step:1 Step:1 Position yourself between two parallel bars with your arms fully extended and your body suspended in the air. Step:2 Step:2 Bend your knees and cross your ankles. Step:3 Step:3 Lower your body by bending your elbows until your upper arms are parallel to the ground. Step:4 Step:4 Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:5 Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated overhead triceps extension', 'barbell seated overhead triceps extension. Secondary Muscles: shoulders', 'Strength', 'Triceps', 'Intermediate', 'Step:1 Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Step:2 Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead. Step:3 Step:3 Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head. Step:4 Step:4 Pause for a moment, then extend your arms to raise the barbell back to the starting position. Step:5 Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Barbell' LIMIT 1), 'barbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith incline bench press', 'smith incline bench press. Secondary Muscles: shoulders, triceps', 'Strength', 'Pectorals', 'Intermediate', 'Step:1 Step:1 Adjust the bench to a 30-45 degree incline. Step:2 Step:2 Sit on the bench with your back flat against the pad and feet firmly on the ground. Step:3 Step:3 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Step:4 Step:4 Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in. Step:5 Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Smith Machine' LIMIT 1), 'smith machine');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted side bend (on stability ball)', 'weighted side bend (on stability ball). Secondary Muscles: obliques, lower back', 'Strength', 'Abs', 'Intermediate', 'Step:1 Step:1 Sit on a stability ball with your feet shoulder-width apart and flat on the ground. Step:2 Step:2 Hold a weight in one hand and place your other hand on your hip. Step:3 Step:3 Engage your core and slowly bend sideways towards the weighted side, keeping your back straight. Step:4 Step:4 Pause for a moment at the bottom, then slowly return to the starting position. Step:5 Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Weighted' LIMIT 1), 'weighted');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm upright row', 'dumbbell one arm upright row. Secondary Muscles: traps, biceps', 'Strength', 'Delts', 'Intermediate', 'Step:1 Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip. Step:2 Step:2 Let the dumbbell hang at arm''s length in front of your thighs, with your palm facing your body. Step:3 Step:3 Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow. Step:4 Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position. Step:5 Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing rocking leg calf raise', 'barbell standing rocking leg calf raise. Secondary Muscles: hamstrings, quadriceps', 'Strength', 'Calves', 'Intermediate', 'Step:1 Step:1 Stand with your feet shoulder-width apart and hold a barbell across your upper back. Step:2 Step:2 Raise your heels off the ground as high as possible, balancing on the balls of your feet. Step:3 Step:3 Slowly lower your heels back down to the starting position. Step:4 Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Barbell' LIMIT 1), 'barbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell wrist curl v. 2', 'barbell wrist curl v. 2. Secondary Muscles: biceps, brachialis', 'Strength', 'Forearms', 'Intermediate', 'Step:1 Step:1 Sit on a bench with your feet flat on the ground and your knees bent. Step:2 Step:2 Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart. Step:3 Step:3 Rest your forearms on your thighs, allowing your wrists to hang off the edge. Step:4 Step:4 Slowly curl your wrists upward, bringing the barbell towards your forearms. Step:5 Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Barbell' LIMIT 1), 'barbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying single extension', 'dumbbell lying single extension. Secondary Muscles: shoulders', 'Strength', 'Triceps', 'Intermediate', 'Step:1 Step:1 Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest. Step:2 Step:2 Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary. Step:3 Step:3 Pause briefly at the bottom of the movement, then extend your arm back to the starting position. Step:4 Step:4 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse spider curl', 'dumbbell reverse spider curl. Secondary Muscles: forearms', 'Strength', 'Biceps', 'Intermediate', 'Step:1 Step:1 Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended. Step:2 Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bent knee lying twist (male)', 'bent knee lying twist (male). Secondary Muscles: obliques, hip flexors', 'Strength', 'Glutes', 'Intermediate', 'Step:1 Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Step:2 Extend your arms out to the sides, perpendicular to your body. Step:3 Step:3 Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees. Step:4 Step:4 Pause for a moment, then engage your core and slowly lift your knees back to the starting position. Step:5 Step:5 Repeat the movement to the other side. Step:6 Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever front pulldown', 'lever front pulldown. Secondary Muscles: biceps, rhomboids, rear deltoids', 'Strength', 'Lats', 'Intermediate', 'Step:1 Step:1 Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground. Step:2 Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Step:3 Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back. Step:4 Step:4 Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together. Step:5 Step:5 Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Leverage Machine' LIMIT 1), 'leverage machine');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated row', 'lever seated row. Secondary Muscles: biceps, forearms', 'Strength', 'Upper Back', 'Intermediate', 'Step:1 Step:1 Adjust the seat height and footrests to a comfortable position. Step:2 Step:2 Sit on the machine with your chest against the pad and your feet on the footrests. Step:3 Step:3 Grasp the handles with an overhand grip, shoulder-width apart. Step:4 Step:4 Keep your back straight and your core engaged. Step:5 Step:5 Pull the handles towards your body, squeezing your shoulder blades together. Step:6 Step:6 Pause for a moment at the peak of the movement. Step:7 Step:7 Slowly release the handles and return to the starting position. Step:8 Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Leverage Machine' LIMIT 1), 'leverage machine');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing concentration curl', 'dumbbell standing concentration curl. Secondary Muscles: forearms', 'Strength', 'Biceps', 'Intermediate', 'Step:1 Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards. Step:2 Step:2 Place your opposite hand on your thigh for support. Step:3 Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps. Step:4 Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Step:6 Inhale and slowly lower the dumbbell back to the starting position. Step:7 Step:7 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable decline fly', 'cable decline fly. Secondary Muscles: shoulders, triceps', 'Strength', 'Pectorals', 'Intermediate', 'Step:1 Step:1 Adjust the cable machine to a decline position. Step:2 Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Step:3 Hold the handles with your palms facing forward and your arms extended straight out in front of you. Step:4 Step:4 Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Step:5 Step:5 Pause for a moment at the fully extended position, then slowly return to the starting position. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Cable' LIMIT 1), 'cable');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith leg press', 'smith leg press. Secondary Muscles: quadriceps, hamstrings, calves', 'Strength', 'Glutes', 'Intermediate', 'Step:1 Step:1 Adjust the seat and footplate of the smith machine to a comfortable position. Step:2 Step:2 Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate. Step:3 Step:3 Grasp the handles or sides of the machine for stability. Step:4 Step:4 Push the footplate away from you by extending your legs, keeping your back against the backrest. Step:5 Step:5 Pause for a moment at the fully extended position. Step:6 Step:6 Slowly bend your knees and lower the footplate back towards you, returning to the starting position. Step:7 Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Smith Machine' LIMIT 1), 'smith machine');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell palms in incline bench press', 'dumbbell palms in incline bench press. Secondary Muscles: chest, shoulders', 'Strength', 'Triceps', 'Intermediate', 'Step:1 Step:1 Set up an incline bench at a 45-degree angle. Step:2 Step:2 Sit on the bench with your back against the backrest and feet flat on the ground. Step:3 Step:3 Hold a dumbbell in each hand with an overhand grip, palms facing inwards. Step:4 Step:4 Extend your arms straight up above your chest, keeping a slight bend in your elbows. Step:5 Step:5 Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body. Step:6 Step:6 Pause for a moment at the bottom, then press the dumbbells back up to the starting position. Step:7 Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted hanging knee raise with throw down', 'assisted hanging knee raise with throw down. Secondary Muscles: hip flexors, lower back', 'Strength', 'Abs', 'Intermediate', 'Step:1 Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Step:2 Engage your core and lift your knees towards your chest, keeping your legs together. Step:3 Step:3 Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully. Step:4 Step:4 Allow your legs to swing back up and repeat the movement for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Assisted' LIMIT 1), 'assisted');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated curl', 'cable seated curl. Secondary Muscles: forearms', 'Strength', 'Biceps', 'Intermediate', 'Step:1 Step:1 Sit on a cable machine with your feet flat on the ground and your back straight. Step:2 Step:2 Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended. Step:3 Step:3 Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps. Step:4 Step:4 Pause for a moment at the top of the movement, squeezing your biceps. Step:5 Step:5 Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Step:6 Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Cable' LIMIT 1), 'cable');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing calf raise', 'barbell standing calf raise. Secondary Muscles: hamstrings, glutes', 'Strength', 'Calves', 'Intermediate', 'Step:1 Step:1 Stand with your feet shoulder-width apart and place a barbell across your upper back. Step:2 Step:2 Raise your heels off the ground as high as possible, using only your toes. Step:3 Step:3 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:4 Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Barbell' LIMIT 1), 'barbell');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted hyperextension (on stability ball)', 'weighted hyperextension (on stability ball). Secondary Muscles: glutes, hamstrings', 'Strength', 'Spine', 'Intermediate', 'Step:1 Step:1 Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability. Step:2 Step:2 Place your hands behind your head or cross them over your chest. Step:3 Step:3 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line. Step:4 Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Weighted' LIMIT 1), 'weighted');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated crunch', 'cable seated crunch. Secondary Muscles: obliques', 'Strength', 'Abs', 'Intermediate', 'Step:1 Step:1 Sit on a cable machine with your feet flat on the ground and your knees bent. Step:2 Step:2 Hold the cable handle with both hands and position it behind your head. Step:3 Step:3 Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees. Step:4 Step:4 Pause for a moment at the top, then slowly return to the starting position. Step:5 Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Cable' LIMIT 1), 'cable');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('flat db press', 'flat db press', 'Strength', 'Chest', 'Intermediate', 'Perform FLAT DB PRESS with proper form. Focus on the target muscles: chest, triceps, front delts.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Dumbbell' LIMIT 1), 'dumbbell');
