INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted crunch', 'weighted crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Hold a weight plate or dumbbell on your chest. Step:3 Engage your abs and lift your upper body off the ground, curling forward until your shoulder blades are off the ground. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
