INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell decline close grip to skull press', 'barbell decline close grip to skull press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip. Step:2 Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary. Step:3 Pause for a moment, then extend your arms to press the barbell back up to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up inside leg kick', 'push-up inside leg kick', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Lower your body towards the ground by bending your elbows, keeping your back straight and your core engaged. Step:3 As you push back up, lift one leg off the ground and kick it out to the side, keeping it straight. Step:4 Lower your leg back down and repeat the push-up, then switch to the other leg. Step:5 Continue alternating leg kicks with each push-up repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable incline fly (on stability ball)', 'cable incline fly (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a stability ball at an incline angle. Step:2 Attach the cable handles to the high pulleys of a cable machine. Step:3 Sit on the stability ball facing away from the machine, with your feet firmly planted on the ground. Step:4 Grasp the cable handles with an overhand grip, palms facing forward. Step:5 Lean forward slightly, keeping your back straight and core engaged. Step:6 With a controlled motion, bring your arms out to the sides, keeping a slight bend in your elbows. Step:7 Continue the motion until your arms are parallel to the ground. Step:8 Pause for a moment, then slowly return to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell double alternating hang clean', 'kettlebell double alternating hang clean', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Step:3 Allow the kettlebells to hang straight down in front of your body. Step:4 In one fluid motion, explosively extend your hips and knees while shrugging your shoulders. Step:5 As the kettlebells rise, pull them up towards your shoulders, keeping your elbows high and out to the sides. Step:6 Catch the kettlebells at shoulder height, with your palms facing inward and your elbows pointing forward. Step:7 Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell contralateral forward lunge', 'dumbbell contralateral forward lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Take a step forward with your right foot, keeping your back straight and core engaged. Step:3 Lower your body by bending both knees until your right thigh is parallel to the ground. Step:4 Push through your right heel to return to the starting position. Step:5 Repeat with your left leg. Step:6 Alternate legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell press sit-up', 'barbell press sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back on a mat with your knees bent and feet flat on the ground. Step:2 Hold the barbell with an overhand grip, resting it on your chest. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse one arm curl', 'cable reverse one arm curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Grasp the cable handle with an underhand grip, palm facing down. Step:3 Keep your elbow close to your side and slowly curl your forearm up towards your shoulder. Step:4 Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell finger curls', 'dumbbell finger curls', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up. Step:3 Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers. Step:4 Repeat for the desired number of repetitions, then switch to the other hand.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band stiff leg deadlift', 'band stiff leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band around your ankles. Step:2 Hold the band with both hands in front of your thighs, palms facing your body. Step:3 Keeping your back straight and your core engaged, hinge at the hips and slowly lower your upper body towards the ground. Step:4 As you lower, push your hips back and allow your knees to bend slightly. Step:5 Lower the band towards the ground, feeling a stretch in your hamstrings. Step:6 Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your upper body back up to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell goblet squat', 'kettlebell goblet squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell close to your chest with both hands. Step:2 Keeping your chest up and core engaged, lower your body down into a squat position by bending at the knees and hips. Step:3 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever chest press', 'lever chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back flat against the pad. Step:2 Grasp the handles with an overhand grip and position your elbows at a 90-degree angle. Step:3 Push the handles forward until your arms are fully extended, exhaling during the movement. Step:4 Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline biceps curl', 'dumbbell incline biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one arm against wall', 'one arm against wall', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall with your feet shoulder-width apart. Step:2 Extend one arm straight out in front of you and place your palm against the wall. Step:3 Engage your core and lean your body forward, keeping your arm straight and your back flat. Step:4 Slowly push against the wall with your palm, activating your lat muscles. Step:5 Hold the position for a few seconds, then release and repeat with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('squat on bosu ball', 'squat on bosu ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the bosu ball on the ground with the flat side up. Step:2 Stand with your feet shoulder-width apart and position yourself on top of the bosu ball. Step:3 Lower your body down by bending your knees and hips, as if sitting back into a chair. Step:4 Keep your chest up and your weight on your heels. Step:5 Lower yourself until your thighs are parallel to the ground. Step:6 Pause for a moment, then push through your heels to return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('close-grip push-up', 'close-grip push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands placed close together, directly under your shoulders. Step:2 Engage your core and lower your body towards the ground, keeping your elbows close to your sides. Step:3 Push through your palms to extend your arms and return to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm shoulder press', 'dumbbell one arm shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward. Step:2 Press the dumbbell upward until your arm is fully extended overhead. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:4 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing up straight crossovers', 'cable standing up straight crossovers', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in the middle of a cable machine with your feet shoulder-width apart. Step:2 Hold the handles of the cables with your palms facing down and your arms extended straight out to the sides. Step:3 Keeping your arms straight, bring your hands together in front of your body, crossing them over each other. Step:4 Pause for a moment, then slowly return to the starting position, keeping your arms extended. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band side triceps extension', 'band side triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down. Step:2 Extend your arms straight out to the sides, keeping them parallel to the ground. Step:3 Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still. Step:4 Pause for a moment, then slowly extend your arms back out to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell side bend', 'dumbbell side bend', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, letting it hang down by your side. Step:2 Keeping your back straight and your core engaged, slowly bend sideways at the waist towards the opposite side of the dumbbell, lowering the weight as far as you comfortably can. Step:3 Pause for a moment, then slowly return to the starting position. Step:4 Repeat for the desired number of repetitions, then switch sides and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell single leg squat', 'dumbbell single leg squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Extend one leg forward and keep it off the ground throughout the exercise. Step:3 Bend your standing leg and lower your body down as if sitting back into a chair. Step:4 Keep your chest up and your back straight. Step:5 Pause for a moment at the bottom, then push through your heel to return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sledge hammer', 'sledge hammer', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the sledge hammer with both hands. Step:2 Engage your core and keep your back straight. Step:3 Swing the sledge hammer down towards the ground, using your core and upper body strength. Step:4 As you swing down, pivot your hips and transfer the force to the hammer. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell full squat (back pov)', 'barbell full squat (back pov)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the barbell across your upper back, resting it on your traps or rear delts. Step:3 Engage your core and keep your chest up as you begin to lower your body down. Step:4 Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Step:5 Lower your body until your thighs are parallel to the ground or slightly below. Step:6 Keep your knees in line with your toes and your weight in your heels. Step:7 Drive through your heels to stand back up, extending your hips and knees. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('archer pull up', 'archer pull up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:2 Engage your core and pull your shoulder blades down and back. Step:3 As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight. Step:4 Continue pulling until your chin is above the bar and your bent arm is fully flexed. Step:5 Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side. Step:6 Alternate sides with each repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm tricep pushdown', 'cable one arm tricep pushdown', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with a straight bar attachment at chest height. Step:2 Grasp the bar with an overhand grip and step back to create tension in the cable. Step:3 Position your feet shoulder-width apart and slightly bend your knees. Step:4 Keep your back straight and core engaged throughout the exercise. Step:5 Start with your arm fully extended and perpendicular to the floor. Step:6 Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended. Step:7 Pause for a moment, then inhale and slowly return to the starting position. Step:8 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted wide-grip chest dip (kneeling)', 'assisted wide-grip chest dip (kneeling)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired height and secure your knees on the pad. Step:2 Grasp the handles with a wide grip and keep your elbows slightly bent. Step:3 Lower your body by bending your elbows until your upper arms are parallel to the floor. Step:4 Push yourself back up to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('stationary bike run v. 3', 'stationary bike run v. 3', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position to ensure proper alignment. Step:2 Place your feet on the pedals and secure them with the straps if available. Step:3 Start pedaling at a comfortable pace. Step:4 Maintain a steady rhythm and increase the resistance as desired. Step:5 Engage your core muscles to maintain stability and proper posture. Step:6 Continue pedaling for the desired duration of your workout. Step:7 Gradually decrease the resistance and slow down before coming to a complete stop. Step:8 Stretch your legs and cool down after the workout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated inner biceps curl', 'dumbbell seated inner biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Step:2 Rest your upper arms on your thighs, allowing the dumbbells to hang down. Step:3 Keeping your upper arms stationary, curl the dumbbells up towards your shoulders by contracting your biceps. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated hip abduction', 'lever seated hip abduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that your knees are at a 90-degree angle. Step:2 Sit on the machine with your back against the backrest and your feet on the footrests. Step:3 Place your hands on the side handles for stability. Step:4 Engage your abductors and slowly push your legs apart, away from the midline of your body. Step:5 Pause for a moment at the end of the movement, then slowly bring your legs back together to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest dip on straight bar', 'chest dip on straight bar', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the parallel bars with your palms facing down and your arms fully extended. Step:2 Bend your knees and cross your ankles. Step:3 Lower your body by bending your arms until your shoulders are below your elbows. Step:4 Push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell front raise and pullover', 'barbell front raise and pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Step:2 Keep your arms straight and raise the barbell in front of you until it reaches shoulder height. Step:3 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:4 Next, lower the barbell behind your head, keeping your arms straight. Step:5 Pause for a moment at the bottom, then raise the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated biceps curl to shoulder press', 'dumbbell seated biceps curl to shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell in each hand with your palms facing forward and arms fully extended. Step:3 Keeping your elbows close to your sides, curl the dumbbells up towards your shoulders. Step:4 Once your forearms are vertical, rotate your wrists so that your palms are facing forward. Step:5 Press the dumbbells overhead until your arms are fully extended. Step:6 Lower the dumbbells back down to the starting position by reversing the movement. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell clean and press', 'barbell clean and press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and the barbell on the floor in front of you. Step:2 Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body. Step:4 As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest. Step:5 As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up. Step:6 From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up. Step:7 Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever rotary calf', 'lever rotary calf', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate. Step:2 Place your toes on the footplate, with your heels hanging off the edge. Step:3 Grasp the handles or the sides of the machine for stability. Step:4 Push through the balls of your feet, raising your heels as high as possible. Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell wrist curl', 'barbell wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip. Step:2 Allow the barbell to roll down to your fingertips, keeping your wrists straight. Step:3 Slowly curl the barbell up towards your forearms by flexing your wrists. Step:4 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('arms apart circular toe touch (male)', 'arms apart circular toe touch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and arms extended to the sides. Step:2 Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand. Step:3 As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance. Step:4 Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverted row bent knees', 'inverted row bent knees', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a bar at waist height and lie underneath it. Step:2 Grab the bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Position your body so that your heels are on the ground and your body is straight. Step:4 Pull your chest up towards the bar by squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell hammer curls (with arm blaster)', 'dumbbell hammer curls (with arm blaster)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your torso. Step:2 Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. Step:3 This will be your starting position. Step:4 Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps. Step:5 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Then, inhale and slowly begin to lower the dumbbells back to the starting position. Step:8 Repeat for the recommended amount of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse grip incline bench row', 'barbell reverse grip incline bench row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench facing the backrest with your chest against it. Step:3 Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart. Step:4 Keep your back straight and core engaged. Step:5 Pull the barbell towards your upper abdomen, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement. Step:7 Slowly lower the barbell back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith narrow row', 'smith narrow row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your feet flat on the floor. Step:2 Grasp the handles with an overhand grip, slightly narrower than shoulder-width apart. Step:3 Keep your back straight and your chest up as you pull the handles towards your body, squeezing your shoulder blades together. Step:4 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted prone lying quads stretch', 'assisted prone lying quads stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the ground with your legs extended. Step:2 Bend your left knee and reach back with your left hand to grab your left foot or ankle. Step:3 Gently pull your left foot towards your glutes, feeling a stretch in your left quad. Step:4 Hold the stretch for 20-30 seconds, then release. Step:5 Repeat with your right leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever preacher curl v. 2', 'lever preacher curl v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your upper arms resting on the pad and your chest against the support. Step:2 Grasp the handles with an underhand grip, slightly wider than shoulder-width apart. Step:3 Keep your upper arms stationary and exhale as you curl the handles towards your shoulders, contracting your biceps. Step:4 Pause for a moment at the top of the movement, squeezing your biceps. Step:5 Inhale as you slowly lower the handles back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated one leg calf raise - palm up', 'dumbbell seated one leg calf raise - palm up', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your back straight and your feet flat on the ground. Step:2 Hold a dumbbell in one hand and place it on top of your thigh, palm facing up. Step:3 Lift one leg off the ground and extend it in front of you, keeping your knee slightly bent. Step:4 Raise your heel as high as possible by pushing through the ball of your foot. Step:5 Pause for a moment at the top, then slowly lower your heel back down. Step:6 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing shoulder external rotation', 'cable standing shoulder external rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Hold the cable handle with your arm extended in front of you, parallel to the ground. Step:3 Keep your elbow slightly bent and your shoulder blades pulled back. Step:4 Slowly rotate your arm outward, away from your body, while keeping your elbow in the same position. Step:5 Pause for a moment at the end of the movement, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('handstand', 'handstand', 'Strength', 'Other', 'Intermediate', 'Step:1 Find an open space with enough room to perform a handstand. Step:2 Place your hands on the ground shoulder-width apart, fingers pointing forward. Step:3 Kick your legs up towards the wall, using your core and shoulders to maintain balance. Step:4 Once in a handstand position, engage your triceps to support your body weight. Step:5 Hold the handstand for as long as you can maintain balance. Step:6 To come down, slowly lower your legs back to the ground. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('full planche push-up', 'full planche push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands placed slightly wider than shoulder-width apart. Step:2 Engage your core and lower your body down towards the ground, keeping your elbows close to your sides. Step:3 As you lower yourself, lean your body forward and lift your feet off the ground, balancing on your hands. Step:4 Continue to lower your body until your chest is just above the ground. Step:5 Push through your hands and extend your arms to lift your body back up to the starting position. Step:6 Maintain a straight line from your head to your heels throughout the movement. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying external shoulder rotation', 'dumbbell lying external shoulder rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees. Step:2 Hold a dumbbell in your hand with your palm facing down. Step:3 Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible. Step:4 Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell seated triceps extension', 'ez barbell seated triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold the ez barbell with an overhand grip, hands shoulder-width apart. Step:3 Raise the barbell overhead, fully extending your arms. Step:4 Keeping your upper arms stationary, lower the barbell behind your head by bending your elbows. Step:5 Pause for a moment, then raise the barbell back to the starting position by extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band standing crunch', 'band standing crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point at waist height. Step:2 Stand facing away from the anchor point with your feet shoulder-width apart. Step:3 Hold the band with both hands and bring it up to your chest, keeping your elbows bent and close to your body. Step:4 Engage your abs and slowly crunch forward, bringing your chest towards your knees. Step:5 Pause for a moment at the top of the crunch, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell straight leg deadlift', 'dumbbell straight leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your torso to lean forward. Step:3 Continue lowering the dumbbells until you feel a stretch in your hamstrings, keeping your knees slightly bent. Step:4 Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith close-grip bench press', 'smith close-grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the bench with your feet flat on the ground. Step:2 Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Step:3 Lower the barbell towards your chest, keeping your elbows close to your body. Step:4 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('suspended push-up', 'suspended push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Find a suspension trainer and adjust it to an appropriate height. Step:2 Stand facing away from the anchor point and hold the handles with an overhand grip. Step:3 Walk your feet forward, leaning your body forward until your weight is supported by the suspension trainer. Step:4 Keep your body straight from head to heels, engage your core, and lower your chest towards the handles. Step:5 Push through your chest and arms to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell single leg deadlift with stepbox support', 'dumbbell single leg deadlift with stepbox support', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart, holding a dumbbell in your right hand. Step:2 Place your left foot on a stepbox or elevated surface behind you. Step:3 Keeping your back straight and core engaged, hinge forward at the hips, lowering the dumbbell towards the ground. Step:4 As you lower the dumbbell, simultaneously lift your left leg behind you, maintaining a straight line from head to heel. Step:5 Lower the dumbbell until you feel a stretch in your right hamstring, then return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing lift', 'cable standing lift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Hold the cable handle with both hands and position it at waist height. Step:3 Engage your core and maintain a straight back throughout the exercise. Step:4 Keeping your arms straight, exhale and lift the cable handle up towards your opposite shoulder, rotating your torso. Step:5 Pause for a moment at the top, then inhale and slowly lower the cable handle back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm reverse preacher curl', 'dumbbell one arm reverse preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with your chest against the pad and your arm extended over the edge of the bench, holding a dumbbell with an underhand grip. Step:2 Lower the dumbbell slowly until your arm is fully extended. Step:3 Curl the dumbbell back up towards your shoulder, keeping your upper arm stationary. Step:4 Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell peacher hammer curl', 'dumbbell peacher hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your torso. Step:2 Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. Step:3 This will be your starting position. Step:4 Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Step:5 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Then, inhale and slowly begin to lower the dumbbells back to the starting position. Step:8 Repeat for the recommended amount of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable front raise', 'cable front raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip. Step:2 Keep your back straight and your core engaged. Step:3 Raise the cable handle in front of you, keeping your arms straight and your palms facing down. Step:4 Continue lifting until your arms are parallel to the floor. Step:5 Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lying triceps extension v. 2', 'cable lying triceps extension v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a low pulley cable machine. Step:2 Lie down on a flat bench facing up, with your head towards the cable machine. Step:3 Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest. Step:4 Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows. Step:5 Pause for a moment at the bottom, then extend your arms back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell alternating press', 'kettlebell alternating press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Step:2 Press one kettlebell overhead, fully extending your arm. Step:3 Lower the kettlebell back to shoulder height. Step:4 Repeat with the other arm. Step:5 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope lying on floor tricep extension', 'cable rope lying on floor tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a cable machine and set it to the lowest position. Step:2 Lie on the floor facing up, with your head towards the cable machine. Step:3 Hold the rope with both hands, palms facing each other, and extend your arms straight up towards the ceiling. Step:4 Keep your upper arms stationary and slowly lower the rope towards your forehead, bending your elbows. Step:5 Pause for a moment, then extend your arms back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bottoms-up', 'bottoms-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Bend your knees and bring them towards your chest, keeping your feet off the ground. Step:3 Engaging your abs, lift your hips off the ground, bringing your knees towards your head. Step:4 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band step-up', 'band step-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Place a band around your thighs, just above your knees. Step:2 Stand facing a step or platform with your feet hip-width apart. Step:3 Step up onto the platform with your right foot, pushing through your heel. Step:4 Extend your left leg behind you, keeping it straight. Step:5 Lower your left foot back down to the ground. Step:6 Repeat with your left foot stepping up onto the platform. Step:7 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable alternate triceps extension', 'cable alternate triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Hold the cable handle with your right hand and bring your arm up so that your upper arm is parallel to the ground and your elbow is bent at a 90-degree angle. Step:3 Keep your upper arm stationary and extend your forearm backward, fully straightening your arm. Step:4 Pause for a moment, then slowly return to the starting position. Step:5 Repeat with your left arm. Step:6 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm decline chest press', 'dumbbell one arm decline chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with a dumbbell in one hand, resting on your chest. Step:2 Place your feet flat on the ground and keep your back pressed against the bench. Step:3 Extend your arm and push the dumbbell up towards the ceiling, fully extending your elbow. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope high pulley overhead tricep extension', 'cable rope high pulley overhead tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a high pulley and adjust the weight accordingly. Step:2 Stand facing away from the pulley machine with your feet shoulder-width apart. Step:3 Grasp the rope with both hands, palms facing down, and bring your hands above your head. Step:4 Keep your upper arms close to your head and perpendicular to the floor. Step:5 Slowly lower the rope behind your head by bending your elbows. Step:6 Pause for a moment, then extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell incline row', 'barbell incline row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Lie face down on the bench with your chest against the pad and your feet flat on the ground. Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:4 Keep your back straight and your core engaged. Step:5 Pull the barbell towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower the barbell back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing lateral stretch', 'standing lateral stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Extend your arms straight out to the sides, parallel to the ground. Step:3 Slowly lean your upper body to one side, feeling a stretch in your side and lats. Step:4 Hold the stretch for 15-30 seconds. Step:5 Return to the starting position and repeat on the other side. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable supine reverse fly', 'cable supine reverse fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a D-handle to a low pulley cable machine and lie face down on a flat bench. Step:2 Grasp the D-handle with each hand, palms facing down, and extend your arms straight out in front of you. Step:3 Keeping your arms straight, raise them out to the sides until they are parallel to the floor. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell single leg deadlift', 'dumbbell single leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart, holding a dumbbell in your right hand. Step:2 Shift your weight onto your left leg and lift your right foot slightly off the ground. Step:3 Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground. Step:4 At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee. Step:5 Lower the dumbbell until your torso and right leg are parallel to the ground. Step:6 Pause for a moment, then engage your glutes and hamstrings to return to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated revers grip concentration curl', 'dumbbell seated revers grip concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up. Step:2 Rest your elbow on the inside of your thigh, just above the knee. Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm hammer press on exercise ball', 'dumbbell incline one arm hammer press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand. Step:2 Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle. Step:4 Press the dumbbell up towards the ceiling, straightening your arm. Step:5 Lower the dumbbell back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side push neck stretch', 'side push neck stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand or sit up straight with your shoulders relaxed. Step:2 Tilt your head to the right, bringing your right ear towards your right shoulder. Step:3 Place your right hand on the left side of your head and gently apply pressure to increase the stretch. Step:4 Hold the stretch for 15-30 seconds. Step:5 Repeat on the other side, tilting your head to the left and applying pressure with your left hand. Step:6 Repeat the stretch 2-3 times on each side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reverse hyper extension (on stability ball)', 'reverse hyper extension (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a stability ball with your hips resting on the ball and your legs extended straight behind you. Step:2 Place your hands on the ground in front of you for stability. Step:3 Engaging your glutes and hamstrings, lift your legs up towards the ceiling as high as you can. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted front plank', 'weighted front plank', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying face down on the floor. Step:2 Place your forearms on the ground, with your elbows directly under your shoulders. Step:3 Extend your legs straight out behind you, with your toes on the ground. Step:4 Engage your core and lift your body off the ground, balancing on your forearms and toes. Step:5 Keep your body in a straight line from your head to your heels. Step:6 Hold this position for the desired amount of time. Step:7 Lower your body back down to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying pronation on floor', 'dumbbell lying pronation on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand. Step:2 Rotate your palms so they are facing down towards the floor. Step:3 Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms. Step:4 Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level. Step:5 Hold for a moment, then slowly lower the dumbbells back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted hanging knee raise', 'assisted hanging knee raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core muscles and lift your knees towards your chest, bending at the hips and knees. Step:3 Pause for a moment at the top of the movement, squeezing your abs. Step:4 Slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith incline shoulder raises', 'smith incline shoulder raises', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the smith machine to an incline position. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:4 Keep your back straight and core engaged. Step:5 Raise the barbell up towards the ceiling, leading with your elbows. Step:6 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sphinx', 'sphinx', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the ground with your forearms flat on the floor, elbows directly under your shoulders. Step:2 Engage your core and lift your chest off the ground, keeping your forearms and toes on the floor. Step:3 Hold this position for a few seconds, making sure to keep your neck in a neutral position. Step:4 Slowly lower your chest back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side-to-side chin', 'side-to-side chin', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Hang from the bar with your arms fully extended and your body relaxed. Step:4 Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight. Step:5 Once your chin is above the bar, lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell bench squat', 'barbell bench squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a barbell on a squat rack at chest height. Step:2 Stand facing away from the rack, with your feet shoulder-width apart. Step:3 Bend your knees and lower your body down into a squat position, keeping your back straight and chest up. Step:4 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:5 Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart. Step:6 Lower your body down into a squat, keeping your knees in line with your toes. Step:7 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight kneeling triceps extension', 'bodyweight kneeling triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Kneel down on the ground with your knees hip-width apart. Step:2 Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward. Step:3 Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels. Step:4 Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides. Step:5 Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable triceps pushdown (v-bar)', 'cable triceps pushdown (v-bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a v-bar attachment to the cable machine at the highest setting. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Engage your triceps and exhale as you push the v-bar down until your arms are fully extended. Step:6 Pause for a moment at the bottom of the movement, squeezing your triceps. Step:7 Inhale as you slowly return the v-bar to the starting position, maintaining control. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell upright shoulder external rotation', 'dumbbell upright shoulder external rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body. Step:2 Raise your arms out to the sides until they are parallel to the ground, keeping your elbows slightly bent. Step:3 Rotate your arms externally, bringing the dumbbells up towards your head while keeping your elbows in the same position. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable middle fly', 'cable middle fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach cables to both sides of a cable machine at chest height. Step:2 Stand in the center of the machine with one foot slightly in front of the other. Step:3 Grasp the handles with an overhand grip and extend your arms out to the sides. Step:4 Keep a slight bend in your elbows and maintain a slight forward lean. Step:5 Engage your chest muscles and bring your arms forward in a sweeping motion. Step:6 Pause for a moment at the center, then slowly return your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever lying leg curl', 'lever lying leg curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to fit your body and select the desired weight. Step:2 Lie face down on the machine with your legs straight and your heels against the padded lever. Step:3 Grasp the handles or the sides of the machine for stability. Step:4 Keeping your upper body stationary, exhale and curl your legs up as far as possible without lifting your hips off the pad. Step:5 Hold the contracted position for a brief pause as you squeeze your hamstrings. Step:6 Inhale and slowly lower the lever back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hyperextension (on bench)', 'hyperextension (on bench)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the hyperextension bench so that your hips are resting comfortably on the pad and your feet are secured. Step:2 Cross your arms over your chest or place your hands behind your head. Step:3 Slowly lower your upper body towards the ground while keeping your back straight. Step:4 Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell stiff leg good morning', 'barbell stiff leg good morning', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Hold the barbell across your upper back, resting it on your traps. Step:3 Keeping your back straight, hinge forward at the hips, pushing your glutes back. Step:4 Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Step:5 Engage your glutes and hamstrings to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band assisted pull-up', 'band assisted pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a pull-up bar or sturdy anchor point. Step:2 Step onto the band and grip the bar with your palms facing away from you, hands slightly wider than shoulder-width apart. Step:3 Hang with your arms fully extended, keeping your core engaged and your shoulders down and back. Step:4 Pull your body up towards the bar by squeezing your shoulder blades together and driving your elbows down towards your hips. Step:5 Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell romanian deadlift', 'barbell romanian deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your toes pointing forward. Step:2 Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Bend at the hips, keeping your back straight and your knees slightly bent. Step:4 Lower the barbell towards the ground, keeping it close to your body. Step:5 Feel the stretch in your hamstrings as you lower the barbell. Step:6 Once you feel a stretch in your hamstrings, push your hips forward and stand up straight. Step:7 Squeeze your glutes at the top of the movement. Step:8 Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band reverse wrist curl', 'band reverse wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground. Step:2 Hold the band with an overhand grip, palms facing down, and wrap it around your fingers. Step:3 Rest your forearms on your thighs, with your wrists hanging off the edge. Step:4 Slowly curl your wrists upward, squeezing your forearms. Step:5 Pause for a moment at the top, then slowly lower your wrists back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell turkish get up (squat style)', 'kettlebell turkish get up (squat style)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your back with your legs extended and the kettlebell held in your right hand, arm fully extended above your shoulder. Step:2 Bend your right knee and place your right foot flat on the ground, keeping your left leg extended. Step:3 Pressing through your right foot, lift your hips off the ground, coming into a bridge position. Step:4 Slide your left leg underneath your body, bending your left knee and placing your left foot flat on the ground. Step:5 Rotate your torso to the left, bringing your left hand to the ground for support. Step:6 Pressing through your right foot and left hand, lift your torso off the ground, coming into a kneeling position. Step:7 From the kneeling position, stand up, keeping the kettlebell extended overhead. Step:8 Reverse the movement to return to the starting position. Step:9 Repeat the exercise on the other side, starting with the kettlebell in your left hand.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell rotation reverse fly', 'dumbbell rotation reverse fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing inwards. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Step:3 Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor. Step:4 Rotate your arms so that your palms are facing downwards. Step:5 Slowly lower your arms back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('tuck crunch', 'tuck crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, lift your shoulder blades off the ground and bring your knees towards your chest, simultaneously curling your upper body towards your knees. Step:4 Pause for a moment at the top, then slowly lower your shoulder blades and extend your legs back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reverse grip machine lat pulldown', 'reverse grip machine lat pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground. Step:2 Grasp the handles with an underhand grip, slightly wider than shoulder-width apart. Step:3 Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back. Step:4 Pull the handles down towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline t-raise', 'dumbbell incline t-raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards. Step:2 Lean forward and let your arms hang straight down, perpendicular to the floor. Step:3 Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a ''T'' shape with your body. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable kickback', 'cable kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Hold the cable handle with your right hand and step back to create tension in the cable. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Keep your upper arm close to your body and your elbow bent at a 90-degree angle. Step:5 Extend your forearm backward, straightening your arm fully. Step:6 Pause for a moment, then slowly return to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell high bar squat', 'barbell high bar squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Place the barbell on your upper back, resting it on your traps. Step:3 Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees. Step:4 Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Drive through your heels to stand back up, extending your hips and knees. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez-barbell standing wide grip biceps curl', 'ez-barbell standing wide grip biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands wider than shoulder-width apart. Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the movement. Step:3 Curl the barbell up towards your shoulders by contracting your biceps. Step:4 Pause for a moment at the top, then slowly lower the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated calf raise', 'barbell seated calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the floor and a barbell resting on your thighs. Step:2 Place the balls of your feet on a raised platform, such as a block or step. Step:3 Lower your heels as far as possible, feeling a stretch in your calves. Step:4 Raise your heels as high as possible, contracting your calves. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight incline side plank', 'bodyweight incline side plank', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your side with your legs extended and stacked on top of each other. Step:2 Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle. Step:3 Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. Step:4 Hold this position for the desired amount of time. Step:5 Lower your hips back down to the ground and repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted prone rectus femoris stretch', 'assisted prone rectus femoris stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the ground with your legs straight. Step:2 Bend your right knee and reach back with your right hand to grab your right foot or ankle. Step:3 Gently pull your right foot or ankle towards your glutes, feeling a stretch in the front of your right thigh. Step:4 Hold the stretch for 20-30 seconds. Step:5 Release and repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline twisted flyes', 'dumbbell incline twisted flyes', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other. Step:2 Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended. Step:3 Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Step:4 As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement. Step:5 Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline push up depth jump', 'incline push up depth jump', 'Strength', 'Other', 'Intermediate', 'Step:1 Find an elevated surface, such as a bench or step, and place your hands shoulder-width apart on the edge. Step:2 Step your feet back, keeping your body in a straight line from head to heels. Step:3 Lower your chest towards the edge of the surface, bending your elbows and keeping your body aligned. Step:4 Push through your palms to extend your arms and return to the starting position. Step:5 Jump off the edge of the surface, landing softly with your knees slightly bent. Step:6 Repeat the push-up and depth jump for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell single arm overhead carry', 'dumbbell single arm overhead carry', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand tall with your feet shoulder-width apart, holding a dumbbell in one hand. Step:2 Raise the dumbbell overhead, fully extending your arm. Step:3 Engage your core and keep your back straight as you walk forward, maintaining the dumbbell overhead. Step:4 Continue walking for the desired distance or time. Step:5 Switch hands and repeat the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted chest dip (kneeling)', 'assisted chest dip (kneeling)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired height and secure your knees on the pad. Step:2 Grasp the handles with your palms facing down and your arms fully extended. Step:3 Lower your body by bending your elbows until your upper arms are parallel to the floor. Step:4 Pause for a moment, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell full can lateral raise', 'dumbbell full can lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Step:2 Keep your back straight and engage your core. Step:3 Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell double windmill', 'kettlebell double windmill', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in your right hand. Step:2 Extend your right arm overhead, keeping your eyes on the kettlebell. Step:3 Rotate your left foot 45 degrees to the left and your right foot 90 degrees to the right. Step:4 Bend at the waist to the left, keeping your right arm extended overhead. Step:5 Lower the kettlebell towards the ground, reaching towards your left foot. Step:6 Pause for a moment, then engage your core and push through your right foot to return to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable kneeling rear delt row (with rope) (male)', 'cable kneeling rear delt row (with rope) (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a low cable pulley and kneel down facing the machine. Step:2 Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you. Step:3 Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades. Step:4 Squeeze your shoulder blades together at the end of the movement and hold for a brief pause. Step:5 Slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated crunch', 'lever seated crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the leverage machine with your back against the pad and your feet flat on the floor. Step:2 Grasp the handles or place your hands on the side pads for support. Step:3 Engage your abs and slowly lean back, allowing the pad to move with you. Step:4 Once your upper body is at a 45-degree angle, contract your abs and crunch forward, bringing your chest towards your knees. Step:5 Pause for a moment at the top, then slowly release and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band horizontal pallof press', 'band horizontal pallof press', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point at waist height. Step:2 Stand perpendicular to the anchor point with your feet shoulder-width apart. Step:3 Grasp the band handle with both hands and step away from the anchor point to create tension in the band. Step:4 Bring your hands to your chest, keeping your elbows bent and close to your body. Step:5 Engage your core and maintain a stable stance. Step:6 Extend your arms straight out in front of you, pushing the band away from your body. Step:7 Hold the extended position for a few seconds, focusing on maintaining tension in your core. Step:8 Slowly bring your hands back to your chest, resisting the pull of the band. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever reverse grip vertical row', 'lever reverse grip vertical row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footplate position to ensure proper alignment. Step:2 Sit on the machine with your chest against the pad and your feet flat on the footplate. Step:3 Grasp the handles with an underhand grip, palms facing up. Step:4 Keep your back straight and engage your core. Step:5 Pull the handles towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball alternating arm ups', 'exercise ball alternating arm ups', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing inwards and your arms extended down by your sides. Step:3 Engage your core and slowly lift one arm up towards your shoulder, keeping your elbow slightly bent. Step:4 Pause for a moment at the top, then slowly lower your arm back down to the starting position. Step:5 Repeat the movement with the other arm. Step:6 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell front squat', 'kettlebell front squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the kettlebell with both hands in front of your chest, close to your body. Step:3 Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair. Step:4 Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Drive through your heels to stand back up, squeezing your glutes at the top. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever alternating narrow grip seated row', 'lever alternating narrow grip seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footplate position to ensure proper alignment. Step:2 Sit on the machine with your back straight and feet flat on the footplate. Step:3 Grasp the handles with a narrow grip, palms facing each other. Step:4 Keep your chest up and shoulders back throughout the exercise. Step:5 Pull one handle towards your torso while keeping the other handle stationary. Step:6 Squeeze your shoulder blades together at the end of the movement. Step:7 Slowly return the handle to the starting position and repeat with the other side. Step:8 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('elevator', 'elevator', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Place your hands on your hips or cross them in front of your chest. Step:3 Keeping your back straight, slowly bend forward at the waist, lowering your upper body towards the ground. Step:4 Pause for a moment at the bottom, then slowly raise your upper body back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pelvic tilt', 'pelvic tilt', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands by your sides. Step:3 Engage your abs and tilt your pelvis upward, pressing your lower back into the ground. Step:4 Hold this position for a few seconds, focusing on contracting your abs. Step:5 Release the tilt and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell kickbacks on exercise ball', 'dumbbell kickbacks on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle. Step:3 Extend your arms straight back, squeezing your triceps at the top of the movement. Step:4 Pause for a moment, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell zottman curl', 'dumbbell zottman curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your body. Step:2 Keep your elbows close to your torso and rotate your palms to face forward. Step:3 Curl the dumbbells up to your shoulders while keeping your upper arms stationary. Step:4 At the top of the movement, rotate your wrists so that your palms are facing away from your body. Step:5 Slowly lower the dumbbells back to the starting position, rotating your palms back to facing your body. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('machine inner chest press', 'machine inner chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back flat against the pad. Step:2 Grasp the handles with an overhand grip and position your elbows at a 90-degree angle. Step:3 Push the handles forward until your arms are fully extended, exhaling during the movement. Step:4 Pause for a moment at the end of the movement, then slowly return to the starting position, inhaling as you do so. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm bent-over row', 'dumbbell one arm bent-over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged. Step:3 Let the dumbbell hang straight down towards the floor, with your arm fully extended. Step:4 Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reverse crunch', 'reverse crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your arms extended along your sides. Step:2 Bend your knees and lift your feet off the ground, bringing your thighs perpendicular to the floor. Step:3 Contract your abs and curl your hips off the floor, bringing your knees towards your chest. Step:4 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying one arm supinated triceps extension', 'dumbbell lying one arm supinated triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your back and head supported, and your feet flat on the ground. Step:2 Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder. Step:3 Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow. Step:4 Pause for a moment at the bottom, then extend your arm back up to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted lying glutes stretch', 'assisted lying glutes stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your legs extended. Step:2 Bend your right knee and place your right ankle on your left thigh, just above the knee. Step:3 Grasp your left thigh with both hands and gently pull it towards your chest. Step:4 Hold the stretch for 20-30 seconds. Step:5 Release and repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted triceps dip (kneeling)', 'assisted triceps dip (kneeling)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired weight and height. Step:2 Kneel down on the pad facing the machine, with your hands gripping the handles. Step:3 Lower your body by bending your elbows, keeping your back straight and close to the machine. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('back extension on exercise ball', 'back extension on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface. Step:2 Position your hands behind your head or crossed over your chest. Step:3 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell deadlift', 'dumbbell deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing forward. Step:2 Hold a dumbbell in each hand, palms facing your body, arms extended downwards. Step:3 Bend at your hips and knees, lowering the dumbbells towards the ground while keeping your back straight. Step:4 Push through your heels and extend your hips and knees, lifting the dumbbells back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell kneeling bicep curl exercise ball', 'dumbbell kneeling bicep curl exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Kneel on the floor with an exercise ball in front of you. Step:2 Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up. Step:3 Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope crossover seated row', 'cable rope crossover seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the rowing machine with your feet flat on the footrests and your knees slightly bent. Step:2 Grasp the cable ropes with an overhand grip, palms facing each other. Step:3 Lean back slightly, keeping your back straight and your core engaged. Step:4 Pull the cable ropes towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope elevated seated row', 'cable rope elevated seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the elevated seat facing the cable machine. Step:2 Grab the cable rope handles with an overhand grip, palms facing each other. Step:3 Keep your back straight and lean slightly back, maintaining a slight bend in your knees. Step:4 Pull the cable towards your body by retracting your shoulder blades and squeezing your back muscles. Step:5 Pause for a moment at the fully contracted position. Step:6 Slowly release the tension and extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell bicep curl with stork stance', 'dumbbell bicep curl with stork stance', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Step:2 Extend one leg behind you, balancing on the toes of that foot. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated alternate hammer curl on exercise ball', 'dumbbell seated alternate hammer curl on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing your body and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while keeping your palm facing your body. Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly lower the dumbbell back to the starting position. Step:7 Repeat the movement with the opposite arm. Step:8 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('astride jumps (male)', 'astride jumps (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees and lower your body into a squat position. Step:3 Jump explosively upwards, extending your legs and arms. Step:4 While in the air, spread your legs apart and bring your arms out to the sides. Step:5 Land softly with your feet shoulder-width apart, bending your knees to absorb the impact. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push and pull bodyweight', 'push and pull bodyweight', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart and your body in a straight line. Step:2 Lower your chest towards the ground by bending your elbows, keeping your body straight. Step:3 Push through your palms to extend your arms and return to the starting position. Step:4 From the push-up position, pull your chest towards the ground by bending your elbows, keeping your body straight. Step:5 Push through your palms to extend your arms and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell twisting bench press', 'dumbbell twisting bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Hold a dumbbell in each hand with an overhand grip, palms facing away from you. Step:3 Extend your arms straight up over your chest, keeping a slight bend in your elbows. Step:4 Lower the dumbbells down towards your chest, keeping your elbows close to your body. Step:5 As you lower the dumbbells, twist your wrists so that your palms face towards you at the bottom of the movement. Step:6 Pause for a moment at the bottom, then reverse the movement by pressing the dumbbells back up to the starting position. Step:7 As you press the dumbbells up, twist your wrists back to the starting position with palms facing away from you. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('full maltese', 'full maltese', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and your arms extended straight out to the sides. Step:2 Slowly lean forward, keeping your arms straight, until your upper body is parallel to the ground. Step:3 Engage your core and hold this position for a few seconds. Step:4 Return to the starting position by pushing through your feet and standing back up. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller seated single leg shoulder flexor depresor retractor', 'roller seated single leg shoulder flexor depresor retractor', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat surface with your legs extended in front of you. Step:2 Hold the roller with both hands, palms facing down, and place it on your thighs. Step:3 Lean back slightly and engage your core muscles. Step:4 Raise the roller up to shoulder level, keeping your arms straight. Step:5 Slowly lower the roller back down to your thighs. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm seated hammer curl', 'dumbbell one arm seated hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell in one hand with a neutral grip (palms facing each other). Step:3 Rest your elbow on the inside of your thigh, just above the knee. Step:4 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Step:5 Pause for a moment at the top, squeezing your biceps. Step:6 Inhale and slowly lower the dumbbell back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell decline pullover', 'barbell decline pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie down on a decline bench with your head lower than your hips and your feet secured. Step:2 Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart. Step:3 Extend your arms above your chest, keeping a slight bend in your elbows. Step:4 Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders. Step:5 Pause for a moment, then return the barbell to the starting position by reversing the motion. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell waiter biceps curl', 'dumbbell waiter biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing forward. Step:2 Keep your upper arms close to your body and your elbows tucked in. Step:3 Slowly curl the dumbbells up towards your shoulders, keeping your wrists straight. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted lying leg raise with lateral throw down', 'assisted lying leg raise with lateral throw down', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Place your hands under your glutes for support. Step:3 Engage your abs and lift your legs off the ground, keeping them straight. Step:4 While keeping your legs together, lower them to one side until they are a few inches above the ground. Step:5 Pause for a moment, then lift your legs back to the starting position. Step:6 Repeat the movement to the other side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('vertical leg raise (on parallel bars)', 'vertical leg raise (on parallel bars)', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from the parallel bars with your arms fully extended and your body straight. Step:2 Engage your core and lift your legs up in front of you, keeping them straight. Step:3 Continue lifting until your legs are parallel to the ground or slightly higher. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lying extension pullover (with rope attachment)', 'cable lying extension pullover (with rope attachment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a cable machine and set the pulley at the highest position. Step:2 Lie down on a bench with your head towards the cable machine. Step:3 Hold the rope with both hands and extend your arms straight up above your chest. Step:4 Keeping your arms straight, slowly lower the rope behind your head while maintaining control. Step:5 Pause for a moment at the bottom, then slowly raise the rope back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell alternating renegade row', 'kettlebell alternating renegade row', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands gripping the kettlebells and your feet hip-width apart. Step:2 Engage your core and keep your body in a straight line from head to heels. Step:3 Pull one kettlebell up towards your chest, keeping your elbow close to your body. Step:4 Lower the kettlebell back down to the starting position and repeat with the other arm. Step:5 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm snatch', 'dumbbell one arm snatch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Step:3 Lower the dumbbell towards the ground, keeping it close to your body. Step:4 Explosively extend your hips, knees, and ankles, driving the dumbbell upwards in a straight line. Step:5 As the dumbbell reaches shoulder height, quickly rotate your hand and punch it overhead, fully extending your arm. Step:6 Catch the dumbbell overhead with a slight bend in your knees and hips. Step:7 Lower the dumbbell back down to the starting position in a controlled manner. Step:8 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller seated shoulder flexor depresor retractor', 'roller seated shoulder flexor depresor retractor', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat surface with your legs extended in front of you. Step:2 Hold the roller with both hands, palms facing down, and place it on your thighs. Step:3 Lean forward slightly and roll the roller away from your body, extending your arms straight in front of you. Step:4 Pause for a moment, then slowly roll the roller back towards your body, bending your arms and bringing the roller back to your thighs. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated lateral raise', 'dumbbell seated lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs. Step:2 Keep your back straight and core engaged. Step:3 Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball pike push up', 'exercise ball pike push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands on the floor and your shins resting on the stability ball. Step:2 Engage your core and lift your hips up towards the ceiling, rolling the ball towards your hands. Step:3 Keep your legs straight and your body in a pike position, forming an inverted V shape. Step:4 Bend your elbows and lower your upper body towards the floor, keeping your head in line with your hands. Step:5 Push through your hands and extend your arms to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triceps dip (between benches)', 'triceps dip (between benches)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your hands gripping the edge of the bench, fingers pointing forward. Step:2 Slide your butt off the bench, supporting your weight with your hands. Step:3 Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever bicep curl', 'lever bicep curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the pad. Step:2 Grasp the handles with an underhand grip, palms facing up, and keep your elbows close to your sides. Step:3 Exhale and curl the handles upward, contracting your biceps. Step:4 Pause for a moment at the top of the movement, squeezing your biceps. Step:5 Inhale and slowly lower the handles back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell over bench one arm neutral wrist curl', 'dumbbell over bench one arm neutral wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in one hand and your arm extended over the bench, palm facing up. Step:2 Keep your upper arm stationary and curl the dumbbell towards your shoulder, keeping your wrist in a neutral position. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:4 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing close grip military press', 'barbell standing close grip military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart. Step:2 Lift the barbell to shoulder height, keeping your elbows close to your body. Step:3 Press the barbell overhead, extending your arms fully. Step:4 Lower the barbell back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell close grip preacher curl', 'ez barbell close grip preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher curl bench and place your upper arms on the pad, gripping the ez barbell with an underhand grip. Step:2 Rest your triceps on the pad and fully extend your arms, keeping your back straight. Step:3 Slowly curl the barbell towards your shoulders, contracting your biceps. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Lower the barbell back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wide-grip chest dip on high parallel bars', 'wide-grip chest dip on high parallel bars', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself on the parallel bars with your arms fully extended and your body suspended in the air. Step:2 Lean forward slightly and lower your body by bending your elbows until your chest is just above the bars. Step:3 Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell close-grip press', 'dumbbell close-grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with a dumbbell in each hand, resting on your thighs. Step:2 Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width. Step:3 Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position. Step:4 As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest. Step:5 As you exhale, use your triceps to lift the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('elbow dips', 'elbow dips', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench or chair with your hands gripping the edge next to your hips. Step:2 Slide your hips forward off the bench and straighten your legs, keeping your heels on the ground. Step:3 Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Step:4 Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline twist fly', 'dumbbell decline twist fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie down on a decline bench with your head lower than your hips. Step:2 Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest. Step:3 Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Step:4 As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement. Step:5 Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('suspended split squat', 'suspended split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing away from a suspension trainer with your feet shoulder-width apart. Step:2 Extend one leg forward and place the top of your foot in the foot cradle of the suspension trainer. Step:3 Bend your standing leg and lower your body down into a lunge position, keeping your chest up and your knee in line with your toes. Step:4 Push through your heel to return to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez-bar close-grip bench press', 'ez-bar close-grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the ez barbell with a close grip, hands shoulder-width apart, palms facing forward. Step:3 Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Step:4 Slowly lower the barbell towards your chest, keeping your elbows close to your body. Step:5 Pause for a moment when the barbell touches your chest. Step:6 Push the barbell back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45в° leg wide press', 'sled 45в° leg wide press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a 45-degree angle. Step:2 Sit on the sled machine with your back against the pad and your feet on the foot platform. Step:3 Position your feet wider than shoulder-width apart. Step:4 Push against the foot platform to extend your legs and straighten your knees. Step:5 Pause for a moment at the end of the movement, then slowly bend your knees to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band standing rear delt row', 'band standing rear delt row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band under your feet. Step:2 Hold the band handles with your palms facing each other and your arms extended in front of you. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Pull the band towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('single leg bridge with outstretched leg', 'single leg bridge with outstretched leg', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the ground. Step:2 Extend one leg straight out in front of you. Step:3 Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders. Step:4 Hold for a moment at the top, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell sumo deadlift', 'barbell sumo deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointing outwards. Step:2 Place a barbell on the ground in front of you, centered between your feet. Step:3 Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip. Step:4 Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously. Step:5 As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes. Step:6 Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('seated calf stretch (male)', 'seated calf stretch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a chair or bench with your feet flat on the ground. Step:2 Extend one leg straight out in front of you, keeping your heel on the ground. Step:3 Lean forward slightly, feeling a stretch in your calf muscle. Step:4 Hold the stretch for 20-30 seconds. Step:5 Switch legs and repeat the stretch.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated bent arm lateral raise', 'dumbbell seated bent arm lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell in each hand with your palms facing your body and your arms bent at a 90-degree angle. Step:3 Keeping your elbows bent, raise your arms out to the sides until they are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band one arm twisting chest press', 'band one arm twisting chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point at chest height. Step:2 Stand with your side facing the anchor point and grab the band with one hand. Step:3 Step away from the anchor point to create tension in the band. Step:4 Position your feet shoulder-width apart and slightly bend your knees. Step:5 Bring your hand holding the band across your body, towards the opposite shoulder. Step:6 While maintaining tension in the band, push your hand forward and away from your body, extending your arm. Step:7 Slowly return to the starting position and repeat for the desired number of repetitions. Step:8 Switch sides and repeat the exercise with the other hand.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted drop push up', 'weighted drop push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Lower your chest towards the ground, keeping your elbows close to your body. Step:3 Once your chest is just above the ground, explosively push yourself up, lifting your hands off the ground. Step:4 As you push up, quickly move your hands out to the sides and slightly forward, allowing your body to drop down towards the ground. Step:5 Catch yourself with your hands in the wider position and immediately lower your chest towards the ground again. Step:6 Repeat the push-up motion, dropping down and catching yourself with your hands in the narrower position. Step:7 Continue alternating between the wider and narrower hand positions for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side-to-side toe touch (male)', 'side-to-side toe touch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms extended to the sides. Step:2 Bend at the waist to the right, reaching your right hand towards your right foot while keeping your left hand extended to the side. Step:3 Return to the starting position and then bend at the waist to the left, reaching your left hand towards your left foot while keeping your right hand extended to the side. Step:4 Repeat the side-to-side bending motion for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell pin presses', 'barbell pin presses', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a barbell on a power rack at chest height. Step:2 Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart. Step:3 Grip the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended. Step:5 Lower the barbell down towards your chest, keeping your elbows tucked in close to your body. Step:6 Pause for a moment when the barbell touches your chest. Step:7 Push the barbell back up to the starting position, fully extending your arms. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lateral to front raise', 'dumbbell lateral to front raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Step:2 Keep your back straight and engage your core. Step:3 Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows. Step:6 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm lateral raise', 'dumbbell incline one arm lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in one hand, resting it on your thigh. Step:2 Lean forward and position your upper arm against the inside of your thigh. Step:3 Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down. Step:4 Continue lifting until your arm is parallel to the floor. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm concentration curl (on stability ball)', 'dumbbell one arm concentration curl (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold a dumbbell in one hand with your palm facing up and your arm extended down towards the floor. Step:3 Rest your elbow on the inside of your thigh, just above the knee. Step:4 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder while contracting your biceps. Step:5 Pause for a moment at the top of the movement, then inhale and slowly lower the dumbbell back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated front raise', 'dumbbell seated front raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs. Step:2 Keep your back straight and core engaged. Step:3 Raise the dumbbells in front of you, with your palms facing down, until they are at shoulder level. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell one arm jerk', 'kettlebell one arm jerk', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height. Step:2 Bend your knees slightly and engage your core. Step:3 Press the kettlebell overhead in a straight line, fully extending your arm. Step:4 As you press the kettlebell overhead, simultaneously dip your knees and quickly straighten them to generate momentum. Step:5 As the kettlebell reaches its highest point, quickly drop underneath it by bending your knees and hips. Step:6 Catch the kettlebell with a slight bend in your knees and hips, and your arm fully extended overhead. Step:7 Stand up straight, fully extending your knees and hips, and stabilize the kettlebell overhead. Step:8 Lower the kettlebell back to the starting position by bending your knees and hips, and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side plank hip adduction', 'side plank hip adduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your side with your legs extended and stacked on top of each other. Step:2 Prop yourself up on your forearm, keeping your elbow directly below your shoulder. Step:3 Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. Step:4 While maintaining the side plank position, lift your top leg towards the ceiling, keeping it straight. Step:5 Slowly lower your leg back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternating seated bicep curl on exercise ball', 'dumbbell alternating seated bicep curl on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder. Step:4 Inhale and slowly lower the dumbbell back to the starting position. Step:5 Repeat the curl with the other arm. Step:6 Continue alternating curls for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable overhead triceps extension (rope attachment)', 'cable overhead triceps extension (rope attachment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a cable machine at a high position. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Grasp the rope with both hands, palms facing each other, and bring your hands above your head. Step:4 Keep your upper arms close to your head and your elbows pointing forward. Step:5 Slowly lower the rope behind your head by bending your elbows. Step:6 Pause for a moment, then extend your arms back up to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pull-up', 'pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your palms facing away from you and your arms fully extended. Step:2 Engage your core and squeeze your shoulder blades together. Step:3 Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar. Step:4 Pause at the top of the movement, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying preacher curl', 'barbell lying preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball back extension with knees off ground', 'exercise ball back extension with knees off ground', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability. Step:2 Position your hands behind your head or crossed over your chest. Step:3 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted lying leg raise with throw down', 'assisted lying leg raise with throw down', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Place your hands under your glutes for support. Step:3 Engage your core and lift your legs off the ground, keeping them straight. Step:4 Raise your legs until they are perpendicular to the ground. Step:5 Lower your legs back down to the starting position. Step:6 Simultaneously, throw your legs down towards the ground, keeping them straight. Step:7 Raise your legs back up to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('seated lower back stretch', 'seated lower back stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a chair with your feet flat on the ground. Step:2 Place your hands on your thighs or on the sides of the chair for support. Step:3 Slowly lean forward from your hips, keeping your back straight. Step:4 Feel the stretch in your lower back and hold for 20-30 seconds. Step:5 Slowly return to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell tricep kickback with stork stance', 'dumbbell tricep kickback with stork stance', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in your right hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Bring your right elbow up to your side, keeping it bent at a 90-degree angle. Step:4 Extend your right arm straight back, squeezing your triceps. Step:5 Pause for a moment, then slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('run', 'run', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing upright with your feet hip-width apart. Step:2 Engage your core and keep your upper body relaxed. Step:3 Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet. Step:4 Maintain a steady pace and continue jogging for the desired duration or distance. Step:5 Remember to breathe deeply and maintain good posture throughout the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('curtsey squat', 'curtsey squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Take a step diagonally behind and across your body with your right foot, crossing it behind your left leg. Step:3 Bend both knees as if you were curtsying, lowering your body towards the ground. Step:4 Keep your torso upright and your weight on your front foot. Step:5 Push through your front foot to return to the starting position. Step:6 Repeat on the other side, stepping diagonally behind and across your body with your left foot.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm straight back high row (kneeling)', 'cable one arm straight back high row (kneeling)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a handle to a cable machine at waist height. Step:2 Kneel down facing the cable machine and grab the handle with one hand. Step:3 Keep your back straight and your core engaged. Step:4 Pull the handle towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top of the movement. Step:6 Slowly release the handle back to the starting position. Step:7 Repeat for the desired number of repetitions. Step:8 Switch sides and repeat the exercise with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable pulldown (pro lat bar)', 'cable pulldown (pro lat bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor. Step:2 Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Sit down and lean back slightly, keeping your chest up and your back straight. Step:4 Pull the bar down towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wind sprints', 'wind sprints', 'Strength', 'Other', 'Intermediate', 'Step:1 Find an open space or a track to perform the exercise. Step:2 Start by standing with your feet shoulder-width apart. Step:3 Begin running as fast as you can, pumping your arms and driving your knees up. Step:4 Continue sprinting for a specific distance or time period. Step:5 Rest and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('raise single arm push-up', 'raise single arm push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Extend one arm straight out to the side, parallel to the ground. Step:3 Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged. Step:4 Push back up to the starting position, using your chest muscles to lift your body. Step:5 Repeat with the other arm extended.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted muscle up (on bar)', 'weighted muscle up (on bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart. Step:2 Engage your core and pull your shoulder blades down and back. Step:3 Bend your elbows and pull your chest towards the bar, keeping your body straight. Step:4 Once your chest reaches the bar, push down with your hands and drive your elbows back, lifting your body above the bar. Step:5 Pause at the top of the movement, then slowly lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('muscle up', 'muscle up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended. Step:2 Engage your core and pull your body up towards the bar, leading with your chest. Step:3 As you reach the top of the movement, transition your grip so that your palms are facing towards you. Step:4 Continue pulling yourself up until your chest is above the bar and your arms are fully flexed. Step:5 Reverse the movement by slowly lowering yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable twist (up-down)', 'cable twist (up-down)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the cable machine. Step:2 Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent. Step:3 Engage your core and slowly rotate your torso to one side, keeping your hips and legs stable. Step:4 Pause for a moment at the end of the rotation, then slowly return to the starting position. Step:5 Repeat the rotation to the opposite side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated leg curl', 'lever seated leg curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to fit your body and sit on it with your back against the backrest. Step:2 Place your lower legs under the padded lever, just above your ankles. Step:3 Grasp the handles on the sides of the machine for support. Step:4 Keeping your upper legs stationary, exhale and curl your legs up as far as possible. Step:5 Hold the contracted position for a brief pause as you squeeze your hamstrings. Step:6 Inhale and slowly lower the lever back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up (wall) v. 2', 'push-up (wall) v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall, about arm''s length away. Step:2 Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart. Step:3 Step back with your feet, keeping them hip-width apart. Step:4 Engage your core and keep your body in a straight line from head to heels. Step:5 Bend your elbows and lower your chest towards the wall, keeping your body straight. Step:6 Pause for a moment, then push yourself back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band one arm standing low row', 'band one arm standing low row', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a stable anchor point at waist height. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Hold the band with one hand, palm facing inward, and step back to create tension in the band. Step:4 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:5 Pull the band towards your waist, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly release the band back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band hip lift', 'band hip lift', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the ground. Step:2 Place a resistance band just above your knees. Step:3 Engage your glutes and core muscles. Step:4 Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top. Step:5 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable kneeling crunch', 'cable kneeling crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a high pulley and kneel down facing away from the machine. Step:2 Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides. Step:3 Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs. Step:4 Pause for a moment at the bottom, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever gripper hands', 'lever gripper hands', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and grip the handles of the leverage machine. Step:2 Keep your back straight and your feet flat on the ground. Step:3 Exhale and squeeze the handles, contracting your forearms. Step:4 Hold the contraction for a second, then slowly release and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever shoulder press v. 2', 'lever shoulder press v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and backrest of the leverage machine to a comfortable position. Step:2 Sit on the machine with your back against the backrest and your feet flat on the floor. Step:3 Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart. Step:4 Push the handles upward and forward until your arms are fully extended, but not locked. Step:5 Pause for a moment at the top, then slowly lower the handles back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kneeling push-up (male)', 'kneeling push-up (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the ground with your hands shoulder-width apart, fingers pointing forward. Step:2 Extend your legs behind you, resting on the balls of your feet, so that your body forms a straight line from head to heels. Step:3 Engage your core and lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:4 Continue lowering until your chest is just above the ground, then push back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline hammer press on exercise ball', 'dumbbell incline hammer press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in each hand, palms facing each other. Step:2 Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides. Step:4 Press the dumbbells up and slightly inward, keeping your palms facing each other. Step:5 Extend your arms fully, squeezing your triceps at the top of the movement. Step:6 Slowly lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('isometric chest squeeze', 'isometric chest squeeze', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Extend your arms straight out in front of you, parallel to the ground, with your palms facing each other. Step:3 Squeeze your chest muscles together as hard as you can, while keeping your arms straight. Step:4 Hold this position for a few seconds, focusing on contracting your chest muscles. Step:5 Release the squeeze and relax your chest muscles. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band hip thrusts on knees (female)', 'resistance band hip thrusts on knees (female)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the ground with your knees hip-width apart and your feet flexed. Step:2 Wrap the resistance band around your thighs, just above your knees. Step:3 Place your hands on your hips or extend them out in front of you for balance. Step:4 Engage your glutes and core muscles. Step:5 Push your hips forward and squeeze your glutes as you lift your knees off the ground, extending your hips until your thighs are parallel to the ground. Step:6 Hold the position for a moment, then slowly lower your knees back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse grip incline bench press', 'barbell reverse grip incline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Lie down on the bench with your feet flat on the ground. Step:3 Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Step:5 Pause for a moment when the barbell touches your chest. Step:6 Push the barbell back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse fly', 'dumbbell reverse fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Extend your arms straight down in front of you, palms facing each other. Step:4 Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground. Step:5 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable straight arm pulldown', 'cable straight arm pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to the high pulley of a cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down. Step:4 Engage your lats and pull the bar down towards your thighs, keeping your arms straight throughout the movement. Step:5 Pause for a moment at the bottom, then slowly return the bar to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing pelvic tilt', 'standing pelvic tilt', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Place your hands on your hips or let them hang by your sides. Step:3 Engage your core muscles and tilt your pelvis forward, pushing your lower back towards the wall behind you. Step:4 Hold the position for a few seconds, then release and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable shrug', 'cable shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Grasp the cable handles with an overhand grip and let your arms hang down in front of you. Step:3 Keeping your arms straight, shrug your shoulders up towards your ears. Step:4 Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell floor calf raise', 'barbell floor calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Place a barbell on the floor in front of you. Step:2 Stand with the balls of your feet on the edge of the barbell, with your heels hanging off. Step:3 Hold onto a stable object for balance if needed. Step:4 Raise your heels as high as possible, using your calves to lift your body. Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted donkey calf raise', 'weighted donkey calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand on a raised platform with your toes on the edge and your heels hanging off. Step:2 Hold onto a stable object for support. Step:3 Raise your heels as high as possible by extending your ankles. Step:4 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lying (side) quads stretch', 'lying (side) quads stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs straight. Step:2 Bend your top leg and grab your ankle or foot with your hand. Step:3 Gently pull your ankle or foot towards your glutes until you feel a stretch in your quads. Step:4 Hold the stretch for 20-30 seconds. Step:5 Release the stretch and repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted side lying adductor stretch', 'assisted side lying adductor stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs straight and stacked on top of each other. Step:2 Bend your bottom leg slightly for stability. Step:3 Place your top foot on a stable surface, such as a bench or step. Step:4 Keeping your top leg straight, slowly lower it towards the ground, feeling a stretch in your inner thigh. Step:5 Hold the stretch for 20-30 seconds. Step:6 Return to the starting position and repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band two legs calf raise - (band under both legs) v. 2', 'band two legs calf raise - (band under both legs) v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place a resistance band under both feet. Step:2 Hold the ends of the band with your hands for stability. Step:3 Raise your heels off the ground as high as possible, using your calves. Step:4 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('short stride run', 'short stride run', 'Strength', 'Other', 'Intermediate', 'Step:1 Find an open space or a treadmill to perform the exercise. Step:2 Stand tall with your feet hip-width apart. Step:3 Start jogging in place, lifting your knees high and pumping your arms. Step:4 After a few seconds, start taking short strides forward, maintaining a quick pace. Step:5 Continue running with short strides for the desired duration or distance.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell alternating row', 'kettlebell alternating row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body. Step:2 Bend forward at the hips, keeping your back straight and your core engaged. Step:3 Pull one kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Step:4 Lower the kettlebell back down to the starting position and repeat with the other arm. Step:5 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triceps stretch', 'triceps stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand or sit upright with your back straight. Step:2 Extend one arm overhead, bending it at the elbow. Step:3 Place your opposite hand on the bent elbow and gently pull it towards your head. Step:4 Hold the stretch for 15-30 seconds, feeling a gentle stretch in your triceps. Step:5 Release the stretch and repeat on the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band close-grip pulldown', 'band close-grip pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a high anchor point, such as a pull-up bar or sturdy beam. Step:2 Stand facing the anchor point and grab the band with an underhand grip, hands shoulder-width apart. Step:3 Step back to create tension in the band, keeping your feet hip-width apart. Step:4 Engage your core and keep your back straight as you pull the band down towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the bottom of the movement, then slowly release the band back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('squat to overhead reach with twist', 'squat to overhead reach with twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and toes slightly turned out. Step:2 Lower your body into a squat position by bending your knees and pushing your hips back. Step:3 As you come up from the squat, raise your arms overhead and twist your torso to one side. Step:4 Return to the starting position and repeat the squat, this time twisting your torso to the opposite side. Step:5 Continue alternating sides with each squat repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever gripless shrug v. 2', 'lever gripless shrug v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the pad. Step:2 Grasp the handles or bars with an overhand grip, keeping your arms straight. Step:3 Keeping your back straight, lift your shoulders up towards your ears as high as possible. Step:4 Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith bent over row', 'smith bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the bar at hip height. Step:2 Stand facing the bar with your feet shoulder-width apart. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:5 Pull the bar towards your lower chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower the bar back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell plyo push-up', 'kettlebell plyo push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands on the kettlebells, shoulder-width apart. Step:2 Lower your chest towards the ground, keeping your elbows close to your body. Step:3 Push through your hands explosively, lifting your hands off the kettlebells and extending your arms fully. Step:4 Land softly back on the kettlebells and immediately lower your chest back down for the next repetition. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated alternate press', 'dumbbell seated alternate press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, palms facing forward. Step:2 Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward. Step:3 Press one dumbbell up overhead, fully extending your arm. Step:4 Lower the dumbbell back down to shoulder height. Step:5 Repeat with the other arm. Step:6 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying extension (across face)', 'dumbbell lying extension (across face)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other. Step:3 Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground. Step:4 Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith single leg split squat', 'smith single leg split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of the smith machine with your feet shoulder-width apart. Step:2 Place one foot behind you on a bench or step, with your toes pointing forward. Step:3 Hold onto the smith machine bar for stability. Step:4 Bend your front knee and lower your body down into a lunge position, keeping your back straight. Step:5 Pause for a moment at the bottom, then push through your front heel to return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kneeling jump squat', 'kneeling jump squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the ground with your feet hip-width apart and your toes pointing forward. Step:2 Hold a barbell across your upper back, resting it on your shoulders. Step:3 Engage your core and glutes, then explosively jump up into the air, extending your hips and knees. Step:4 As you jump, push through your toes and fully extend your ankles, knees, and hips. Step:5 Land softly back on the ground, bending your knees to absorb the impact. Step:6 Immediately go into the next repetition, repeating the jump squat motion.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('scapula dips', 'scapula dips', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and your arms extended in front of you. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Lower your body by bending your elbows and retracting your shoulder blades, as if you are trying to squeeze a pencil between them. Step:4 Pause for a moment at the bottom, then push through your hands to extend your elbows and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable front shoulder raise', 'cable front shoulder raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip. Step:2 Keep your back straight and your core engaged. Step:3 Raise the cable handle in front of you, keeping your arms straight and your palms facing down. Step:4 Continue lifting until your arms are parallel to the floor. Step:5 Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hack one leg calf raise', 'hack one leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to an appropriate weight. Step:2 Stand on the sled machine with one foot, keeping the other foot off the ground. Step:3 Hold onto the handles for stability. Step:4 Raise your heel as high as possible, lifting your body up on the ball of your foot. Step:5 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:6 Repeat for the desired number of repetitions. Step:7 Switch legs and repeat the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline inner biceps curl', 'dumbbell incline inner biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, palms facing each other. Step:2 Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm reverse spider curl', 'dumbbell one arm reverse spider curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in one hand, palm facing down and arm fully extended. Step:2 Keeping your upper arm stationary, curl the dumbbell towards your shoulder by flexing your elbow. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:4 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell palms down wrist curl over a bench', 'barbell palms down wrist curl over a bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down. Step:2 Hold a barbell with an overhand grip, hands shoulder-width apart. Step:3 Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary. Step:4 Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight standing one arm row', 'bodyweight standing one arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand. Step:2 Bend forward at the hips, keeping your back straight and your core engaged. Step:3 Let the dumbbell hang straight down in front of you, with your arm fully extended. Step:4 Pull the dumbbell up towards your chest, keeping your elbow close to your body. Step:5 Squeeze your shoulder blades together at the top of the movement. Step:6 Lower the dumbbell back down to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one arm towel row', 'one arm towel row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand. Step:2 Bend forward at the waist, keeping your back straight and your core engaged. Step:3 Extend your arm fully, allowing the towel to hang in front of you. Step:4 Pull the towel towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the towel back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ski step', 'ski step', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees slightly and keep your back straight. Step:3 Jump to the right, landing on your right foot while swinging your left leg behind your right leg. Step:4 Immediately jump to the left, landing on your left foot while swinging your right leg behind your left leg. Step:5 Continue alternating jumps from side to side, mimicking a skiing motion. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chair leg extended stretch', 'chair leg extended stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a chair with your back straight and feet flat on the ground. Step:2 Extend one leg straight out in front of you, keeping your heel on the ground. Step:3 Lean forward slightly, feeling a stretch in your quadriceps. Step:4 Hold this position for 20-30 seconds. Step:5 Switch legs and repeat the stretch.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('single arm push-up', 'single arm push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and one hand placed slightly wider than the other. Step:2 Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight. Step:3 As you lower yourself, shift your weight to one side and lift the opposite arm off the ground, extending it straight out to the side. Step:4 Push through your chest and triceps to raise your body back up to the starting position, while simultaneously lowering your extended arm back to the ground. Step:5 Repeat the movement, alternating the arm you extend with each repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell decline wide-grip press', 'barbell decline wide-grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your feet secured and your head lower than your hips. Step:2 Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Step:3 Lower the barbell to your chest, keeping your elbows out to the sides. Step:4 Push the barbell back up to the starting position, fully extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band one arm overhead biceps curl', 'band one arm overhead biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place one end of the band under your foot. Step:2 Hold the other end of the band with your arm fully extended overhead, palm facing forward. Step:3 Keeping your upper arm stationary, curl your forearm towards your shoulder, squeezing your biceps. Step:4 Pause for a moment at the top, then slowly lower your forearm back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable overhead curl', 'cable overhead curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a high pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an underhand grip, hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary. Step:5 Exhale and curl the bar down towards your forehead, keeping your upper arms stationary. Step:6 Pause for a moment at the bottom of the movement, squeezing your biceps. Step:7 Inhale and slowly return the bar to the starting position, fully extending your arms. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying one arm deltoid rear', 'dumbbell lying one arm deltoid rear', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards. Step:2 Extend your arm straight down towards the floor, keeping it close to your body. Step:3 Raise your arm up and back, squeezing your shoulder blade towards your spine. Step:4 Pause for a moment at the top, then slowly lower your arm back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable pulldown bicep curl', 'cable pulldown bicep curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to the cable machine at the highest setting. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an underhand grip, hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary. Step:5 Exhale and slowly curl the bar down towards your thighs, keeping your wrists straight. Step:6 Pause for a moment at the bottom of the movement, squeezing your biceps. Step:7 Inhale and slowly return the bar to the starting position, fully extending your arms. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable side bend', 'cable side bend', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and grasp the cable handle with one hand. Step:2 Keep your back straight and your core engaged. Step:3 Slowly bend sideways at the waist, lowering the cable handle towards your knee. Step:4 Pause for a moment, then return to the starting position. Step:5 Repeat on the other side. Step:6 Alternate sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever reverse grip preacher curl', 'lever reverse grip preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the leverage machine. Step:2 Grasp the handles with an underhand grip, palms facing up. Step:3 Rest your upper arms on the preacher pad, ensuring your elbows are fully extended. Step:4 Keeping your upper arms stationary, exhale and curl the handles towards your shoulders. Step:5 Pause for a moment at the top of the movement, squeezing your biceps. Step:6 Inhale and slowly lower the handles back to the starting position, fully extending your elbows. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell seesaw press', 'kettlebell seesaw press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Step:2 Press one kettlebell overhead while keeping the other kettlebell at shoulder height. Step:3 Lower the pressed kettlebell back to shoulder height while simultaneously pressing the other kettlebell overhead. Step:4 Continue alternating the pressing motion, creating a seesaw-like movement. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell one arm floor press', 'barbell one arm floor press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back on the floor with your knees bent and feet flat on the ground. Step:2 Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest. Step:3 Slowly lower the barbell towards your chest, keeping your elbow close to your body. Step:4 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm standing curl', 'dumbbell one arm standing curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in one hand, palm facing forward and arm fully extended. Step:2 Keeping your upper arm stationary, exhale and curl the weight upward while contracting your biceps. Step:3 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller body saw', 'roller body saw', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a plank position with your forearms on the roller and your body in a straight line. Step:2 Engage your core and slowly roll the roller forward, extending your body as far as you can while maintaining control. Step:3 Pause for a moment at the furthest point, then slowly roll the roller back towards your starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm reverse preacher curl', 'cable one arm reverse preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the pulley is at the lowest position. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Grasp the cable handle with an underhand grip and position your upper arm against the preacher bench pad. Step:4 Keep your back straight and your core engaged throughout the exercise. Step:5 Slowly curl your forearm towards your bicep, keeping your upper arm stationary against the pad. Step:6 Pause for a moment at the top of the movement, squeezing your bicep. Step:7 Slowly lower the cable handle back to the starting position. Step:8 Repeat for the desired number of repetitions. Step:9 Switch arms and repeat the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('jackknife sit-up', 'jackknife sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms overhead. Step:2 Engage your core and lift your legs and upper body simultaneously, reaching your hands towards your toes. Step:3 Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45в° leg press (back pov)', 'sled 45в° leg press (back pov)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the sled machine so that your knees are at a 45-degree angle. Step:2 Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate. Step:3 Grip the handles on the sides of the seat for stability. Step:4 Push the footplate away from your body by extending your legs, keeping your heels on the footplate. Step:5 Pause for a moment at the fully extended position. Step:6 Slowly bend your knees and lower the footplate back towards your body, controlling the movement. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell jump squat', 'barbell jump squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Step:2 Lower your body into a squat position by bending your knees and pushing your hips back. Step:3 Once you reach the bottom of the squat, explode upwards by jumping off the ground. Step:4 As you jump, extend your hips, knees, and ankles, pushing through your toes. Step:5 Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted tricep dips', 'weighted tricep dips', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench or chair with your hands gripping the edge next to your hips. Step:2 Slide your butt off the front of the bench with your legs extended in front of you. Step:3 Keep your back close to the bench and your elbows slightly bent. Step:4 Lower your body by bending your elbows until your upper arms are parallel to the floor. Step:5 Push yourself back up to the starting position by straightening your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse-grip pushdown', 'cable reverse-grip pushdown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a high pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Using your triceps, push the bar down until your arms are fully extended and your triceps are contracted. Step:6 Pause for a moment, then slowly return the bar to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band seated biceps curl', 'resistance band seated biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a chair or bench with your back straight and feet flat on the ground. Step:2 Hold the resistance band with an underhand grip, palms facing up, and arms extended down by your sides. Step:3 Keeping your upper arms stationary, exhale and curl the resistance band up towards your shoulders. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the resistance band back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing ab rollerout', 'barbell standing ab rollerout', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs. Step:2 Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended. Step:3 Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head. Step:4 Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell bench press', 'dumbbell bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest. Step:3 Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Step:4 Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying one arm press v. 2', 'dumbbell lying one arm press v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your back supported and feet flat on the ground. Step:2 Hold a dumbbell in one hand with your palm facing towards your feet. Step:3 Extend your arm straight up towards the ceiling, keeping your elbow slightly bent. Step:4 Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body. Step:5 Pause for a moment at the bottom, then push the dumbbell back up to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying rear delt row', 'dumbbell lying rear delt row', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards. Step:2 Extend your arms straight down towards the floor, keeping a slight bend in your elbows. Step:3 Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable decline one arm press', 'cable decline one arm press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a decline position. Step:2 Stand facing away from the machine and grab the handle with one hand. Step:3 Position yourself with your back against the decline bench and your arm extended straight in front of you. Step:4 Bend your elbow and lower the handle towards your chest while keeping your upper arm stationary. Step:5 Pause for a moment at the bottom, then push the handle back up to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever one arm bent over row', 'lever one arm bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with an overhand grip. Step:2 Bend forward at the hips, keeping your back straight and your head up. Step:3 Let the barbell hang in front of you with your arms fully extended. Step:4 Pull the barbell up towards your chest, keeping your elbows close to your body. Step:5 Squeeze your shoulder blades together at the top of the movement. Step:6 Lower the barbell back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated bicep curl', 'dumbbell seated bicep curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Step:2 Keep your back straight and your elbows close to your torso. Step:3 Exhale and curl the dumbbells up towards your shoulders, contracting your biceps. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse-grip straight back seated high row', 'cable reverse-grip straight back seated high row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the seat facing the cable machine with your feet flat on the floor. Step:2 Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart. Step:3 Keep your back straight and lean slightly forward from your hips. Step:4 Pull the cable towards your torso by retracting your shoulder blades and squeezing your back muscles. Step:5 Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever incline chest press v. 2', 'lever incline chest press v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and backrest angle on the leverage machine to a comfortable position. Step:2 Sit on the machine with your back against the backrest and your feet flat on the floor. Step:3 Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Step:4 Push the handles forward and away from your body until your arms are fully extended, but without locking your elbows. Step:5 Pause for a moment at the fully extended position, then slowly bend your elbows and lower the handles back towards your chest. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline close-grip push-up', 'incline close-grip push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart. Step:2 Extend your legs behind you, resting on the balls of your feet, with your body forming a straight line from head to heels. Step:3 Lower your chest towards the elevated surface by bending your elbows, keeping them close to your sides. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline shrug', 'dumbbell decline shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a decline bench at a 45-degree angle. Step:2 Lie face down on the bench with your chest and stomach resting against it. Step:3 Hold a dumbbell in each hand with your arms fully extended towards the floor. Step:4 Keeping your arms straight, raise your shoulders towards your ears as high as possible. Step:5 Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lunge', 'barbell lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and a barbell resting on your upper back. Step:2 Take a step forward with your right foot, keeping your torso upright. Step:3 Lower your body by bending your right knee until your thigh is parallel to the ground. Step:4 Push through your right heel to return to the starting position. Step:5 Repeat with your left leg, alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable cross-over revers fly', 'cable cross-over revers fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a D-handle to each low pulley cable and stand in the middle of the cable crossover machine. Step:2 Grasp the handles with a pronated grip (palms facing down) and take a step forward, positioning your feet shoulder-width apart. Step:3 Bend your knees slightly and lean forward at the waist, keeping your back straight and your abs engaged. Step:4 With your arms extended out to the sides and slightly bent at the elbows, exhale and squeeze your shoulder blades together as you pull the cables back and upward in a reverse fly motion. Step:5 Pause for a moment at the peak contraction, then inhale and slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing bradford press', 'barbell standing bradford press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip. Step:2 Press the barbell overhead, fully extending your arms. Step:3 Lower the barbell back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell thruster', 'barbell thruster', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip. Step:2 Lower into a squat position by bending your knees and pushing your hips back. Step:3 As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead. Step:4 Lower the barbell back to shoulder height as you lower back into the squat position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell supported squat', 'dumbbell supported squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Step:2 Keeping your chest up and core engaged, slowly lower your body down by bending your knees and pushing your hips back. Step:3 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated bench extension', 'dumbbell seated bench extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell with both hands and extend your arms straight up above your head. Step:3 Slowly lower the dumbbell behind your head, keeping your elbows close to your ears. Step:4 Pause for a moment, then raise the dumbbell back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell overhead squat', 'barbell overhead squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and toes slightly turned out. Step:2 Hold the barbell with a wide grip, positioning it overhead with your arms fully extended. Step:3 Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse grip decline bench press', 'barbell reverse grip decline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your feet secured and your head lower than your hips. Step:2 Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart. Step:3 Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Step:4 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted overhead crunch (on stability ball)', 'weighted overhead crunch (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold a weight plate or dumbbell with both hands and extend your arms overhead. Step:3 Engage your abs and slowly curl your torso forward, bringing your chest towards your knees. Step:4 Pause for a moment at the top, then slowly lower your torso back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing reverse grip one arm overhead tricep extension', 'cable standing reverse grip one arm overhead tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing away from the cable machine with your feet shoulder-width apart. Step:2 Hold the cable handle with an underhand grip and extend your arm overhead, keeping your elbow close to your head. Step:3 Keep your upper arm stationary and slowly lower the cable handle behind your head by bending your elbow. Step:4 Pause for a moment at the bottom, then extend your arm back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell front chest squat', 'barbell front chest squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward. Step:3 Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Step:4 Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball one leg prone lower body rotation', 'exercise ball one leg prone lower body rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the stability ball with your hips resting on the ball and your legs extended straight behind you. Step:2 Place your hands on the ground in front of you for support. Step:3 Engage your glutes and core muscles to stabilize your body. Step:4 Slowly lift one leg off the ground, keeping it straight and parallel to the floor. Step:5 Rotate your leg outward, away from your body, while keeping your hips and upper body stable. Step:6 Pause for a moment at the end of the rotation, then slowly return your leg to the starting position. Step:7 Repeat the rotation with the other leg. Step:8 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever deadlift', 'lever deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and foot platform to your desired position. Step:2 Sit on the machine with your back against the pad and your feet flat on the foot platform. Step:3 Grasp the handles or the sides of the seat for stability. Step:4 Engage your glutes and hamstrings, and push through your heels to lift the weight up. Step:5 Keep your back straight and avoid rounding your shoulders. Step:6 Extend your hips fully at the top of the movement, squeezing your glutes. Step:7 Lower the weight back down in a controlled manner, keeping tension on your glutes and hamstrings. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball lower back stretch (pyramid)', 'exercise ball lower back stretch (pyramid)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Slowly walk your feet forward, rolling the ball down your back until your lower back is resting on the ball. Step:3 Place your hands behind your head or cross them over your chest. Step:4 Engage your core and slowly lower your upper body towards the ground, allowing your lower back to stretch over the ball. Step:5 Hold the stretch for a few seconds, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable assisted inverse leg curl', 'cable assisted inverse leg curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the ankle attachment is at the lowest setting. Step:2 Lie face down on the bench with your legs straight and the ankle attachment secured to your ankles. Step:3 Hold onto the handles of the bench for stability. Step:4 Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees. Step:5 Pause for a moment at the top of the movement, squeezing your hamstrings. Step:6 Inhale and slowly lower your legs back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest stretch with exercise ball', 'chest stretch with exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your back straight. Step:2 Hold the exercise ball with both hands and extend your arms straight out in front of you. Step:3 Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles. Step:4 Hold the stretch for a few seconds, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('narrow push-up on exercise ball', 'narrow push-up on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and position yourself in a push-up position with your hands on the ball, slightly narrower than shoulder-width apart. Step:2 Engage your core and keep your body in a straight line from head to toe. Step:3 Lower your chest towards the ball by bending your elbows, keeping them close to your body. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell split squat v. 2', 'barbell split squat v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Step:2 Take a large step forward with your right foot, keeping your torso upright. Step:3 Lower your body by bending your knees and hips until your right thigh is parallel to the ground. Step:4 Pause for a moment, then push through your right heel to return to the starting position. Step:5 Repeat with your left leg forward for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing wheel rollerout', 'standing wheel rollerout', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing tall with your feet shoulder-width apart and the wheel roller in front of you. Step:2 Bend at your waist and slowly roll the wheel forward, keeping your back straight and your core engaged. Step:3 Continue rolling forward until you feel a stretch in your abs and your body is extended as far as possible. Step:4 Pause for a moment, then slowly roll the wheel back towards your body, returning to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('plyo push up', 'plyo push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart. Step:2 Lower your chest towards the ground by bending your elbows, keeping your body in a straight line. Step:3 Push explosively off the ground, using your chest muscles to propel your upper body off the ground. Step:4 Land softly with your hands back in the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('run (equipment)', 'run (equipment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing upright with your feet hip-width apart. Step:2 Engage your core and keep your upper body relaxed. Step:3 Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet. Step:4 Maintain a steady pace and continue jogging for the desired duration or distance. Step:5 Remember to breathe deeply and maintain good posture throughout the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('stalder press', 'stalder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and your arms extended overhead. Step:2 Bend your knees slightly and engage your core. Step:3 Lower your body down into a squat position while keeping your arms extended overhead. Step:4 As you squat down, press your arms down towards the ground, engaging your triceps. Step:5 Pause for a moment at the bottom of the squat, then push through your heels to stand back up while simultaneously raising your arms back overhead. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing biceps curl', 'dumbbell standing biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band bicycle crunch', 'band bicycle crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your hands behind your head and your knees bent. Step:2 Lift your feet off the ground and bring your right knee towards your chest while simultaneously twisting your torso to bring your left elbow towards your right knee. Step:3 Straighten your right leg while bringing your left knee towards your chest and twisting your torso to bring your right elbow towards your left knee. Step:4 Continue alternating the twisting motion, as if you are pedaling a bicycle, while keeping your core engaged throughout the movement. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell low bar squat', 'barbell low bar squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and the barbell resting on your upper back. Step:2 Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back. Step:3 Continue lowering until your thighs are parallel to the ground or slightly below. Step:4 Pause for a moment, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable palm rotational row', 'cable palm rotational row', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a handle to a cable machine at waist height. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the handle with an overhand grip, palms facing down. Step:4 Step back to create tension on the cable, keeping your back straight and knees slightly bent. Step:5 Pull the handle towards your body, rotating your palms to face upwards as you do so. Step:6 Squeeze your shoulder blades together at the end of the movement. Step:7 Slowly release the handle back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing pulldown (with rope)', 'cable standing pulldown (with rope)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to the cable machine at the highest setting. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the rope with an overhand grip, palms facing down. Step:4 Keep your back straight and core engaged throughout the exercise. Step:5 Pull the rope down towards your thighs, squeezing your biceps. Step:6 Pause for a moment at the bottom, then slowly release the rope back up. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band squat', 'band squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, with the band placed just above your knees. Step:2 Keeping your chest up and core engaged, push your hips back and bend your knees to lower into a squat position. Step:3 Make sure your knees are tracking over your toes and your weight is in your heels. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('potty squat', 'potty squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing slightly outward. Step:2 Lower your body down by bending your knees and pushing your hips back as if you were sitting on a chair. Step:3 Keep your chest up and your back straight throughout the movement. Step:4 Lower yourself until your thighs are parallel to the ground or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell wide reverse grip bench press', 'barbell wide reverse grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart. Step:3 Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Step:4 Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight. Step:5 Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm fly on exercise ball', 'dumbbell one arm fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground. Step:2 Walk your feet forward and roll your body down until your upper back is resting on the exercise ball. Step:3 Extend your arm with the dumbbell straight up above your chest, palm facing inwards. Step:4 Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Step:5 Pause for a moment, then squeeze your chest muscles to bring the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline row', 'dumbbell incline row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Grab a dumbbell in each hand and sit on the bench with your chest against the incline. Step:3 Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders. Step:4 Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing one arm curl (over incline bench)', 'dumbbell standing one arm curl (over incline bench)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing forward. Step:2 Place your other hand on an incline bench for support. Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lying elbow to knee', 'lying elbow to knee', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee. Step:4 At the same time, extend your right leg straight out and lift it off the ground. Step:5 Pause for a moment, then return to the starting position. Step:6 Repeat the movement, this time bringing your left elbow towards your right knee and extending your left leg. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable upright row', 'cable upright row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold the cable attachment with an overhand grip. Step:2 Keep your back straight and your core engaged throughout the exercise. Step:3 Pull the cable attachment straight up towards your chin, leading with your elbows. Step:4 Pause for a moment at the top, squeezing your shoulder blades together. Step:5 Slowly lower the cable attachment back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('intermediate hip flexor and quad stretch', 'intermediate hip flexor and quad stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand upright with your feet shoulder-width apart. Step:2 Hold onto a stable object for support. Step:3 Bend your right knee and bring your right foot towards your glutes, grabbing the rope with your right hand. Step:4 Slowly pull your right foot towards your glutes, feeling a stretch in your right quad. Step:5 Hold the stretch for 20-30 seconds. Step:6 Release the stretch and repeat on the left side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest dip', 'chest dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself on parallel bars with your arms fully extended and your body straight. Step:2 Lower your body by bending your elbows until your shoulders are below your elbows. Step:3 Push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith chair squat', 'smith chair squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the height of the smith machine bar to a comfortable position. Step:2 Stand with your feet shoulder-width apart, toes slightly turned out. Step:3 Place the barbell across your upper back, resting it on your traps. Step:4 Engage your core and keep your chest up as you slowly lower your body by bending your knees and hips. Step:5 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:6 Pause for a moment, then push through your heels to return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one arm chin-up', 'one arm chin-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a pull-up bar with your feet shoulder-width apart. Step:2 Reach up and grab the bar with an underhand grip, with one hand gripping the bar and the other hand holding your wrist for support. Step:3 Hang from the bar with your arm fully extended, keeping your body straight and your core engaged. Step:4 Pull yourself up towards the bar by bending your elbow and squeezing your back muscles. Step:5 Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever hammer grip preacher curl', 'lever hammer grip preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the leverage machine. Step:2 Place your upper arms on the preacher pad, ensuring your chest is pressed against it. Step:3 Grasp the handles with a hammer grip (palms facing each other). Step:4 Keeping your upper arms stationary, exhale and curl the handles towards your shoulders. Step:5 Pause for a moment at the top, squeezing your biceps. Step:6 Inhale and slowly lower the handles back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing alternate overhead press', 'dumbbell standing alternate overhead press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward. Step:2 Press one dumbbell overhead, fully extending your arm. Step:3 Lower the dumbbell back to shoulder level. Step:4 Repeat with the other arm. Step:5 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('overhead triceps stretch', 'overhead triceps stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand or sit upright with your feet shoulder-width apart. Step:2 Extend one arm overhead, bending at the elbow so that your hand reaches towards the opposite shoulder blade. Step:3 With your other hand, gently pull the elbow of the extended arm towards the opposite side of your head, feeling a stretch in your triceps. Step:4 Hold the stretch for 15-30 seconds, then release. Step:5 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted muscle up', 'weighted muscle up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart. Step:2 Engage your core and pull your body up towards the bar, leading with your chest. Step:3 As you reach the top of the movement, transition your grip so that your palms are facing towards you. Step:4 Continue pulling yourself up until your chest reaches the bar, then pause for a moment. Step:5 Slowly lower yourself back down to the starting position, maintaining control throughout the movement. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever calf press', 'lever calf press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the leverage machine so that your shoulders are aligned with the lever pad. Step:2 Place your toes on the lever pad, with your heels hanging off the edge. Step:3 Grasp the handles or side supports for stability. Step:4 Push the lever pad down by extending your ankles, contracting your calf muscles. Step:5 Pause for a moment at the bottom of the movement. Step:6 Slowly return to the starting position by allowing your heels to rise back up. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternate biceps curl (with arm blaster)', 'dumbbell alternate biceps curl (with arm blaster)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Step:2 Place the arm blaster on your upper arms, ensuring a secure fit. Step:3 Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while contracting your biceps. Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly lower the dumbbell back to the starting position. Step:7 Repeat the movement with the opposite arm. Step:8 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted svend press', 'weighted svend press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a weight plate in front of your chest with both hands. Step:2 Keep your elbows slightly bent and your palms facing each other. Step:3 Press the weight plate straight out in front of you, fully extending your arms. Step:4 Pause for a moment at the end of the movement, then slowly bring the weight plate back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell squat jump step rear lunge', 'barbell squat jump step rear lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, holding a barbell across your upper back. Step:2 Lower your body into a squat position by bending your knees and pushing your hips back. Step:3 Explode upwards, jumping off the ground as high as you can. Step:4 Land softly on your feet and immediately step back with one leg into a reverse lunge. Step:5 Lower your body down until your front thigh is parallel to the ground, keeping your back straight. Step:6 Push through your front heel to return to the starting position. Step:7 Repeat the jump and lunge sequence on the other leg. Step:8 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('close-grip push-up (on knees)', 'close-grip push-up (on knees)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by getting on your hands and knees, with your hands shoulder-width apart and your knees hip-width apart. Step:2 Lower your upper body towards the ground by bending your elbows, keeping them close to your sides. Step:3 Pause for a moment when your chest is just above the ground. Step:4 Push through your palms to straighten your arms and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse crunch', 'cable reverse crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable to a low pulley and lie down facing up on a mat. Step:2 Hold the cable with both hands and extend your arms straight up towards the ceiling. Step:3 Bend your knees and lift your legs up, bringing your thighs towards your chest. Step:4 While keeping your upper body stable, curl your pelvis up towards your chest, lifting your hips off the mat. Step:5 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell one leg squat', 'barbell one leg squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell across your upper back. Step:2 Lift one foot off the ground and extend it forward, keeping it parallel to the ground. Step:3 Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight. Step:4 Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm seated neutral wrist curl', 'dumbbell one arm seated neutral wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up. Step:2 Rest your forearm on your thigh, allowing your wrist to hang off the edge. Step:3 Keeping your forearm stationary, curl your wrist upward as far as possible. Step:4 Pause for a moment at the top, then slowly lower your wrist back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other hand.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable pushdown', 'cable pushdown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a high pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Step:3 Grasp the bar with an overhand grip, hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary. Step:5 Exhale and push the bar down until your elbows are fully extended. Step:6 Pause for a moment, then inhale and slowly return the bar to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lean planche', 'lean planche', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and your body straight. Step:2 Engage your core and slowly shift your weight forward, bringing your shoulders past your hands. Step:3 Keep your elbows slightly bent and your body straight as you lean forward. Step:4 Hold this position for a few seconds, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell windmill', 'kettlebell windmill', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in your right hand overhead. Step:2 Rotate your left foot outwards about 45 degrees and keep your right foot pointing forward. Step:3 Bend your torso to the left side, keeping your right arm extended overhead and your eyes on the kettlebell. Step:4 Lower your torso as far as you can while keeping your right arm straight and your left arm extended to the side. Step:5 Pause for a moment, then return to the starting position by pushing through your right foot and engaging your obliques. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell iron cross', 'dumbbell iron cross', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Step:2 Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body. Step:3 Pause for a moment, then slowly lower your arms back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever preacher curl', 'lever preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the leverage machine. Step:2 Place your upper arms on the pad and grip the handles with an underhand grip. Step:3 Keep your back straight and your elbows positioned on the pad. Step:4 Exhale and curl your forearms towards your upper arms, contracting your biceps. Step:5 Pause for a moment at the top of the movement, squeezing your biceps. Step:6 Inhale and slowly lower the handles back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up on lower arms', 'push-up on lower arms', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a plank position with your forearms on the ground and elbows directly below your shoulders. Step:2 Engage your core and keep your body in a straight line from head to toe. Step:3 Lower your chest towards the ground by bending your elbows, keeping them close to your body. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('straddle maltese', 'straddle maltese', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pair of rings with your arms fully extended and your body in a straight line. Step:2 Spread your legs wide apart, forming a straddle position. Step:3 Engage your core and slowly lower your body until your arms are parallel to the ground. Step:4 Hold this position for a few seconds, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell biceps curl reverse', 'dumbbell biceps curl reverse', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell stiff leg deadlift', 'dumbbell stiff leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing a slight bend in your knees. Step:3 Lower the dumbbells until you feel a stretch in your hamstrings, then squeeze your glutes and push through your heels to return to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted standing chin-up', 'assisted standing chin-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired assistance level. Step:2 Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Keep your chest up and shoulders back, engage your core, and slightly bend your knees. Step:4 Pull your body up by flexing your elbows and driving your elbows down towards your sides. Step:5 Continue pulling until your chin is above the bar. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell wide-grip upright row', 'barbell wide-grip upright row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart. Step:2 Let the barbell hang in front of your thighs, arms fully extended. Step:3 Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows. Step:4 Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable low seated row', 'cable low seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the machine with your feet flat on the footrests and your knees slightly bent. Step:2 Grasp the handles with an overhand grip, palms facing down. Step:3 Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows. Step:4 Pull the handles towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline two arm extension', 'dumbbell incline two arm extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Step:2 Slowly lie back on the bench, keeping the dumbbells close to your chest. Step:3 Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('butt-ups', 'butt-ups', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands by your sides, palms facing down. Step:3 Engaging your abs, lift your legs off the ground, bringing your knees towards your chest. Step:4 At the top of the movement, squeeze your abs and pause for a moment. Step:5 Slowly lower your legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying triceps extension', 'dumbbell lying triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing each other. Step:2 Extend your arms straight up over your chest, keeping your elbows close to your body. Step:3 Lower the dumbbells down towards your forehead, bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band seated hip abduction', 'resistance band seated hip abduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a chair or bench with your back straight and feet flat on the ground. Step:2 Wrap the resistance band around your thighs, just above your knees. Step:3 Place your hands on the sides of the chair or bench for support. Step:4 Engage your abductors (outer thigh muscles) and slowly push your knees apart, against the resistance of the band. Step:5 Pause for a moment at the end of the movement, then slowly bring your knees back together. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated rear lateral raise', 'cable seated rear lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench facing the cable machine with your feet flat on the ground. Step:2 Grasp the cable handles with an overhand grip and extend your arms straight in front of you. Step:3 Keeping your arms straight, slowly raise them out to the sides until they are parallel to the floor. Step:4 Pause for a moment at the top, then slowly lower your arms back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell two arm row', 'kettlebell two arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body. Step:2 Bend forward at the hips, keeping your back straight and your core engaged. Step:3 Pull the kettlebells up towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower the kettlebells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell rear delt raise', 'barbell rear delt raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing bent over one arm triceps extension', 'dumbbell standing bent over one arm triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand. Step:2 Bend forward at the waist, keeping your back straight and parallel to the ground. Step:3 Extend your arm straight back, keeping your elbow close to your body. Step:4 Slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm press', 'dumbbell incline one arm press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in one hand, resting on your thigh. Step:2 Lie back on the bench and position the dumbbell at shoulder level, palm facing forward. Step:3 Press the dumbbell upward and slightly inward, extending your arm fully. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled forward angled calf raise', 'sled forward angled calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a comfortable weight and position yourself on the machine with your toes on the platform and your heels hanging off. Step:2 Place your hands on the handles or the sides of the machine for support. Step:3 Engage your calves and slowly raise your heels as high as possible, pushing against the resistance of the sled. Step:4 Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell biceps curl squat', 'dumbbell biceps curl squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Step:2 Keeping your back straight and your elbows close to your sides, exhale and curl the dumbbells up towards your shoulders. Step:3 Pause for a moment at the top, squeezing your biceps. Step:4 Inhale and slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell biceps curl (with arm blaster)', 'barbell biceps curl (with arm blaster)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Step:2 Place your upper arms against the arm blaster, keeping your elbows close to your torso. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the barbell back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying triceps extension', 'barbell lying triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Step:4 Pause for a moment at the bottom, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse preacher curl', 'barbell reverse preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip. Step:2 Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps. Step:3 Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up (on stability ball)', 'push-up (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart. Step:2 Extend your legs straight out behind you, balancing on your toes. Step:3 Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith seated shoulder press', 'smith seated shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that the handles are at shoulder level. Step:2 Sit on the machine with your back against the pad and your feet flat on the floor. Step:3 Grasp the handles with an overhand grip and lift them off the supports, extending your arms fully. Step:4 Lower the handles down to shoulder level, keeping your elbows slightly bent. Step:5 Press the handles up overhead until your arms are fully extended. Step:6 Pause for a moment at the top, then slowly lower the handles back down to shoulder level. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kipping muscle up', 'kipping muscle up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:2 Engage your core and use a swinging motion to generate momentum. Step:3 As you swing forward, pull your chest towards the bar, using your lats and biceps to initiate the movement. Step:4 Continue the upward motion until your chest reaches the bar, then transition into a dip position by pushing down on the bar and extending your arms. Step:5 Lower yourself back down to the starting position by bending your arms and controlling the descent. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('korean dips', 'korean dips', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself between two parallel bars with your arms extended and supporting your body weight. Step:2 Lower your body by bending your elbows until your upper arms are parallel to the ground. Step:3 Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated hip adduction', 'lever seated hip adduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the backrest. Step:2 Place your feet on the footrests and grasp the handles for stability. Step:3 Engage your adductor muscles and slowly bring your legs together, squeezing your inner thighs. Step:4 Pause for a moment at the peak contraction, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell pullover', 'barbell pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet on the floor. Step:2 Hold a barbell with a shoulder-width grip and extend your arms straight above your chest. Step:3 Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats. Step:4 Pause for a moment, then raise the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell biceps curl v sit on bosu ball', 'dumbbell biceps curl v sit on bosu ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bosu ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold a dumbbell in each hand with your palms facing forward and your arms fully extended down by your sides. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell pullover', 'dumbbell pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet on the floor. Step:2 Hold a dumbbell with both hands and extend your arms straight above your chest. Step:3 Keeping a slight bend in your elbows, slowly lower the dumbbell behind your head until you feel a stretch in your chest and shoulders. Step:4 Pause for a moment, then raise the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever overhand triceps dip', 'lever overhand triceps dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to the appropriate height and secure your body in position. Step:2 Grasp the handles with an overhand grip and position your body so that your arms are fully extended. Step:3 Lower your body by bending your elbows, keeping your upper arms close to your sides. Step:4 Continue lowering until your upper arms are parallel to the floor. Step:5 Pause for a moment, then push yourself back up to the starting position by extending your elbows. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('full planche', 'full planche', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and your fingers pointing forward. Step:2 Engage your core and slowly shift your weight forward, lifting your feet off the ground. Step:3 Continue shifting your weight forward until your body is parallel to the ground, balancing on your hands. Step:4 Hold this position for as long as you can, maintaining a straight body line. Step:5 Slowly lower your feet back to the ground and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cocoons', 'cocoons', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side hip (on parallel bars)', 'side hip (on parallel bars)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand between two parallel bars with your feet shoulder-width apart. Step:2 Place your hands on the bars and lift your body off the ground, supporting your weight on your arms. Step:3 Engage your abs and slowly lift your legs to the side, keeping them straight. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('peroneals stretch', 'peroneals stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you. Step:2 Loop the rope around the ball of your foot and hold the ends of the rope with your hands. Step:3 Gently pull the rope towards you, flexing your foot and stretching your calf muscles. Step:4 Hold the stretch for 15-30 seconds. Step:5 Release the tension on the rope and repeat the stretch on the other leg. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight squatting row (with towel)', 'bodyweight squatting row (with towel)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down. Step:2 Bend your knees and lower your body into a squat position, keeping your back straight and your chest up. Step:3 As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying supine biceps curl', 'dumbbell lying supine biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your back and head supported, and your feet flat on the ground. Step:2 Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('alternate heel touchers', 'alternate heel touchers', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Extend your arms straight out to the sides, parallel to the ground. Step:3 Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel. Step:4 Return to the starting position and repeat on the left side, reaching your left hand towards your left heel. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest dip (on dip-pull-up cage)', 'chest dip (on dip-pull-up cage)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the dip bars to a height that allows you to comfortably grip them. Step:2 Stand between the bars and place your hands on each bar, slightly wider than shoulder-width apart. Step:3 Jump up and straighten your arms, supporting your body weight on the bars. Step:4 Bend your knees and cross your ankles behind you. Step:5 Lower your body by bending your elbows, keeping your chest up and your shoulders down. Step:6 Continue lowering until your shoulders are below your elbows or until you feel a stretch in your chest. Step:7 Push through your palms and extend your elbows to raise your body back up to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever unilateral row', 'lever unilateral row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself facing the machine. Step:2 Grasp the handles with an overhand grip and keep your back straight. Step:3 Pull the handles towards your body, squeezing your shoulder blades together. Step:4 Pause for a moment at the peak of the movement, then slowly release and extend your arms back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated one arm bicep curl on exercise ball with leg raised', 'dumbbell seated one arm bicep curl on exercise ball with leg raised', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with your palm facing up and your arm fully extended. Step:3 Place your other hand on your hip for stability. Step:4 Slowly curl the dumbbell towards your shoulder, keeping your upper arm stationary. Step:5 Pause for a moment at the top of the movement, squeezing your bicep. Step:6 Slowly lower the dumbbell back to the starting position. Step:7 Repeat for the desired number of repetitions. Step:8 Switch arms and repeat the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing one arm curl over incline bench', 'dumbbell standing one arm curl over incline bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand. Step:2 Place your other hand on an incline bench for support. Step:3 Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller back stretch', 'roller back stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by sitting on the ground with your legs extended in front of you. Step:2 Place the roller perpendicular to your body, just below your glutes. Step:3 Slowly roll your body backwards, allowing the roller to move up your back. Step:4 Continue rolling until the roller reaches your upper back. Step:5 Pause for a moment, then slowly roll back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell drag curl', 'barbell drag curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Step:2 Let the barbell hang at arm''s length in front of your thighs. Step:3 Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps. Step:4 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm incline chest press', 'dumbbell one arm incline chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the incline bench to a 45-degree angle. Step:2 Sit on the bench with your back against the pad and feet flat on the ground. Step:3 Hold a dumbbell in one hand with an overhand grip, resting it on your shoulder. Step:4 Push the dumbbell up and away from your body, extending your arm fully. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying supination on floor', 'dumbbell lying supination on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand. Step:2 Rotate your palms to face up, keeping your elbows close to your sides. Step:3 Slowly curl the dumbbells towards your shoulders, squeezing your forearms. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable pull through (with rope)', 'cable pull through (with rope)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing away from the cable machine with your feet shoulder-width apart. Step:2 Grab the rope attachment with both hands and step forward, creating tension in the cable. Step:3 Bend at the hips and lower your upper body until it is parallel to the ground, keeping your back straight. Step:4 Engage your glutes and hamstrings to pull your body back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline alternate press', 'dumbbell incline alternate press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Step:2 Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward. Step:3 Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward. Step:4 Push the dumbbells up with your chest and shoulders, extending your arms fully. Step:5 Lower the dumbbells back down to the starting position, keeping your elbows slightly bent. Step:6 Repeat for the desired number of repetitions, alternating arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable tuck reverse crunch', 'cable tuck reverse crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable to a low pulley and lie down on a mat facing up. Step:2 Hold the cable with both hands and extend your arms straight up above your chest. Step:3 Bend your knees and lift your legs up, bringing your knees towards your chest. Step:4 At the same time, curl your pelvis up towards your chest, lifting your hips off the ground. Step:5 Pause for a moment at the top, then slowly lower your legs and hips back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell speed squat', 'barbell speed squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the barbell across your upper back, resting it on your traps or rear delts. Step:3 Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair. Step:4 Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Drive through your heels to stand back up, squeezing your glutes at the top. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled calf press on leg press', 'sled calf press on leg press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled. Step:2 Place your feet shoulder-width apart on the sled, with your toes pointing forward. Step:3 Release the safety handles and push the sled away from you by extending your knees and ankles. Step:4 Pause for a moment at the top of the movement, then slowly lower the sled back down by bending your knees and ankles. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith seated one leg calf raise', 'smith seated one leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the machine with your back against the pad and your feet on the footrest. Step:2 Place one leg on the footrest and keep the other leg off the footrest. Step:3 Using your calf muscles, raise your heel as high as possible. Step:4 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell reverse grip curl', 'ez barbell reverse grip curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip. Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the exercise. Step:3 Curl the barbell upwards by contracting your biceps, while exhaling. Step:4 Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Slowly begin to bring the barbell back to the starting position as you inhale. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying close-grip press', 'barbell lying close-grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet. Step:3 Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Step:4 Slowly lower the barbell towards your chest, keeping your elbows close to your body. Step:5 Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted decline sit-up', 'weighted decline sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a decline bench with your feet secured under the foot pads. Step:2 Place your hands behind your head or across your chest. Step:3 Engage your abs and slowly lift your upper body off the bench, curling forward until your torso is perpendicular to the ground. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell rear lunge', 'dumbbell rear lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Take a step backward with your right foot, lowering your body into a lunge position. Step:3 Bend your left knee and lower your body until your left thigh is parallel to the ground. Step:4 Pause for a moment, then push through your left heel to return to the starting position. Step:5 Repeat on the other side, stepping back with your left foot.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing back wrist curl', 'barbell standing back wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip. Step:2 Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body. Step:3 Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible. Step:4 Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated one leg calf raise - hammer grip', 'dumbbell seated one leg calf raise - hammer grip', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs. Step:2 Place one foot on a raised surface, such as a step or block, with your heel hanging off the edge. Step:3 Hold the dumbbell with a hammer grip, meaning your palms are facing each other and your fingers are wrapped around the handle. Step:4 Keeping your core engaged and your back straight, slowly raise your heel as high as possible by pushing through the ball of your foot. Step:5 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled one leg calf press on leg press', 'sled one leg calf press on leg press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled. Step:2 Sit on the machine with your back against the backrest and your feet on the sled, shoulder-width apart. Step:3 Place your toes and the balls of your feet on the sled, keeping your heels off. Step:4 Push the sled forward by extending your ankles, keeping your knees slightly bent. Step:5 Pause for a moment at the top, then slowly lower the sled back down by flexing your ankles. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted seated pectoralis major stretch with stability ball', 'assisted seated pectoralis major stretch with stability ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your back straight. Step:2 Hold a stability ball with both hands and extend your arms straight out in front of you. Step:3 Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles. Step:4 Hold the stretch for a few seconds, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('calf stretch with rope', 'calf stretch with rope', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall or sturdy object with your feet hip-width apart. Step:2 Hold the ends of the rope in each hand and place the middle of the rope around the ball of your right foot. Step:3 Step back with your left foot, keeping your heel on the ground and your leg straight. Step:4 Lean forward, keeping your back straight, and gently pull on the rope to stretch your calf. Step:5 Hold the stretch for 20-30 seconds, then release. Step:6 Repeat on the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band concentration curl', 'band concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your legs spread apart and your feet flat on the ground. Step:2 Hold one end of the band in your hand and step on the other end with your foot on the same side. Step:3 Lean forward slightly and rest your elbow on the inside of your thigh, just above the knee. Step:4 With your palm facing up, slowly curl your hand towards your shoulder, keeping your upper arm stationary. Step:5 Pause for a moment at the top, then slowly lower your hand back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up (bosu ball)', 'push-up (bosu ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the bosu ball on the ground with the flat side facing up. Step:2 Position yourself in a push-up position with your hands on the outer edges of the bosu ball. Step:3 Engage your core and lower your body down towards the bosu ball by bending your elbows. Step:4 Push yourself back up to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('tire flip', 'tire flip', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the tire. Step:2 Bend your knees and hinge at the hips, lowering into a squat position. Step:3 Reach down and grab the bottom edge of the tire with both hands, fingers facing towards you. Step:4 Engage your glutes and leg muscles, and explosively drive through your legs to lift the tire off the ground. Step:5 As the tire flips over, use your upper body strength to guide it and maintain control. Step:6 Once the tire is fully flipped, quickly step back and reset your stance. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternate biceps curl', 'dumbbell alternate biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions, alternating arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing reverse grip curl', 'barbell standing reverse grip curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Step:2 Keep your elbows close to your torso and your upper arms stationary. Step:3 Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated curl', 'dumbbell seated curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and a dumbbell in each hand, palms facing forward. Step:2 Keep your back straight and your elbows close to your torso. Step:3 Exhale and curl the dumbbells up towards your shoulders, contracting your biceps. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell raise', 'dumbbell raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Step:2 Keep your back straight and engage your core. Step:3 Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball catch and overhead throw', 'medicine ball catch and overhead throw', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a medicine ball in both hands at chest level. Step:2 Bend your knees slightly and engage your core. Step:3 Lower your body into a squat position, keeping your back straight and chest up. Step:4 Explosively extend your hips and legs, while simultaneously throwing the medicine ball overhead. Step:5 Release the ball at the top of the movement and catch it on the way down. Step:6 Lower your body back into the squat position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('spider crawl push up', 'spider crawl push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Bring your right knee towards your right elbow, keeping it off the ground. Step:3 As you bring your right knee back, simultaneously lower your body towards the ground by bending your elbows. Step:4 Push back up to the starting position and repeat with your left knee towards your left elbow. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell kickback', 'dumbbell kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle. Step:4 Extend your arms straight back, squeezing your triceps at the top of the movement. Step:5 Pause for a moment, then slowly lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band straight back stiff leg deadlift', 'band straight back stiff leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band around your upper legs. Step:2 Hold the band with both hands in front of your thighs, palms facing your body. Step:3 Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground. Step:4 Feel the stretch in your hamstrings as you lower the band. Step:5 Engage your glutes and hamstrings to lift your body back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell rear delt row', 'barbell rear delt row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Bend forward at the hips, keeping your back straight and chest up. Step:4 Pull the barbell towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('swing 360', 'swing 360', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold your arms straight out in front of you, parallel to the ground. Step:3 Engage your core and swing your arms in a circular motion, rotating your torso as you do so. Step:4 Continue the circular motion, swinging your arms and rotating your torso for the desired number of repetitions. Step:5 Remember to breathe throughout the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chin-up', 'chin-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Step:2 Engage your core and pull your body up towards the bar, leading with your chest. Step:3 Continue pulling until your chin is above the bar. Step:4 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated alternate front raise', 'dumbbell seated alternate front raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell in each hand with your palms facing your body and arms extended down by your sides. Step:3 Keeping your arms straight, raise one dumbbell in front of you until it is parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat with the other arm. Step:6 Alternate between arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('flexion leg sit up (bent knee)', 'flexion leg sit up (bent knee)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 At the same time, lift your legs off the ground, bending your knees and bringing them towards your chest. Step:5 Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated crunch v. 2', 'lever seated crunch v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the leverage machine with your back against the pad and your feet secured under the footpads. Step:2 Place your hands on the handles or the sides of the seat for support. Step:3 Engage your abs and slowly crunch forward, bringing your chest towards your knees. Step:4 Pause for a moment at the top of the movement, squeezing your abs. Step:5 Slowly return to the starting position, allowing your back to round slightly. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm seated bicep curl on exercise ball', 'dumbbell one arm seated bicep curl on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with your palm facing up and your arm fully extended. Step:3 Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side push-up', 'side push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your side with your legs extended and stacked on top of each other. Step:2 Place your bottom hand on the ground directly under your shoulder, fingers pointing forward. Step:3 Press through your bottom hand to lift your body off the ground, keeping your legs straight and your core engaged. Step:4 Extend your top arm straight up towards the ceiling, creating a straight line from your head to your heels. Step:5 Lower your body back down to the starting position with control. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell close-grip curl', 'ez barbell close-grip curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands shoulder-width apart. Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the movement. Step:3 Curl the barbell up towards your shoulders, contracting your biceps. Step:4 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball prone leg raise', 'exercise ball prone leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a mat with your legs extended and your toes resting on top of the stability ball. Step:2 Place your hands on the ground, shoulder-width apart, and engage your core muscles. Step:3 Keeping your legs straight, slowly lift them off the ground, using your lower back and glutes to raise them as high as possible. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell alternating press on floor', 'kettlebell alternating press on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your back on the floor with your knees bent and feet flat on the ground. Step:2 Hold a kettlebell in each hand, with your palms facing towards your feet and your arms extended straight up towards the ceiling. Step:3 Lower one kettlebell down towards your shoulder while keeping the other kettlebell extended straight up. Step:4 Press the lowered kettlebell back up to the starting position while simultaneously lowering the other kettlebell down towards your shoulder. Step:5 Continue alternating the press motion with each kettlebell for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever kneeling leg curl', 'lever kneeling leg curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to fit your body and select the desired weight. Step:2 Kneel on the machine facing downwards, with your knees resting on the pad and your feet secured under the footpads. Step:3 Grasp the handles or the sides of the machine for stability. Step:4 Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees. Step:5 Pause for a moment at the top of the movement, squeezing your hamstrings. Step:6 Inhale and slowly lower your legs back to the starting position, fully extending your knees. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('twisted leg raise (female)', 'twisted leg raise (female)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Bend your knees and lift your legs off the ground, bringing them towards your chest. Step:3 As you lift your legs, twist your hips to one side, bringing your knees towards your opposite shoulder. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat the movement, this time twisting your hips to the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable decline press', 'cable decline press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a decline position. Step:2 Sit on the decline bench facing the cable machine. Step:3 Grasp the handles with an overhand grip and position them at chest level. Step:4 Keep your feet flat on the ground and your back firmly against the bench. Step:5 Exhale and push the handles away from your body, extending your arms fully. Step:6 Pause for a moment at the end of the movement, squeezing your chest muscles. Step:7 Inhale and slowly return the handles back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell upright row', 'barbell upright row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:2 Let the barbell hang in front of your thighs, arms fully extended. Step:3 Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows. Step:4 Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm lateral raise', 'dumbbell one arm lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body. Step:2 Keep your back straight and your core engaged throughout the exercise. Step:3 Raise the dumbbell to the side, keeping your arm straight and your palm facing down. Step:4 Continue lifting until your arm is parallel to the ground. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell cuban press', 'dumbbell cuban press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down. Step:2 Keeping your core engaged and your elbows slightly bent, press the dumbbells up and overhead until your arms are fully extended. Step:3 Rotate your wrists so that your palms are facing forward. Step:4 Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as you do so. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('isometric wipers', 'isometric wipers', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying flat on your back on a mat or bench. Step:2 Extend your arms straight out to the sides, perpendicular to your body. Step:3 Engage your core and lift both legs off the ground, keeping them together and straight. Step:4 Slowly lower your legs to one side, aiming to touch the ground with your feet while maintaining control. Step:5 Pause for a moment, then use your core to lift your legs back to the starting position. Step:6 Repeat the movement, this time lowering your legs to the opposite side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline breeding', 'dumbbell incline breeding', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench with your back against the pad and feet flat on the ground. Step:3 Hold a dumbbell in each hand with an overhand grip, palms facing forward. Step:4 Start with your arms fully extended, perpendicular to the ground. Step:5 Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Step:6 Pause for a moment at the bottom, then push the dumbbells back up to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing wide grip biceps curl', 'barbell standing wide grip biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart. Step:2 Keep your back straight and your elbows close to your torso. Step:3 Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the barbell back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell squat (on knees)', 'barbell squat (on knees)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward. Step:2 Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart. Step:3 Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight. Step:4 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell palms up wrist curl over a bench', 'barbell palms up wrist curl over a bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up. Step:2 Rest your forearms on the bench, allowing your wrists to hang off the edge. Step:3 Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible. Step:4 Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith rear delt row', 'smith rear delt row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the ground. Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Keep your back straight and your core engaged as you pull the handles towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the top of the movement, then slowly release the handles back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted seated twist (on stability ball)', 'weighted seated twist (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold a weight plate or dumbbell with both hands close to your chest. Step:3 Engage your core and slowly rotate your torso to one side, keeping your hips stable. Step:4 Pause for a moment at the end of the rotation, then slowly return to the starting position. Step:5 Repeat the rotation to the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverted row', 'inverted row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a bar at waist height or use a suspension trainer. Step:2 Stand facing the bar or suspension trainer, with your feet shoulder-width apart. Step:3 Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lean back, keeping your body straight and your heels on the ground. Step:5 Pull your chest towards the bar or handles, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower yourself back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable press on exercise ball', 'cable press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your knees at a 90-degree angle. Step:2 Hold the cable handles at chest height with your palms facing down and your elbows bent. Step:3 Engage your core and press the cable handles forward until your arms are fully extended. Step:4 Pause for a moment, then slowly release the tension and bring the cable handles back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline triceps extension', 'dumbbell decline triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other. Step:2 Extend your arms fully, keeping your elbows close to your head. Step:3 Lower the dumbbells slowly behind your head, bending your elbows. Step:4 Pause for a moment, then raise the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lying bicep curl', 'cable lying bicep curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a low pulley cable machine. Step:2 Lie face up on a flat bench with your feet flat on the ground. Step:3 Grasp the bar with an underhand grip, hands shoulder-width apart. Step:4 Extend your arms fully, keeping your elbows close to your sides. Step:5 Keeping your upper arms stationary, exhale and curl the bar up towards your shoulders. Step:6 Pause for a moment at the top, squeezing your biceps. Step:7 Inhale and slowly lower the bar back to the starting position, fully extending your arms. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated good morning', 'barbell seated good morning', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and a barbell resting on your upper back. Step:2 Keep your back straight and your chest up. Step:3 Slowly hinge forward at the hips, lowering your torso towards the ground. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted cossack squats (male)', 'weighted cossack squats (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart and toes pointing slightly outward. Step:2 Hold a weight in front of your chest with both hands. Step:3 Shift your weight to one side and lower your body by bending the knee of the side you shifted towards, while keeping the other leg straight. Step:4 Go as low as you can while maintaining balance and keeping your chest up. Step:5 Push through the heel of the bent leg to return to the starting position. Step:6 Repeat on the other side, alternating between legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse curl', 'cable reverse curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a low pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart and your knees slightly bent. Step:3 Grasp the bar with an underhand grip, hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Exhale and curl the bar up towards your shoulders, contracting your biceps. Step:6 Pause for a moment at the top, squeezing your biceps. Step:7 Inhale and slowly lower the bar back to the starting position, fully extending your arms. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith sumo squat', 'smith sumo squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the barbell at hip height. Step:2 Stand with your feet wider than shoulder-width apart, toes pointing outwards. Step:3 Position yourself under the barbell, resting it on your upper back and shoulders. Step:4 Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Step:5 Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go. Step:6 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm pulldown', 'cable one arm pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a single handle to a high pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the handle with an overhand grip and extend your arm fully. Step:4 Keep your back straight and your core engaged. Step:5 Pull the handle down towards your side while keeping your elbow close to your body. Step:6 Pause for a moment at the bottom of the movement, squeezing your lat muscle. Step:7 Slowly release the handle back to the starting position. Step:8 Repeat for the desired number of repetitions. Step:9 Switch sides and repeat the exercise with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline curl', 'dumbbell incline curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward. Step:2 Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell zottman preacher curl', 'dumbbell zottman preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with a dumbbell in each hand, palms facing up and elbows resting on the pad. Step:2 Curl the dumbbells up towards your shoulders, keeping your upper arms stationary and your palms facing up. Step:3 At the top of the curl, rotate your wrists so that your palms are facing down. Step:4 Slowly lower the dumbbells back down to the starting position, rotating your wrists back to the starting position as you do so. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted prone hamstring', 'assisted prone hamstring', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a mat or bench with your legs fully extended. Step:2 Have a partner or use a resistance band to secure your ankles. Step:3 Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('flag', 'flag', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by gripping a vertical pole with both hands, palms facing each other, and arms fully extended. Step:2 Engage your core and lift your legs off the ground, keeping them straight. Step:3 Using your core and upper body strength, raise your legs until they are parallel to the ground. Step:4 Hold this position for as long as you can, maintaining a straight body line. Step:5 Slowly lower your legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('twist hip lift', 'twist hip lift', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the ground. Step:2 Place your hands by your sides for support. Step:3 Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders. Step:4 While keeping your hips lifted, twist your lower body to the right side, bringing your knees towards the ground. Step:5 Return to the starting position and repeat the twist to the left side. Step:6 Continue alternating twists for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable high pulley overhead tricep extension', 'cable high pulley overhead tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a high pulley and stand facing away from the machine. Step:2 Grasp the rope with both hands and extend your arms overhead. Step:3 Keep your elbows close to your head and your upper arms stationary. Step:4 Slowly lower the rope behind your head by bending your elbows. Step:5 Pause for a moment, then extend your arms back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline triceps extension', 'dumbbell incline triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, palms facing inwards. Step:2 Extend your arms fully overhead, keeping your elbows close to your head. Step:3 Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary. Step:4 Pause for a moment, then raise the dumbbells back to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing inner curl', 'cable standing inner curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Grasp the cable handle with an underhand grip, palms facing up. Step:3 Keep your elbows close to your sides and your upper arms stationary. Step:4 Exhale and curl the cable handle towards your shoulders, contracting your biceps. Step:5 Pause for a moment at the top of the movement, squeezing your biceps. Step:6 Inhale and slowly lower the cable handle back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell extended range one arm press on floor', 'kettlebell extended range one arm press on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your back on the floor with your knees bent and feet flat on the ground. Step:2 Hold a kettlebell in one hand, with your palm facing towards your feet. Step:3 Extend your arm straight up towards the ceiling, keeping your elbow locked and your wrist straight. Step:4 Slowly lower the kettlebell back down to the starting position, maintaining control throughout the movement. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell side split squat', 'barbell side split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Step:2 Hold a barbell across your upper back, resting it on your traps. Step:3 Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips. Step:4 As you lower, push your knees out to the sides and keep your weight on your heels. Step:5 Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith squat', 'smith squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the barbell at an appropriate height for your squat. Step:2 Stand with your feet shoulder-width apart, toes slightly turned out. Step:3 Position yourself under the barbell, resting it on your upper traps and shoulders. Step:4 Grip the barbell with a wide grip, slightly wider than shoulder-width apart. Step:5 Engage your core and unrack the barbell, stepping back to clear the rack. Step:6 Keeping your chest up and back straight, initiate the squat by bending at the hips and knees. Step:7 Lower your body until your thighs are parallel to the ground or slightly below. Step:8 Pause for a moment at the bottom, then drive through your heels to return to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push to run', 'push to run', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and your body in a straight line. Step:2 Lower your chest towards the ground by bending your elbows, keeping your body straight. Step:3 Push through your hands to extend your arms and return to the starting position. Step:4 Quickly bring one knee towards your chest, then quickly switch and bring the other knee towards your chest. Step:5 Continue alternating knees as fast as you can while maintaining good form. Step:6 Continue for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm fly on exercise ball', 'dumbbell incline one arm fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand. Step:2 Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards. Step:4 Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Step:5 Pause for a moment when your arm is parallel to the ground. Step:6 Engage your chest muscles to bring the dumbbell back up to the starting position. Step:7 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell one arm military press to the side', 'kettlebell one arm military press to the side', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height. Step:2 Engage your core and keep your back straight. Step:3 Press the kettlebell overhead, extending your arm fully. Step:4 Pause for a moment at the top, then slowly lower the kettlebell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight standing row (with towel)', 'bodyweight standing row (with towel)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a towel in front of you with both hands. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Pull the towel towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly release the tension and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell side plank with rear fly', 'dumbbell side plank with rear fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your side with your legs extended and stacked on top of each other. Step:2 Place your forearm on the ground directly below your shoulder, keeping your elbow bent at a 90-degree angle. Step:3 Hold a dumbbell in your top hand, with your arm extended straight down towards the ground. Step:4 Engage your core and lift your hips off the ground, creating a straight line from your head to your heels. Step:5 While maintaining the side plank position, lift the dumbbell up towards the ceiling, squeezing your shoulder blades together. Step:6 Lower the dumbbell back down to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm decline chest fly', 'cable one arm decline chest fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a D-handle to a low pulley cable machine and set the bench to a decline angle. Step:2 Lie down on the bench with your head towards the machine and grab the handle with your right hand. Step:3 Extend your arm straight up above your chest, keeping a slight bend in your elbow. Step:4 With a controlled motion, lower your arm out to the side until your hand is in line with your shoulder. Step:5 Pause for a moment, then reverse the motion and bring your arm back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to your left arm and repeat the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable incline triceps extension', 'cable incline triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a low pulley position. Step:2 Attach a straight bar to the cable. Step:3 Stand facing away from the machine with your feet shoulder-width apart. Step:4 Grasp the bar with an overhand grip and extend your arms straight overhead. Step:5 Lean forward slightly, keeping your back straight and core engaged. Step:6 Bend your elbows and lower the bar behind your head, keeping your upper arms close to your ears. Step:7 Pause for a moment, then extend your arms back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable close grip curl', 'cable close grip curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a low pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart and your knees slightly bent. Step:3 Grasp the bar with an underhand grip, hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Exhale and curl the bar up towards your shoulders, contracting your biceps. Step:6 Pause for a moment at the top of the movement, squeezing your biceps. Step:7 Inhale and slowly lower the bar back to the starting position, fully extending your arms. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm incline press', 'cable one arm incline press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a low pulley position. Step:2 Sit on an incline bench facing away from the cable machine. Step:3 Grasp the handle with one hand and bring it up to shoulder height. Step:4 Position your feet firmly on the ground and maintain a stable position. Step:5 Press the handle forward and upward, extending your arm fully. Step:6 Pause for a moment at the top, then slowly lower the handle back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('snatch pull', 'snatch pull', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and the barbell on the ground in front of you. Step:2 Bend your knees and hinge at the hips to lower into a squat position, gripping the barbell with an overhand grip. Step:3 Keep your back straight and chest up as you drive through your heels to lift the barbell off the ground, extending your hips and knees. Step:4 As the barbell reaches hip level, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides. Step:5 As the barbell reaches its highest point, quickly drop underneath it, pulling yourself into a deep squat position. Step:6 Catch the barbell overhead with your arms fully extended and your knees bent. Step:7 Stand up by extending your hips and knees, keeping the barbell overhead. Step:8 Lower the barbell back down to the starting position by reversing the movement. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated bent over triceps extension', 'dumbbell seated bent over triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand. Step:2 Bend forward at the waist, keeping your back straight and your head up. Step:3 Extend your arms straight back, keeping your elbows close to your head. Step:4 Pause for a moment, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell one arm snatch', 'kettlebell one arm snatch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand between your legs. Step:2 Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground. Step:3 Explosively extend your hips and knees, using the momentum to swing the kettlebell up towards your shoulder. Step:4 As the kettlebell reaches shoulder height, rotate your hand and punch it straight up overhead, fully extending your arm. Step:5 Lower the kettlebell back down between your legs and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm press on exercise ball', 'dumbbell incline one arm press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground. Step:2 Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbell at shoulder height with your palm facing forward. Step:4 Press the dumbbell upward until your arm is fully extended. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bench pull-ups', 'bench pull-ups', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself under a bar or a sturdy horizontal surface that is at chest height. Step:2 Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang with your arms fully extended and your body straight. Step:4 Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows. Step:5 Continue pulling until your chin is above the bar or surface. Step:6 Lower yourself back down to the starting position with control. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell single leg deadlift', 'barbell single leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip. Step:2 Shift your weight onto your left foot and lift your right foot slightly off the ground. Step:3 Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance. Step:4 Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent. Step:5 Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('glute bridge two legs on bench (male)', 'glute bridge two legs on bench (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench with your back against it and your feet flat on the ground. Step:2 Place your hands on the bench beside your hips for support. Step:3 Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Step:4 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell two arm clean', 'kettlebell two arm clean', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs with both hands, palms facing towards you. Step:2 Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground. Step:3 Explosively extend your hips and knees, using the momentum to pull the kettlebell up towards your shoulders. Step:4 As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbows tucked in and the kettlebell resting on the back of your forearm. Step:5 Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell wide bench press', 'barbell wide bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Step:3 Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Step:4 Lower the barbell slowly towards your chest, keeping your elbows slightly flared out. Step:5 Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying rear lateral raise', 'dumbbell lying rear lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with a dumbbell in each hand, palms facing each other. Step:2 Extend your arms straight down towards the floor, keeping a slight bend in your elbows. Step:3 Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline fly', 'dumbbell decline fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your feet secured and your head lower than your hips. Step:2 Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Step:3 Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Step:4 Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight side lying biceps curl', 'bodyweight side lying biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs extended and your head supported by your arm. Step:2 Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder. Step:3 Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted lunge with swing', 'weighted lunge with swing', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a weight in each hand. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 As you lunge forward, swing the weights forward and upward, keeping your arms straight. Step:4 Push off with your right foot and return to the starting position, swinging the weights back down. Step:5 Repeat with your left foot and continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline push-up (on box)', 'incline push-up (on box)', 'Strength', 'Other', 'Intermediate', 'Step:1 Place your hands on the edge of a box or elevated surface, slightly wider than shoulder-width apart. Step:2 Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels. Step:3 Lower your chest towards the box by bending your elbows, keeping your body in a straight line. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated fly', 'lever seated fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the pad. Step:2 Grasp the handles with a pronated grip and keep your elbows slightly bent. Step:3 Exhale and push the handles forward, bringing them together in front of your chest. Step:4 Pause for a moment, squeezing your chest muscles. Step:5 Inhale and slowly return to the starting position, allowing your chest muscles to stretch. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying back of the head tricep extension', 'barbell lying back of the head tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell rollerout from bench', 'barbell rollerout from bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the floor with a barbell placed on a bench in front of you. Step:2 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you. Step:4 Continue rolling the barbell forward until your body is fully extended and your arms are overhead. Step:5 Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying elbow press', 'dumbbell lying elbow press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest. Step:2 Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary. Step:3 Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline hammer press', 'dumbbell incline hammer press', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs. Step:2 Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other. Step:3 Press the dumbbells up and away from your body until your arms are fully extended. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wide grip rear pull-up', 'wide grip rear pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with a wide overhand grip, hands slightly wider than shoulder-width apart. Step:2 Hang from the bar with your arms fully extended and your body straight. Step:3 Engage your back muscles and pull your body up towards the bar, leading with your chest. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline shoulder raise', 'dumbbell incline shoulder raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down. Step:2 Rest the dumbbells on your thighs and lean back onto the bench. Step:3 Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward. Step:4 Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows. Step:5 Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted three bench dips', 'weighted three bench dips', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward. Step:2 Walk your feet forward, sliding your butt off the bench and supporting your weight with your arms. Step:3 Lower your body by bending your elbows, keeping your back close to the bench. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell fly on exercise ball', 'dumbbell fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball and hold a dumbbell in each hand. Step:2 Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball. Step:3 Extend your arms straight up above your chest, palms facing each other. Step:4 Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Step:5 Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing one arm concentration curl', 'dumbbell standing one arm concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, palm facing up. Step:2 Place your free hand on your thigh for support. Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps. Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly lower the dumbbell back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('crunch (hands overhead)', 'crunch (hands overhead)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Extend your arms straight above your head. Step:3 Engaging your abs, lift your upper body off the ground, curling forward towards your knees. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band single leg split squat', 'band single leg split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and place a resistance band around your ankles. Step:2 Take a big step forward with your right foot and a smaller step back with your left foot. Step:3 Bend your knees and lower your body until your right thigh is parallel to the ground, keeping your left knee slightly above the ground. Step:4 Push through your right heel to return to the starting position. Step:5 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball on the wall calf raise (tennis ball between knees)', 'exercise ball on the wall calf raise (tennis ball between knees)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your back against a wall and place an exercise ball between your lower back and the wall. Step:2 Position your feet shoulder-width apart and slightly in front of you. Step:3 Hold a dumbbell in each hand, with your arms extended by your sides. Step:4 Place a tennis ball between your knees. Step:5 Raise your heels off the ground, lifting your body up onto your toes. Step:6 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('squat jerk', 'squat jerk', 'Strength', 'Other', 'Intermediate', 'Step:1 Start with the barbell resting on your shoulders, with your feet shoulder-width apart. Step:2 Lower your body into a squat position, keeping your chest up and your knees tracking over your toes. Step:3 As you reach the bottom of the squat, explosively drive through your legs and push the barbell overhead. Step:4 As the barbell reaches its peak, quickly drop into a split position, with one foot forward and one foot back. Step:5 Catch the barbell overhead with your arms fully extended and your back knee slightly touching the ground. Step:6 Stand up from the split position, bringing your feet back together. Step:7 Lower the barbell back to your shoulders and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hands reversed clasped circular toe touch (male)', 'hands reversed clasped circular toe touch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms extended to the sides. Step:2 Bend forward at the waist, keeping your back straight and your knees slightly bent. Step:3 Reach down with your hands and clasp them together behind your legs. Step:4 Slowly raise your hands up and over your head in a circular motion, keeping your legs straight. Step:5 Continue the circular motion until your hands touch your toes. Step:6 Reverse the motion and bring your hands back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline fly on exercise ball', 'dumbbell incline fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on an exercise ball and roll forward until your upper back is resting on the incline bench. Step:3 Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Step:4 Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Step:5 Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm lateral bent-over', 'cable one arm lateral bent-over', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing a cable machine. Step:2 Grasp the handle with one hand and step back to create tension on the cable. Step:3 Bend forward at the waist, keeping your back straight and your core engaged. Step:4 Extend your arm out to the side, parallel to the ground, with a slight bend in your elbow. Step:5 Slowly bring your arm back to the starting position, maintaining control throughout the movement. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell neutral grip bench press', 'dumbbell neutral grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Hold a dumbbell in each hand with a neutral grip (palms facing each other) and your arms extended straight up over your chest. Step:3 Slowly lower the dumbbells down towards your chest, keeping your elbows close to your body. Step:4 Pause for a moment at the bottom, then push the dumbbells back up to the starting position, fully extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith wide grip decline bench press', 'smith wide grip decline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the decline bench to the desired angle. Step:2 Lie down on the bench with your feet secured under the foot pads. Step:3 Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows pointed outwards. Step:5 Pause for a moment when the barbell touches your chest. Step:6 Push the barbell back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chin-ups (narrow parallel grip)', 'chin-ups (narrow parallel grip)', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with a narrow parallel grip, palms facing towards you. Step:2 Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Step:3 Continue pulling until your chin is above the bar. Step:4 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying close-grip triceps extension', 'barbell lying close-grip triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up. Step:3 Extend your arms fully, lifting the barbell above your chest. Step:4 Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Step:5 Pause for a moment at the bottom, then extend your arms back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable alternate shoulder press', 'cable alternate shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and grasp the handles of the cable machine with an overhand grip. Step:2 Position your hands at shoulder height, with your palms facing forward. Step:3 Keep your core engaged and your back straight. Step:4 Press one handle up and forward until your arm is fully extended. Step:5 Pause for a moment at the top, then slowly lower the handle back to the starting position. Step:6 Repeat with the other arm. Step:7 Alternate between arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline rear lateral raise', 'dumbbell incline rear lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench with your chest against the backrest and hold a dumbbell in each hand. Step:3 Extend your arms straight down with your palms facing each other. Step:4 Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground. Step:5 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side bridge v. 2', 'side bridge v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs extended and stacked on top of each other. Step:2 Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle. Step:3 Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. Step:4 Hold this position for the desired amount of time. Step:5 Lower your hips back down to the starting position. Step:6 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell decline triceps extension', 'ez barbell decline triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your head lower than your feet and your feet secured. Step:2 Hold the ez barbell with an overhand grip, hands shoulder-width apart. Step:3 Extend your arms fully, keeping your elbows close to your head. Step:4 Lower the barbell slowly towards your forehead, bending your elbows. Step:5 Pause for a moment, then extend your arms back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing calf raise (on a staircase)', 'standing calf raise (on a staircase)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand on the edge of a step or a sturdy platform with your heels hanging off and your toes on the step. Step:2 Hold onto a railing or wall for balance if needed. Step:3 Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet. Step:4 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell reverse grip preacher curl', 'ez barbell reverse grip preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with your chest against the pad and your feet flat on the floor. Step:2 Grasp the ez barbell with an underhand grip, hands shoulder-width apart. Step:3 Rest your upper arms on the pad, allowing your forearms to hang down. Step:4 Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Step:5 Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever t-bar reverse grip row', 'lever t-bar reverse grip row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Keep your back straight and engage your core. Step:4 Pull the handles towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('semi squat jump (male)', 'semi squat jump (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees and lower your body into a squat position. Step:3 Jump explosively, extending your hips and knees while swinging your arms for momentum. Step:4 Land softly on the balls of your feet and immediately go into the next repetition. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell glute bridge', 'barbell glute bridge', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying flat on your back on the ground with your knees bent and feet flat on the floor. Step:2 Place a barbell across your hips, holding it securely with both hands. Step:3 Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Step:4 Pause for a moment at the top, squeezing your glutes. Step:5 Slowly lower your hips back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('otis up', 'otis up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated one arm kickback', 'dumbbell seated one arm kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand. Step:2 Bend your torso forward at the waist, keeping your back straight and parallel to the ground. Step:3 Extend your arm straight back, keeping your elbow close to your body. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('walking on stepmill', 'walking on stepmill', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the stepmill machine to a comfortable level. Step:2 Step onto the machine and place your hands on the handrails for support. Step:3 Start walking by placing one foot on a step and then the other, alternating between legs. Step:4 Maintain an upright posture and engage your core muscles. Step:5 Continue walking for the desired duration or distance. Step:6 Gradually increase the intensity or speed as you become more comfortable with the exercise. Step:7 Remember to cool down and stretch after completing the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse wrist curl', 'barbell reverse wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down. Step:2 Rest your forearms on your thighs, allowing your wrists to hang off the edge. Step:3 Slowly curl your wrists upward, bringing the barbell towards your body. Step:4 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kneeling lat stretch', 'kneeling lat stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Kneel on the ground with your knees hip-width apart and your toes pointing back. Step:2 Extend your arms overhead and interlace your fingers. Step:3 Keeping your back straight, slowly lean to the right side, feeling a stretch in your left lat muscle. Step:4 Hold the stretch for 20-30 seconds, then return to the starting position. Step:5 Repeat the stretch on the left side, leaning to the left and feeling a stretch in your right lat muscle. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez bar lying close grip triceps extension behind head', 'ez bar lying close grip triceps extension behind head', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold the ez barbell with a close grip, palms facing up, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('posterior tibialis stretch', 'posterior tibialis stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you. Step:2 Loop the rope around the ball of your foot and hold the ends of the rope with your hands. Step:3 Gently pull the rope towards you, flexing your foot and stretching your calf muscles. Step:4 Hold the stretch for 20-30 seconds. Step:5 Release the tension on the rope and relax your foot. Step:6 Repeat the stretch on the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('frog planche', 'frog planche', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and your feet together. Step:2 Bend your elbows and lower your body towards the ground, keeping your back straight. Step:3 As you lower your body, lift your feet off the ground and bring your knees towards your chest. Step:4 Hold this position for a few seconds, then extend your legs back out and push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell rear lateral raise', 'dumbbell rear lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and core engaged. Step:3 Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band close-grip push-up', 'band close-grip push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Place a band around your upper arms, just above the elbows. Step:2 Assume a push-up position with your hands directly under your shoulders and your body in a straight line from head to heels. Step:3 Bend your elbows and lower your chest towards the ground, keeping your elbows close to your sides. Step:4 Push through your palms to extend your arms and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell seated press', 'kettlebell seated press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a kettlebell in each hand at shoulder height, palms facing forward. Step:3 Press the kettlebells overhead, fully extending your arms. Step:4 Lower the kettlebells back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell pronate-grip triceps extension', 'dumbbell pronate-grip triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your back straight and feet flat on the ground. Step:2 Hold a dumbbell with both hands, palms facing down, and extend your arms straight up overhead. Step:3 Keeping your upper arms close to your head and elbows pointing forward, slowly lower the dumbbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing archer', 'standing archer', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Extend your arms straight out in front of you at shoulder height, parallel to the ground. Step:3 Rotate your torso to the right, keeping your arms extended and your back straight. Step:4 As you rotate, extend your right arm forward and your left arm back, mimicking the motion of drawing a bowstring. Step:5 Hold the position for a moment, then return to the starting position. Step:6 Repeat the motion, this time rotating your torso to the left and extending your left arm forward and your right arm back. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side bridge hip abduction', 'side bridge hip abduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs extended and stacked on top of each other. Step:2 Prop yourself up on your forearm, keeping your elbow directly below your shoulder. Step:3 Engage your core and lift your hips off the ground, creating a straight line from your head to your feet. Step:4 While keeping your core engaged, lift your top leg as high as possible without rotating your hips. Step:5 Pause for a moment at the top, then lower your leg back down. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying femoral', 'dumbbell lying femoral', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen. Step:2 Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted triceps dip on high parallel bars', 'weighted triceps dip on high parallel bars', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself between two parallel bars with your hands gripping the bars and your arms fully extended. Step:2 Bend your elbows and lower your body until your upper arms are parallel to the ground. Step:3 Pause for a moment, then push through your palms to straighten your arms and return to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell single leg split squat', 'dumbbell single leg split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Take a step forward with one foot and position your feet so that your front foot is flat on the ground and your back foot is elevated on a bench or step. Step:3 Lower your body by bending your front knee and hip, keeping your back knee slightly bent and your back heel off the ground. Step:4 Continue lowering until your front thigh is parallel to the ground, then push through your front heel to return to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('quick feet v. 2', 'quick feet v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms by your sides. Step:2 Begin by rapidly moving your feet up and down, as if you were running in place. Step:3 Keep your movements quick and light, focusing on staying on the balls of your feet. Step:4 Continue for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lateral raise', 'dumbbell lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Step:2 Keep your back straight and engage your core. Step:3 Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('split squats', 'split squats', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Take a step forward with one foot and place it about two feet in front of the other foot. Step:3 Lower your body by bending your knees and hips, keeping your back straight. Step:4 Continue lowering until your front thigh is parallel to the ground, and your back knee is hovering just above the ground. Step:5 Pause for a moment, then push through your front heel to return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm prone hammer curl', 'dumbbell one arm prone hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with a dumbbell in one hand, palm facing your body and arm fully extended. Step:2 Keep your upper arm stationary and curl the dumbbell towards your shoulder, contracting your biceps. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:4 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lunge with bicep curl', 'dumbbell lunge with bicep curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground. Step:3 As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body. Step:4 Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides. Step:5 Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell spider curl', 'ez barbell spider curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up. Step:2 Rest your upper arms on a preacher bench or stability ball, allowing your elbows to hang down. Step:3 Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable deadlift', 'cable deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Bend at the hips and knees, lowering your torso until your back is parallel to the ground. Step:3 Grasp the cable handles with an overhand grip, keeping your arms straight and your shoulders back. Step:4 Engage your glutes and hamstrings to lift the cable handles, extending your hips and standing up straight. Step:5 Pause for a moment at the top, then slowly lower the cable handles back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band y-raise', 'band y-raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing inwards. Step:2 Keep your arms straight and lift them up and out to the sides, forming a ''Y'' shape with your body. Step:3 Squeeze your shoulder blades together at the top of the movement. Step:4 Slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell bent over row', 'dumbbell bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body. Step:2 Bend forward at the hips, keeping your back straight and your core engaged. Step:3 Let your arms hang straight down towards the floor, with your elbows slightly bent. Step:4 Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell cross body hammer curl', 'dumbbell cross body hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your body. Step:2 Keep your elbows close to your torso and your upper arms stationary. Step:3 Exhale and curl the weights while contracting your biceps, bringing the dumbbells across your body towards your opposite shoulder. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable twisting pull', 'cable twisting pull', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable handle to a low pulley and stand facing the machine. Step:2 Grasp the handle with your left hand and step away from the machine, extending your arm fully. Step:3 Position your feet shoulder-width apart, with your knees slightly bent. Step:4 Keep your back straight and your core engaged throughout the exercise. Step:5 Pull the handle towards your body, rotating your torso to the right as you do so. Step:6 Squeeze your back muscles at the end of the movement. Step:7 Slowly return to the starting position, keeping tension on the cable. Step:8 Repeat for the desired number of repetitions, then switch sides and perform with your right hand.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band fixed back close grip pulldown', 'band fixed back close grip pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a fixed point above you, such as a pull-up bar or sturdy beam. Step:2 Sit down on a bench or chair facing the band, with your feet flat on the ground and your knees bent. Step:3 Grasp the band with a close grip, palms facing towards you. Step:4 Keep your back straight and engage your core. Step:5 Pull the band down towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Step:7 Slowly release the band back to the starting position, maintaining control throughout the movement. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell concentration curl', 'dumbbell concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh. Step:2 Fully extend your arm and hold the dumbbell with an underhand grip. Step:3 Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps. Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly lower the dumbbell back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('frankenstein squat', 'frankenstein squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the barbell in front of your body with straight arms. Step:2 Keeping your back straight, lower your body by bending at the knees and hips, as if sitting back into a chair. Step:3 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:4 Pause for a moment, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted stretch lunge', 'weighted stretch lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Take a step forward with your right foot, keeping your back straight. Step:3 Lower your body by bending your knees until your right thigh is parallel to the ground. Step:4 Push through your right heel to return to the starting position. Step:5 Repeat with your left leg. Step:6 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('landmine lateral raise', 'landmine lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold the barbell with an overhand grip, resting it on the front of your shoulders. Step:3 Keeping your core engaged and back straight, lift the barbell up and away from your body, raising it to shoulder height. Step:4 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('suspended reverse crunch', 'suspended reverse crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your knees up towards your chest, curling your pelvis towards your ribcage. Step:3 Pause for a moment at the top, then slowly lower your knees back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable wrist curl', 'cable wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a low pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Step:4 Rest your forearms on a bench or pad, with your wrists hanging off the edge. Step:5 Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Step:6 Pause for a moment at the top, then inhale and slowly lower the bar back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball chest push from 3 point stance', 'medicine ball chest push from 3 point stance', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a 3 point stance with one hand on the medicine ball and the other hand on the ground. Step:2 Extend your legs and position your body in a straight line. Step:3 Lower your chest towards the ground while keeping your back straight. Step:4 Push the medicine ball away from your body, extending your arm fully. Step:5 Return to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inchworm', 'inchworm', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a standing position with your feet hip-width apart. Step:2 Bend forward at the waist and place your hands on the ground in front of you. Step:3 Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe. Step:4 Pause for a moment, then walk your hands back towards your feet, keeping your legs as straight as possible. Step:5 Once your hands reach your feet, stand back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse grip bent over row', 'barbell reverse grip bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart. Step:3 Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor. Step:4 Pull the barbell towards your lower chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever reverse grip lateral pulldown', 'lever reverse grip lateral pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground. Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back. Step:4 Pull the handles down towards your chest, leading with your elbows and squeezing your shoulder blades together. Step:5 Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('flutter kicks', 'flutter kicks', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your hands by your sides. Step:2 Engage your core and lift your legs off the ground about 6 inches. Step:3 Keeping your legs straight, alternate lifting one leg slightly higher than the other. Step:4 Continue this fluttering motion for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('decline push-up', 'decline push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Place your hands on the ground slightly wider than shoulder-width apart, with your feet elevated on a stable surface. Step:2 Keep your body in a straight line from head to toe, engaging your core muscles. Step:3 Lower your chest towards the ground by bending your elbows, keeping them close to your body. Step:4 Push through your palms to extend your arms and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wide grip pull-up', 'wide grip pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your palms facing away from you and your hands wider than shoulder-width apart. Step:2 Engage your core and squeeze your shoulder blades together. Step:3 Pull your body up towards the bar until your chin is above the bar. Step:4 Lower your body back down to the starting position with control. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated close-grip concentration curl', 'barbell seated close-grip concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart. Step:2 Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you. Step:3 Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps. Step:4 Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell glute bridge two legs on bench (male)', 'barbell glute bridge two legs on bench (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart. Step:2 Place a barbell across your hips, holding it securely with both hands. Step:3 Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders. Step:4 Pause for a moment at the top, squeezing your glutes. Step:5 Slowly lower your hips back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm lateral raise', 'cable one arm lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the cable machine. Step:2 Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable. Step:3 Keep your arm straight and slowly raise it out to the side until it is parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower your arm back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell single leg calf raise', 'dumbbell single leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand on the edge of a step or platform with your heels hanging off and your toes on the step. Step:2 Hold a dumbbell in one hand and place your other hand on a wall or railing for support. Step:3 Raise your heel as high as possible, lifting your body up onto your toes. Step:4 Pause for a moment at the top, then slowly lower your heel back down below the step. Step:5 Repeat for the desired number of repetitions, then switch to the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline hammer press', 'dumbbell decline hammer press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your feet secured and your head lower than your hips. Step:2 Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest. Step:3 Lower the dumbbells to the sides of your chest, keeping your elbows slightly bent. Step:4 Press the dumbbells back up to the starting position, fully extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse grip incline bench two arm row', 'dumbbell reverse grip incline bench two arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench with your chest against the backrest and your feet flat on the ground. Step:3 Hold a dumbbell in each hand with an underhand grip. Step:4 Lean forward and let your arms hang straight down, fully extended. Step:5 Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side lying hip adduction (male)', 'side lying hip adduction (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs straight and stacked on top of each other. Step:2 Place your bottom arm under your head for support. Step:3 Engage your adductors and lift your top leg as high as possible without rotating your hips or leaning backward. Step:4 Pause for a moment at the top, then slowly lower your leg back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell pirate supper legs', 'kettlebell pirate supper legs', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Raise the kettlebell up to shoulder height, keeping your elbow close to your body. Step:4 Extend your arm fully overhead, straightening your elbow. Step:5 Lower the kettlebell back down to shoulder height, then return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band v-up', 'band v-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Step:2 Engaging your abs, lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. Step:3 Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted standing pull-up', 'assisted standing pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired weight and height settings. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:4 Engage your lats and biceps, and pull yourself up towards the handles. Step:5 Pause for a moment at the top, squeezing your back muscles. Step:6 Slowly lower yourself back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable bench press', 'cable bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to chest height and attach the handles. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Grasp the handles with an overhand grip and step forward to create tension in the cables. Step:4 Position your feet firmly on the ground and engage your core. Step:5 Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle. Step:6 Push the handles forward, extending your arms fully in front of you. Step:7 Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45в° leg press', 'sled 45в° leg press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat and footplate of the sled machine to a comfortable position. Step:2 Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate. Step:3 Grip the handles on the sides of the seat for stability. Step:4 Push the footplate away from your body by extending your legs, keeping your heels on the footplate. Step:5 Continue pushing until your legs are almost fully extended, but without locking your knees. Step:6 Pause for a moment at the top of the movement, then slowly lower the footplate back towards your body by bending your knees. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hamstring stretch', 'hamstring stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Step forward with your right foot and shift your weight onto your right leg. Step:3 Keeping your back straight, slowly bend forward at the hips, reaching towards your right foot with both hands. Step:4 Hold the stretch for 20-30 seconds, then return to the starting position. Step:5 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith bench press', 'smith bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the height of the smith machine bar to chest level. Step:2 Lie flat on the bench with your feet firmly planted on the ground. Step:3 Grip the bar with an overhand grip slightly wider than shoulder-width apart. Step:4 Unrack the bar and lower it towards your chest, keeping your elbows tucked in. Step:5 Pause for a moment when the bar touches your chest. Step:6 Push the bar back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging leg raise', 'hanging leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up in front of you, keeping them straight. Step:3 Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope one arm hammer preacher curl', 'cable rope one arm hammer preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a low pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the rope handle with an underhand grip, palms facing up. Step:4 Position your upper arm against the preacher bench pad, keeping your elbow slightly bent. Step:5 Keep your back straight and your core engaged throughout the exercise. Step:6 Slowly curl the rope handle towards your shoulder, keeping your upper arm stationary. Step:7 Squeeze your biceps at the top of the movement, then slowly lower the rope handle back to the starting position. Step:8 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lying close-grip curl', 'cable lying close-grip curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a low pulley cable machine. Step:2 Lie face up on a flat bench with your feet flat on the ground. Step:3 Grasp the bar with an underhand grip, hands shoulder-width apart. Step:4 Extend your arms fully, keeping your elbows close to your sides. Step:5 Keeping your upper arms stationary, curl the bar towards your chest by contracting your biceps. Step:6 Pause for a moment at the top, squeezing your biceps. Step:7 Slowly lower the bar back to the starting position, fully extending your arms. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable underhand pulldown', 'cable underhand pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the pulldown bar is at a height above your head. Step:2 Sit down on the seat and grab the pulldown bar with an underhand grip, hands slightly wider than shoulder-width apart. Step:3 Keep your back straight and lean back slightly. Step:4 Pull the bar down towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('three bench dip', 'three bench dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your hands gripping the edge, fingers pointing forward. Step:2 Slide your butt off the bench, supporting your weight with your hands. Step:3 Bend your elbows and lower your body until your upper arms are parallel to the ground. Step:4 Push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell pullover hip extension on exercise ball', 'dumbbell pullover hip extension on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and the dumbbell resting on your thighs. Step:2 Slowly walk your feet forward, rolling the exercise ball down your back until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbell with both hands and extend your arms straight up over your chest, keeping a slight bend in your elbows. Step:4 Lower the dumbbell behind your head, keeping your arms straight and maintaining control. Step:5 Pause for a moment, then raise the dumbbell back to the starting position. Step:6 While keeping your arms extended, lift your hips off the ground, squeezing your glutes and engaging your core. Step:7 Lower your hips back down to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated palms up wrist curl', 'dumbbell seated palms up wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Step:2 Rest your forearms on your thighs, allowing your wrists to hang off the edge. Step:3 Slowly curl your wrists upward, squeezing your forearms at the top of the movement. Step:4 Pause for a moment, then lower your wrists back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell bench front squat', 'barbell bench front squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone. Step:2 Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground. Step:3 Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up. Step:4 Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bridge - mountain climber (cross body)', 'bridge - mountain climber (cross body)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Step:2 Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow. Step:3 Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow. Step:4 Continue alternating sides, moving at a controlled pace. Step:5 Keep your hips level and avoid lifting your hips too high or sagging them too low. Step:6 Maintain a steady breathing pattern throughout the exercise. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('crunch (on stability ball)', 'crunch (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Lie back on the ball until your lower back is supported and your upper body is parallel to the floor. Step:3 Place your hands behind your head or across your chest. Step:4 Engage your abs and lift your upper body towards your knees, curling your torso forward. Step:5 Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell decline bent arm pullover', 'barbell decline bent arm pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie down on a decline bench with your head lower than your hips and your feet secured. Step:2 Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest. Step:3 Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent. Step:4 Pause for a moment, then raise the barbell back to the starting position by contracting your lats. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band alternating v-up', 'band alternating v-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Step:2 Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. Step:3 As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other. Step:4 Repeat the movement, alternating the position of your legs with each repetition. Step:5 Continue for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cambered bar lying row', 'cambered bar lying row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a barbell on the floor and lie face down on a bench with your chest just off the edge. Step:2 Reach down and grab the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 With your legs straight and feet on the ground, lift the barbell off the floor by extending your arms. Step:4 Pull the barbell towards your chest, squeezing your shoulder blades together. Step:5 Lower the barbell back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell prone incline curl', 'barbell prone incline curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Lie face down on the bench with your chest and stomach resting against it. Step:3 Hold a barbell with an underhand grip, shoulder-width apart. Step:4 Extend your arms fully, allowing the barbell to hang down towards the floor. Step:5 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:6 Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level. Step:7 Hold the contracted position for a brief pause as you squeeze your biceps. Step:8 Inhale and slowly begin to lower the barbell back to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('skater hops', 'skater hops', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees slightly and jump to the right, landing on your right foot. Step:3 As you land, swing your left leg behind your right leg and tap the ground with your left toes. Step:4 Immediately jump to the left, landing on your left foot. Step:5 As you land, swing your right leg behind your left leg and tap the ground with your right toes. Step:6 Continue alternating sides, jumping and tapping the ground with each leg. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band seated chest press', 'resistance band seated chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a chair or bench with your back straight and feet flat on the ground. Step:2 Hold the resistance band handles in each hand, with your palms facing down and elbows bent at a 90-degree angle. Step:3 Extend your arms forward, pushing the resistance band away from your chest. Step:4 Pause for a moment at the end of the movement, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sit-up with arms on chest', 'sit-up with arms on chest', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Cross your arms over your chest. Step:3 Engaging your abs, lift your upper body off the ground towards your knees. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rocky pull-up pulldown', 'rocky pull-up pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a pull-up bar with your feet shoulder-width apart. Step:2 Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang from the bar with your arms fully extended and your body straight. Step:4 Engage your back muscles and pull your body up towards the bar, leading with your chest. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell bench press', 'barbell bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Step:3 Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Step:4 Lower the barbell slowly towards your chest, keeping your elbows tucked in. Step:5 Pause for a moment when the barbell touches your chest. Step:6 Push the barbell back up to the starting position by extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted seated bicep curl (on stability ball)', 'weighted seated bicep curl (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your back straight. Step:2 Hold a medicine ball with an underhand grip, palms facing up, and let your arms hang down by your sides. Step:3 Keeping your upper arms stationary, exhale and curl the medicine ball up towards your shoulders. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the medicine ball back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted squat', 'weighted squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing slightly outward. Step:2 Hold a weight in front of your chest or on your shoulders. Step:3 Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair. Step:4 Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Push through your heels to stand back up, squeezing your glutes at the top. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever hip extension v. 2', 'lever hip extension v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to fit your body and sit on it with your back against the backrest. Step:2 Place your feet on the footrests and grip the handles for stability. Step:3 Engage your glutes and hamstrings, then push against the footrests to extend your hips and raise your legs backward. Step:4 Pause for a moment at the top, then slowly lower your legs back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ring dips', 'ring dips', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from the rings with your arms fully extended and your body straight. Step:2 Lower your body by bending your elbows until your shoulders are below your elbows. Step:3 Push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reverse hyper on flat bench', 'reverse hyper on flat bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with your hips at the edge and your legs hanging off the bench. Step:2 Hold onto the bench for stability. Step:3 Keeping your legs straight, raise them up towards the ceiling as high as you can. Step:4 Squeeze your glutes at the top of the movement. Step:5 Slowly lower your legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball back extension with hands behind head', 'exercise ball back extension with hands behind head', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and lie face down on top of it with your hips resting on the ball. Step:2 Position your feet against a wall or other stable surface for support. Step:3 Cross your arms behind your head, with your hands touching the back of your head. Step:4 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your hips. Step:5 Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('runners stretch', 'runners stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart. Step:2 Take a step forward with your right foot, keeping your left foot planted. Step:3 Bend your right knee and lower your body down, keeping your left leg straight. Step:4 Place your hands on your right thigh for support. Step:5 Hold the stretch for 20-30 seconds, then switch sides and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('iron cross stretch', 'iron cross stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your arms extended out to the sides. Step:2 Raise your legs up towards the ceiling, keeping them straight. Step:3 Slowly lower your legs to one side, aiming to touch the floor with your feet. Step:4 Hold the stretch for a few seconds, then return your legs to the starting position. Step:5 Repeat the stretch on the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell revers wrist curl v. 2', 'barbell revers wrist curl v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and your knees bent. Step:2 Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart. Step:3 Rest your forearms on your thighs, allowing your wrists to hang off the edge. Step:4 Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Step:5 Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell tate press', 'dumbbell tate press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with a dumbbell in each hand, palms facing each other. Step:2 Raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing away from you. Step:3 Press the dumbbells up until your arms are fully extended, then lower them back down to shoulder height. Step:4 Rotate your wrists back to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez bar lying bent arms pullover', 'ez bar lying bent arms pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet on the floor. Step:2 Hold the EZ barbell with a pronated grip (palms facing away from you) and your hands shoulder-width apart. Step:3 Extend your arms straight above your chest, keeping a slight bend in your elbows. Step:4 Lower the barbell in an arc motion behind your head, maintaining the slight bend in your elbows. Step:5 Pause for a moment, then return the barbell to the starting position by reversing the arc motion. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated leg raise crunch', 'lever seated leg raise crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the leverage machine with your back against the backrest and your feet on the footrests. Step:2 Grasp the handles or sidebars for stability. Step:3 Engage your abs and slowly raise your legs up towards your chest, curling your torso forward at the same time. Step:4 Pause for a moment at the top, then slowly lower your legs and torso back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('prone twist on stability ball', 'prone twist on stability ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying face down on a stability ball with your feet shoulder-width apart and your toes touching the ground. Step:2 Place your hands behind your head or cross them over your chest. Step:3 Engage your core muscles and slowly lift your upper body off the ball, keeping your back straight. Step:4 Rotate your torso to one side, bringing your shoulder towards your hip. Keep your hips and legs stable throughout the movement. Step:5 Pause for a moment, then return to the starting position. Step:6 Repeat the rotation to the other side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell sumo high pull', 'kettlebell sumo high pull', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointing outwards. Step:2 Hold a kettlebell with both hands in front of your body, arms extended downwards. Step:3 Bend your knees and lower your hips into a squat position, keeping your back straight. Step:4 Drive through your heels and explosively extend your hips and knees, pulling the kettlebell up towards your chin. Step:5 As you pull the kettlebell up, keep your elbows high and wide, and squeeze your shoulder blades together. Step:6 Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball back extension with arms extended', 'exercise ball back extension with arms extended', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability. Step:2 Extend your arms straight out in front of you, with your palms facing down. Step:3 Engage your core and slowly lift your upper body off the ball, keeping your back straight and your neck in line with your spine. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band single leg reverse calf raise', 'band single leg reverse calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and place the band around the ball of your foot. Step:2 Hold onto a stable object for balance. Step:3 Slowly raise your heel off the ground, lifting your body weight onto the ball of your foot. Step:4 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('jack burpee', 'jack burpee', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a standing position with your feet shoulder-width apart. Step:2 Lower your body into a squat position, placing your hands on the ground in front of you. Step:3 Kick your feet back, landing in a push-up position. Step:4 Perform a push-up, lowering your chest to the ground and then pushing back up. Step:5 Jump your feet forward, landing in a squat position. Step:6 Jump up explosively, reaching your arms overhead. Step:7 Land softly and immediately lower back into the squat position to begin the next repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side lying floor stretch', 'side lying floor stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs straight and your bottom arm extended straight overhead. Step:2 Bend your top knee and place your foot on the ground in front of your bottom leg. Step:3 Reach your top arm over your head and grab onto something stable, like a wall or a piece of furniture. Step:4 Slowly lift your bottom leg off the ground, keeping it straight, until you feel a stretch in your side. Step:5 Hold the stretch for 20-30 seconds, then slowly lower your leg back down. Step:6 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated calf raise', 'lever seated calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate. Step:2 Place your toes on the footplate with your heels hanging off the edge. Step:3 Grasp the handles or the sides of the seat for stability. Step:4 Push through the balls of your feet to raise your heels as high as possible. Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('neck side stretch', 'neck side stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand or sit up straight with your shoulders relaxed. Step:2 Tilt your head to one side, bringing your ear towards your shoulder. Step:3 Hold the stretch for 15-30 seconds. Step:4 Repeat on the other side. Step:5 Perform 2-4 sets on each side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith reverse-grip press', 'smith reverse-grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the height of the smith machine bar to chest level. Step:2 Stand facing the bar with your feet shoulder-width apart. Step:3 Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:4 Step back and position yourself with a slight bend in your knees. Step:5 Keep your chest up and core engaged throughout the exercise. Step:6 Lower the bar towards your chest, keeping your elbows tucked in. Step:7 Pause for a moment at the bottom, then push the bar back up to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight standing row', 'bodyweight standing row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Grasp a bar or handles with an overhand grip, palms facing down. Step:3 Keep your back straight and core engaged. Step:4 Pull the bar or handles towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the top of the movement. Step:6 Slowly release and extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('high knee against wall', 'high knee against wall', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall with your feet hip-width apart. Step:2 Place your hands on the wall for support. Step:3 Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground. Step:4 Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down. Step:5 Continue alternating legs in a running motion, bringing your knees up as high as possible. Step:6 Maintain a fast pace and keep your upper body stable throughout the exercise. Step:7 Repeat for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('air bike', 'air bike', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your hands placed behind your head. Step:2 Lift your legs off the ground and bend your knees at a 90-degree angle. Step:3 Bring your right elbow towards your left knee while simultaneously straightening your right leg. Step:4 Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg. Step:5 Continue alternating sides in a pedaling motion for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm curl', 'cable one arm curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Grasp the cable handle with an underhand grip, palm facing up. Step:3 Keep your elbow close to your side and slowly curl your forearm up towards your shoulder. Step:4 Pause for a moment at the top, then slowly lower your forearm back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell preacher curl', 'dumbbell preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher curl bench with your upper arms resting on the pad and your chest against it. Step:2 Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated alternate shoulder', 'dumbbell seated alternate shoulder', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell in each hand, palms facing inwards, and raise them to shoulder height. Step:3 Press one dumbbell up overhead while keeping the other dumbbell at shoulder height. Step:4 Lower the raised dumbbell back to shoulder height while simultaneously pressing the other dumbbell up overhead. Step:5 Continue alternating between arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band standing twisting crunch', 'band standing twisting crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band around your upper back, crossing it in front of your chest. Step:2 Hold the ends of the band with your hands, keeping your elbows bent and close to your sides. Step:3 Engage your abs and twist your torso to one side, bringing your elbow towards the opposite knee. Step:4 Pause for a moment, then return to the starting position. Step:5 Repeat on the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sit-up v. 2', 'sit-up v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith decline bench press', 'smith decline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the decline bench to the desired angle. Step:2 Lie down on the bench with your feet secured under the foot pads. Step:3 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side wrist pull stretch', 'side wrist pull stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms extended in front of you. Step:2 Extend your right arm out to the side, parallel to the ground, with your palm facing down. Step:3 With your left hand, grab your right hand and gently pull it towards your body, feeling a stretch in your right forearm. Step:4 Hold the stretch for 15-30 seconds, then release. Step:5 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kick out sit', 'kick out sit', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench or chair with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Lean back slightly and place your hands on the edge of the bench or chair for support. Step:3 Engaging your hamstrings, lift your feet off the ground and extend your legs straight out in front of you. Step:4 Pause for a moment at the top, then slowly bend your knees and bring your feet back towards your body. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell bent over row', 'barbell bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Bend forward at the hips while keeping your back straight and chest up. Step:3 Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:4 Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles. Step:5 Pause for a moment at the top, then slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bench dip (knees bent)', 'bench dip (knees bent)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench or chair with your hands gripping the edge next to your hips. Step:2 Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground. Step:3 Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing overhead triceps extension', 'barbell standing overhead triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip. Step:2 Raise the barbell overhead, fully extending your arms. Step:3 Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows. Step:4 Pause for a moment, then raise the barbell back to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hip raise (bent knee)', 'hip raise (bent knee)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands by your sides, palms facing down. Step:3 Engage your core and glutes, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Step:4 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell prone incline hammer curl', 'dumbbell prone incline hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the bench to a 45-degree incline. Step:2 Lie face down on the bench with a dumbbell in each hand, palms facing each other. Step:3 Allow your arms to hang straight down towards the floor, keeping your elbows slightly bent. Step:4 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:5 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('leg pull in flat bench', 'leg pull in flat bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with your legs extended straight out in front of you. Step:2 Place your hands on the bench beside your hips for support. Step:3 Engage your abs and lift your legs off the ground, bringing your knees towards your chest. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable russian twists (on stability ball)', 'cable russian twists (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold the cable handle with both hands and extend your arms straight out in front of you. Step:3 Lean back slightly while keeping your back straight and your core engaged. Step:4 Twist your torso to the right, bringing the cable handle towards your right hip. Step:5 Pause for a moment, then twist your torso to the left, bringing the cable handle towards your left hip. Step:6 Continue alternating twists for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell step-up', 'dumbbell step-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a bench or step with a dumbbell in each hand, palms facing your body. Step:2 Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface. Step:3 Push through your right heel and lift your body up onto the bench or step, straightening your right leg. Step:4 Bring your left foot up onto the bench or step, standing fully upright. Step:5 Step back down with your left foot, followed by your right foot, returning to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('glute-ham raise', 'glute-ham raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the glute-ham raise machine to fit your body. Step:2 Position yourself face down on the machine with your ankles secured. Step:3 Place your hands on your chest or cross them over your chest. Step:4 Engage your hamstrings and glutes to lift your upper body up towards the ceiling. Step:5 Continue lifting until your body is in a straight line from your head to your heels. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying supination', 'dumbbell lying supination', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground. Step:2 Hold a dumbbell in each hand with your palms facing up and your arms fully extended. Step:3 Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging oblique knee raise', 'hanging oblique knee raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so. Step:3 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:4 Repeat on the other side, twisting your torso in the opposite direction. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope incline tricep extension', 'cable rope incline tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a high pulley and adjust the incline bench to a comfortable angle. Step:2 Stand facing away from the pulley with your feet shoulder-width apart. Step:3 Grasp the rope with an overhand grip and extend your arms straight overhead. Step:4 Keep your elbows close to your head and your upper arms stationary throughout the exercise. Step:5 Lower the rope behind your head by bending your elbows until your forearms touch your biceps. Step:6 Pause for a moment, then extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing concentration curl', 'barbell standing concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up. Step:2 Rest your opposite hand on your thigh for support. Step:3 Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the weight back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse preacher curl', 'cable reverse preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the preacher curl pad is at chest height. Step:2 Sit on the preacher curl bench and place your upper arms on the pad, with your palms facing down and your elbows fully extended. Step:3 Grab the cable handles with an underhand grip, shoulder-width apart. Step:4 Keeping your upper arms stationary, exhale and curl the handles towards your shoulders, contracting your biceps. Step:5 Pause for a moment at the top of the movement, squeezing your biceps. Step:6 Inhale and slowly lower the handles back to the starting position, fully extending your elbows. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever pullover', 'lever pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat and handles of the leverage machine to a comfortable position. Step:2 Sit on the machine with your back against the pad and grasp the handles with an overhand grip. Step:3 Keep your arms slightly bent and your core engaged. Step:4 Slowly pull the handles towards your chest, squeezing your lats. Step:5 Pause for a moment at the peak contraction, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated bradford rocky press', 'barbell seated bradford rocky press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward. Step:4 Press the barbell overhead, fully extending your arms. Step:5 Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up (wall)', 'push-up (wall)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall, about arm''s length away. Step:2 Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart. Step:3 Step back a few feet, keeping your body straight and your feet hip-width apart. Step:4 Bend your elbows and lower your chest towards the wall, keeping your body in a straight line. Step:5 Push back up to the starting position, straightening your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell one arm clean and jerk', 'kettlebell one arm clean and jerk', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip. Step:2 Bend your knees slightly and hinge at the hips, lowering the kettlebell between your legs. Step:3 Explosively extend your hips, knees, and ankles, using the momentum to swing the kettlebell up to shoulder height. Step:4 As the kettlebell reaches shoulder height, rotate your wrist and punch your hand straight up, locking out your arm overhead. Step:5 Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band reverse fly', 'band reverse fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a stationary object at chest height. Step:2 Stand with your feet shoulder-width apart and hold the band with both hands in front of you. Step:3 Keep your arms straight and lift them out to the sides until they are parallel to the ground. Step:4 Squeeze your shoulder blades together at the top of the movement. Step:5 Slowly lower your arms back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline press on exercise ball', 'dumbbell incline press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in each hand, palms facing forward. Step:2 Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides. Step:4 Press the dumbbells upward, extending your arms fully. Step:5 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell side split squat v. 2', 'barbell side split squat v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards. Step:2 Hold a barbell across your upper back, resting it on your shoulders. Step:3 Take a big step to the side with your right foot, keeping your left foot planted. Step:4 Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight. Step:5 Push through your right heel to return to the starting position. Step:6 Repeat on the other side, stepping out with your left foot. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing twist row (v-bar)', 'cable standing twist row (v-bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a v-bar attachment to a cable machine at chest height. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Grasp the v-bar with an overhand grip, palms facing down. Step:4 Take a step back to create tension in the cable. Step:5 Keep your back straight and core engaged throughout the exercise. Step:6 Pull the v-bar towards your torso by retracting your shoulder blades and bending your elbows. Step:7 As you pull, twist your torso to one side, squeezing your shoulder blades together. Step:8 Pause for a moment at the top of the movement, feeling the contraction in your upper back. Step:9 Slowly release the tension and return to the starting position, untwisting your torso. Step:10 Repeat the movement for the desired number of repetitions, alternating the twisting direction with each rep.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith machine incline tricep extension', 'smith machine incline tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the smith machine so that the bar is at shoulder height. Step:2 Sit on the bench with your back against the pad and your feet flat on the ground. Step:3 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:4 Extend your arms fully, lifting the bar off the rack and holding it directly above your chest. Step:5 Lower the bar slowly towards your forehead, keeping your elbows close to your head. Step:6 Pause for a moment at the bottom, then push the bar back up to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dead bug', 'dead bug', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your arms extended towards the ceiling. Step:2 Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees. Step:3 Engage your core and lower back to press your lower back into the ground. Step:4 Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor. Step:5 Pause for a moment, then return to the starting position. Step:6 Repeat the movement with your left arm and right leg. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('olympic barbell hammer curl', 'olympic barbell hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold an Olympic barbell with an overhand grip. Step:2 Let the barbell hang at arm''s length in front of your thighs, with your palms facing your body. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the barbell back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('v-sit on floor', 'v-sit on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the floor with your legs extended in front of you. Step:2 Lean back slightly and lift your legs off the ground, keeping them straight. Step:3 Simultaneously, lift your upper body off the ground and reach your arms towards your legs. Step:4 Hold this position for a few seconds, then slowly lower your upper body and legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push up on bosu ball', 'push up on bosu ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the bosu ball on the ground with the flat side facing up. Step:2 Position yourself in a push-up position with your hands on the outer edges of the bosu ball. Step:3 Engage your core and lower your body down towards the bosu ball by bending your elbows. Step:4 Push yourself back up to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side hip abduction', 'side hip abduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your hands on your hips. Step:2 Shift your weight to one leg and lift the opposite leg out to the side, keeping it straight. Step:3 Pause for a moment at the top, then slowly lower your leg back down to the starting position. Step:4 Repeat on the other side. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated hammer curl', 'dumbbell seated hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended straight down. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band kneeling twisting crunch', 'band kneeling twisting crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point at waist height. Step:2 Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides. Step:3 Engage your abs and slowly twist your torso to one side, bringing your hands towards your opposite hip. Step:4 Pause for a moment, then slowly return to the starting position. Step:5 Repeat on the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('walking on incline treadmill', 'walking on incline treadmill', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the incline level on the treadmill to your desired intensity. Step:2 Stand on the treadmill with your feet shoulder-width apart. Step:3 Start walking at a comfortable pace, ensuring that you maintain proper form. Step:4 Engage your core muscles and keep your back straight throughout the exercise. Step:5 Continue walking on the incline treadmill for the desired duration of your cardio workout. Step:6 Gradually decrease the incline and speed of the treadmill to cool down before stopping.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wrist rollerer', 'wrist rollerer', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a weight to one end of a rope or bar. Step:2 Hold the other end of the rope or bar with both hands, palms facing down. Step:3 Stand with your feet shoulder-width apart and your arms fully extended in front of you. Step:4 Slowly roll the weight up towards your hands by flexing your wrists. Step:5 Pause for a moment at the top, then slowly lower the weight back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted sissy squat', 'weighted sissy squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your toes pointing slightly outward. Step:2 Hold a weight in front of your chest with both hands, or place a barbell across your upper back. Step:3 Keeping your chest up and your core engaged, slowly lower your body down by bending at the knees and hips. Step:4 Continue lowering until your thighs are parallel to the ground or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell step-up lunge', 'dumbbell step-up lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a step or platform with a dumbbell in each hand, palms facing your sides. Step:2 Place your right foot on the step, ensuring your entire foot is on the surface. Step:3 Push through your right heel and lift your body up onto the step, bringing your left foot up as well. Step:4 Once both feet are on the step, lower your left foot back down to the starting position, keeping your right foot on the step. Step:5 Repeat the movement, alternating which foot you step up with each time. Step:6 Continue for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('spine twist', 'spine twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you. Step:2 Bend your knees and place your feet flat on the ground, hip-width apart. Step:3 Place your hands behind your head with your elbows pointing outwards. Step:4 Engage your abs and slowly twist your torso to the right, bringing your right elbow towards your left knee. Step:5 Pause for a moment at the end of the twist, then slowly return to the starting position. Step:6 Repeat the twist to the left side, bringing your left elbow towards your right knee. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('seated piriformis stretch', 'seated piriformis stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you. Step:2 Bend your right knee and place your right foot on the outside of your left knee. Step:3 Place your left elbow on the outside of your right knee and gently twist your torso to the right. Step:4 Hold the stretch for 20-30 seconds, then switch sides and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('seated wide angle pose sequence', 'seated wide angle pose sequence', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in a wide angle. Step:2 Flex your feet and engage your quadriceps. Step:3 Place your hands on the ground behind you for support. Step:4 Keeping your back straight, lean forward from your hips. Step:5 Continue leaning forward until you feel a stretch in your hamstrings. Step:6 Hold this position for a few breaths. Step:7 Slowly release the stretch and return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell full squat', 'barbell full squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the barbell across your upper back, resting it on your traps or rear delts. Step:3 Engage your core and keep your chest up as you begin to lower your body down. Step:4 Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Step:5 Lower yourself until your thighs are parallel to the ground or slightly below. Step:6 Keep your knees in line with your toes and your weight in your heels. Step:7 Drive through your heels to stand back up, extending your hips and knees. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rear delt row (stirrups)', 'cable rear delt row (stirrups)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a stirrup handle to a low cable pulley and stand facing the machine. Step:2 Grasp the handle with your left hand and take a step back with your right foot, positioning your body at a slight angle. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged. Step:4 With your left arm extended and your palm facing down, pull the handle towards your chest by retracting your shoulder blade. Step:5 Pause for a moment at the top of the movement, squeezing your shoulder blade. Step:6 Slowly release the handle back to the starting position and repeat for the desired number of repetitions. Step:7 Switch sides and repeat the exercise with your right arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell arnold press', 'dumbbell arnold press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent. Step:2 Press the dumbbells upward until your arms are fully extended and your palms are facing forward. Step:3 Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('l-sit on floor', 'l-sit on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the floor with your legs extended in front of you. Step:2 Place your hands on the floor beside your hips, fingers pointing forward. Step:3 Engage your core and lift your legs off the ground, keeping them straight. Step:4 Try to bring your legs parallel to the floor, forming an ''L'' shape with your body. Step:5 Hold this position for as long as you can. Step:6 Slowly lower your legs back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight squatting row', 'bodyweight squatting row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended. Step:2 Lower your body into a squat position, keeping your back straight and your knees behind your toes. Step:3 From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted round arm', 'weighted round arm', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Raise your arms out to the sides, keeping a slight bend in your elbows. Step:4 Continue lifting your arms until they are parallel to the ground. Step:5 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying supine curl', 'dumbbell lying supine curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell bent arm pullover', 'barbell bent arm pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet on the floor. Step:2 Hold a barbell with a shoulder-width grip and extend your arms straight above your chest. Step:3 Lower the barbell behind your head while keeping your arms slightly bent. Step:4 Pause for a moment, then raise the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable overhead curl on exercise ball', 'cable overhead curl on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball and hold the cable handle with an underhand grip. Step:2 Extend your arms fully overhead, keeping your elbows close to your ears. Step:3 Slowly curl the cable down towards your forehead, keeping your upper arms stationary. Step:4 Pause for a moment at the bottom of the movement, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying lifting (on hip)', 'barbell lying lifting (on hip)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back on a bench with your feet flat on the ground and your knees bent. Step:2 Hold the barbell with an overhand grip and position it on your hips. Step:3 Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Step:4 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band squat row', 'band squat row', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point at waist height. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Hold the band handles with your palms facing each other and your arms extended in front of you. Step:4 Bend your knees and lower into a squat position, keeping your back straight and chest lifted. Step:5 From the squat position, pull the band handles towards your body, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly release the tension and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell wide squat', 'barbell wide squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Step:2 Hold the barbell across your upper back, resting it on your traps or rear delts. Step:3 Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees. Step:4 Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated chest press', 'cable seated chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and cable handles to a comfortable position. Step:2 Sit on the bench with your back straight and feet flat on the floor. Step:3 Grasp the cable handles with an overhand grip at shoulder height. Step:4 Push the handles forward and away from your body, extending your arms fully. Step:5 Pause for a moment, then slowly bring the handles back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell one arm floor press', 'kettlebell one arm floor press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back on the floor with your knees bent and feet flat on the ground. Step:2 Hold the kettlebell in one hand with your palm facing towards your feet and your arm extended straight up towards the ceiling. Step:3 Slowly lower the kettlebell towards your chest by bending your elbow, keeping your upper arm close to your body. Step:4 Pause for a moment when the kettlebell is just above your chest, then push it back up to the starting position by extending your elbow. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell push press', 'dumbbell push press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level. Step:2 Bend your knees slightly and dip your body down, then explosively extend your legs and press the dumbbells overhead. Step:3 Lock out your arms at the top of the movement, then lower the dumbbells back to shoulder level. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one arm slam (with medicine ball)', 'one arm slam (with medicine ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding the medicine ball with one hand in front of your waist. Step:2 Bend your knees slightly and engage your core. Step:3 Raise the medicine ball above your head, fully extending your arm. Step:4 Forcefully slam the medicine ball down to the ground, using your core and shoulders to generate power. Step:5 Catch the medicine ball on the bounce and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band lying hip internal rotation', 'band lying hip internal rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your legs straight and a resistance band looped around your feet. Step:2 Bend your knees and bring them towards your chest, keeping your feet together. Step:3 Slowly rotate your knees outwards, away from each other, while keeping your feet together. Step:4 Pause for a moment at the end of the rotation, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up', 'push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Engage your core and lower your body towards the ground by bending your elbows, keeping your body in a straight line. Step:3 Pause for a moment when your chest is just above the ground, then push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted pull-up', 'assisted pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired weight and height settings. Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang with your arms fully extended and your feet off the ground. Step:4 Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body. Step:5 Continue pulling until your chin is above the handles. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('mountain climber', 'mountain climber', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Step:2 Engage your core and bring your right knee towards your chest, then quickly switch and bring your left knee towards your chest. Step:3 Continue alternating legs in a running motion, keeping your hips low and your core engaged. Step:4 Maintain a steady pace and breathe evenly throughout the exercise. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternate hammer preacher curl', 'dumbbell alternate hammer preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with a dumbbell in each hand, palms facing your torso and arms fully extended. Step:2 Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the recommended amount of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable incline fly', 'cable incline fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a low position and attach the handles. Step:2 Sit on an incline bench with your back against the pad and feet flat on the floor. Step:3 Grasp the handles with an overhand grip and extend your arms straight out in front of you. Step:4 Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Step:5 Pause for a moment at the fully extended position, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell hang clean', 'kettlebell hang clean', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Lower the kettlebell towards the ground, allowing it to swing between your legs. Step:4 Quickly extend your hips and knees, using the momentum to swing the kettlebell up to shoulder height. Step:5 As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbow tucked in and the kettlebell resting on your forearm. Step:6 Lower the kettlebell back down to the starting position between your legs, and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell rear fly', 'dumbbell rear fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Extend your arms straight down towards the ground, palms facing each other. Step:4 Keeping a slight bend in your elbows, lift your arms out to the sides and squeeze your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing preacher curl', 'dumbbell standing preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand upright with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Step:2 Rest the back of your upper arms against the preacher bench or an incline bench, with your elbows slightly bent. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('olympic barbell triceps extension', 'olympic barbell triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and holding the barbell with an overhand grip. Step:2 Raise the barbell above your head, fully extending your arms. Step:3 Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated overhead curl', 'cable seated overhead curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench facing the cable machine with your feet flat on the ground. Step:2 Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart. Step:3 Keep your upper arms stationary and your elbows close to your sides. Step:4 Exhale and curl the cable attachment towards your shoulders, contracting your biceps. Step:5 Pause for a moment at the top of the movement, squeezing your biceps. Step:6 Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever back extension', 'lever back extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to fit your body size and range of motion. Step:2 Sit on the machine with your back against the pad and your feet secured. Step:3 Place your hands on the handles or grip bars. Step:4 Engage your core and slowly lean forward, allowing your back to round slightly. Step:5 Pause for a moment at the bottom position, feeling a stretch in your lower back. Step:6 Using your back muscles, slowly raise your torso back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith reverse grip bent over row', 'smith reverse grip bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the bar at hip height. Step:2 Stand facing the bar with your feet shoulder-width apart. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Grasp the bar with an underhand grip, hands shoulder-width apart. Step:5 Pull the bar towards your lower chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower the bar back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm prone curl', 'dumbbell one arm prone curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with a dumbbell in one hand, palm facing down. Step:2 Extend your arm fully, letting it hang straight down towards the floor. Step:3 Keeping your upper arm stationary, curl the dumbbell up towards your shoulder by contracting your biceps. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith one arm row', 'smith one arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the height of the smith machine bar to waist level. Step:2 Stand facing the smith machine with your feet shoulder-width apart. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Grasp the bar with one hand using an overhand grip, with your palm facing down. Step:5 Keep your elbow close to your body and pull the bar towards your waist, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly lower the bar back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing leg calf raise', 'barbell standing leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place a barbell across your upper back. Step:2 Raise your heels off the ground as high as possible, using your calves. Step:3 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing cross-over high reverse fly', 'cable standing cross-over high reverse fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a D-handle to each side of a cable machine at shoulder height. Step:2 Stand in the middle of the cable machine with your feet shoulder-width apart. Step:3 Grasp the handles with an overhand grip and extend your arms out to the sides, palms facing forward. Step:4 Keep a slight bend in your elbows and maintain a straight back throughout the exercise. Step:5 Engage your shoulder muscles and squeeze your shoulder blades together as you pull the handles towards the front of your body. Step:6 Pause for a moment at the peak of the movement, then slowly return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('gironda sternum chin', 'gironda sternum chin', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a high bar with your feet shoulder-width apart. Step:2 Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang from the bar with your arms fully extended and your body straight. Step:4 Engage your lats and biceps to pull your chest up towards the bar, leading with your sternum. Step:5 Pause for a moment at the top, then slowly lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverted row v. 2', 'inverted row v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a bar at waist height on a Smith machine or use a suspension trainer. Step:2 Stand facing the bar or suspension trainer and grab it with an overhand grip, hands shoulder-width apart. Step:3 Walk your feet forward, leaning back until your body is at a slight angle. Step:4 Keep your body straight and pull your chest up towards the bar or handles, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith front squat (clean grip)', 'smith front squat (clean grip)', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the barbell at shoulder height. Step:2 Stand facing the barbell with your feet shoulder-width apart. Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:4 Step back and position the barbell on your front shoulders, resting it on your collarbone and deltoids. Step:5 Keep your chest up, back straight, and core engaged. Step:6 Lower your body by bending at the knees and hips, as if sitting back into a chair. Step:7 Continue lowering until your thighs are parallel to the ground or slightly below. Step:8 Pause for a moment, then push through your heels to return to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing overhead press', 'dumbbell standing overhead press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward. Step:2 Press the dumbbells upward until your arms are fully extended overhead. Step:3 Pause for a moment at the top, then slowly lower the dumbbells back down to shoulder level. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rear pulldown', 'cable rear pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the pulley is at the highest position. Step:2 Sit facing the machine with your feet flat on the ground and your knees slightly bent. Step:3 Grasp the cable attachment with an overhand grip, hands slightly wider than shoulder-width apart. Step:4 Lean back slightly, keeping your back straight and your chest up. Step:5 Pull the cable attachment down towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, then slowly release the cable back up to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm hammer press on exercise ball', 'dumbbell one arm hammer press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with your palm facing inwards and your elbow bent at a 90-degree angle. Step:3 Place your other hand on your hip for stability. Step:4 Press the dumbbell upwards, extending your arm fully. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing around world', 'dumbbell standing around world', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Extend your arms straight out to the sides at shoulder height, palms facing down. Step:3 Keeping your arms straight, slowly rotate your arms in a circular motion, bringing the dumbbells in front of your body and then overhead. Step:4 Continue the circular motion, bringing the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever t bar row', 'lever t bar row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footplate position to ensure proper alignment. Step:2 Sit on the machine with your chest against the pad and your feet flat on the footplate. Step:3 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:4 Keep your back straight and engage your core. Step:5 Pull the handles towards your torso, squeezing your shoulder blades together. Step:6 Pause for a moment at the peak contraction, then slowly release the handles back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('modified push up to lower arms', 'modified push up to lower arms', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands directly under your shoulders and your body in a straight line. Step:2 Lower your body down towards the ground by bending your elbows, keeping them close to your sides. Step:3 Once your elbows are at a 90-degree angle, lower your forearms to the ground, keeping your elbows directly under your shoulders. Step:4 Pause for a moment, then push through your palms to lift your forearms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled hack squat', 'sled hack squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a comfortable position for your height. Step:2 Stand with your feet shoulder-width apart on the platform, toes slightly pointed outwards. Step:3 Hold onto the handles or bars for stability. Step:4 Lower your body by bending your knees and hips, keeping your back straight and chest up. Step:5 Continue lowering until your thighs are parallel to the ground or slightly below. Step:6 Pause for a moment, then push through your heels to raise your body back up to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated triceps extension', 'dumbbell seated triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell with both hands and extend your arms straight up overhead. Step:3 Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears. Step:4 Pause for a moment, then straighten your arms and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith deadlift', 'smith deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the bar at hip height. Step:2 Stand with your feet shoulder-width apart, toes pointing slightly outward. Step:3 Bend at the hips and knees, keeping your back straight and chest up, and grip the bar with an overhand grip slightly wider than shoulder-width apart. Step:4 Engage your core and lift the bar by extending your hips and knees, keeping the bar close to your body. Step:5 Stand up straight, fully extending your hips and knees. Step:6 Lower the bar back down by bending at the hips and knees, maintaining control and keeping your back straight. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell palm rotational bent over row', 'dumbbell palm rotational bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Bend forward at the hips, keeping your back straight and your knees slightly bent. Step:3 Let your arms hang straight down, palms facing your body. Step:4 Engage your core and pull the dumbbells up towards your chest, keeping your elbows close to your body. Step:5 As you pull the dumbbells up, rotate your palms so they face away from your body. Step:6 Squeeze your shoulder blades together at the top of the movement. Step:7 Slowly lower the dumbbells back down to the starting position, rotating your palms back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing triceps extension', 'dumbbell standing triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand. Step:2 Raise the dumbbell overhead, keeping your arm straight. Step:3 Bend your elbow and lower the dumbbell behind your head, keeping your upper arm stationary. Step:4 Extend your arm back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable drag curl', 'cable drag curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Grasp the cable attachment with an underhand grip, palms facing up, and arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders by contracting your biceps. Step:4 Pause for a moment at the top of the movement, squeezing your biceps. Step:5 Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band twisting overhead press', 'band twisting overhead press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band under your feet. Step:2 Hold the band handles at shoulder height with your palms facing forward. Step:3 Engage your core and press the band overhead, fully extending your arms. Step:4 As you press, twist your torso to one side, keeping your hips stable. Step:5 Pause for a moment at the top, then return to the starting position. Step:6 Repeat the press and twist on the opposite side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing crunch', 'cable standing crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable handle to a high pulley and stand facing away from the machine. Step:2 Hold the handle with both hands and place it behind your head, keeping your elbows bent. Step:3 Stand with your feet shoulder-width apart and your knees slightly bent. Step:4 Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs. Step:5 Pause for a moment at the bottom of the movement, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell rear lateral raise (support head)', 'dumbbell rear lateral raise (support head)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball one legged diagonal kick hamstring curl', 'exercise ball one legged diagonal kick hamstring curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your back with your legs extended and your heels resting on top of the stability ball. Step:2 Place your arms by your sides for stability. Step:3 Engage your glutes and core muscles to lift your hips off the ground, creating a straight line from your shoulders to your heels. Step:4 Bend your right knee and bring it towards your chest, keeping your left leg extended and your foot flexed. Step:5 Kick your right leg diagonally across your body, extending it fully and engaging your hamstrings. Step:6 Slowly return your right leg to the starting position, maintaining control and stability. Step:7 Repeat the movement with your left leg, alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable incline pushdown', 'cable incline pushdown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a high pulley cable machine. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:4 Lean forward slightly and keep your back straight. Step:5 Pull the bar down towards your thighs by extending your elbows. Step:6 Pause for a moment at the bottom, then slowly return the bar to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('shoulder grip pull-up', 'shoulder grip pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with a shoulder-width grip, palms facing away from you. Step:2 Hang freely with your arms fully extended. Step:3 Engage your back muscles and pull your body up towards the bar until your chin is above the bar. Step:4 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline scapula push up', 'incline scapula push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Place your hands on the bench slightly wider than shoulder-width apart. Step:3 Position your feet on the ground, hip-width apart. Step:4 Lower your chest towards the bench, keeping your elbows tucked in. Step:5 As you lower, retract your shoulder blades, squeezing your scapulae together. Step:6 Push through your palms to extend your arms and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable two arm curl on incline bench', 'cable two arm curl on incline bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with your back against the pad and your feet flat on the ground. Step:2 Grasp the cable handles with an underhand grip, palms facing up, and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl the handles towards your shoulders while contracting your biceps. Step:4 Pause for a moment at the top of the movement, squeezing your biceps. Step:5 Inhale and slowly lower the handles back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging straight leg raise', 'hanging straight leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up in front of you, keeping them straight. Step:3 Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted sit-up', 'assisted sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench or have someone hold your feet down. Step:2 Lie flat on your back with your knees bent and feet flat on the ground. Step:3 Place your hands behind your head with your elbows pointing outwards. Step:4 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:5 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing wide-grip curl', 'barbell standing wide-grip curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart. Step:2 Let the barbell hang at arm''s length in front of your thighs, with your palms facing away from your body. Step:3 Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps. Step:4 Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the barbell back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('battling ropes', 'battling ropes', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold one end of the rope in each hand, with your palms facing each other. Step:3 Raise your arms to shoulder height, keeping your elbows slightly bent. Step:4 Begin making alternating waves with the ropes by rapidly raising and lowering each arm. Step:5 Continue for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell hammer curl on exercise ball', 'dumbbell hammer curl on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing your body and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell rear lunge v. 2', 'barbell rear lunge v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell across your upper back. Step:2 Take a step backward with your right foot, landing on the ball of your foot. Step:3 Bend both knees to lower your body until your left thigh is parallel to the ground. Step:4 Push through your left heel to return to the starting position. Step:5 Repeat with the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever reverse t-bar row', 'lever reverse t-bar row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footplate position on the leverage machine. Step:2 Sit on the machine with your chest against the pad and your feet flat on the footplate. Step:3 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:4 Keep your back straight and engage your core. Step:5 Pull the handles towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell double push press', 'kettlebell double push press', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Step:2 Bend your knees slightly and engage your core. Step:3 Initiate the movement by explosively extending your hips, knees, and ankles, driving the kettlebells overhead. Step:4 As the kettlebells reach the top, press them fully overhead, locking out your arms. Step:5 Lower the kettlebells back to the starting position by bending your elbows and bringing them back down to shoulder height. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reclining big toe pose with rope', 'reclining big toe pose with rope', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your legs extended and your arms by your sides. Step:2 Loop the rope around the ball of your right foot and hold the ends of the rope with your hands. Step:3 Slowly raise your right leg towards your chest, keeping your knee straight and your foot flexed. Step:4 Hold the stretch for a few seconds, then slowly lower your leg back down to the starting position. Step:5 Repeat with your left leg. Step:6 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('mixed grip chin-up', 'mixed grip chin-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an underhand grip (palms facing towards you) and your hands slightly wider than shoulder-width apart. Step:2 Hang from the bar with your arms fully extended and your feet off the ground. Step:3 Engage your back muscles and pull your body up towards the bar, leading with your chest. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position with control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('deep push up', 'deep push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line. Step:2 Lower your chest towards the ground by bending your elbows, keeping them close to your body. Step:3 Push through your palms to extend your arms and return to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('crab twist toe touch', 'crab twist toe touch', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by sitting on the ground with your knees bent and feet flat on the floor. Step:2 Place your hands behind you, fingers pointing towards your feet, and lift your hips off the ground. Step:3 Extend one leg straight out in front of you while simultaneously reaching your opposite hand towards your toes. Step:4 Return to the starting position and repeat on the other side. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('jump squat', 'jump squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Lower your body into a squat position by bending your knees and pushing your hips back. Step:3 Jump explosively off the ground, extending your hips, knees, and ankles. Step:4 While in mid-air, quickly bring your arms forward for balance. Step:5 Land softly on the balls of your feet and immediately go into the next repetition. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell upright row', 'dumbbell upright row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Let the dumbbells hang in front of your thighs, with your arms fully extended. Step:3 Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm preacher curl', 'cable one arm preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the preacher curl pad is at chest height. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Grasp the cable handle with an underhand grip and position your upper arm against the preacher curl pad. Step:4 Keep your back straight and your core engaged. Step:5 Slowly curl the cable handle towards your shoulder, keeping your upper arm against the pad. Step:6 Pause for a moment at the top of the movement, squeezing your biceps. Step:7 Slowly lower the cable handle back to the starting position. Step:8 Repeat for the desired number of repetitions. Step:9 Switch arms and repeat the exercise.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell double jerk', 'kettlebell double jerk', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height. Step:2 Bend your knees slightly and engage your core. Step:3 Press the kettlebells overhead, fully extending your arms. Step:4 Bend your knees and quickly drop into a partial squat. Step:5 Explosively extend your hips and knees, driving the kettlebells overhead. Step:6 Lock out your arms and catch the kettlebells overhead with your knees slightly bent. Step:7 Stand up straight and return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell step-up', 'barbell step-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a bench or step with a barbell resting on your upper back. Step:2 Place one foot on the bench or step, ensuring your entire foot is in contact with the surface. Step:3 Push through your heel and step up onto the bench or step, fully extending your hip and knee. Step:4 Pause briefly at the top, then lower yourself back down to the starting position. Step:5 Repeat with the opposite leg. Step:6 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band front lateral raise', 'band front lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down. Step:2 Keep your arms straight and lift the band up in front of you until your arms are parallel to the ground. Step:3 Pause for a moment at the top, then slowly lower the band back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('butterfly yoga pose', 'butterfly yoga pose', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the floor with your legs extended in front of you. Step:2 Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides. Step:3 Hold onto your ankles or feet with your hands. Step:4 Sit up tall and lengthen your spine. Step:5 Gently press your knees down towards the floor, feeling a stretch in your inner thighs. Step:6 Hold this position for a few breaths. Step:7 To release, slowly bring your knees back up and extend your legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('two toe touch (male)', 'two toe touch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms extended out to the sides. Step:2 Bend forward at the waist, keeping your back straight and your knees slightly bent. Step:3 Reach down towards your toes with both hands, keeping your legs straight. Step:4 Pause for a moment at the bottom, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lateral pulldown (with rope attachment)', 'cable lateral pulldown (with rope attachment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope attachment to the cable machine at a high position. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the rope with an overhand grip, palms facing each other. Step:4 Keep your back straight and lean slightly back. Step:5 Pull the rope down towards your sides, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement. Step:7 Slowly release the tension and allow the rope to return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline curl v. 2', 'dumbbell incline curl v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hands bike', 'hands bike', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and handlebar position to a comfortable level. Step:2 Sit on the ergometer with your back straight and feet on the pedals. Step:3 Grasp the handles with your hands and position your arms at a 90-degree angle. Step:4 Start pedaling with your hands, pushing and pulling the handles in a controlled motion. Step:5 Continue pedaling for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever high row', 'lever high row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and foot platform to a comfortable position. Step:2 Sit on the machine with your chest against the pad and your feet flat on the foot platform. Step:3 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:4 Keep your back straight and engage your core. Step:5 Pull the handles towards your body, squeezing your shoulder blades together. Step:6 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('knee touch crunch', 'knee touch crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, lift your shoulder blades off the ground and reach your right hand towards your left knee. Step:4 Return to the starting position and repeat, this time reaching your left hand towards your right knee. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('drop push up', 'drop push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart. Step:2 Lower your chest towards the ground, keeping your elbows close to your body. Step:3 Once your chest is just above the ground, quickly drop your knees to the ground. Step:4 Push yourself back up to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell guillotine bench press', 'barbell guillotine bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lower the barbell slowly towards your neck, keeping your elbows pointed outwards. Step:4 Pause for a moment when the barbell is just above your neck. Step:5 Push the barbell back up to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm standing hammer curl', 'dumbbell one arm standing hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your torso. Step:2 Keep your elbows close to your torso and your upper arms stationary. Step:3 Exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell romanian deadlift', 'dumbbell romanian deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your knees to bend slightly. Step:3 Lower the dumbbells until you feel a stretch in your hamstrings, then push through your heels and engage your glutes to return to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated high row (v-bar)', 'cable seated high row (v-bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the cable machine with your feet flat on the floor and your knees slightly bent. Step:2 Grasp the v-bar attachment with an overhand grip, palms facing each other, and your hands shoulder-width apart. Step:3 Keep your back straight and lean slightly forward from the hips. Step:4 Pull the v-bar towards your torso by retracting your shoulder blades and squeezing your back muscles. Step:5 Pause for a moment at the peak of the contraction, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing alternate raise', 'dumbbell standing alternate raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body. Step:2 Keep your back straight and your core engaged. Step:3 Raise one dumbbell to the side, keeping your arm straight and your palm facing down. Step:4 Continue lifting until your arm is parallel to the ground. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:6 Repeat with the other arm. Step:7 Alternate between arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying alternate extension', 'dumbbell lying alternate extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing each other. Step:2 Extend your arms straight up over your chest, keeping a slight bend in your elbows. Step:3 Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended. Step:4 Pause for a moment at the bottom, then raise the dumbbell back up to the starting position. Step:5 Repeat with the other arm, alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted standing curl', 'weighted standing curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Step:2 Keep your elbows close to your torso and exhale as you curl the weights up to shoulder level. Step:3 Pause for a moment at the top, then inhale as you slowly lower the weights back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell arnold press v. 2', 'dumbbell arnold press v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent. Step:2 Press the dumbbells upward until your arms are fully extended and your palms are facing forward. Step:3 Rotate your wrists as you lift, so that your palms end up facing forward at the top of the movement. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable side crunch', 'cable side crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable handle to a low pulley and stand sideways to the machine. Step:2 Grasp the handle with the hand furthest from the machine and place your other hand on your hip. Step:3 Keep your feet shoulder-width apart and your knees slightly bent. Step:4 With your abs engaged, bend sideways at the waist, bringing your elbow down towards your hip. Step:5 Pause for a moment at the bottom, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('stability ball crunch (full range hands behind head)', 'stability ball crunch (full range hands behind head)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly curl your upper body forward, bringing your chest towards your knees. Step:4 Pause for a moment at the top, then slowly lower your upper body back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell shrug', 'barbell shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip. Step:2 Keep your arms straight and your back straight throughout the exercise. Step:3 Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top. Step:4 Hold for a moment, then slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever shrug', 'lever shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the leverage machine with your back against the pad. Step:2 Grasp the handles with an overhand grip and keep your arms straight. Step:3 Keeping your back straight, lift your shoulders up towards your ears as high as possible. Step:4 Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('clock push-up', 'clock push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Step:2 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:3 As you lower, rotate your body to the left, extending your left arm straight out to the side. Step:4 Push back up to the starting position, while rotating your body to the center. Step:5 Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side. Step:6 Continue alternating sides with each repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell shrug', 'dumbbell shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body. Step:2 Keep your arms straight and let the dumbbells hang by your sides. Step:3 Raise your shoulders as high as possible, as if you are trying to touch your ears with your shoulders. Step:4 Hold the contraction for a second, then slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band bench press', 'band bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the band handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Extend your arms fully, pushing the bands away from your chest. Step:4 Slowly lower the bands back down to your chest, keeping your elbows at a 90-degree angle. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lateral raise', 'cable lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip. Step:2 Keep your arms straight and your core engaged. Step:3 Raise your arms out to the sides until they are parallel to the floor. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable forward raise', 'cable forward raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Hold the cable handle with an overhand grip, palms facing down, and your arms fully extended in front of you. Step:3 Keeping your arms straight, raise the cable handle up to shoulder level. Step:4 Pause for a moment at the top, then slowly lower the cable handle back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing palms in press', 'dumbbell standing palms in press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing inwards. Step:2 Keeping your core engaged and your back straight, press the dumbbells upwards until your arms are fully extended overhead. Step:3 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball lat stretch', 'exercise ball lat stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand and extend your arm straight up overhead. Step:3 Slowly lean to the opposite side, feeling a stretch in your lat muscle. Step:4 Hold the stretch for 20-30 seconds, then return to the starting position. Step:5 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lower back curl', 'lower back curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your stomach with your legs extended and your arms by your sides. Step:2 Engage your glutes and hamstrings, and slowly lift your upper body off the ground, curling your back upwards. Step:3 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triceps dip (bench leg)', 'triceps dip (bench leg)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward. Step:2 Walk your feet forward, sliding your butt off the bench, and straighten your arms. Step:3 Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Step:4 Push through your palms to straighten your arms and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball supine chest throw', 'medicine ball supine chest throw', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back on a bench with your knees bent and feet flat on the ground. Step:2 Hold the medicine ball with both hands, extending your arms straight up above your chest. Step:3 Lower the medicine ball towards your chest, keeping your elbows close to your body. Step:4 Explosively push the medicine ball upwards, extending your arms fully and throwing the ball as high as possible. Step:5 Catch the medicine ball and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band bent-over hip extension', 'band bent-over hip extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point at ankle height. Step:2 Stand facing away from the anchor point with your feet shoulder-width apart. Step:3 Step back to create tension in the band, keeping your knees slightly bent. Step:4 Hinge at the hips and lean forward, maintaining a neutral spine. Step:5 Extend your right leg straight back, squeezing your glutes at the top. Step:6 Lower your right leg back down and repeat with the left leg. Step:7 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('biceps pull-up', 'biceps pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart. Step:2 Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar. Step:3 Pause at the top of the movement, then slowly lower yourself back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('potty squat with support', 'potty squat with support', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing slightly outward. Step:2 Hold onto a stable support, such as a chair or wall, for balance. Step:3 Lower your body down into a squat position by bending your knees and pushing your hips back. Step:4 Keep your chest up and your back straight throughout the movement. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing calf raise', 'cable standing calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Hold onto the cable machine handles or attach a cable ankle strap to your ankles. Step:3 Raise your heels off the ground by extending your ankles as high as possible. Step:4 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell alternate biceps curl', 'barbell alternate biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward. Step:2 Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps. Step:3 Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale as you slowly begin to lower the barbells back to the starting position. Step:6 Repeat for the desired number of repetitions, alternating arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight standing close-grip one arm row', 'bodyweight standing close-grip one arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip. Step:2 Bend forward at the hips, keeping your back straight and your core engaged. Step:3 Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('forward jump', 'forward jump', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees and lower your body into a squat position. Step:3 Swing your arms back for momentum. Step:4 Jump forward explosively, extending your hips, knees, and ankles. Step:5 Land softly on the balls of your feet and immediately go into the next jump. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable floor seated wide-grip row', 'cable floor seated wide-grip row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the floor with your legs extended and your back straight. Step:2 Attach a cable handle to a low pulley and position the cable machine behind you. Step:3 Grasp the handle with a wide overhand grip, palms facing down. Step:4 Lean back slightly, keeping your back straight and your chest lifted. Step:5 Pull the handle towards your waist, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly release the handle back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band leg extension', 'resistance band leg extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the resistance band to a sturdy anchor point and secure it around your ankle. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Keeping your core engaged and your upper body stable, extend your leg straight out in front of you. Step:4 Pause for a moment at the top, then slowly return your leg to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one leg squat', 'one leg squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Extend one leg forward, keeping it off the ground. Step:3 Bend your standing leg and lower your body down as if sitting back into a chair. Step:4 Keep your chest up and your back straight. Step:5 Push through your heel to return to the starting position. Step:6 Repeat with the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm press on exercise ball', 'dumbbell one arm press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold a dumbbell in one hand and position it at shoulder height, with your elbow bent and palm facing forward. Step:3 Slowly press the dumbbell upward until your arm is fully extended, while keeping your core engaged and maintaining balance on the exercise ball. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('burpee', 'burpee', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a standing position with your feet shoulder-width apart. Step:2 Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you. Step:3 Kick your feet back into a push-up position. Step:4 Perform a push-up, keeping your body in a straight line. Step:5 Jump your feet back into the squat position. Step:6 Jump up explosively, reaching your arms overhead. Step:7 Land softly and immediately lower back into a squat position to begin the next repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('scissor jumps (male)', 'scissor jumps (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Jump off the ground and simultaneously cross your right leg in front of your left leg. Step:3 As you land, quickly switch legs, crossing your left leg in front of your right leg. Step:4 Continue alternating legs and jumping as quickly as possible. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated one arm rotate', 'dumbbell seated one arm rotate', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and hold a dumbbell in one hand, resting it on your thigh. Step:2 Raise the dumbbell up to shoulder height, keeping your elbow close to your body. Step:3 Rotate your forearm outward, away from your body, while keeping your upper arm stationary. Step:4 Pause for a moment at the top, then slowly rotate your forearm back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rear deltoid stretch', 'rear deltoid stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand tall with your feet shoulder-width apart. Step:2 Extend your right arm across your chest, placing your left hand on your right elbow. Step:3 Gently pull your right arm towards your left shoulder, feeling a stretch in your right shoulder. Step:4 Hold the stretch for 15-30 seconds, then release. Step:5 Repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('upward facing dog', 'upward facing dog', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the floor with your legs extended behind you. Step:2 Place your hands on the floor next to your lower ribs, fingers pointing forward. Step:3 Press your hands firmly into the floor and straighten your arms, lifting your torso and thighs off the ground. Step:4 Roll your shoulders back and down, opening your chest and lifting your gaze towards the ceiling. Step:5 Hold this position for a few breaths, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell front raise v. 2', 'dumbbell front raise v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Step:2 Keep your back straight and engage your core. Step:3 Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted close grip chin-up on dip cage', 'weighted close grip chin-up on dip cage', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of the dip cage and grab the parallel bars with an underhand grip, hands shoulder-width apart. Step:2 Hang from the bars with your arms fully extended, feet off the ground, and body straight. Step:3 Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your sides. Step:4 Continue pulling until your chin is above the bars, then pause for a moment. Step:5 Slowly lower your body back down to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted straight bar dip', 'weighted straight bar dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself between parallel bars with your arms fully extended and your body straight. Step:2 Lower your body by bending your elbows until your upper arms are parallel to the ground. Step:3 Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band jack knife sit-up', 'band jack knife sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Step:2 Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet. Step:3 Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell preacher curl', 'barbell preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with your upper arms resting on the pad and your chest against the support. Step:2 Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart. Step:3 Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated one arm concentration curl', 'cable seated one arm concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the floor and your back straight. Step:2 Hold a cable handle with one hand and place your elbow on the inside of your thigh, just above the knee. Step:3 Keep your upper arm stationary and curl the cable handle towards your shoulder while exhaling. Step:4 Pause for a moment at the top of the movement, squeezing your biceps. Step:5 Slowly lower the cable handle back to the starting position while inhaling. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band front raise', 'band front raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down. Step:2 Keep your arms straight and slowly raise them forward until they are parallel to the ground. Step:3 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline twisting sit-up', 'incline twisting sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Lie down on the bench with your feet secured under the foot pads. Step:3 Place your hands behind your head or across your chest. Step:4 Engage your abs and lift your upper body off the bench, curling forward. Step:5 As you curl up, twist your torso to one side, bringing your elbow towards the opposite knee. Step:6 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:7 Repeat the movement, this time twisting your torso to the other side. Step:8 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever reverse hyperextension', 'lever reverse hyperextension', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the leverage machine to fit your body and secure your feet in the foot pads. Step:2 Lie face down on the machine with your upper body hanging off the edge and your hips resting on the pad. Step:3 Cross your arms over your chest or place them behind your head. Step:4 Engage your glutes and hamstrings to lift your legs upward until they are parallel to the ground. Step:5 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell bent press', 'kettlebell bent press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in your right hand. Step:2 Bend your knees slightly and press the kettlebell overhead with your right arm, keeping your elbow locked. Step:3 Rotate your torso to the left, shifting your weight onto your left foot. Step:4 Bend your left knee and lower your torso towards the ground, keeping your right arm extended overhead. Step:5 As you lower, keep your eyes on the kettlebell and your chest lifted. Step:6 Once your left hand touches the ground, push through your left foot and straighten your left leg, driving your hips forward. Step:7 As you drive your hips forward, use your core and right arm to press the kettlebell back up to the starting position. Step:8 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever horizontal one leg press', 'lever horizontal one leg press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the machine so that your knees are at a 90-degree angle when your feet are on the footplate. Step:2 Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate. Step:3 Place your hands on the handles or sides of the machine for stability. Step:4 Push the footplate away from your body by extending your leg, keeping your back against the backrest. Step:5 Pause for a moment at the fully extended position, then slowly bend your leg to return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable triceps pushdown (v-bar) (with arm blaster)', 'cable triceps pushdown (v-bar) (with arm blaster)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a v-bar attachment to the cable machine at the highest setting. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Engage your triceps and exhale as you push the v-bar down until your arms are fully extended. Step:6 Pause for a moment at the bottom of the movement, squeezing your triceps. Step:7 Inhale as you slowly return the v-bar to the starting position, maintaining control. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('outside leg kick push-up', 'outside leg kick push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged. Step:3 As you push back up, kick one leg out to the side, extending it fully and engaging your glutes. Step:4 Return your leg to the starting position and repeat the push-up, alternating legs with each repetition. Step:5 Continue alternating leg kicks and push-ups for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated twist', 'cable seated twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a cable machine with your feet flat on the ground and your knees slightly bent. Step:2 Hold the cable handle with both hands and extend your arms straight in front of you. Step:3 Keeping your core engaged, slowly rotate your torso to one side, pulling the cable across your body. Step:4 Pause for a moment at the end of the range of motion, then slowly rotate back to the starting position. Step:5 Repeat on the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell front squat', 'barbell front squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders. Step:3 Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees. Step:4 Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('front plank with twist', 'front plank with twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe. Step:2 Engage your core and glutes to maintain a stable position. Step:3 Rotate your torso to the right, lifting your right arm and extending it towards the ceiling. Step:4 Keep your hips and legs stable as you twist. Step:5 Hold for a moment, then return to the starting position. Step:6 Repeat the twist on the left side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell close-grip bench press', 'barbell close-grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Step:3 Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Step:4 Pause for a moment when the barbell touches your chest. Step:5 Push the barbell back up to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell over bench one arm reverse wrist curl', 'dumbbell over bench one arm reverse wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down. Step:2 Rest your forearm on the bench with your wrist hanging off the edge. Step:3 Slowly curl your wrist upwards, bringing the dumbbell towards your forearm. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('crunch (on stability ball, arms straight)', 'crunch (on stability ball, arms straight)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Lie back on the ball until your lower back is supported and your upper body is parallel to the floor. Step:3 Place your hands behind your head or cross them over your chest. Step:4 Engage your abs and lift your upper body off the ball, curling your shoulders towards your hips. Step:5 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted standing triceps extension (with towel)', 'assisted standing triceps extension (with towel)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a towel with both hands behind your head. Step:2 Keep your elbows close to your ears and your upper arms stationary. Step:3 Slowly extend your forearms upward, squeezing your triceps at the top. Step:4 Pause for a moment, then slowly lower the towel back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball back extension with rotation', 'exercise ball back extension with rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying face down on the stability ball with your hips resting on the ball and your feet firmly planted on the ground. Step:2 Place your hands behind your head or cross them over your chest. Step:3 Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels. Step:4 Pause for a moment at the top, then slowly rotate your torso to one side, keeping your hips and legs stable. Step:5 Return to the center and repeat the rotation to the other side. Step:6 Lower your upper body back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell jefferson squat', 'barbell jefferson squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and toes slightly turned out. Step:2 Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist. Step:3 Step your left foot forward and your right foot back, keeping your feet shoulder-width apart. Step:4 Bend your knees and lower your body down into a squat position, keeping your back straight and chest up. Step:5 Push through your heels to stand back up to the starting position. Step:6 Repeat the movement, alternating your forward and back foot with each repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm reverse grip press', 'dumbbell one arm reverse grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with a dumbbell in one hand, palm facing towards your body. Step:2 Place your feet flat on the ground and keep your back straight. Step:3 Raise the dumbbell to shoulder height, keeping your elbow close to your body. Step:4 Press the dumbbell upwards until your arm is fully extended. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('twin handle parallel grip lat pulldown', 'twin handle parallel grip lat pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself facing the cable machine. Step:2 Grasp the handles with an overhand grip, hands shoulder-width apart. Step:3 Sit down and position your thighs under the thigh pads, keeping your feet flat on the floor. Step:4 Lean back slightly and keep your chest up, maintaining a neutral spine. Step:5 Pull the handles down towards your upper chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Step:7 Slowly release the handles and return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell around pullover', 'dumbbell around pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet firmly on the ground. Step:2 Hold a dumbbell with both hands and extend your arms straight above your chest. Step:3 Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion. Step:4 Pause for a moment at the bottom, then raise the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith seated wrist curl', 'smith seated wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench in front of a Smith machine with your feet flat on the ground. Step:2 Grasp the barbell with an underhand grip, hands shoulder-width apart. Step:3 Rest your forearms on your thighs, allowing your wrists to hang off. Step:4 Slowly curl your wrists upward, bringing the barbell towards your forearms. Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('muscle-up (on vertical bar)', 'muscle-up (on vertical bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a vertical bar with your palms facing away from you and your arms fully extended. Step:2 Engage your core and pull your body up towards the bar, leading with your chest. Step:3 As you pull yourself up, lean back slightly and bring your elbows towards your sides. Step:4 Continue pulling until your chest reaches the bar and your elbows are fully bent. Step:5 Pause for a moment at the top, then slowly lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated row', 'cable seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Step:2 Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed. Step:3 Pull the handles towards your body, squeezing your shoulder blades together. Step:4 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('leg up hamstring stretch', 'leg up hamstring stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended. Step:2 Bend one knee and bring it towards your chest, holding onto your thigh or shin. Step:3 Straighten your leg as much as possible while keeping it elevated. Step:4 Hold the stretch for 20-30 seconds. Step:5 Repeat with the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('trap bar deadlift', 'trap bar deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and the trap bar on the ground in front of you. Step:2 Bend at the hips and knees to lower yourself down and grip the handles of the trap bar with an overhand grip. Step:3 Keep your back straight and chest up as you begin to lift the trap bar off the ground by extending your hips and knees. Step:4 As you lift, focus on driving through your heels and squeezing your glutes at the top of the movement. Step:5 Lower the trap bar back down to the ground by bending at the hips and knees, keeping your back straight throughout the movement. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('balance board', 'balance board', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the balance board on a flat surface. Step:2 Step onto the balance board with one foot, ensuring it is centered. Step:3 Slowly shift your weight onto the foot on the balance board, keeping your core engaged. Step:4 Maintain your balance and stability as you hold the position for a desired amount of time. Step:5 Repeat the exercise with the other foot.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline raise', 'dumbbell incline raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, resting on your thighs. Step:2 Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward. Step:3 Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing inner biceps curl v. 2', 'dumbbell standing inner biceps curl v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your torso. Step:2 Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. Step:3 While holding your upper arms stationary, curl the weights while contracting your biceps. Step:4 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Slowly begin to bring the dumbbells back to the starting position as your breathe in. Step:7 Repeat for the recommended amount of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('left hook. boxing', 'left hook. boxing', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Keep your left hand up to protect your face and your right hand by your chin. Step:3 Rotate your hips and pivot on your left foot as you extend your left arm forward in a punching motion. Step:4 Twist your torso and engage your core muscles to generate power in the punch. Step:5 Snap your arm back to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled lying calf press', 'sled lying calf press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a comfortable weight. Step:2 Sit on the sled machine with your back against the pad and your feet on the platform. Step:3 Place your toes and the balls of your feet on the edge of the platform, with your heels hanging off. Step:4 Push the platform away from you by extending your ankles, keeping your knees slightly bent. Step:5 Continue pushing until your calves are fully contracted. Step:6 Hold the contraction for a moment, then slowly lower the platform back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball dip', 'exercise ball dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Place your hands on the ball beside your hips, fingers pointing forward. Step:3 Engage your triceps and push through your hands to lift your body off the ball, straightening your arms. Step:4 Lower your body back down by bending your elbows, keeping them close to your sides. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing row (v-bar)', 'cable standing row (v-bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Grasp the v-bar attachment with an overhand grip, palms facing down. Step:3 Keep your back straight and your core engaged. Step:4 Pull the v-bar towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('finger curls', 'finger curls', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up. Step:2 Rest your forearms on your thighs, allowing your wrists to hang off the edge. Step:3 Slowly curl your fingers towards your palms, squeezing the barbell tightly. Step:4 Hold the contraction for a moment, then slowly release your fingers back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('jump rope', 'jump rope', 'Strength', 'Other', 'Intermediate', 'Step:1 Hold the handles of the jump rope with your hands, palms facing inward. Step:2 Stand with your feet shoulder-width apart and knees slightly bent. Step:3 Swing the rope over your head and jump over it as it comes towards your feet. Step:4 Land softly on the balls of your feet and repeat the jump as the rope comes around again. Step:5 Continue jumping for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying wide curl', 'dumbbell lying wide curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated one arm alternate row', 'cable seated one arm alternate row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench facing a cable machine with your feet flat on the ground and knees slightly bent. Step:2 Grasp the handle with one hand and keep your arm fully extended in front of you. Step:3 Pull the handle towards your body, retracting your shoulder blade and keeping your elbow close to your side. Step:4 Pause for a moment at the top of the movement, squeezing your back muscles. Step:5 Slowly release the handle back to the starting position. Step:6 Repeat with the other arm. Step:7 Alternate between arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith upright row', 'smith upright row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the smith machine. Step:2 Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Keep your back straight and your core engaged. Step:4 Pull the barbell up towards your chin, leading with your elbows. Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever standing chest press', 'lever standing chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your feet flat on the ground. Step:2 Grasp the handles with an overhand grip and position your hands at chest level. Step:3 Push the handles forward until your arms are fully extended, keeping your elbows slightly bent. Step:4 Pause for a moment, then slowly bring the handles back towards your chest, maintaining control throughout the movement. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated close grip behind neck triceps extension', 'barbell seated close grip behind neck triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold the barbell with a close grip behind your neck, palms facing forward. Step:3 Keep your elbows close to your head and slowly lower the barbell towards the back of your head. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated shoulder press', 'dumbbell seated shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, resting on your thighs. Step:2 Raise the dumbbells to shoulder height, palms facing forward. Step:3 Press the dumbbells upward until your arms are fully extended overhead. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight standing close-grip row', 'bodyweight standing close-grip row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Bend forward at the waist, keeping your back straight and your core engaged. Step:3 Extend your arms straight in front of you, gripping the bar or handles with a close grip. Step:4 Pull the bar or handles towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the top of the movement, then slowly release and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated neutral wrist curl', 'dumbbell seated neutral wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing each other. Step:2 Rest your forearms on your thighs, allowing the dumbbells to hang down. Step:3 Keeping your wrists in a neutral position, curl the dumbbells up towards your shoulders. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball on the wall calf raise (tennis ball between ankles)', 'exercise ball on the wall calf raise (tennis ball between ankles)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall with your feet shoulder-width apart. Step:2 Place an exercise ball between the wall and your lower back. Step:3 Hold a dumbbell in each hand, with your arms extended by your sides. Step:4 Place a tennis ball between your ankles. Step:5 Raise your heels off the ground, lifting your body up onto your toes. Step:6 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('archer push up', 'archer push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart. Step:2 Extend one arm straight out to the side, parallel to the ground. Step:3 Lower your body by bending your elbows, keeping your back straight and core engaged. Step:4 Push back up to the starting position. Step:5 Repeat on the other side, extending the opposite arm out to the side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('close grip chin-up', 'close grip chin-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart. Step:2 Hang from the bar with your arms fully extended and your feet off the ground. Step:3 Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell bench squat', 'dumbbell bench squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Place a dumbbell on the ground in front of a bench. Step:2 Stand facing away from the bench with your feet shoulder-width apart. Step:3 Bend at the knees and hips to lower yourself down towards the bench, keeping your chest up and back straight. Step:4 Once your glutes touch the bench, push through your heels to stand back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm fly', 'dumbbell incline one arm fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the incline bench to a 30-45 degree angle. Step:2 Sit on the bench with a dumbbell in one hand, resting it on your thigh. Step:3 Lie back on the bench, keeping your feet flat on the ground. Step:4 Hold the dumbbell with your arm extended straight up over your chest. Step:5 Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow. Step:6 Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triceps dips floor', 'triceps dips floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a chair or bench with your hands next to your hips, fingers pointing forward. Step:2 Slide your butt off the front of the chair with your legs extended in front of you. Step:3 Straighten your arms, keeping a little bend in your elbows to keep tension on your triceps and off your elbow joints. Step:4 Slowly bend your elbows to lower your body toward the floor until your elbows are at about a 90-degree angle. Step:5 Once you reach the bottom of the movement, press down into the chair to straighten your elbows, returning to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell pullover to press', 'barbell pullover to press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet on the ground. Step:2 Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest. Step:3 Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats. Step:4 Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('single leg squat (pistol) male', 'single leg squat (pistol) male', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and arms extended in front of you. Step:2 Lift your right foot off the ground and extend it forward. Step:3 Slowly lower your body down by bending your left knee and pushing your hips back. Step:4 Keep your chest up and your back straight as you lower yourself down. Step:5 Lower until your left thigh is parallel to the ground, or as low as you can comfortably go. Step:6 Pause for a moment at the bottom, then push through your left heel to return to the starting position. Step:7 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('45° side bend', '45° side bend', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms extended straight down by your sides. Step:2 Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee. Step:3 Pause for a moment at the bottom, then slowly return to the starting position. Step:4 Repeat on the other side. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell arnold press', 'kettlebell arnold press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height with your palms facing towards you. Step:2 Engage your core and press the kettlebells overhead, rotating your palms to face forward as you extend your arms. Step:3 Pause at the top of the movement, then slowly lower the kettlebells back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band one arm single leg split squat', 'band one arm single leg split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and place a resistance band around your ankles. Step:2 Extend one leg forward and rest the top of your foot on a bench or step behind you. Step:3 Hold onto a support with one hand for balance. Step:4 Bend your standing leg and lower your body down into a squat position, keeping your knee in line with your toes. Step:5 Push through your heel to return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bear crawl', 'bear crawl', 'Strength', 'Other', 'Intermediate', 'Step:1 Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Step:2 Lift your knees slightly off the ground, keeping your back flat and your core engaged. Step:3 Move your right hand and left foot forward simultaneously, followed by your left hand and right foot. Step:4 Continue crawling forward, alternating your hand and foot movements. Step:5 Maintain a steady pace and keep your core tight throughout the exercise. Step:6 Continue for the desired distance or time.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying on floor rear delt raise', 'dumbbell lying on floor rear delt raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the floor with a dumbbell in each hand, palms facing each other. Step:2 Extend your arms straight out in front of you, keeping a slight bend in your elbows. Step:3 Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rear delt row (with rope)', 'cable rear delt row (with rope)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a low pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the rope handle with an overhand grip, palms facing each other. Step:4 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:5 Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball close grip push up', 'medicine ball close grip push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands on the medicine ball, shoulder-width apart. Step:2 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:3 Push back up to the starting position, fully extending your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball on the wall calf raise', 'exercise ball on the wall calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your back against a wall and place an exercise ball between your lower back and the wall. Step:2 Position your feet shoulder-width apart, with your toes pointing forward. Step:3 Hold a dumbbell in each hand, with your arms extended by your sides. Step:4 Raise your heels off the ground, lifting your body weight onto the balls of your feet. Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable judo flip', 'cable judo flip', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Hold the cable handle with both hands at chest level, palms facing down. Step:3 Engage your core and rotate your torso to the right, pulling the cable across your body. Step:4 As you rotate, pivot your back foot and allow your hips to rotate naturally. Step:5 Extend your arms fully and finish the movement by flipping the cable handle over your shoulder. Step:6 Return to the starting position by reversing the movement, rotating your torso back to the center. Step:7 Repeat the movement on the opposite side. Step:8 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('calf stretch with hands against wall', 'calf stretch with hands against wall', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall with your feet hip-width apart. Step:2 Place your hands against the wall at shoulder height. Step:3 Step your right foot back, keeping your heel on the ground and your leg straight. Step:4 Bend your left knee and lean forward, keeping your back leg straight and your heel on the ground. Step:5 Hold the stretch for 20-30 seconds. Step:6 Switch legs and repeat the stretch.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('donkey calf raise', 'donkey calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your toes on an elevated surface, such as a step or block. Step:2 Place your hands on a stable support, such as a wall or railing, for balance. Step:3 Raise your heels as high as possible, lifting your body weight onto the balls of your feet. Step:4 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('superman push-up', 'superman push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Engage your core and lower your body towards the ground, keeping your elbows close to your sides. Step:3 As you lower your body, simultaneously lift your right arm and left leg off the ground, extending them straight out. Step:4 Pause for a moment at the top, then lower your arm and leg back down while pushing yourself back up to the starting position. Step:5 Repeat the movement, this time lifting your left arm and right leg. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing single leg curl', 'standing single leg curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and your hands on your hips. Step:2 Shift your weight onto your left leg and lift your right foot off the ground, bending your knee. Step:3 Slowly curl your right heel towards your glutes, squeezing your hamstring. Step:4 Pause for a moment at the top, then slowly lower your right foot back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith reverse calf raises', 'smith reverse calf raises', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the smith machine bar to a height just below your shoulders. Step:2 Stand facing the bar with your feet hip-width apart and toes pointing forward. Step:3 Place the balls of your feet on the edge of a step or platform, with your heels hanging off. Step:4 Hold onto the bar for support. Step:5 Raise your heels as high as possible, lifting your body up onto your toes. Step:6 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell incline triceps extension', 'ez barbell incline triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench with your back against the pad and hold the ez barbell with an overhand grip. Step:3 Extend your arms fully overhead, keeping your elbows close to your head. Step:4 Lower the barbell behind your head by bending your elbows, keeping your upper arms stationary. Step:5 Pause for a moment, then extend your arms back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable cross-over lateral pulldown', 'cable cross-over lateral pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable handle to each side of a cable machine at shoulder height. Step:2 Stand in the middle of the machine with your feet shoulder-width apart. Step:3 Grasp the handles with an overhand grip and step back to create tension in the cables. Step:4 Lean forward slightly from the hips, keeping your back straight and your chest up. Step:5 Pull the handles down and across your body, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, then slowly return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith standing behind head military press', 'smith standing behind head military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height of the smith machine so that the bar is at shoulder level. Step:2 Stand with your feet shoulder-width apart and your knees slightly bent. Step:3 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lift the bar off the rack and step back, maintaining a stable stance. Step:5 Position the bar behind your head, resting on your upper traps. Step:6 Keep your core engaged and your chest lifted throughout the exercise. Step:7 Press the bar overhead by extending your arms, fully straightening them. Step:8 Pause briefly at the top of the movement, then slowly lower the bar back down to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith hack squat', 'smith hack squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the barbell on the smith machine to an appropriate height for your body. Step:2 Stand with your feet shoulder-width apart, toes slightly pointed outwards. Step:3 Position yourself under the barbell, resting it on your upper traps and shoulders. Step:4 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:5 Engage your core and keep your chest up as you unrack the barbell. Step:6 Take a step back and position your feet slightly wider than shoulder-width apart. Step:7 Bend your knees and lower your body down, keeping your chest up and back straight. Step:8 Continue descending until your thighs are parallel to the ground or slightly below. Step:9 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:10 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith hip raise', 'smith hip raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself on the smith machine with your back against the pad and your feet shoulder-width apart. Step:2 Place your hands on the barbell, slightly wider than shoulder-width apart. Step:3 Engage your core and glutes, then push through your heels to raise your hips off the ground. Step:4 Continue lifting until your body forms a straight line from your knees to your shoulders. Step:5 Hold for a moment at the top, then slowly lower your hips back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted lying gluteus and piriformis stretch', 'assisted lying gluteus and piriformis stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your legs extended. Step:2 Bend your right knee and place your right ankle on your left thigh, just above the knee. Step:3 Grasp your left thigh with both hands and gently pull it towards your chest. Step:4 Hold the stretch for 20-30 seconds. Step:5 Release the stretch and repeat on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell plyo squat', 'dumbbell plyo squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Step:2 Lower your body into a squat position by bending your knees and pushing your hips back. Step:3 As you reach the bottom of the squat, explode upward, jumping off the ground. Step:4 While in the air, quickly switch the position of your feet, landing with your opposite foot forward. Step:5 Immediately lower your body back into a squat position and repeat the jump, switching your feet again. Step:6 Continue alternating the position of your feet with each jump for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('back lever', 'back lever', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:2 Engage your core and pull your shoulder blades down and back. Step:3 Bend your knees and tuck them towards your chest. Step:4 Slowly lift your legs up, keeping them straight, until your body is parallel to the ground. Step:5 Hold this position for a few seconds, then slowly lower your legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever shoulder press v. 3', 'lever shoulder press v. 3', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and backrest of the leverage machine to a comfortable position. Step:2 Sit on the machine with your back against the backrest and your feet flat on the floor. Step:3 Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart. Step:4 Push the handles upward and forward until your arms are fully extended, but not locked. Step:5 Pause for a moment at the top, then slowly lower the handles back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('walking lunge', 'walking lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Take a step forward with your right leg, lowering your body into a lunge position. Step:3 Keep your torso upright and your front knee aligned with your ankle. Step:4 Push off with your right foot and bring your left foot forward, stepping into a lunge position with your left leg. Step:5 Continue alternating legs and walking forward, maintaining a controlled and steady pace. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternate preacher curl', 'dumbbell alternate preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with a dumbbell in each hand, palms facing up. Step:2 Rest your upper arms on the pad of the preacher bench, allowing your arms to fully extend. Step:3 Keeping your upper arms stationary, exhale and curl the dumbbell in your right hand as you contract your biceps. Step:4 Continue to curl the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Pause for a moment, then inhale and slowly lower the dumbbell back to the starting position. Step:6 Repeat the movement with your left arm. Step:7 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell step up single leg balance with bicep curl', 'dumbbell step up single leg balance with bicep curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a step or platform with a dumbbell in each hand, palms facing your body. Step:2 Place your right foot on the step, ensuring your entire foot is in contact with the surface. Step:3 Engage your core and push through your right heel to lift your body up onto the step, bringing your left knee up towards your chest. Step:4 At the top of the movement, perform a bicep curl by bending your elbows and bringing the dumbbells towards your shoulders. Step:5 Lower the dumbbells back down and simultaneously lower your left foot back to the ground. Step:6 Repeat the movement on the opposite side, stepping up with your left foot and curling the dumbbells. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell bicep curl lunge with bowling motion', 'dumbbell bicep curl lunge with bowling motion', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward. Step:2 Take a step forward with your right foot, bending your right knee and lowering your body into a lunge position. Step:3 As you lunge forward, curl the dumbbells up towards your shoulders, keeping your elbows close to your body. Step:4 At the bottom of the lunge, rotate your torso to the right, as if you were bowling a ball. Step:5 Reverse the motion, stepping back with your right foot and returning to the starting position while lowering the dumbbells back down. Step:6 Repeat the lunge and curl motion, this time rotating your torso to the left. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable low fly', 'cable low fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the handles to the low pulleys of a cable machine and select an appropriate weight. Step:2 Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees. Step:3 Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows. Step:4 Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body. Step:5 Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles. Step:6 Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('seated glute stretch', 'seated glute stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you. Step:2 Bend your right knee and cross your right ankle over your left thigh. Step:3 Place your right hand on the ground behind you for support. Step:4 With your left hand, gently press down on your right knee to deepen the stretch. Step:5 Hold the stretch for 30 seconds to 1 minute. Step:6 Switch sides and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell prone incline curl', 'dumbbell prone incline curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the bench to a 45-degree incline. Step:2 Lie face down on the bench with your chest and stomach resting against it. Step:3 Hold a dumbbell in each hand with your palms facing down and your arms fully extended. Step:4 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:5 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing one arm triceps extension', 'cable standing one arm triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the cable machine. Step:2 Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground. Step:3 Keep your elbow stationary and close to your body. Step:4 Slowly bend your elbow, lowering the cable handle towards the back of your head. Step:5 Pause for a moment at the bottom of the movement, then extend your arm back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell straight leg deadlift', 'barbell straight leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your toes pointing forward. Step:2 Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent. Step:4 Lower the barbell until you feel a stretch in your hamstrings. Step:5 Engage your hamstrings and glutes to lift the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell curl', 'ez barbell curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up. Step:2 Keep your elbows close to your torso and your upper arms stationary throughout the movement. Step:3 Exhale as you curl the barbell up towards your shoulders, contracting your biceps. Step:4 Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('curl-up', 'curl-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell zercher squat', 'barbell zercher squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and toes slightly turned out. Step:2 Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability. Step:3 Engage your core and keep your chest lifted as you lower your hips back and down into a squat position. Step:4 Keep your knees in line with your toes and your weight in your heels. Step:5 Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell jm bench press', 'ez barbell jm bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the ez barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lower the barbell to your chest, keeping your elbows tucked in close to your body. Step:4 Push the barbell back up to the starting position, fully extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying extension', 'barbell lying extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band underhand pulldown', 'band underhand pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a high anchor point, such as a pull-up bar or sturdy beam. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart. Step:4 Extend your arms fully overhead, keeping your elbows slightly bent. Step:5 Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever leg extension', 'lever leg extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and backrest of the machine to fit your body. Step:2 Sit on the machine with your back against the backrest and your feet on the footpad. Step:3 Grasp the handles or sidebars for stability. Step:4 Extend your legs forward by straightening your knees, lifting the weight. Step:5 Pause for a moment at the top, then slowly lower the weight back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wheel run', 'wheel run', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a plank position with your hands on the wheel and your body straight. Step:2 Engage your core and start rolling the wheel forward by extending your arms. Step:3 Continue rolling until your body is fully extended and your arms are overhead. Step:4 Reverse the movement by pulling the wheel back towards your body, using your core and arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell w-press', 'dumbbell w-press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, palms facing forward. Step:2 Raise the dumbbells to shoulder height, elbows bent and palms facing forward. Step:3 Press the dumbbells upward until your arms are fully extended overhead. Step:4 Lower the dumbbells back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable incline bench press', 'cable incline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the bench to a 45-degree incline. Step:2 Attach the cable handles to the high pulleys. Step:3 Sit on the bench facing the cable machine with your feet flat on the ground. Step:4 Grasp the handles with an overhand grip and bring them to shoulder height. Step:5 Push the handles forward and upward until your arms are fully extended. Step:6 Pause for a moment, then slowly lower the handles back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable upper row', 'cable upper row', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a cable machine at chest height. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:4 Keep your back straight and your core engaged. Step:5 Pull the bar towards your upper chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement. Step:7 Slowly release the bar back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable pushdown (with rope attachment)', 'cable pushdown (with rope attachment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope attachment to a high pulley on a cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Step:3 Grasp the rope with an overhand grip, palms facing each other. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Exhale and push the rope downward by extending your elbows until your arms are fully extended. Step:6 Pause for a moment, then inhale and slowly return to the starting position by allowing your elbows to flex. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable two arm tricep kickback', 'cable two arm tricep kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold the cable handle in each hand with your palms facing inwards and your arms bent at a 90-degree angle. Step:3 Keeping your upper arms stationary, extend your forearms backwards until your arms are fully extended. Step:4 Pause for a moment, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell good morning', 'barbell good morning', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and the barbell resting on your upper back. Step:2 Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes. Step:3 Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Step:4 Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('body-up', 'body-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward. Step:2 Extend your legs out in front of you, keeping your heels on the ground and your body straight. Step:3 Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground. Step:4 Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable shoulder press', 'cable shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the handles are at shoulder height. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Grasp the handles with an overhand grip and bring them up to shoulder level, with your elbows bent and pointing outwards. Step:4 Press the handles upwards until your arms are fully extended overhead. Step:5 Pause for a moment at the top, then slowly lower the handles back down to shoulder level. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('alternate lateral pulldown', 'alternate lateral pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the cable machine with your back straight and feet flat on the ground. Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lean back slightly and pull the handles towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell preacher curl over exercise ball', 'dumbbell preacher curl over exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with an underhand grip, resting your elbow on the exercise ball. Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated wide-grip row', 'cable seated wide-grip row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Step:2 Grasp the handle with a wide overhand grip, palms facing down. Step:3 Keep your back straight and lean slightly forward from the hips. Step:4 Pull the handle towards your lower chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the contraction. Step:6 Slowly release the handle back to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable concentration extension (on knee)', 'cable concentration extension (on knee)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your knees bent and feet flat on the ground. Step:2 Hold the cable handle with your right hand and place your elbow on the inside of your right knee. Step:3 Extend your arm fully, keeping your elbow stationary and close to your knee. Step:4 Pause for a moment at the top, then slowly lower your arm back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller side lat stretch', 'roller side lat stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the roller with both hands in front of your body. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Extend your arms forward and roll the roller down towards your feet, feeling a stretch in your lats. Step:4 Hold the stretch for a few seconds, then slowly roll the roller back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell upright row (back pov)', 'dumbbell upright row (back pov)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Let the dumbbells hang in front of your thighs, with your arms fully extended and your palms facing your body. Step:3 Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows. Step:4 Continue lifting until the dumbbells are at shoulder height, with your elbows pointing out to the sides. Step:5 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated twist', 'barbell seated twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with your feet flat on the ground and your knees bent. Step:2 Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent. Step:3 Engage your core and slowly twist your torso to one side, keeping your back straight. Step:4 Pause for a moment at the end of the twist, then slowly rotate back to the starting position. Step:5 Repeat the twist to the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell upright row v. 2', 'barbell upright row v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:2 Let the barbell hang in front of your thighs, arms fully extended. Step:3 Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows. Step:4 Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever gripless shrug', 'lever gripless shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the leverage machine. Step:2 Grasp the handles with your palms facing inwards and your arms fully extended. Step:3 Keeping your back straight, exhale and elevate your shoulders as high as possible. Step:4 Hold the contraction for a brief moment, then inhale and slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('upper back stretch', 'upper back stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart. Step:2 Extend your arms straight in front of you, parallel to the ground. Step:3 Interlace your fingers and rotate your palms away from your body. Step:4 Slowly raise your arms overhead, keeping them straight and parallel to each other. Step:5 As you raise your arms, squeeze your shoulder blades together. Step:6 Hold the stretch for 15-30 seconds, then release and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('landmine 180', 'landmine 180', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the barbell with both hands in front of your chest. Step:2 Bend your knees slightly and rotate your torso to the right, swinging the barbell down towards your right hip. Step:3 As you reach the bottom of the movement, quickly reverse the motion and rotate your torso to the left, swinging the barbell up and across your body towards your left shoulder. Step:4 Continue this twisting motion, alternating sides, for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline bench press', 'dumbbell decline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie down on a decline bench with your feet secured and your head lower than your hips. Step:2 Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward. Step:3 Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle. Step:4 Push the dumbbells back up to the starting position, fully extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell upright row v. 3', 'barbell upright row v. 3', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:2 Let the barbell hang in front of your thighs, arms fully extended. Step:3 Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows. Step:4 Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pull-in (on stability ball)', 'pull-in (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by sitting on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Place your hands on the sides of the stability ball for support. Step:3 Engage your abs and slowly roll your hips forward, bringing your knees towards your chest. Step:4 Pause for a moment at the top of the movement, then slowly extend your legs back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('suspended abdominal fallout', 'suspended abdominal fallout', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a suspension trainer to a high anchor point and adjust the straps to waist height. Step:2 Stand facing away from the anchor point and hold the handles with your arms extended in front of you. Step:3 Lean forward at the waist, keeping your body straight and your core engaged. Step:4 Lower your body as far as you can while maintaining control and tension in your abs. Step:5 Pause for a moment at the bottom, then slowly raise your body back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell fly', 'dumbbell fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing each other. Step:2 Extend your arms straight up over your chest, with a slight bend in your elbows. Step:3 Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Step:4 Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse grip skullcrusher', 'barbell reverse grip skullcrusher', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart. Step:3 Extend your arms straight up over your chest, keeping your elbows in and your wrists straight. Step:4 Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary. Step:5 Pause for a moment at the bottom, then extend your arms back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell deadlift', 'barbell deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and the barbell on the ground in front of you. Step:2 Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees. Step:4 As you stand up straight, squeeze your glutes and keep your core engaged. Step:5 Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band fixed back underhand pulldown', 'band fixed back underhand pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point above your head. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart. Step:4 Step back to create tension in the band, keeping your arms fully extended. Step:5 Engage your core and squeeze your shoulder blades together. Step:6 Pull the band down towards your chest, leading with your elbows. Step:7 Pause for a moment at the bottom of the movement, feeling the contraction in your lats. Step:8 Slowly release the tension in the band and return to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('single leg calf raise (on a dumbbell)', 'single leg calf raise (on a dumbbell)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and hold a dumbbell in one hand. Step:2 Lift one foot off the ground and balance on the other foot. Step:3 Slowly raise your heel as high as possible, using your calf muscles. Step:4 Pause for a moment at the top, then slowly lower your heel back down. Step:5 Repeat for the desired number of repetitions, then switch to the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing hip extension', 'cable standing hip extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable to a low pulley and stand facing away from the machine. Step:2 Place the cable around your ankle and stand with your feet shoulder-width apart. Step:3 Keep your core engaged and your back straight throughout the exercise. Step:4 Slowly extend your leg straight back, squeezing your glutes at the top of the movement. Step:5 Pause for a moment, then return to the starting position. Step:6 Repeat for the desired number of repetitions. Step:7 Switch sides and repeat with the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated good morning', 'lever seated good morning', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that your hips are slightly higher than your knees. Step:2 Sit on the machine with your back against the pad and your feet flat on the footrests. Step:3 Grasp the handles or the sides of the seat for stability. Step:4 Keeping your back straight, slowly lean forward from your hips until your upper body is parallel to the ground. Step:5 Pause for a moment, then slowly return to the starting position by pushing through your glutes and hamstrings. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope hammer preacher curl', 'cable rope hammer preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope attachment to a low pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the rope with a neutral grip (palms facing each other). Step:4 Position your upper arms against the preacher bench pad, keeping your elbows slightly bent. Step:5 Keeping your upper arms stationary, exhale and curl the rope towards your shoulders by contracting your biceps. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Inhale and slowly lower the rope back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pelvic tilt into bridge', 'pelvic tilt into bridge', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the ground. Step:2 Place your arms by your sides with your palms facing down. Step:3 Engage your glutes and core muscles. Step:4 Tilt your pelvis upward, lifting your hips off the ground. Step:5 Hold the bridge position for a few seconds. Step:6 Slowly lower your hips back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing one arm reverse curl', 'dumbbell standing one arm reverse curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand with an overhand grip. Step:2 Keep your arm fully extended and close to your body, with your palm facing down. Step:3 Slowly curl the dumbbell up towards your shoulder, keeping your upper arm stationary. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball seated hamstring stretch', 'exercise ball seated hamstring stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Slowly roll the ball forward, walking your feet out until your upper back is resting on the ball and your legs are extended straight in front of you. Step:3 Place your hands on your hips for support. Step:4 Engage your core and slowly lower your upper body towards the ground, keeping your back straight and your chest lifted. Step:5 Stop when you feel a stretch in your hamstrings, and hold the position for 20-30 seconds. Step:6 Slowly return to the starting position by pushing through your heels and using your hamstrings to pull yourself back up. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm incline fly on exercise ball', 'cable one arm incline fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back against an incline bench. Step:2 Hold a cable handle in one hand with your arm extended and palm facing inward. Step:3 Keeping a slight bend in your elbow, slowly lower your arm out to the side until your hand is in line with your shoulder. Step:4 Pause for a moment, then squeeze your chest muscles to bring your arm back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell full zercher squat', 'barbell full zercher squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and toes slightly turned out. Step:2 Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability. Step:3 Engage your core and keep your chest lifted as you lower your hips back and down into a squat position. Step:4 Keep your knees in line with your toes and your weight in your heels. Step:5 Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:6 Drive through your heels to stand back up, squeezing your glutes at the top of the movement. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball seated triceps stretch', 'exercise ball seated triceps stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand and extend your arm straight up above your head. Step:3 Bend your elbow and lower the dumbbell behind your head, keeping your upper arm close to your ear. Step:4 Hold the stretch for a few seconds, then return to the starting position. Step:5 Repeat with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('arm slingers hanging bent knee legs', 'arm slingers hanging bent knee legs', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle. Step:2 Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible. Step:3 Slowly lower your legs back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band vertical pallof press', 'band vertical pallof press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height. Step:2 Hold the band with both hands and step away from the anchor point, creating tension in the band. Step:3 Position yourself perpendicular to the anchor point, with your side facing the band. Step:4 Extend your arms straight out in front of you, keeping your hands at chest height. Step:5 Engage your core and press the band away from your chest, fully extending your arms. Step:6 Hold the position for a few seconds, then slowly bring the band back towards your chest. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell forward lunge triceps extension', 'dumbbell forward lunge triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 Keep your back straight and your chest up. Step:4 Extend your arms straight overhead, keeping your elbows close to your ears. Step:5 Lower the dumbbells behind your head by bending your elbows. Step:6 Pause for a moment, then straighten your arms to return to the starting position. Step:7 Repeat the movement for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('floor fly (with barbell)', 'floor fly (with barbell)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back on the floor with your knees bent and feet flat on the ground. Step:2 Hold a barbell with an overhand grip, arms extended straight up over your chest. Step:3 Slowly lower the barbell out to the sides, keeping a slight bend in your elbows. Step:4 Lower the barbell until your arms are parallel to the floor, feeling a stretch in your chest. Step:5 Pause for a moment, then squeeze your chest muscles to bring the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('biceps leg concentration curl', 'biceps leg concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your legs spread apart and your feet flat on the ground. Step:2 Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee. Step:3 With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary. Step:4 Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wrist circles', 'wrist circles', 'Strength', 'Other', 'Intermediate', 'Step:1 Extend your arms straight out in front of you. Step:2 Make a fist with both hands. Step:3 Rotate your wrists in a circular motion, keeping your arms still. Step:4 Continue the wrist circles for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell hammer curl v. 2', 'dumbbell hammer curl v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your torso. Step:2 Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. Step:3 This will be your starting position. Step:4 Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Step:5 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Then, inhale and slowly begin to lower the dumbbells back to the starting position. Step:8 Repeat for the recommended amount of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing bent over two arm triceps extension', 'dumbbell standing bent over two arm triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Bend forward at the waist, keeping your back straight and your knees slightly bent. Step:3 Extend your arms straight back, keeping your elbows close to your body. Step:4 Slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted russian twist (legs up)', 'weighted russian twist (legs up)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your knees bent and feet lifted off the ground, keeping your legs together. Step:2 Hold the weight with both hands in front of your chest, keeping your elbows slightly bent. Step:3 Lean back slightly to engage your core muscles. Step:4 Twist your torso to the right, bringing the weight towards the ground on your right side. Step:5 Pause for a moment, then twist your torso to the left, bringing the weight towards the ground on your left side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell sumo pull through', 'dumbbell sumo pull through', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointed outwards. Step:2 Hold a dumbbell with both hands in front of your body, arms extended. Step:3 Bend your knees and lower your hips down into a squat position, keeping your back straight. Step:4 Lower the dumbbell down between your legs, keeping your arms straight. Step:5 Drive through your heels and extend your hips forward, pulling the dumbbell up and in front of your body. Step:6 Squeeze your glutes at the top of the movement, then lower the dumbbell back down between your legs. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith bent knee good morning', 'smith bent knee good morning', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, toes pointing forward. Step:2 Place the barbell across your upper back, resting it on your traps. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Step:5 Engage your glutes and hamstrings to raise your torso back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying one arm pronated triceps extension', 'dumbbell lying one arm pronated triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your back and head supported, and your feet flat on the ground. Step:2 Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder. Step:3 Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow. Step:4 Pause for a moment at the bottom, then extend your arm back up to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wheel rollerout', 'wheel rollerout', 'Strength', 'Other', 'Intermediate', 'Step:1 Kneel on the floor and place the wheel roller in front of you. Step:2 Place your hands on the handles of the wheel roller and extend your arms straight out in front of you. Step:3 Engage your core muscles and slowly roll the wheel forward, keeping your back straight and your abs tight. Step:4 Continue rolling forward until your body is fully extended and your arms are overhead. Step:5 Pause for a moment, then slowly roll the wheel back towards your knees, maintaining control and keeping your abs engaged. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('jack jump (male)', 'jack jump (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet together and your arms by your sides. Step:2 Jump up, spreading your feet apart and raising your arms above your head. Step:3 As you land, quickly jump back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell full squat (side pov)', 'barbell full squat (side pov)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the barbell across your upper back, resting it on your traps or rear delts. Step:3 Engage your core and keep your chest up as you begin to lower your body down. Step:4 Bend at the knees and hips, pushing your hips back and down as if sitting into a chair. Step:5 Lower your body until your thighs are parallel to the ground or slightly below. Step:6 Keep your knees in line with your toes and your weight in your heels. Step:7 Drive through your heels to stand back up, extending your hips and knees. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith shrug', 'smith shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Keep your arms straight and your shoulders relaxed. Step:4 Lift your shoulders up towards your ears, squeezing your traps at the top. Step:5 Hold for a moment, then slowly lower your shoulders back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('power point plank', 'power point plank', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe. Step:2 Engage your core and squeeze your glutes to maintain a stable position. Step:3 Lower your body down onto your forearms, one arm at a time, maintaining a straight line from head to toe. Step:4 Hold this position for the desired amount of time, keeping your core and glutes engaged. Step:5 To return to the starting position, push through your forearms and lift your body back up into a high plank position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up close-grip off dumbbell', 'push-up close-grip off dumbbell', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands placed close together, directly under your shoulders. Step:2 Hold a dumbbell in each hand, resting them on the ground. Step:3 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:4 Push through your palms to extend your arms and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith standing military press', 'smith standing military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lift the barbell off the rack and bring it down to shoulder level, with your palms facing forward. Step:4 Press the barbell upward until your arms are fully extended overhead. Step:5 Pause for a moment at the top, then slowly lower the barbell back down to shoulder level. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lunge with twist', 'lunge with twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 As you lunge, twist your torso to the right, bringing your left elbow towards your right knee. Step:4 Pause for a moment, then return to the starting position. Step:5 Repeat on the other side, stepping forward with your left foot and twisting your torso to the left. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell seated two arm military press', 'kettlebell seated two arm military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a kettlebell in each hand at shoulder level with your palms facing forward. Step:3 Press the kettlebells overhead by extending your arms fully. Step:4 Pause for a moment at the top, then slowly lower the kettlebells back to shoulder level. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('groin crunch', 'groin crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, lift your legs off the ground, bringing your knees towards your chest. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated calf raise', 'dumbbell seated calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs. Step:2 Place the balls of your feet on a raised surface such as a step or block, with your heels hanging off the edge. Step:3 Hold onto the dumbbell for stability. Step:4 Raise your heels as high as possible, lifting your body weight onto the balls of your feet. Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band shoulder press', 'band shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band under your feet. Step:2 Hold the band with your palms facing forward and raise your hands to shoulder height, elbows bent. Step:3 Press the band overhead, fully extending your arms. Step:4 Pause for a moment at the top, then slowly lower the band back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith standing back wrist curl', 'smith standing back wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the smith machine with your feet shoulder-width apart. Step:2 Grasp the barbell with an overhand grip, hands shoulder-width apart. Step:3 Keep your back straight and your elbows close to your body. Step:4 Slowly curl your wrists upwards, bringing the barbell towards your body. Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('seated side crunch (wall)', 'seated side crunch (wall)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the floor with your back against a wall and your legs extended in front of you. Step:2 Bend your knees and place your feet flat on the floor, hip-width apart. Step:3 Place your hands behind your head with your elbows pointing outwards. Step:4 Engage your abs and lean to one side, bringing your elbow towards your hip. Step:5 Pause for a moment, then return to the starting position. Step:6 Repeat on the other side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope extension incline bench row', 'cable rope extension incline bench row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle and attach a cable machine to the low pulley. Step:2 Attach a rope handle to the cable machine and sit on the incline bench facing the machine. Step:3 Grab the rope handle with an overhand grip and lean forward, keeping your back straight. Step:4 Extend your arms fully, pulling the rope towards your upper chest while keeping your elbows close to your body. Step:5 Squeeze your shoulder blades together at the end of the movement. Step:6 Slowly release the tension and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lat pulldown full range of motion', 'cable lat pulldown full range of motion', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the lat pulldown machine with your knees positioned under the pads. Step:2 Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lean back slightly and keep your chest up, maintaining a slight arch in your lower back. Step:4 Pull the bar down towards your upper chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell rear lunge', 'barbell rear lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and a barbell resting on your upper back. Step:2 Take a step backward with your right foot, landing on the ball of your foot. Step:3 Bend both knees to lower your body until your left thigh is parallel to the ground. Step:4 Push through your left heel to return to the starting position. Step:5 Repeat with the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable preacher curl', 'cable preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the preacher curl pad is at chest height. Step:2 Sit on the preacher curl bench and place your upper arms on the pad, gripping the cable attachment with an underhand grip. Step:3 Keep your back straight and your elbows tucked in at your sides. Step:4 Slowly curl the cable attachment up towards your shoulders, squeezing your biceps at the top of the movement. Step:5 Pause for a moment, then slowly lower the cable attachment back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated squat calf raise on leg press machine', 'lever seated squat calf raise on leg press machine', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the footplate. Step:2 Sit on the machine with your back against the backrest and your feet flat on the footplate, shoulder-width apart. Step:3 Place your toes and the balls of your feet on the footplate, keeping your heels off the edge. Step:4 Release the safety handles and push the footplate away from you by extending your knees. Step:5 Once your knees are fully extended, slowly lower your heels by flexing your calves. Step:6 Pause for a moment at the bottom, then push the footplate back up by extending your calves. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('prisoner half sit-up (male)', 'prisoner half sit-up (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller reverse crunch', 'roller reverse crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your arms extended straight above your head and your legs straight out in front of you. Step:2 Place the roller between your feet and grip it with your toes. Step:3 Engaging your abs, lift your legs off the ground and curl your knees towards your chest, rolling the roller towards your body. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position, rolling the roller away from your body. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated one leg calf raise', 'dumbbell seated one leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your right thigh. Step:2 Extend your left leg straight out in front of you, keeping your foot flexed. Step:3 Place the ball of your right foot on an elevated surface, such as a step or weight plate. Step:4 Using your calf muscles, raise your right heel as high as possible. Step:5 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('glute bridge march', 'glute bridge march', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders. Step:3 While keeping your hips lifted, lift one foot off the ground and bring your knee towards your chest. Step:4 Lower your foot back to the ground and repeat the movement with the other leg. Step:5 Continue alternating legs in a marching motion while maintaining the bridge position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell swing', 'kettlebell swing', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointed slightly outward. Step:2 Hold the kettlebell with both hands in front of your body, arms extended. Step:3 Bend your knees slightly and hinge at the hips, pushing your butt back. Step:4 Swing the kettlebell back between your legs, keeping your arms straight and maintaining a flat back. Step:5 Drive your hips forward and swing the kettlebell up to shoulder height, using the momentum generated by your hips. Step:6 Allow the kettlebell to swing back down between your legs and repeat the movement for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('modified hindu push-up (male)', 'modified hindu push-up (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet hip-width apart. Step:2 Lower your body towards the ground, bending your elbows and keeping your core engaged. Step:3 As you lower your body, shift your weight back and lift your hips up towards the ceiling, creating an inverted V shape with your body. Step:4 Continue to lower your body until your chest is just above the ground, then reverse the movement, pushing your hips back down and extending your arms to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('spine stretch', 'spine stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you. Step:2 Place your hands on the ground behind you, fingers pointing towards your body. Step:3 Engage your core and slowly lean back, keeping your back straight. Step:4 Continue leaning back until you feel a stretch in your spine. Step:5 Hold the stretch for a few seconds, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing front raise over head', 'barbell standing front raise over head', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip. Step:2 Keep your back straight and engage your core. Step:3 Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down. Step:4 Continue lifting until the barbell is slightly above shoulder level. Step:5 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight standing one arm row (with towel)', 'bodyweight standing one arm row (with towel)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand. Step:2 Bend forward at the hips, keeping your back straight and your core engaged. Step:3 Pull the towel towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower the towel back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('spell caster', 'spell caster', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand. Step:2 Bend your knees slightly and hinge forward at the waist, keeping your back straight. Step:3 Extend your arm with the dumbbell towards the opposite foot, rotating your torso as you do so. Step:4 Return to the starting position and repeat on the other side. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell lunge pass through', 'kettlebell lunge pass through', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 As you lunge forward, pass the kettlebell under your right thigh and transfer it to your left hand. Step:4 Push off with your right foot to return to the starting position, while simultaneously passing the kettlebell back to your right hand. Step:5 Repeat the lunge on the opposite side, passing the kettlebell under your left thigh. Step:6 Continue alternating lunges and passing the kettlebell between hands for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever donkey calf raise', 'lever donkey calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the leverage machine to the appropriate height for your body. Step:2 Position yourself facing the machine, with your toes on the foot platform and your heels hanging off the edge. Step:3 Place your hands on the handles or the support bars for stability. Step:4 Engage your calves and lift your heels as high as possible, using the balls of your feet. Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse grip incline bench one arm row', 'dumbbell reverse grip incline bench one arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Place a dumbbell on the floor next to the bench. Step:3 Stand facing the bench with your feet shoulder-width apart. Step:4 Bend at the waist and place your left knee and left hand on the bench for support. Step:5 Pick up the dumbbell with your right hand using a reverse grip (palm facing down). Step:6 Keep your back straight and your core engaged. Step:7 Pull the dumbbell up towards your chest, keeping your elbow close to your body. Step:8 Squeeze your back muscles at the top of the movement. Step:9 Lower the dumbbell back down to the starting position in a controlled manner. Step:10 Repeat for the desired number of repetitions. Step:11 Switch sides and repeat the exercise with your left arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell front raise', 'barbell front raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip. Step:2 Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level. Step:3 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted kneeling step with swing', 'weighted kneeling step with swing', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a kneeling position with your knees hip-width apart and your back straight. Step:2 Hold a weight in each hand, with your arms extended straight down in front of you. Step:3 Engage your core and swing the weights up and overhead, keeping your arms straight. Step:4 Lower the weights back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing one arm extension', 'dumbbell standing one arm extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand. Step:2 Raise the dumbbell overhead, fully extending your arm. Step:3 Keep your upper arm close to your head and perpendicular to the ground. Step:4 Slowly lower the dumbbell behind your head, bending your elbow. Step:5 Pause for a moment, then raise the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell revers grip biceps curl', 'dumbbell revers grip biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('front lever reps', 'front lever reps', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with an overhand grip, palms facing away from you. Step:2 Engage your core and pull your shoulder blades down and back. Step:3 Keeping your body straight, lift your legs up until they are parallel to the ground. Step:4 Hold this position for as long as you can, aiming for 10-20 seconds. Step:5 Slowly lower your legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cycle cross trainer', 'cycle cross trainer', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the cycle cross trainer. Step:2 Place your feet on the pedals and grip the handlebars. Step:3 Start pedaling in a smooth and controlled motion. Step:4 Maintain a steady pace and increase the resistance if desired. Step:5 Continue pedaling for the desired duration of your cardio workout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('seated leg raise', 'seated leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with your back straight and your feet flat on the ground. Step:2 Place your hands on the sides of the bench for support. Step:3 Keeping your legs straight, slowly raise them up in front of you until they are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing kickback', 'dumbbell standing kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Extend your arms straight back, squeezing your triceps at the top of the movement. Step:4 Pause for a moment, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell jm bench press', 'barbell jm bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lower the barbell to your chest, keeping your elbows tucked in close to your body. Step:4 Push the barbell back up to the starting position, fully extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball chest push with run release', 'medicine ball chest push with run release', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a medicine ball at chest level. Step:2 Step forward with your right foot and simultaneously push the medicine ball forward, extending your arms fully. Step:3 As you push the ball forward, release it and let it roll forward. Step:4 Quickly run forward and catch the ball before it hits the ground. Step:5 Once you catch the ball, bring it back to your chest and repeat the movement with your left foot forward. Step:6 Continue alternating legs and repeating the exercise for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated shoulder press (parallel grip)', 'dumbbell seated shoulder press (parallel grip)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, palms facing inward. Step:2 Raise the dumbbells to shoulder height, elbows bent and palms facing forward. Step:3 Press the dumbbells upward until your arms are fully extended overhead. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted pull-up', 'weighted pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:2 Hang from the bar with your arms fully extended and your body straight. Step:3 Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline palm-in press', 'dumbbell incline palm-in press', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench with a dumbbell in each hand, palms facing each other. Step:3 Plant your feet firmly on the ground and keep your back straight against the bench. Step:4 Start with the dumbbells at shoulder level, elbows bent and palms facing each other. Step:5 Press the dumbbells up and away from your body, extending your arms fully. Step:6 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band assisted wheel rollerout', 'band assisted wheel rollerout', 'Strength', 'Other', 'Intermediate', 'Step:1 Kneel on the floor and hold the handles of the band with both hands, palms facing down. Step:2 Place the band on the ground in front of you and position your hands shoulder-width apart. Step:3 Engage your core and slowly roll the wheel forward, extending your body as far as you can while maintaining control. Step:4 Pause for a moment at the furthest point, then slowly roll the wheel back towards your knees to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('gorilla chin', 'gorilla chin', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Grasp a pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang from the bar with your arms fully extended and your palms facing away from you. Step:4 Engage your core and pull your body up towards the bar, bringing your chin above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing alternating tricep kickback', 'dumbbell standing alternating tricep kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Extend your arms straight back, keeping your elbows close to your body. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat with the other arm, alternating sides with each repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('squat to overhead reach', 'squat to overhead reach', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and toes slightly turned out. Step:2 Lower your body down into a squat position by bending your knees and pushing your hips back. Step:3 As you come up from the squat, extend your arms overhead, reaching towards the ceiling. Step:4 Return to the starting position by lowering your arms and bending your knees to squat down again. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable wide grip rear pulldown behind neck', 'cable wide grip rear pulldown behind neck', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the pulldown bar is at a height above your head. Step:2 Sit down on the seat and grab the pulldown bar with a wide overhand grip. Step:3 Keep your back straight and your chest up as you lean back slightly. Step:4 Pull the bar down towards your upper chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying pullover on exercise ball', 'dumbbell lying pullover on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball and roll forward until your upper back is resting on the ball. Step:2 Hold a dumbbell with both hands and extend your arms straight up over your chest. Step:3 Slowly lower the dumbbell behind your head while keeping your arms straight. Step:4 Pause for a moment, then raise the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline push-up', 'incline push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart. Step:2 Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels. Step:3 Lower your chest towards the elevated surface by bending your elbows, keeping your body in a straight line. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever triceps extension', 'lever triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the pad. Step:2 Grasp the handles with an overhand grip and fully extend your arms in front of you. Step:3 Keeping your upper arms stationary, slowly lower the handles towards your forehead by bending your elbows. Step:4 Pause for a moment at the bottom, then push the handles back up to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted motion russian twist', 'assisted motion russian twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your knees bent and feet flat on the floor. Step:2 Hold the medicine ball with both hands in front of your chest. Step:3 Lean back slightly, engaging your abs and keeping your back straight. Step:4 Slowly twist your torso to the right, bringing the medicine ball towards the right side of your body. Step:5 Pause for a moment, then twist your torso to the left, bringing the medicine ball towards the left side of your body. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted bench dip', 'weighted bench dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your hands gripping the edge, fingers pointing forward. Step:2 Slide your butt off the bench, supporting your weight with your hands. Step:3 Lower your body by bending your elbows until your upper arms are parallel to the floor. Step:4 Push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band push sit-up', 'band push sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band securely to a stable anchor point. Step:2 Lie flat on your back with your knees bent and feet flat on the ground. Step:3 Hold the band with both hands and extend your arms straight up towards the ceiling. Step:4 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:5 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm french press on exercise ball', 'dumbbell one arm french press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with your palm facing up and your elbow bent at a 90-degree angle. Step:3 Extend your arm straight up towards the ceiling, keeping your elbow stationary. Step:4 Slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band seated twist', 'band seated twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you and your back straight. Step:2 Wrap the band around your waist and hold the ends with both hands. Step:3 Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground. Step:4 Pause for a moment at the end of the twist, then slowly return to the starting position. Step:5 Repeat the twist to the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lying leg-hip raise', 'lying leg-hip raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Place your hands under your glutes for support. Step:3 Engage your core and lift your legs off the ground, raising them towards the ceiling. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell bottoms up clean from the hang position', 'kettlebell bottoms up clean from the hang position', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Step:3 Allow the kettlebell to hang down between your legs, with your arm fully extended. Step:4 In one fluid motion, explosively extend your hips and knees while pulling the kettlebell up towards your shoulder. Step:5 As the kettlebell reaches shoulder height, rotate your wrist so that the bottom of the kettlebell is facing up. Step:6 Catch the kettlebell at shoulder height with your elbow bent and your palm facing up. Step:7 Lower the kettlebell back down to the starting position by reversing the movement. Step:8 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable thibaudeau kayak row', 'cable thibaudeau kayak row', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable handle to a low pulley and sit facing the machine with your feet flat on the floor. Step:2 Grasp the handle with your right hand and extend your arm fully, keeping a slight bend in your elbow. Step:3 Lean forward from your hips, keeping your back straight and your abs engaged. Step:4 Pull the handle towards your torso by retracting your shoulder blade and bending your elbow, keeping your arm close to your body. Step:5 Squeeze your back muscles at the top of the movement, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides and perform with your left arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverse leg curl (on pull-up cable machine)', 'inverse leg curl (on pull-up cable machine)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the ankle straps are at the lowest setting. Step:2 Lie face down on the bench with your legs extended and the ankle straps attached to your feet. Step:3 Hold onto the handles of the bench for stability. Step:4 Bend your knees and curl your legs towards your glutes, squeezing your hamstrings. Step:5 Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell incline reverse-grip press', 'barbell incline reverse-grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Step:3 Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in. Step:4 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rope climb', 'rope climb', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the rope with your feet shoulder-width apart. Step:2 Grab the rope with both hands, palms facing towards you. Step:3 Bend your knees slightly and engage your core. Step:4 Begin pulling yourself up the rope by alternating hand-over-hand movements. Step:5 Use your legs to assist in the upward movement. Step:6 Continue climbing until you reach the desired height or the top of the rope. Step:7 To descend, reverse the hand-over-hand movement while controlling your descent. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball chest pass', 'medicine ball chest pass', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding the medicine ball at chest level. Step:2 Extend your arms forward, pushing the medicine ball away from your chest with force. Step:3 As you release the ball, follow through with your arms and torso, transferring your weight from your back foot to your front foot. Step:4 Catch the ball as it rebounds off the wall or partner, and immediately repeat the movement. Step:5 Continue for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell incline shoulder raise', 'barbell incline shoulder raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench with your back against the pad and feet flat on the ground. Step:3 Hold a barbell with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lift the barbell up to shoulder height, keeping your elbows slightly bent. Step:5 Slowly raise the barbell overhead, extending your arms fully. Step:6 Pause for a moment at the top, then slowly lower the barbell back to shoulder height. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing zottman preacher curl', 'dumbbell standing zottman preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing forward. Step:2 Place your upper arms against the preacher bench and keep your elbows slightly bent. Step:3 Curl the dumbbells up towards your shoulders while keeping your upper arms stationary. Step:4 At the top of the movement, rotate your wrists so that your palms are facing downward. Step:5 Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as well. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse preacher curl', 'dumbbell reverse preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with your upper arms resting on the pad and your chest against the support. Step:2 Hold a dumbbell in each hand with an underhand grip, palms facing up. Step:3 Keeping your upper arms stationary, exhale and curl the dumbbells as you contract your biceps. Step:4 Continue to curl the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bench dip on floor', 'bench dip on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward. Step:2 Slide your butt off the bench, supporting your weight with your hands. Step:3 Lower your body by bending your elbows until your upper arms are parallel to the floor. Step:4 Push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('janda sit-up', 'janda sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith low bar squat', 'smith low bar squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the barbell at a height that allows you to comfortably rest it on your upper back. Step:2 Stand with your feet shoulder-width apart, toes slightly turned outwards. Step:3 Step under the bar and position it across your upper back, resting it on your traps. Step:4 Grip the bar with your hands slightly wider than shoulder-width apart. Step:5 Unrack the bar by straightening your legs and stepping back from the rack. Step:6 Take a deep breath and brace your core. Step:7 Initiate the squat by pushing your hips back and bending your knees. Step:8 Lower your body until your thighs are parallel to the ground or slightly below. Step:9 Keep your chest up and your back straight throughout the movement. Step:10 Drive through your heels to stand back up, extending your hips and knees. Step:11 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing reverse curl', 'dumbbell standing reverse curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:3 Hold the contracted position for a brief pause as you squeeze your biceps. Step:4 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell scott press', 'dumbbell scott press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, palms facing forward. Step:2 Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward. Step:3 Press the dumbbells upward until your arms are fully extended. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm triceps extension (on bench)', 'dumbbell one arm triceps extension (on bench)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell in one hand and place your other hand on the bench for support. Step:3 Raise the dumbbell overhead, keeping your upper arm close to your head and your elbow pointing forward. Step:4 Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary. Step:5 Extend your arm back up to the starting position, fully straightening your elbow. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hug keens to chest', 'hug keens to chest', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart. Step:2 Bend your knees and lower your body down into a squat position. Step:3 As you squat down, bring your knees up towards your chest and hug them with your arms. Step:4 Hold this position for a moment, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm reverse wrist curl', 'dumbbell one arm reverse wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground. Step:2 Hold a dumbbell in one hand with an overhand grip, palm facing down. Step:3 Rest your forearm on your thigh, with your wrist hanging off the edge. Step:4 Slowly lower the dumbbell towards the ground by flexing your wrist. Step:5 Pause for a moment at the bottom, then slowly curl your wrist back up towards your body. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('calf push stretch with hands against wall', 'calf push stretch with hands against wall', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall with your feet hip-width apart. Step:2 Place your hands against the wall at shoulder height. Step:3 Step back with one foot, keeping your heel on the ground and your leg straight. Step:4 Bend your front knee slightly and lean forward, feeling a stretch in your calf. Step:5 Hold the stretch for 20-30 seconds. Step:6 Switch legs and repeat the stretch.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band wrist curl', 'band wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground. Step:2 Hold the band with both hands, palms facing up, and rest your forearms on your thighs. Step:3 Slowly curl your wrists upward, squeezing your forearms. Step:4 Pause for a moment at the top, then slowly lower your wrists back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('basic toe touch (male)', 'basic toe touch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms by your sides. Step:2 Bend forward at the waist, keeping your back straight and your knees slightly bent. Step:3 Reach down towards your toes with your hands, keeping your legs as straight as possible. Step:4 Pause for a moment at the bottom, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('crunch floor', 'crunch floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engage your abs and lift your shoulders off the ground, curling forward towards your knees. Step:4 Pause for a moment at the top, then slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying one arm press', 'dumbbell lying one arm press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground. Step:2 Hold the dumbbell at shoulder level with your palm facing forward. Step:3 Press the dumbbell upward until your arm is fully extended. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse close-grip bench press', 'barbell reverse close-grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with a reverse grip, hands shoulder-width apart. Step:3 Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Step:4 Slowly lower the barbell down towards your chest, keeping your elbows close to your body. Step:5 Pause for a moment when the barbell is just above your chest. Step:6 Push the barbell back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell double snatch', 'kettlebell double snatch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand at arm''s length in front of your thighs. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back flat and chest up. Step:3 In one explosive motion, extend your hips, knees, and ankles, and simultaneously pull the kettlebells up towards your shoulders. Step:4 As the kettlebells reach shoulder level, rotate your wrists and punch the kettlebells overhead, fully extending your arms. Step:5 Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell squat', 'dumbbell squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Step:2 Keeping your chest up and core engaged, lower your body down by bending at the knees and hips, as if sitting back into a chair. Step:3 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline hammer curl', 'dumbbell incline hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended. Step:2 Keep your back against the bench and your feet flat on the floor. Step:3 While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band pull through', 'band pull through', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a resistance band to a sturdy anchor point at ground level. Step:2 Stand facing away from the anchor point with your feet shoulder-width apart. Step:3 Step forward to create tension in the band, keeping your knees slightly bent. Step:4 Hinge at the hips and push your glutes back, maintaining a slight bend in your knees. Step:5 Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings. Step:6 Drive your hips forward and squeeze your glutes to return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell bench seated press', 'dumbbell bench seated press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, resting on your thighs. Step:2 Lean back and position the dumbbells to the sides of your chest, palms facing forward. Step:3 Press the dumbbells upward until your arms are fully extended. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith machine decline close grip bench press', 'smith machine decline close grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the bench on the smith machine to a decline position. Step:2 Lie down on the bench with your feet firmly planted on the ground. Step:3 Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Step:5 Pause for a moment when the barbell is just above your chest. Step:6 Push the barbell back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse grip triceps pushdown (sz-bar) (with arm blaster)', 'cable reverse grip triceps pushdown (sz-bar) (with arm blaster)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to the cable machine at the highest setting. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Engage your triceps and slowly push the bar down until your arms are fully extended. Step:6 Pause for a moment at the bottom, then slowly return the bar to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('suspended row', 'suspended row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a suspension trainer at an appropriate height. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Hold the handles with an overhand grip, palms facing each other. Step:4 Lean back, keeping your body straight and your heels on the ground. Step:5 Pull your chest towards the handles, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower yourself back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith toe raise', 'smith toe raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the smith machine bar to a height that allows you to comfortably stand with your feet flat on the ground. Step:2 Position yourself under the bar with your shoulders directly below it and your feet shoulder-width apart. Step:3 Place the balls of your feet on a raised platform or weight plates, with your heels hanging off the edge. Step:4 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:5 Engage your core and keep your back straight throughout the exercise. Step:6 Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet. Step:7 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('decline sit-up', 'decline sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your feet secured and your knees bent. Step:2 Place your hands behind your head or across your chest. Step:3 Engage your abs and lift your upper body off the bench, curling forward towards your knees. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('front lever', 'front lever', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with an overhand grip, hands shoulder-width apart. Step:2 Engage your core and pull your shoulder blades down and back. Step:3 Bend your knees and tuck them towards your chest. Step:4 Simultaneously, lift your legs up and extend them straight out in front of you, keeping your body parallel to the ground. Step:5 Hold this position for as long as you can, aiming for a full front lever position. Step:6 To release, slowly lower your legs back down and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up plus', 'push-up plus', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels. Step:2 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:3 Once your chest is just above the ground, push through your hands to extend your arms and lift your upper body up. Step:4 At the top of the movement, protract your shoulder blades by pushing your upper back towards the ceiling. Step:5 Pause for a moment, then reverse the movement by retracting your shoulder blades and lowering your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell burpee', 'dumbbell burpee', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand. Step:2 Lower your body into a squat position, placing the dumbbells on the ground in front of you. Step:3 Kick your feet back into a push-up position, keeping your body in a straight line. Step:4 Perform a push-up, bending your elbows and lowering your chest towards the ground. Step:5 Jump your feet back towards your hands, landing in a squat position. Step:6 Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders. Step:7 Press the dumbbells overhead, fully extending your arms. Step:8 Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm incline press on exercise ball', 'cable one arm incline press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back resting against an incline bench. Step:2 Hold a cable handle in one hand and position your arm at a 90-degree angle with your elbow bent. Step:3 Press the cable handle forward and upward, extending your arm fully. Step:4 Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable upper chest crossovers', 'cable upper chest crossovers', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the handles to the cables at chest height. Step:2 Stand in the center of the cable machine with one foot slightly in front of the other. Step:3 Grasp the handles with your palms facing down and your arms extended out to the sides. Step:4 Keep a slight bend in your elbows and engage your core. Step:5 Pull the cables together in front of your chest, crossing them over each other. Step:6 Squeeze your chest muscles at the peak of the movement. Step:7 Slowly release the cables back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing fly', 'cable standing fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the handles to the cables at chest height. Step:2 Stand with your feet shoulder-width apart, facing away from the cable machine. Step:3 Grasp the handles with an overhand grip, palms facing forward. Step:4 Step forward slightly to create tension in the cables. Step:5 Keep your core engaged and your back straight throughout the exercise. Step:6 With a slight bend in your elbows, slowly bring your arms forward and together in front of your chest. Step:7 Squeeze your chest muscles at the peak of the movement. Step:8 Slowly reverse the movement, returning your arms to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rear decline bridge', 'rear decline bridge', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your feet flat on the ground and your knees bent. Step:2 Place your arms by your sides with your palms facing down. Step:3 Engage your glutes and hamstrings, and lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Step:4 Hold this position for a few seconds, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying triceps extension skull crusher', 'barbell lying triceps extension skull crusher', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Step:4 Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('half knee bends (male)', 'half knee bends (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees and lower your body down as if you were sitting back into a chair. Step:3 Keep your chest up and your weight in your heels. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated lateral raise v. 2', 'dumbbell seated lateral raise v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs. Step:2 Keep your back straight and core engaged. Step:3 Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm wrist curl', 'dumbbell one arm wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground. Step:2 Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh. Step:3 Allow your wrist to extend, letting the dumbbell roll down towards your fingers. Step:4 Slowly curl your wrist back up, bringing the dumbbell towards your forearm. Step:5 Repeat for the desired number of repetitions, then switch to the other hand.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wide hand push up', 'wide hand push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands wider than shoulder-width apart. Step:2 Keep your body in a straight line from head to toe. Step:3 Lower your chest towards the ground by bending your elbows, keeping them close to your sides. Step:4 Push through your palms to extend your arms and return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell one arm side deadlift', 'barbell one arm side deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip. Step:2 Keep your back straight and your core engaged. Step:3 Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up. Step:4 Lower the barbell as far as you can while maintaining good form. Step:5 Pause for a moment, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse curl', 'barbell reverse curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down. Step:2 Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps. Step:3 Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reverse plank with leg lift', 'reverse plank with leg lift', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you and your hands resting on the ground behind you, fingers pointing towards your feet. Step:2 Press through your hands and lift your hips off the ground, coming into a reverse plank position. Step:3 Engage your core and lift one leg off the ground, extending it straight up towards the ceiling. Step:4 Hold for a moment, then lower your leg back down. Step:5 Repeat with the other leg. Step:6 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('diamond push-up', 'diamond push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers. Step:2 Keep your body in a straight line from head to toe, engaging your core and glutes. Step:3 Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('self assisted inverse leg curl (on floor)', 'self assisted inverse leg curl (on floor)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Bend your knees and place your feet flat on the ground, hip-width apart. Step:3 Lift your hips off the ground, engaging your glutes and hamstrings. Step:4 Slowly curl your legs towards your glutes, keeping your hips lifted. Step:5 Pause for a moment at the top, then slowly extend your legs back to the starting position. Step:6 Lower your hips back down to the ground. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('posterior step to overhead reach', 'posterior step to overhead reach', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and your arms by your sides. Step:2 Take a step back with your right foot, landing on the ball of your foot. Step:3 Bend your left knee and lower your body into a lunge position. Step:4 As you lower into the lunge, simultaneously reach your arms overhead. Step:5 Pause for a moment at the bottom of the lunge, then return to the starting position by pushing through your left heel and bringing your right foot forward. Step:6 Repeat the movement on the other side, stepping back with your left foot and bending your right knee. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith wide grip bench press', 'smith wide grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the bench to a comfortable position on the smith machine. Step:2 Lie down on the bench with your feet flat on the ground. Step:3 Grasp the barbell with a wide grip, slightly wider than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows out to the sides. Step:5 Pause for a moment when the barbell touches your chest. Step:6 Push the barbell back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hyperextension', 'hyperextension', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the hyperextension bench so that your upper thighs are resting on the pad and your feet are secured. Step:2 Cross your arms over your chest or place your hands behind your head. Step:3 Lower your upper body towards the ground while keeping your back straight. Step:4 Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell pendlay row', 'barbell pendlay row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Bend forward at the hips, keeping your back straight and your chest up. Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:4 Pull the barbell towards your upper abdomen, squeezing your shoulder blades together. Step:5 Lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball lying side lat stretch', 'exercise ball lying side lat stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs extended and your head supported by the stability ball. Step:2 Place your top arm on the ball for stability. Step:3 Reach your top arm overhead and allow your torso to rotate slightly. Step:4 Feel the stretch in your lat muscles on the side of your body. Step:5 Hold the stretch for 20-30 seconds, then switch sides and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell one arm bent over row', 'barbell one arm bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip. Step:2 Bend forward at the hips, keeping your back straight and your head in a neutral position. Step:3 Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Step:4 Lower the barbell back down to the starting position in a controlled manner. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('back and forth step', 'back and forth step', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Step forward with your right foot, bending your knee and lowering your body into a lunge position. Step:3 Push off with your right foot and step back to the starting position. Step:4 Repeat the movement with your left foot, alternating legs with each step. Step:5 Continue stepping back and forth, maintaining a steady pace. Step:6 Repeat for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable twist', 'cable twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the cable machine. Step:2 Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent. Step:3 Engage your core and twist your torso to the right, pulling the cable across your body. Step:4 Pause for a moment at the end of the movement, feeling the contraction in your abs and obliques. Step:5 Slowly return to the starting position, resisting the cable''s pull. Step:6 Repeat the movement to the left side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell hack squat', 'barbell hack squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and your toes slightly turned out. Step:2 Hold the barbell behind your legs, resting it on your upper thighs. Step:3 Lower your body by bending at the knees and hips, keeping your back straight and your chest up. Step:4 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Pause for a moment, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever one arm shoulder press', 'lever one arm shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the pad. Step:2 Grasp the lever handle with one hand and position your elbow at a 90-degree angle. Step:3 Press the lever upward until your arm is fully extended overhead. Step:4 Pause for a moment at the top, then slowly lower the lever back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('stationary bike walk', 'stationary bike walk', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position on the stationary bike to ensure proper alignment. Step:2 Place your feet on the pedals and secure them with the straps if available. Step:3 Start pedaling at a comfortable pace, keeping your back straight and core engaged. Step:4 Maintain a steady rhythm and increase the resistance level if desired. Step:5 Continue pedaling for the desired duration of your cardio workout. Step:6 Cool down by gradually reducing your pace and resistance level. Step:7 Stretch your leg muscles after the workout to prevent tightness and promote recovery.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band seated hip internal rotation', 'band seated hip internal rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a chair or bench with your back straight and feet flat on the ground. Step:2 Place a resistance band around your thighs, just above your knees. Step:3 Keep your knees bent at a 90-degree angle and your feet shoulder-width apart. Step:4 Engage your glutes and slowly rotate your knees outward, pushing against the resistance of the band. Step:5 Pause for a moment at the end of the movement, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever shoulder press', 'lever shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the backrest. Step:2 Grasp the handles with an overhand grip and position your hands at shoulder level. Step:3 Push the handles upward until your arms are fully extended, but do not lock your elbows. Step:4 Pause for a moment at the top, then slowly lower the handles back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band lying straight leg raise', 'band lying straight leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs straight and your feet together. Step:2 Place the band around the arches of your feet and hold the ends of the band with your hands. Step:3 Engaging your abs, lift both legs off the ground until they are perpendicular to the floor. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('straight leg outer hip abductor', 'straight leg outer hip abductor', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs straight and stacked on top of each other. Step:2 Place your bottom arm under your head for support. Step:3 Engage your core and lift your top leg as high as possible without rotating your hips or leaning backward. Step:4 Pause for a moment at the top, then slowly lower your leg back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever one arm lateral high row', 'lever one arm lateral high row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself facing the machine. Step:2 Grasp the handle with one hand and keep your back straight. Step:3 Pull the handle towards your body, keeping your elbow close to your side. Step:4 Squeeze your back muscles at the top of the movement. Step:5 Slowly release the handle back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell cuban press v. 2', 'dumbbell cuban press v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down. Step:2 Keeping your core engaged and your back straight, press the dumbbells straight up overhead until your arms are fully extended. Step:3 Rotate your wrists so that your palms are facing forward. Step:4 Lower the dumbbells back down to shoulder height, rotating your wrists back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('skin the cat', 'skin the cat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a bar with your arms fully extended and your body relaxed. Step:2 Engage your core and lift your legs up, bringing your knees towards your chest. Step:3 Continue to lift your legs up and over your head, allowing your body to pass through the arms. Step:4 Once your legs are fully extended over your head, begin to lower them back down towards the starting position. Step:5 As you lower your legs, allow your body to pass back through the arms until you are hanging with your arms fully extended again. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell rollerout', 'barbell rollerout', 'Strength', 'Other', 'Intermediate', 'Step:1 Kneel on the floor and hold a barbell with both hands, shoulder-width apart. Step:2 Roll the barbell forward, extending your arms and keeping your core engaged. Step:3 Continue rolling forward until your body is fully extended and your arms are overhead. Step:4 Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing calves calf stretch', 'standing calves calf stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall or sturdy object, about an arm''s length away. Step:2 Place your hands on the wall or object at shoulder height. Step:3 Step back with one foot, keeping your heel flat on the ground. Step:4 Bend your front knee slightly and lean forward, keeping your back leg straight. Step:5 You should feel a stretch in your calf muscle. Step:6 Hold the stretch for 20-30 seconds. Step:7 Repeat on the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up to side plank', 'push-up to side plank', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and your body in a straight line. Step:2 Lower your body towards the ground by bending your elbows, keeping your core engaged. Step:3 Push back up to the starting position. Step:4 Shift your weight onto your left hand and rotate your body to the right, lifting your right arm towards the ceiling. Step:5 Hold the side plank position for a few seconds, then return to the starting position. Step:6 Repeat the push-up and side plank on the opposite side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell clean-grip front squat', 'barbell clean-grip front squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward. Step:2 Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair. Step:3 Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes. Step:4 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith incline reverse-grip press', 'smith incline reverse-grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the smith machine to a comfortable incline angle. Step:2 Sit on the machine with your back against the pad and your feet flat on the ground. Step:3 Grasp the bar with an overhand grip that is slightly wider than shoulder-width apart. Step:4 Unrack the bar and lower it slowly towards your chest, keeping your elbows tucked in. Step:5 Pause for a moment when the bar is just above your chest. Step:6 Push the bar back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lateral pulldown with v-bar', 'cable lateral pulldown with v-bar', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit down on the cable pulldown machine and grab the v-bar attachment with an overhand grip. Step:2 Adjust the knee pad so that your thighs are secured under it. Step:3 Keep your back straight and lean back slightly. Step:4 Pull the v-bar down towards your upper chest while keeping your elbows close to your body. Step:5 Squeeze your back muscles at the bottom of the movement. Step:6 Slowly return the v-bar to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lunge with jump', 'lunge with jump', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 Push off with your right foot and jump into the air, switching the position of your feet mid-air. Step:4 Land softly with your left foot forward and immediately lower your body into a lunge position. Step:5 Continue alternating between lunges and jumps for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('scapula push-up', 'scapula push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Step:2 Lower your chest towards the ground, keeping your elbows close to your body. Step:3 As you lower, squeeze your shoulder blades together and push your chest forward. Step:4 Pause for a moment at the bottom, then push back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted hanging leg-hip raise', 'weighted hanging leg-hip raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up in front of you, keeping them straight. Step:3 Continue lifting until your legs are parallel to the ground or slightly higher. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell side lying one hand raise', 'dumbbell side lying one hand raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your side with your legs extended and your head supported by your arm. Step:2 Hold a dumbbell in your top hand with your palm facing down. Step:3 Keeping your arm straight, raise the dumbbell up to shoulder height. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45 degrees one leg press', 'sled 45 degrees one leg press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a 45-degree angle. Step:2 Sit on the sled machine with your back against the pad and your feet on the footplate. Step:3 Place one foot on the footplate and extend your leg, pushing the sled away from you. Step:4 Slowly bend your knee and lower the sled back to the starting position. Step:5 Repeat with the other leg. Step:6 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled lying squat', 'sled lying squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a comfortable weight. Step:2 Lie on your back on the sled machine with your feet on the footplate. Step:3 Position your feet shoulder-width apart and slightly angled outwards. Step:4 Grip the handles of the sled machine for stability. Step:5 Engage your glutes and core muscles. Step:6 Push through your heels and extend your legs to lift the sled. Step:7 Lower the sled back down by bending your knees and hips. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated behind head military press', 'barbell seated behind head military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lift the barbell off the rack and bring it down to shoulder level, behind your head. Step:4 Press the barbell upward until your arms are fully extended. Step:5 Lower the barbell back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline shrug', 'dumbbell incline shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand. Step:2 Place your feet flat on the ground and let your arms hang straight down with your palms facing your body. Step:3 Keeping your arms straight, shrug your shoulders up towards your ears as high as possible. Step:4 Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell over bench neutral wrist curl', 'dumbbell over bench neutral wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up. Step:2 Rest your forearms on the bench, allowing your wrists to hang off the edge. Step:3 Keeping your upper arms stationary, exhale and curl the dumbbells up towards your shoulders. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever military press', 'lever military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the backrest. Step:2 Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Step:3 Push the handles upward until your arms are fully extended, but do not lock your elbows. Step:4 Pause for a moment at the top, then slowly lower the handles back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('decline crunch', 'decline crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle. Step:2 Place your hands behind your head or across your chest. Step:3 Engage your abs and lift your upper body towards your knees, curling your torso. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell two arm military press', 'kettlebell two arm military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder level with your palms facing forward. Step:2 Engage your core and press the kettlebells overhead, fully extending your arms. Step:3 Pause for a moment at the top, then slowly lower the kettlebells back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated biceps curl (on stability ball)', 'dumbbell seated biceps curl (on stability ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps. Step:4 Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverted row on bench', 'inverted row on bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a bench at a height that allows your body to hang freely underneath it. Step:2 Lie face up on the ground with your head towards the bench. Step:3 Reach up and grab the bench with an overhand grip, slightly wider than shoulder-width apart. Step:4 Position your body so that your heels are on the ground and your arms are fully extended. Step:5 Engage your core and squeeze your shoulder blades together as you pull your chest up towards the bench. Step:6 Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('oblique crunches floor', 'oblique crunches floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the floor. Step:2 Place your hands behind your head or cross them over your chest. Step:3 Engage your abs and lift your shoulder blades off the floor, rotating your torso to one side. Step:4 Pause for a moment, then lower your shoulder blades back down to the floor. Step:5 Repeat on the other side, alternating sides with each repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell side bent v. 2', 'barbell side bent v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down. Step:2 Keep your back straight and core engaged throughout the exercise. Step:3 Slowly bend your torso to the right side, lowering the barbell towards your right knee. Step:4 Pause for a moment, then return to the starting position. Step:5 Repeat the movement on the left side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('shoulder tap push-up', 'shoulder tap push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels. Step:2 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:3 As you push back up, lift your right hand off the ground and tap your left shoulder. Step:4 Return your right hand to the ground and repeat the push-up, this time lifting your left hand and tapping your right shoulder. Step:5 Continue alternating shoulder taps with each push-up repetition. Step:6 Maintain a stable core and avoid excessive hip rotation throughout the exercise. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated shoulder internal rotation', 'cable seated shoulder internal rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair facing the cable machine with your feet flat on the ground. Step:2 Hold the cable handle with your arm extended straight out in front of you, parallel to the ground. Step:3 Keep your elbow slightly bent and your shoulder blades pulled back and down. Step:4 Slowly rotate your arm inward, bringing the cable handle towards the center of your body. Step:5 Pause for a moment at the end of the movement, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable decline seated wide-grip row', 'cable decline seated wide-grip row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the decline bench facing the cable machine with your feet securely placed on the footrests. Step:2 Grasp the cable attachment with a wide overhand grip, palms facing down. Step:3 Lean back slightly, keeping your back straight and your core engaged. Step:4 Pull the cable towards your lower chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverse leg curl (bench support)', 'inverse leg curl (bench support)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a bench with your hips at the edge and your legs extended straight behind you. Step:2 Hold onto the bench for support. Step:3 Keeping your upper body still, bend your knees and curl your legs towards your glutes. Step:4 Pause for a moment at the top, then slowly extend your legs back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez bar standing french press', 'ez bar standing french press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the ez barbell with an overhand grip. Step:2 Raise the barbell above your head, fully extending your arms. Step:3 Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ski ergometer', 'ski ergometer', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footrests to a comfortable position. Step:2 Grasp the handles with an overhand grip, palms facing down. Step:3 Sit up straight with your feet flat on the footrests. Step:4 Extend your arms straight out in front of you, keeping your elbows slightly bent. Step:5 Engage your triceps and push the handles down towards your thighs. Step:6 Pause for a moment at the bottom, then slowly return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging straight leg hip raise', 'hanging straight leg hip raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up in front of you until they are parallel to the ground. Step:3 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lying leg raise flat bench', 'lying leg raise flat bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a flat bench with your back pressed against it. Step:2 Place your hands under your glutes for support. Step:3 Keep your legs straight and together, and lift them up towards the ceiling. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell biceps curl (with arm blaster)', 'dumbbell biceps curl (with arm blaster)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing forward. Step:2 Keep your elbows close to your torso and your upper arms stationary. Step:3 Exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm press on exercise ball', 'cable one arm press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a cable handle in one hand and position your arm at chest height, elbow bent. Step:3 Place your other hand on your hip for stability. Step:4 Press the cable handle forward, extending your arm fully. Step:5 Pause for a moment, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one arm dip', 'one arm dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing away from a bench or chair, with your feet shoulder-width apart. Step:2 Place one hand on the bench or chair behind you, fingers pointing towards your body. Step:3 Extend your legs out in front of you, keeping your heels on the ground. Step:4 Bend your elbows and lower your body towards the ground, keeping your back close to the bench or chair. Step:5 Pause for a moment at the bottom, then push through your palms to straighten your arms and return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides and repeat with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable concentration curl', 'cable concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the floor and your knees slightly bent. Step:2 Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh. Step:3 Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps. Step:4 Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline shrug v. 2', 'dumbbell decline shrug v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a decline bench at a 45-degree angle. Step:2 Lie face down on the bench with your chest and stomach resting on it. Step:3 Hold a dumbbell in each hand with your palms facing each other and your arms fully extended. Step:4 Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together. Step:5 Hold the contraction for a brief pause, then lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell close grip press', 'dumbbell close grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with a dumbbell in each hand, resting on your thighs. Step:2 Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width. Step:3 Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position. Step:4 As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest. Step:5 As you exhale, use your triceps to lift the dumbbells back to the starting position. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells. Step:6 After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sissy squat', 'sissy squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your toes pointing slightly outward. Step:2 Hold onto a stable object for balance if needed. Step:3 Slowly lower your body by bending your knees and leaning back, keeping your torso upright. Step:4 Continue lowering until your thighs are parallel to the ground or as far as you can comfortably go. Step:5 Pause for a moment, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable hip adduction', 'cable hip adduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the ankle cuff to your ankle and stand facing the cable machine. Step:2 Position yourself far enough away from the machine so that there is tension on the cable. Step:3 Place your hands on the machine for support. Step:4 Keeping your leg straight, slowly move your leg across your body towards the midline. Step:5 Pause for a moment at the end of the movement, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell sitted alternate leg raise', 'barbell sitted alternate leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and hold a barbell across your thighs. Step:2 Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground. Step:3 Lower the raised leg back down and repeat with the other leg. Step:4 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band alternating biceps curl', 'band alternating biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the band with an underhand grip, palms facing up. Step:2 Keep your elbows close to your sides and slowly curl one arm up towards your shoulder, squeezing your biceps at the top. Step:3 Lower the arm back down to the starting position and repeat with the other arm. Step:4 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('march sit (wall)', 'march sit (wall)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your back against a wall and your feet hip-width apart. Step:2 Slowly slide your back down the wall until your knees are bent at a 90-degree angle. Step:3 Lift your right foot off the ground and bring your knee towards your chest. Step:4 Lower your right foot back down and lift your left foot off the ground, bringing your knee towards your chest. Step:5 Continue alternating between lifting your right and left foot for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dynamic chest stretch (male)', 'dynamic chest stretch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand tall with your feet shoulder-width apart. Step:2 Extend your arms straight out to the sides, parallel to the ground. Step:3 Slowly bring your arms forward, crossing them in front of your body. Step:4 Feel the stretch in your chest muscles. Step:5 Hold the stretch for 10-30 seconds. Step:6 Return to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball overhead slam', 'medicine ball overhead slam', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a medicine ball with both hands above your head. Step:2 Engage your core and keep your back straight. Step:3 Bend your knees slightly and forcefully slam the medicine ball down to the ground in front of you. Step:4 As you slam the ball down, use your entire body to generate power, including your shoulders and core. Step:5 Catch the ball on the bounce and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm lateral raise with support', 'dumbbell one arm lateral raise with support', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your palm facing your body. Step:2 Place your other hand on a stable surface, such as a bench or wall, for support. Step:3 Keep your back straight and engage your core. Step:4 Raise the dumbbell out to the side, keeping your arm straight and your palm facing down. Step:5 Continue lifting until your arm is parallel to the ground. Step:6 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez-bar biceps curl (with arm blaster)', 'ez-bar biceps curl (with arm blaster)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up. Step:2 Place your upper arms against the arm blaster, keeping them stationary throughout the exercise. Step:3 Keeping your elbows close to your body, exhale and curl the barbell up towards your shoulders. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Inhale and slowly lower the barbell back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bench hip extension', 'bench hip extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back against the bench and your feet flat on the ground. Step:2 Place your hands on the bench for support. Step:3 Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders. Step:4 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('behind head chest stretch', 'behind head chest stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand tall with your feet shoulder-width apart. Step:2 Interlace your fingers behind your head with your elbows pointing outwards. Step:3 Slowly squeeze your shoulder blades together and push your chest forward. Step:4 Hold the stretch for 15-30 seconds. Step:5 Release the stretch and repeat as desired.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball chest push multiple response', 'medicine ball chest push multiple response', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a medicine ball at chest level. Step:2 Extend your arms forward, pushing the medicine ball away from your chest. Step:3 Pause for a moment, then slowly bring the medicine ball back to your chest. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith sprint lunge', 'smith sprint lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the barbell at hip height. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Step back with your right foot and place it on the barbell, resting the top of your foot on the bar. Step:4 Bend your left knee and lower your body into a lunge position, keeping your back straight. Step:5 Push through your left heel to return to the starting position. Step:6 Repeat on the other side, stepping back with your left foot. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted lying calves stretch', 'assisted lying calves stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your legs extended. Step:2 Bend one knee and place your foot flat on the ground. Step:3 Using your hands or a towel, gently pull your toes towards your body, feeling a stretch in your calf. Step:4 Hold the stretch for 20-30 seconds. Step:5 Release the stretch and repeat on the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('walk elliptical cross trainer', 'walk elliptical cross trainer', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the resistance level and incline of the elliptical machine to your desired settings. Step:2 Step onto the pedals of the machine and grip the handles lightly. Step:3 Begin by pushing down with your feet and pulling the handles towards your body. Step:4 Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion. Step:5 Maintain a steady pace and keep your core engaged throughout the exercise. Step:6 Continue for the desired duration of your cardio workout. Step:7 Gradually decrease the intensity and speed of the machine before stepping off.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing alternate hammer curl and press', 'dumbbell standing alternate hammer curl and press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your body. Step:2 Keep your elbows close to your torso and your back straight. Step:3 Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary. Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Inhale and slowly lower the dumbbell back to the starting position. Step:6 Repeat the curl with your left hand. Step:7 After completing the curl with your left hand, exhale and press the dumbbell in your right hand overhead. Step:8 Extend your arm fully and hold for a moment at the top. Step:9 Inhale and slowly lower the dumbbell back to the starting position. Step:10 Repeat the press with your left hand. Step:11 Continue alternating between curls and presses for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('scapular pull-up', 'scapular pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended. Step:2 Retract your shoulder blades by pulling them down and back. Step:3 Engage your back muscles and pull your body up towards the bar, focusing on squeezing your shoulder blades together. Step:4 Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell incline close grip bench press', 'barbell incline close grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Lie down on the bench with your feet flat on the ground. Step:3 Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body. Step:5 Pause for a moment when the barbell touches your chest. Step:6 Push the barbell back up to the starting position, fully extending your arms. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell one arm row', 'kettlebell one arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged. Step:3 Pull the kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower the kettlebell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides and repeat with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('half sit-up (male)', 'half sit-up (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable high row (kneeling)', 'cable high row (kneeling)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a cable machine at chest height. Step:2 Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart. Step:3 Sit back on your heels, keeping your back straight and your core engaged. Step:4 Pull the bar towards your upper abdomen, squeezing your shoulder blades together. Step:5 Pause for a moment at the top of the movement, then slowly release the bar back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable bar lateral pulldown', 'cable bar lateral pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable pulley to a high position and attach a straight bar. Step:2 Sit facing the cable machine with your feet flat on the ground and your knees slightly bent. Step:3 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lean back slightly and keep your chest up, maintaining a slight arch in your lower back. Step:5 Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight drop jump squat', 'bodyweight drop jump squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Lower your body into a squat position by bending your knees and pushing your hips back. Step:3 Jump up explosively, extending your hips, knees, and ankles. Step:4 While in mid-air, quickly bring your feet together. Step:5 Land softly on the balls of your feet and immediately drop back into a squat position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging leg hip raise', 'hanging leg hip raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up by flexing your hips and knees until your thighs are parallel to the ground. Step:3 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline y-raise', 'dumbbell incline y-raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards. Step:2 Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows. Step:3 Raise your arms out to the sides and up in a Y shape until they are parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lunge', 'dumbbell lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 Keep your back straight and your chest up as you lower your body. Step:4 Push through your right heel to return to the starting position. Step:5 Repeat with your left leg. Step:6 Alternate legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one leg donkey calf raise', 'one leg donkey calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing forward. Step:2 Place your hands on a stable surface for support, such as a wall or a bar. Step:3 Lift one leg off the ground, keeping your knee slightly bent. Step:4 Raise your heel as high as possible, using your calf muscles. Step:5 Pause for a moment at the top, then slowly lower your heel back down. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell narrow stance squat', 'barbell narrow stance squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and toes pointing slightly outward. Step:2 Hold the barbell across your upper back, resting it on your traps or rear delts. Step:3 Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back. Step:4 Continue lowering until your thighs are parallel to the ground or slightly below. Step:5 Pause for a moment, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell decline wide-grip pullover', 'barbell decline wide-grip pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your head lower than your hips and your feet secured. Step:2 Hold a barbell with a wide grip and extend your arms straight above your chest. Step:3 Lower the barbell behind your head in a controlled manner, keeping your arms straight. Step:4 Pause for a moment, then raise the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('shoulder tap', 'shoulder tap', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Step:2 Engage your core and lift your right hand off the ground, reaching across to tap your left shoulder. Step:3 Place your right hand back on the ground and repeat with your left hand tapping your right shoulder. Step:4 Continue alternating shoulder taps while keeping your hips and torso stable. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith full squat', 'smith full squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the barbell at shoulder height. Step:2 Stand with your feet shoulder-width apart, toes slightly turned out. Step:3 Step under the bar and position it across your upper back, resting on your traps. Step:4 Grip the bar with your hands slightly wider than shoulder-width apart. Step:5 Unrack the bar and take a step back, maintaining a stable stance. Step:6 Keeping your chest up and core engaged, initiate the squat by pushing your hips back and bending your knees. Step:7 Lower your body until your thighs are parallel to the ground, or as low as your flexibility allows. Step:8 Pause for a moment at the bottom, then drive through your heels to return to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('self assisted inverse leg curl', 'self assisted inverse leg curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a leg curl machine with your legs extended and your ankles hooked under the padded lever. Step:2 Place your hands on the side handles of the machine for support. Step:3 Keeping your upper body stationary, exhale and curl your legs upward as far as possible. Step:4 Hold the contracted position for a brief pause as you squeeze your hamstrings. Step:5 Slowly lower your legs back to the starting position while inhaling. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball hug', 'exercise ball hug', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your back straight. Step:2 Hold the stability ball with both hands, hugging it close to your chest. Step:3 Engage your core muscles and slowly lean back, keeping your back straight and your feet planted on the ground. Step:4 Continue leaning back until you feel a stretch in your back muscles. Step:5 Hold the position for a few seconds, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('monster walk', 'monster walk', 'Strength', 'Other', 'Intermediate', 'Step:1 Place a resistance band around your ankles. Step:2 Stand with your feet shoulder-width apart and slightly bend your knees. Step:3 Take a step to the side with your right foot, maintaining tension on the resistance band. Step:4 Follow with your left foot, stepping to the side to return to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('bodyweight standing calf raise', 'bodyweight standing calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing forward. Step:2 Place your hands on a wall or stable surface for balance. Step:3 Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet. Step:4 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever bent-over row with v-bar', 'lever bent-over row with v-bar', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself facing the machine. Step:2 Grasp the v-bar with an overhand grip, keeping your back straight and your knees slightly bent. Step:3 Pull the v-bar towards your abdomen, squeezing your shoulder blades together. Step:4 Pause for a moment at the top of the movement, then slowly release the weight back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith decline reverse-grip press', 'smith decline reverse-grip press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the smith machine to a decline position. Step:2 Lie down on the bench with your feet secured under the foot pads. Step:3 Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart. Step:4 Unrack the barbell and lower it towards your chest, keeping your elbows tucked in. Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('negative crunch', 'negative crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pull up (neutral grip)', 'pull up (neutral grip)', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with a neutral grip (palms facing each other) and your arms fully extended. Step:2 Engage your core and squeeze your shoulder blades together. Step:3 Pull your body up towards the bar by bending your elbows and driving your elbows down towards your hips. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position with control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline fly', 'dumbbell incline fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Set an incline bench to a 45-degree angle. Step:2 Sit on the bench with a dumbbell in each hand, palms facing each other. Step:3 Lie back on the bench and press the dumbbells up to the starting position, directly above your chest. Step:4 Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Step:5 Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band straight leg deadlift', 'band straight leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band around your feet. Step:2 Hold the band with both hands, palms facing your body, and keep your arms straight. Step:3 Engage your core and maintain a slight bend in your knees. Step:4 Slowly hinge forward at your hips, keeping your back straight and chest lifted. Step:5 Lower the band towards the ground while keeping your legs straight. Step:6 Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated bent over alternate kickback', 'dumbbell seated bent over alternate kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, palms facing inwards. Step:2 Bend forward at the waist, keeping your back straight and parallel to the ground. Step:3 Extend one arm straight back, keeping it close to your body, until your arm is fully extended. Step:4 Pause for a moment, then slowly lower the dumbbell back to the starting position. Step:5 Repeat with the other arm. Step:6 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith back shrug', 'smith back shrug', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Keep your arms straight and allow the barbell to hang in front of your thighs. Step:4 Lift your shoulders straight up towards your ears, squeezing your traps at the top. Step:5 Hold for a moment, then lower your shoulders back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm chest fly on exercise ball', 'dumbbell one arm chest fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground. Step:2 Walk your feet forward, rolling the ball until your upper back is supported on the ball and your head, neck, and shoulders are off the ball. Step:3 Extend your arm with the dumbbell straight up above your chest, palm facing inward. Step:4 Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Step:5 Pause for a moment when your arm is parallel to the ground. Step:6 Engage your chest muscles to bring the dumbbell back up to the starting position. Step:7 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm bent over row', 'cable one arm bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Grasp the cable handle with one hand, palm facing inward, and extend your arm fully. Step:4 Pull the cable handle towards your body, keeping your elbow close to your side, until your hand reaches your lower chest. Step:5 Pause for a moment, then slowly extend your arm back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hyght dumbbell fly', 'hyght dumbbell fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing each other. Step:2 Extend your arms straight up over your chest, with a slight bend in your elbows. Step:3 Keeping a slight bend in your elbows, lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest. Step:4 Pause for a moment, then reverse the movement and bring the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band kneeling one arm pulldown', 'band kneeling one arm pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point above your head. Step:2 Kneel down and hold the band with one hand, palm facing down. Step:3 Extend your arm fully overhead, keeping your elbow slightly bent. Step:4 Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage. Step:5 Pause for a moment at the bottom, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing one arm palm in press', 'dumbbell standing one arm palm in press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in one hand at shoulder height with your palm facing inwards. Step:2 Engage your core and keep your back straight. Step:3 Press the dumbbell upwards until your arm is fully extended. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('3/4 sit-up', '3/4 sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell one arm snatch', 'barbell one arm snatch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing slightly outwards. Step:2 Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Bend your knees and lower your hips into a squat position, keeping your back straight and chest up. Step:4 Explosively extend your hips, knees, and ankles, driving the barbell upwards. Step:5 As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body. Step:6 Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow. Step:7 Lower the barbell back down to the starting position in a controlled manner. Step:8 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverted row with straps', 'inverted row with straps', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a suspension trainer or straps at chest height. Step:2 Stand facing the anchor point and grab the handles with an overhand grip. Step:3 Walk your feet forward, leaning back until your body is at an angle. Step:4 Keep your body straight and engage your core. Step:5 Pull your chest towards the handles, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower yourself back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing calf raise', 'dumbbell standing calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Raise your heels off the ground as high as possible, using your calves. Step:3 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith standing leg calf raise', 'smith standing leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the smith machine bar to a height that allows you to stand with your feet flat on the ground and your shoulders under the bar. Step:2 Position yourself under the bar with your feet shoulder-width apart and your toes pointing forward. Step:3 Place your hands on the bar for stability. Step:4 Engage your calves and slowly raise your heels off the ground, lifting your body up onto your toes. Step:5 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('flexion leg sit up (straight arm)', 'flexion leg sit up (straight arm)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and arms straight above your head. Step:2 Engaging your abs, lift your upper body off the ground while simultaneously lifting your legs towards your chest. Step:3 Reach your hands towards your toes as you lift your upper body and legs. Step:4 Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('circles knee stretch', 'circles knee stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your hands on your hips. Step:2 Bend your knees slightly and lift your heels off the ground, balancing on the balls of your feet. Step:3 Keeping your knees bent, rotate your knees in a circular motion, first clockwise and then counterclockwise. Step:4 Perform the movement for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted russian twist', 'weighted russian twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your knees bent and your feet flat on the floor. Step:2 Hold a weight or medicine ball with both hands in front of your chest. Step:3 Lean back slightly, keeping your back straight and your core engaged. Step:4 Slowly twist your torso to the right, bringing the weight or medicine ball towards the floor on your right side. Step:5 Pause for a moment, then twist your torso to the left, bringing the weight or medicine ball towards the floor on your left side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('arm slingers hanging straight legs', 'arm slingers hanging straight legs', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your legs straight down. Step:2 Engage your core and lift your legs up in front of you until they are parallel to the ground. Step:3 Hold for a moment at the top, then slowly lower your legs back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller hip stretch', 'roller hip stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by sitting on the ground with your legs extended in front of you. Step:2 Place the roller under your glutes, just above your knees. Step:3 Lean back and place your hands on the ground behind you for support. Step:4 Engage your glutes and slowly roll the roller forward, bending your knees and bringing them towards your chest. Step:5 Pause for a moment at the end of the movement, feeling a stretch in your glutes. Step:6 Slowly roll the roller back to the starting position, extending your legs. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith machine reverse decline close grip bench press', 'smith machine reverse decline close grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the smith machine to a decline position. Step:2 Lie down on the bench with your feet secured under the foot pads. Step:3 Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('star jump (male)', 'star jump (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms by your sides. Step:2 Bend your knees slightly and jump up explosively. Step:3 As you jump, spread your legs and extend your arms out to the sides, forming a star shape with your body. Step:4 Land softly on the balls of your feet with your knees slightly bent. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one leg floor calf raise', 'one leg floor calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and place your hands on a wall or sturdy object for balance. Step:2 Lift one foot off the ground and balance on the other foot. Step:3 Slowly raise your heel off the ground, lifting your body up onto the ball of your foot. Step:4 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('walking high knees lunge', 'walking high knees lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart. Step:2 Lift your right knee up towards your chest as high as you can while balancing on your left leg. Step:3 Step forward with your right foot and lower your body into a lunge position, bending both knees to a 90-degree angle. Step:4 Push off with your right foot and bring your left knee up towards your chest. Step:5 Step forward with your left foot and lower your body into a lunge position. Step:6 Continue alternating legs and lunging forward, keeping your core engaged and maintaining a steady pace. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('elbow lift - reverse push-up', 'elbow lift - reverse push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying face down on the ground with your legs extended and your hands placed directly under your shoulders. Step:2 Engage your core and press through your palms to lift your upper body off the ground, keeping your elbows close to your sides. Step:3 Pause at the top for a moment, squeezing your upper back muscles. Step:4 Slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted one hand pull up', 'weighted one hand pull up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:2 Hang from the bar with your arm fully extended and your body straight. Step:3 Engage your core and pull your body up towards the bar by bending your elbow and squeezing your back muscles. Step:4 Continue pulling until your chin is above the bar. Step:5 Lower your body back down to the starting position with control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell curl', 'barbell curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward. Step:2 Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps. Step:3 Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale as you slowly begin to lower the bar back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm reverse fly (with support)', 'dumbbell one arm reverse fly (with support)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with your palm facing inwards. Step:3 Lean forward and place your free hand on the bench for support. Step:4 Keep your arm slightly bent and raise it out to the side until it is parallel to the ground. Step:5 Pause for a moment at the top, then slowly lower your arm back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell bicep curl on exercise ball with leg raised', 'dumbbell bicep curl on exercise ball with leg raised', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Step:3 Slowly curl the dumbbells towards your shoulders, keeping your elbows close to your sides. Step:4 Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position. Step:5 While performing the bicep curl, raise one leg off the ground and hold it in the air for the duration of the exercise. Step:6 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball hip flexor stretch', 'exercise ball hip flexor stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and kneel in front of it. Step:2 Place your right foot on top of the stability ball, with your knee bent at a 90-degree angle. Step:3 Extend your left leg behind you, keeping it straight. Step:4 Lean forward, pushing your hips towards the stability ball, until you feel a stretch in your right hip flexor. Step:5 Hold the stretch for 20-30 seconds, then switch sides and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever lying two-one leg curl', 'lever lying two-one leg curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to fit your body and sit on it with your back against the backrest. Step:2 Place your legs on the lever pad, just above your ankles. Step:3 Grasp the handles on the sides of the machine for support. Step:4 Keeping your upper body still, exhale and curl your legs up towards your glutes. Step:5 Pause for a moment at the top, then inhale and slowly lower your legs back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing back wrist curl', 'cable standing back wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Hold the cable handle with an overhand grip, palms facing down. Step:3 Keep your arms straight and your elbows close to your sides. Step:4 Slowly curl your wrists upward, bringing the cable handle towards your body. Step:5 Pause for a moment at the top, then slowly lower the cable handle back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated dip', 'lever seated dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that your feet are flat on the ground and your knees are at a 90-degree angle. Step:2 Grasp the handles of the leverage machine with your palms facing down and your arms fully extended. Step:3 Slowly lower your body by bending your elbows until your upper arms are parallel to the ground. Step:4 Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing calves', 'standing calves', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes pointing forward. Step:2 Raise your heels off the ground as high as possible, standing on your toes. Step:3 Hold the position for a moment, then slowly lower your heels back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing twist', 'barbell standing twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down. Step:2 Engage your core and keep your back straight throughout the exercise. Step:3 Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable. Step:4 Pause for a moment at the end of the twist, then slowly return to the starting position. Step:5 Repeat the twist to the left side. Step:6 Continue alternating twists for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever kneeling twist', 'lever kneeling twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your knees resting on the pads and your upper body facing forward. Step:2 Grasp the handles or the sides of the machine for stability. Step:3 Keeping your core engaged, twist your torso to one side as far as comfortably possible. Step:4 Pause for a moment, then slowly return to the starting position. Step:5 Repeat the twist to the opposite side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline leg hip raise (leg straight)', 'incline leg hip raise (leg straight)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on an incline bench with your back flat against the bench and your legs extended straight out in front of you. Step:2 Place your hands on the sides of the bench for support. Step:3 Engaging your abs, lift your legs off the bench, raising them as high as you can while keeping them straight. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell straight arm pullover', 'dumbbell straight arm pullover', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet planted firmly on the ground. Step:2 Hold a dumbbell with both hands and extend your arms straight above your chest. Step:3 Keeping your arms straight, slowly lower the dumbbell behind your head in an arc-like motion. Step:4 Pause for a moment, then raise the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell goblet squat', 'dumbbell goblet squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands. Step:2 Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees. Step:3 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell decline bench press', 'barbell decline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your feet secured and your head lower than your hips. Step:2 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Step:3 Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Step:4 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever assisted chin-up', 'lever assisted chin-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the leverage machine to your desired resistance level. Step:2 Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang with your arms fully extended, keeping your body straight. Step:4 Engage your back muscles and pull your body up towards the handles, leading with your chest. Step:5 Continue pulling until your chin is above the handles. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever alternate leg press', 'lever alternate leg press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat and foot platform of the leverage machine to your desired position. Step:2 Sit on the machine with your back against the backrest and your feet on the foot platform. Step:3 Place your hands on the handles or sides of the machine for stability. Step:4 Push one foot against the foot platform, extending your leg until it is almost fully straight. Step:5 Pause for a moment, then slowly bend your leg and return to the starting position. Step:6 Repeat with the other leg. Step:7 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest tap push-up (male)', 'chest tap push-up (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line. Step:2 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:3 As you lower yourself, tap your chest with your right hand. Step:4 Push yourself back up to the starting position. Step:5 Repeat the movement, this time tapping your chest with your left hand. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated preacher curl', 'dumbbell seated preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher curl bench with your feet flat on the floor. Step:2 Hold a dumbbell in one hand with an underhand grip, resting your upper arm against the preacher pad. Step:3 Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted front raise', 'weighted front raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs. Step:2 Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level. Step:3 Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reverse dip', 'reverse dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself between two parallel bars with your arms fully extended and your body straight. Step:2 Lower your body by bending your elbows until your upper arms are parallel to the ground. Step:3 Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated reverse grip one arm overhead tricep extension', 'dumbbell seated reverse grip one arm overhead tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell with an underhand grip and extend your arm straight up overhead. Step:3 Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary. Step:4 Pause for a moment, then extend your arm back up to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell one arm push press', 'kettlebell one arm push press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder level. Step:2 Bend your knees slightly and engage your core. Step:3 Press the kettlebell overhead by extending your arm and fully extending your legs. Step:4 Lower the kettlebell back to the starting position by bending your knees and bringing the kettlebell back to your shoulder. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternate seated hammer curl', 'dumbbell alternate seated hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended down. Step:2 Keep your back straight and your elbows close to your torso. Step:3 Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary. Step:4 Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level. Step:5 Pause for a brief moment, then inhale and slowly lower the dumbbell back to the starting position. Step:6 Repeat the movement with your left arm. Step:7 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('reverse grip pull-up', 'reverse grip pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an underhand grip, hands shoulder-width apart. Step:2 Hang from the bar with your arms fully extended and your body straight. Step:3 Engage your back muscles and pull your body up towards the bar, leading with your chest. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('captains chair straight leg raise', 'captains chair straight leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the captain''s chair with your back against the backrest and your forearms resting on the arm pads. Step:2 Keep your upper body stable and your back straight. Step:3 Engage your abs and lift your legs up in front of you, keeping them straight. Step:4 Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Step:5 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('power clean', 'power clean', 'Strength', 'Other', 'Intermediate', 'Step:1 Start with the barbell on the ground in front of you, with your feet shoulder-width apart. Step:2 Bend down and grip the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Keep your back straight and chest up as you lift the barbell off the ground, extending your hips and knees. Step:4 As the barbell reaches your mid-thigh, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides. Step:5 As the barbell reaches its highest point, quickly drop underneath it, rotating your elbows around and catching the barbell on your shoulders in a front squat position. Step:6 Stand up with the barbell, fully extending your hips and knees. Step:7 Lower the barbell back down to the starting position, keeping control of the weight throughout the movement. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez bar seated close grip concentration curl', 'ez bar seated close grip concentration curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold an EZ barbell with an underhand grip. Step:2 Rest your elbow on the inside of your thigh, just above the knee. Step:3 Curl the barbell up towards your shoulder while keeping your upper arm stationary. Step:4 Squeeze your biceps at the top of the movement, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('forward lunge (male)', 'forward lunge (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and hands on your hips. Step:2 Take a big step forward with your right foot, lowering your body into a lunge position. Step:3 Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle. Step:4 Push off with your right foot and return to the starting position. Step:5 Repeat with your left leg, alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternating bicep curl with leg raised on exercise ball', 'dumbbell alternating bicep curl with leg raised on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward. Step:2 Place an exercise ball behind you and position one foot on top of it, keeping your balance. Step:3 With your arms fully extended and elbows close to your sides, curl one dumbbell towards your shoulder while keeping your upper arm stationary. Step:4 Lower the dumbbell back down to the starting position and repeat with the other arm. Step:5 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triceps dip', 'triceps dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward. Step:2 Slide your butt off the bench, supporting your weight with your hands. Step:3 Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell decline close grip face press', 'ez barbell decline close grip face press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your head lower than your feet. Step:2 Grasp the ez barbell with a close grip, palms facing each other. Step:3 Extend your arms straight up above your chest, keeping your elbows close to your body. Step:4 Lower the barbell towards your forehead by bending your elbows. Step:5 Pause for a moment, then press the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith one leg floor calf raise', 'smith one leg floor calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself on the floor under the smith machine bar, facing away from the machine. Step:2 Place the balls of your feet on a raised surface, such as a weight plate or block. Step:3 Position the smith machine bar across your lower legs, just above your ankles. Step:4 Hold onto the bar with your hands for stability. Step:5 Raise your heels off the ground by extending your ankles, lifting your body up. Step:6 Pause at the top of the movement, then slowly lower your heels back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging straight twisting leg hip raise', 'hanging straight twisting leg hip raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your legs straight. Step:2 Engage your core and lift your legs up towards your chest, keeping them straight. Step:3 Once your legs are parallel to the ground, twist your hips to one side, bringing your legs towards that side. Step:4 Pause for a moment, then return to the starting position. Step:5 Repeat the movement, but this time twist your hips to the opposite side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated crunch (chest pad)', 'lever seated crunch (chest pad)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and chest pad position according to your comfort. Step:2 Sit on the machine with your back against the chest pad and your feet flat on the floor. Step:3 Grasp the handles or side bars for stability. Step:4 Engage your abs and slowly lean back, allowing the chest pad to move with you. Step:5 Pause for a moment at the maximum contraction, feeling the tension in your abs. Step:6 Slowly return to the starting position by contracting your abs and pulling yourself back up. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm fly on exercise ball', 'cable one arm fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a cable handle in one hand and extend your arm out to the side, parallel to the ground. Step:3 Keep your elbow slightly bent and your palm facing forward. Step:4 Slowly bring your arm across your body, squeezing your chest muscles. Step:5 Pause for a moment at the end of the movement, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('oblique crunch v. 2', 'oblique crunch v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head or cross them over your chest. Step:3 Engage your abs and lift your shoulder blades off the ground, rotating your torso to one side. Step:4 Pause for a moment, then lower your shoulder blades back down to the starting position. Step:5 Repeat on the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable cross-over variation', 'cable cross-over variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable pulleys to chest height. Step:2 Stand in the center of the cable machine with one foot in front of the other. Step:3 Grasp the handles with your palms facing down and your arms extended out to the sides. Step:4 Take a step forward, keeping your arms slightly bent. Step:5 With a slight bend in your elbows, bring your hands together in front of your chest. Step:6 Pause for a moment, then slowly return your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell over bench wrist curl', 'dumbbell over bench wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your forearms resting on the bench and your palms facing up, holding a dumbbell in each hand. Step:2 Allow your wrists to hang over the edge of the bench. Step:3 Slowly curl your wrists upward, squeezing your forearms at the top of the movement. Step:4 Pause for a moment, then slowly lower your wrists back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell single leg split squat', 'barbell single leg split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a barbell across your upper back. Step:2 Take a large step forward with one leg, keeping your torso upright. Step:3 Lower your body by bending your front knee and hip, while keeping your back leg straight. Step:4 Continue lowering until your front thigh is parallel to the ground. Step:5 Pause for a moment, then push through your front heel to return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm hammer press', 'dumbbell incline one arm hammer press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an incline bench with a dumbbell in one hand, resting on your thigh. Step:2 Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height. Step:3 Rotate your wrist so that your palm is facing inward, towards your body. Step:4 Press the dumbbell up and away from your body, extending your arm fully. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45в° calf press', 'sled 45в° calf press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a 45-degree angle. Step:2 Place your feet on the sled platform with your toes pointing forward. Step:3 Push the sled platform away from you by extending your ankles and calves. Step:4 Pause for a moment at the top, then slowly lower the sled platform back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pike-to-cobra push-up', 'pike-to-cobra push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together. Step:2 Engage your core and lift your hips up towards the ceiling, forming an inverted V shape with your body. Step:3 Lower your upper body towards the ground by bending your elbows, keeping them close to your body. Step:4 As you lower down, shift your weight forward and transition into a cobra pose by straightening your arms and lifting your chest up. Step:5 Reverse the movement by bending your elbows and lowering your chest back down towards the ground. Step:6 Push through your hands to return to the inverted V position. Step:7 Continue the movement by lowering your hips back down towards the ground, returning to the starting push-up position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell seated overhead press', 'barbell seated overhead press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward. Step:4 Press the barbell overhead by extending your arms fully. Step:5 Pause for a moment at the top, then slowly lower the barbell back to shoulder level. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith shoulder press', 'smith shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the smith machine with your feet shoulder-width apart. Step:2 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lift the bar off the rack and position it at shoulder level, with your elbows bent and palms facing forward. Step:4 Press the bar upward until your arms are fully extended overhead. Step:5 Pause for a moment at the top, then slowly lower the bar back down to shoulder level. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable pushdown (straight arm) v. 2', 'cable pushdown (straight arm) v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a high pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Step:3 Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down. Step:4 Engage your core and keep your back straight as you exhale and push the bar down towards your thighs. Step:5 Pause for a moment at the bottom, then slowly return the bar to the starting position while inhaling. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('frog crunch', 'frog crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying hammer press', 'dumbbell lying hammer press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up. Step:2 Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle. Step:3 Press the dumbbells back up to the starting position, fully extending your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm kickback', 'dumbbell one arm kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in your right hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Bring your right elbow up to your side, keeping it bent at a 90-degree angle. Step:4 Extend your right arm straight back, squeezing your triceps at the top of the movement. Step:5 Slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest and front of shoulder stretch', 'chest and front of shoulder stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand tall with your feet shoulder-width apart. Step:2 Extend your arms straight out in front of you at shoulder height. Step:3 Cross your arms in front of your body, with your right arm on top of your left arm. Step:4 Interlace your fingers and press your palms together. Step:5 Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders. Step:6 Hold the stretch for 20-30 seconds, then release. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell standing front raise above head', 'dumbbell standing front raise above head', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Keep your arms straight and lift the dumbbells in front of you, raising them above your head. Step:3 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ankle circles', 'ankle circles', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you. Step:2 Lift one leg off the ground and rotate your ankle in a circular motion. Step:3 Perform the desired number of circles in one direction, then switch to the other direction. Step:4 Repeat with the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('roller hip lat stretch', 'roller hip lat stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the ground with the roller positioned under your hips. Step:2 Place your hands on the roller for support. Step:3 Slowly roll the roller forward, extending your hips and stretching your glutes. Step:4 Hold the stretch for a few seconds, then roll back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable incline bench row', 'cable incline bench row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley. Step:2 Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent. Step:3 Grasp the cable handle with an overhand grip and extend your arms fully in front of you. Step:4 Lean forward from your hips while keeping your back straight and your core engaged. Step:5 Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows. Step:6 Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever bent over row', 'lever bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Bend forward at the hips, keeping your back straight and chest up. Step:4 Pull the barbell towards your lower chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing wide military press', 'barbell standing wide military press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width. Step:2 Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar. Step:3 Press the barbell overhead, extending your arms fully. Step:4 Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell sitted alternate leg raise (female)', 'barbell sitted alternate leg raise (female)', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and hold a barbell across your thighs. Step:2 Place your hands on the sides of the bench for support. Step:3 Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground. Step:4 Lower the leg back down and repeat with the other leg. Step:5 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell seated curls', 'ez barbell seated curls', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and your back straight. Step:2 Hold the ez barbell with an underhand grip, palms facing up, and your hands shoulder-width apart. Step:3 Rest your upper arms on your thighs, allowing the ez barbell to hang down in front of you. Step:4 Keeping your upper arms stationary, exhale and curl the ez barbell upwards towards your shoulders. Step:5 Pause for a moment at the top, squeezing your biceps. Step:6 Inhale and slowly lower the ez barbell back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted parallel close grip pull-up', 'assisted parallel close grip pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired weight and height. Step:2 Place your hands on the parallel bars with a close grip, palms facing each other. Step:3 Hang from the bars with your arms fully extended and your feet off the ground. Step:4 Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your body. Step:5 Continue pulling until your chin is above the bars. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbells seated triceps extension', 'dumbbells seated triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a dumbbell in both hands with an overhand grip, and raise it above your head. Step:3 Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears. Step:4 Extend your arms and raise the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging pike', 'hanging pike', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up towards the bar, keeping them straight. Step:3 Continue lifting until your body forms a ''V'' shape, with your legs parallel to the ground. Step:4 Hold the position for a moment, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted standing hand squeeze', 'weighted standing hand squeeze', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a weight in each hand. Step:2 Extend your arms straight in front of you, palms facing each other. Step:3 Squeeze your hands together as hard as you can, engaging your forearms. Step:4 Hold the squeeze for a few seconds, then release. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell biceps curl', 'dumbbell biceps curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended. Step:2 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:3 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable straight arm pulldown (with rope)', 'cable straight arm pulldown (with rope)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to the cable machine at the highest setting. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the rope with both hands, palms facing down. Step:4 Extend your arms fully in front of you, keeping your elbows slightly bent. Step:5 Engage your lats and slowly pull the rope down towards your thighs, keeping your arms straight. Step:6 Pause for a moment at the bottom, then slowly release the tension and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever narrow grip seated row', 'lever narrow grip seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footrests to ensure proper form. Step:2 Sit on the machine with your feet flat on the footrests and your knees slightly bent. Step:3 Grasp the handles with a narrow grip, palms facing each other. Step:4 Keep your back straight and lean slightly forward. Step:5 Pull the handles towards your torso, squeezing your shoulder blades together. Step:6 Pause for a moment at the peak of the movement. Step:7 Slowly release the handles and return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('box jump down with one leg stabilization', 'box jump down with one leg stabilization', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a box or platform with your feet shoulder-width apart. Step:2 Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge. Step:3 Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground. Step:4 Hold this position for a few seconds, engaging your calf muscles to maintain balance. Step:5 Slowly step down with the foot that is on the box, returning to the starting position. Step:6 Repeat the exercise with the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated kickback', 'dumbbell seated kickback', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand. Step:2 Bend your knees slightly and lean forward from your hips, keeping your back straight. Step:3 Bring your upper arms close to your sides and keep your elbows bent at a 90-degree angle. Step:4 Extend your arms straight back, squeezing your triceps at the top of the movement. Step:5 Pause for a moment, then slowly lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell clean', 'dumbbell clean', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Bend your knees and lower your hips into a squat position, keeping your back straight and chest up. Step:3 Explosively extend your hips and knees, driving through your heels to jump off the ground. Step:4 As you jump, shrug your shoulders and pull the dumbbells up towards your shoulders, keeping them close to your body. Step:5 Catch the dumbbells at shoulder height, with your elbows pointing forward and your palms facing up. Step:6 Lower the dumbbells back down to the starting position by reversing the movement. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('elbow-to-knee', 'elbow-to-knee', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee. Step:4 At the same time, bring your left knee towards your right elbow, creating a twisting motion. Step:5 Pause for a moment at the top, then slowly lower your upper body and extend your legs back to the starting position. Step:6 Repeat the movement, this time bringing your left elbow towards your right knee and your right knee towards your left elbow. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated reverse fly', 'lever seated reverse fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Step:2 Grasp the handles with an overhand grip and keep your arms slightly bent. Step:3 Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body. Step:4 Pause for a moment at the peak contraction, then inhale and slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band seated straight back row', 'resistance band seated straight back row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the floor with your legs extended and loop the resistance band around your feet. Step:2 Hold the ends of the resistance band with your hands, palms facing each other. Step:3 Keep your back straight and lean slightly back, engaging your core. Step:4 Pull the resistance band towards your chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted russian twist v. 2', 'weighted russian twist v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your knees bent and feet flat on the floor. Step:2 Hold the weight with both hands in front of your chest. Step:3 Lean back slightly to engage your core muscles. Step:4 Twist your torso to the right, bringing the weight towards the right side of your body. Step:5 Pause for a moment, then twist your torso to the left, bringing the weight towards the left side of your body. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('world greatest stretch', 'world greatest stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a lunge position with your right foot forward and your left foot back. Step:2 Place your hands on the ground on either side of your right foot. Step:3 Lower your left knee to the ground and extend your right leg, keeping your right foot flat on the ground. Step:4 Rotate your torso to the right, reaching your right arm up towards the ceiling. Step:5 Hold this position for a few seconds, then return to the starting position. Step:6 Switch sides and repeat the stretch with your left foot forward.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever incline chest press', 'lever incline chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat and backrest of the leverage machine to a comfortable position. Step:2 Sit on the machine with your back against the backrest and your feet flat on the floor. Step:3 Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Step:4 Push the handles forward and away from your body until your arms are fully extended. Step:5 Pause for a moment, then slowly bend your elbows and lower the handles back towards your chest. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('back pec stretch', 'back pec stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand tall with your feet shoulder-width apart. Step:2 Extend your arms straight out in front of you, parallel to the ground. Step:3 Cross your arms in front of your body, with your right arm over your left arm. Step:4 Interlock your fingers and rotate your palms away from your body. Step:5 Slowly raise your arms up and away from your body, feeling a stretch in your back and chest. Step:6 Hold the stretch for 15-30 seconds, then release. Step:7 Repeat on the opposite side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable curl', 'cable curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Grasp the cable attachment with an underhand grip, palms facing up. Step:3 Keep your elbows close to your sides and your upper arms stationary. Step:4 Exhale and curl the cable attachment towards your shoulders, contracting your biceps. Step:5 Pause for a moment at the top of the movement, squeezing your biceps. Step:6 Inhale and slowly lower the cable attachment back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball supine triceps extension', 'exercise ball supine triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold a dumbbell with both hands and extend your arms straight up towards the ceiling. Step:3 Slowly lower the dumbbell behind your head, keeping your elbows close to your ears. Step:4 Pause for a moment, then raise the dumbbell back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('twisted leg raise', 'twisted leg raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Place your hands under your glutes for support. Step:3 Engage your abs and lift both legs off the ground, keeping them straight. Step:4 As you lift your legs, twist your hips to one side, bringing your legs towards your opposite shoulder. Step:5 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:6 Repeat the movement, this time twisting your hips to the other side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable side bend crunch (bosu ball)', 'cable side bend crunch (bosu ball)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a cable handle in one hand. Step:2 Place the other hand on your hip. Step:3 Engage your core and slowly bend sideways towards the hand holding the cable, keeping your back straight. Step:4 Pause for a moment at the bottom of the movement, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('clap push up', 'clap push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands slightly wider than shoulder-width apart. Step:2 Lower your body towards the ground by bending your elbows, keeping your core engaged. Step:3 Push through your palms explosively to propel your body off the ground. Step:4 While in mid-air, clap your hands together before landing back in the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell hammer curl', 'dumbbell hammer curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your torso. Step:2 Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. Step:3 This will be your starting position. Step:4 Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Step:5 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Then, inhale and slowly begin to lower the dumbbells back to the starting position. Step:8 Repeat for the recommended amount of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rear pull-up', 'rear pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:2 Hang from the bar with your arms fully extended and your body straight. Step:3 Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm zottman preacher curl', 'dumbbell one arm zottman preacher curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher curl bench and hold a dumbbell in one hand with an underhand grip. Step:2 Rest your upper arm on the preacher bench pad, allowing your arm to fully extend. Step:3 Curl the dumbbell up towards your shoulder, keeping your upper arm stationary. Step:4 At the top of the curl, rotate your wrist so that your palm faces up. Step:5 Slowly lower the dumbbell back down to the starting position, rotating your wrist back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lateral lunge', 'barbell lateral lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a barbell across your upper back. Step:2 Take a big step to the side with your right foot, keeping your left foot planted. Step:3 Bend your right knee and lower your body down into a lunge position, keeping your left leg straight. Step:4 Push off with your right foot and return to the starting position. Step:5 Repeat on the other side, stepping with your left foot.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up medicine ball', 'push-up medicine ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands on the medicine ball, shoulder-width apart. Step:2 Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight. Step:3 Push through your palms to extend your arms and return to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever standing calf raise', 'lever standing calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your height and stand with your feet shoulder-width apart. Step:2 Place your shoulders under the pads and hold onto the handles for stability. Step:3 Raise your heels as high as possible by extending your ankles. Step:4 Pause for a moment at the top, then slowly lower your heels back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell alternating hang clean', 'kettlebell alternating hang clean', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Step:3 Allow the kettlebells to hang in front of your body with your arms fully extended. Step:4 In one fluid motion, explosively extend your hips, shrug your shoulders, and pull the kettlebells up towards your shoulders. Step:5 As the kettlebells reach shoulder height, rotate your wrists and catch the kettlebells in the rack position, with your palms facing inward and the kettlebells resting on the outside of your forearms. Step:6 Lower the kettlebells back down to the starting position and repeat the movement with the opposite arm. Step:7 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell rear delt row_shoulder', 'dumbbell rear delt row_shoulder', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold a dumbbell in each hand with your palms facing your body. Step:3 Bend forward at the waist, keeping your back straight and your core engaged. Step:4 Extend your arms straight down towards the floor, with a slight bend in your elbows. Step:5 Raise the dumbbells out to the sides, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable reverse wrist curl', 'cable reverse wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable to a low pulley and sit on a bench facing the cable machine. Step:2 Grasp the cable handle with an overhand grip, palms facing down. Step:3 Rest your forearms on your thighs, with your wrists hanging off the edge. Step:4 Keeping your forearms stationary, exhale and curl your wrists upward as far as possible. Step:5 Pause for a moment at the top, then inhale and slowly lower your wrists back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing crunch (with rope attachment)', 'cable standing crunch (with rope attachment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a cable machine at chest height. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Hold the rope with both hands and bring it behind your head, keeping your elbows bent. Step:4 Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees. Step:5 Pause for a moment at the top of the crunch, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell advanced windmill', 'kettlebell advanced windmill', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointing slightly outward. Step:2 Hold a kettlebell in your right hand, with your arm extended overhead and your palm facing forward. Step:3 Rotate your left foot slightly to the right, and shift your weight onto your left leg. Step:4 Bend your left knee and hinge at the hip, lowering your torso towards the left side. Step:5 Keep your right arm extended overhead and your eyes on the kettlebell. Step:6 As you lower your torso, allow your right leg to straighten and your right foot to pivot slightly. Step:7 Lower your torso until you feel a stretch in your left hamstring and your right arm is pointing towards the ground. Step:8 Pause for a moment, then engage your core and push through your left heel to return to the starting position. Step:9 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing hamstring and calf stretch with strap', 'standing hamstring and calf stretch with strap', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand upright with your feet shoulder-width apart. Step:2 Hold the strap with both hands and place it around the ball of your foot. Step:3 Keep your leg straight and slowly lean forward from your hips, keeping your back straight. Step:4 Feel the stretch in your hamstring and calf muscles. Step:5 Hold the stretch for 20-30 seconds. Step:6 Release the stretch and repeat with the other leg. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez bar french press on exercise ball', 'ez bar french press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball and hold an EZ barbell with an overhand grip. Step:2 Extend your arms straight up, keeping your elbows close to your head. Step:3 Slowly lower the barbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('single leg platform slide', 'single leg platform slide', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with one foot on a platform or slide board. Step:2 Bend your knee slightly and slide the foot on the platform backward, extending your leg. Step:3 Keep your core engaged and maintain a straight posture throughout the movement. Step:4 Slowly return to the starting position by sliding your foot back to the initial position. Step:5 Repeat the movement for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever one arm lateral wide pulldown', 'lever one arm lateral wide pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Step:2 Grasp the handle with an overhand grip and fully extend your arm, keeping a slight bend in your elbow. Step:3 Pull the handle down and across your body towards your opposite hip, squeezing your lat muscle at the bottom of the movement. Step:4 Slowly return the handle to the starting position, fully extending your arm. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing one leg calf raise', 'cable standing one leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Hold onto the cable machine for support. Step:3 Lift one leg off the ground and balance on the other leg. Step:4 Slowly raise your heel off the ground, lifting your body up onto your toes. Step:5 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable pulldown', 'cable pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured. Step:2 Sit on the seat with your back straight and your feet flat on the ground. Step:3 Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lean back slightly and engage your core. Step:5 Pull the cable bar down towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('london bridge', 'london bridge', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the rope to a high anchor point. Step:2 Stand facing away from the anchor point with your feet shoulder-width apart. Step:3 Grasp the rope with an overhand grip, palms facing down. Step:4 Lean forward slightly, keeping your back straight and core engaged. Step:5 Pull the rope towards your body, squeezing your shoulder blades together. Step:6 Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez bar reverse grip bent over row', 'ez bar reverse grip bent over row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold the ez barbell with an underhand grip, palms facing up, and hands shoulder-width apart. Step:3 Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor. Step:4 Pull the ez barbell towards your lower chest, squeezing your shoulder blades together. Step:5 Pause for a moment at the top, then slowly lower the ez barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band single leg calf raise', 'band single leg calf raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and place the band around the ball of your left foot. Step:2 Hold onto a stable object for balance if needed. Step:3 Slowly raise your left heel off the ground, lifting your body weight onto the ball of your foot. Step:4 Pause for a moment at the top, then slowly lower your left heel back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the right leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band one arm twisting seated row', 'band one arm twisting seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground and your back straight. Step:2 Hold the band with one hand and extend your arm fully in front of you. Step:3 Keeping your back straight, pull the band towards your body by bending your elbow and squeezing your shoulder blades together. Step:4 At the same time, twist your torso towards the side of the pulling arm. Step:5 Pause for a moment at the top, then slowly release the tension in the band and return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell pullover on exercise ball', 'dumbbell pullover on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball and hold a dumbbell with both hands above your chest, arms extended. Step:2 Slowly lower the dumbbell behind your head while keeping your arms straight. Step:3 Pause for a moment, then raise the dumbbell back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('quarter sit-up', 'quarter sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('all fours squad stretch', 'all fours squad stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Step:2 Extend one leg straight back, keeping your knee bent and your foot flexed. Step:3 Slowly lower your hips towards the ground, feeling a stretch in your quads. Step:4 Hold this position for 20-30 seconds. Step:5 Switch legs and repeat the stretch on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated reverse fly (parallel grip)', 'lever seated reverse fly (parallel grip)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor. Step:2 Grasp the handles with a parallel grip, palms facing each other, and keep your arms slightly bent. Step:3 Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body. Step:4 Pause for a moment at the peak contraction, then inhale and slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline one arm hammer press', 'dumbbell decline one arm hammer press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with a dumbbell in one hand, resting on your chest. Step:2 Extend your arm straight up, keeping your elbow slightly bent. Step:3 Lower the dumbbell down towards your shoulder, keeping your elbow close to your body. Step:4 Press the dumbbell back up to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('jump squat v. 2', 'jump squat v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Lower your body into a squat position by bending your knees and pushing your hips back. Step:3 Jump explosively, extending your hips and knees fully. Step:4 Land softly on the balls of your feet and immediately lower your body back into a squat position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rear drive', 'cable rear drive', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a handle to a low pulley cable machine and stand facing away from the machine. Step:2 Grasp the handle with an overhand grip and extend your arms straight out in front of you. Step:3 Keeping your elbows stationary, pull the handle back towards your body, squeezing your triceps at the end of the movement. Step:4 Slowly return the handle to the starting position and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell skier', 'barbell skier', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up. Step:3 Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground. Step:4 As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell over bench one arm wrist curl', 'dumbbell over bench one arm wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down. Step:2 Rest your forearm on the bench with your wrist hanging off the edge. Step:3 Slowly curl your wrist upwards, bringing the dumbbell towards your forearm. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline bench press', 'dumbbell incline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench. Step:3 Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height. Step:4 Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle. Step:5 Push the dumbbells back up to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope seated row', 'cable rope seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the rowing machine with your feet flat on the footrests and knees slightly bent. Step:2 Grasp the cable ropes with an overhand grip, palms facing each other. Step:3 Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows. Step:4 Pull the cable ropes towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith behind neck press', 'smith behind neck press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height of the smith machine so that the bar is at shoulder level. Step:2 Stand with your feet shoulder-width apart and your knees slightly bent. Step:3 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lift the bar off the rack and step back, maintaining a stable stance. Step:5 Lower the bar down to the back of your neck, keeping your elbows pointing forward. Step:6 Press the bar up overhead until your arms are fully extended. Step:7 Pause for a moment at the top, then slowly lower the bar back down to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('farmers walk', 'farmers walk', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your sides. Step:2 Keep your back straight and your shoulders back. Step:3 Take small, controlled steps forward, maintaining an upright posture. Step:4 Continue walking for the desired distance or time. Step:5 To finish, stop walking and carefully lower the dumbbells to your sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable squat row (with rope attachment)', 'cable squat row (with rope attachment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a cable machine at waist height. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Bend your knees and lower your body into a squat position, keeping your back straight and chest up. Step:4 Grasp the rope with an overhand grip, with your hands shoulder-width apart. Step:5 Engage your core and pull the rope towards your body, squeezing your shoulder blades together. Step:6 Keep your elbows close to your body and continue pulling until your hands reach your chest. Step:7 Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable straight back seated row', 'cable straight back seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Step:2 Grasp the cable handles with an overhand grip, palms facing down. Step:3 Keep your back straight and lean slightly forward from the hips. Step:4 Pull the cable handles towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever decline chest press', 'lever decline chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and backrest of the leverage machine to a comfortable position. Step:2 Sit on the machine with your back against the backrest and your feet flat on the floor. Step:3 Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Step:4 Push the handles forward and away from your body until your arms are fully extended. Step:5 Slowly lower the handles back towards your chest, keeping your elbows slightly bent. Step:6 Pause for a moment at the bottom, then push the handles back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever lateral raise', 'lever lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the pad. Step:2 Grasp the handles with an overhand grip and keep your arms straight. Step:3 Exhale and raise your arms out to the sides until they are parallel to the floor. Step:4 Pause for a moment at the top, then inhale and slowly lower your arms back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inchworm v. 2', 'inchworm v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a standing position with your feet hip-width apart. Step:2 Bend forward at the waist and place your hands on the ground in front of you. Step:3 Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe. Step:4 Keeping your legs straight, walk your feet towards your hands, bringing your hips up towards the ceiling. Step:5 Continue walking your hands forward, repeating the movement for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kneeling plank tap shoulder (male)', 'kneeling plank tap shoulder (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a kneeling position with your hands on the ground, shoulder-width apart. Step:2 Extend your legs behind you, resting on your toes, and lift your body into a plank position. Step:3 Keeping your core engaged and your hips stable, lift one hand off the ground and tap the opposite shoulder. Step:4 Return the hand to the ground and repeat with the other hand. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('handstand push-up', 'handstand push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Find a wall and face away from it, standing a few feet away. Step:2 Place your hands on the ground shoulder-width apart and kick your feet up against the wall, coming into a handstand position. Step:3 Bend your elbows and lower your head towards the ground, keeping your body in a straight line. Step:4 Push through your hands and extend your arms to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled closer hack squat', 'sled closer hack squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a comfortable weight and position yourself with your back against the pad. Step:2 Place your feet shoulder-width apart on the platform, toes slightly pointed outwards. Step:3 Grip the handles on the sides of the machine for stability. Step:4 Engage your core and slowly lower your body by bending your knees and hips, keeping your back straight. Step:5 Continue lowering until your thighs are parallel to the ground or slightly below. Step:6 Pause for a moment at the bottom, then push through your heels to extend your legs and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell rear delt raise', 'dumbbell rear delt raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor. Step:4 Pause for a moment at the top, then slowly lower your arms back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('medicine ball chest push single response', 'medicine ball chest push single response', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding the medicine ball at chest level. Step:2 Extend your arms forward, pushing the medicine ball away from your chest. Step:3 Pause for a moment, then slowly bring the medicine ball back to your chest. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rocking frog stretch', 'rocking frog stretch', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the ground with your knees hip-width apart. Step:2 Place your hands on the ground in front of you for support. Step:3 Slowly lean forward, shifting your weight onto your hands and extending your legs behind you. Step:4 Keep your back straight and engage your glutes as you push your hips back and up towards the ceiling. Step:5 Hold this position for a few seconds, feeling a stretch in your glutes. Step:6 Slowly return to the starting position by bending your knees and lowering your hips back down. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm shoulder press v. 2', 'dumbbell one arm shoulder press v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward. Step:2 Engage your core and press the dumbbell straight up overhead, fully extending your arm. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back to shoulder level. Step:4 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell step-up split squat', 'dumbbell step-up split squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a bench or step with a dumbbell in each hand, palms facing your body. Step:2 Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface. Step:3 Step up onto the bench or step with your right foot, pushing through your heel to lift your body up. Step:4 As you step up, simultaneously lift your left knee towards your chest. Step:5 Pause at the top of the movement, then slowly lower your left foot back to the ground while keeping your right foot on the bench or step. Step:6 Repeat the movement with your left foot on the bench or step. Step:7 Continue alternating between your right and left foot for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('standing behind neck press', 'standing behind neck press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the barbell behind your neck with an overhand grip. Step:2 Keep your back straight and core engaged. Step:3 Press the barbell overhead by extending your arms, fully extending your elbows. Step:4 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('biceps narrow pull-ups', 'biceps narrow pull-ups', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Step:2 Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body. Step:3 Pause for a moment at the top, then slowly lower yourself back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hands clasped circular toe touch (male)', 'hands clasped circular toe touch (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your hands clasped together in front of your chest. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Lower your hands towards your toes in a circular motion, reaching as far as you can without straining. Step:4 Pause for a moment at the bottom, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('l-pull-up', 'l-pull-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:2 Hang with your arms fully extended and your body straight. Step:3 Engage your lats and biceps to pull your body up towards the bar, keeping your elbows close to your body. Step:4 Continue pulling until your chin is above the bar. Step:5 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse grip row (female)', 'dumbbell reverse grip row (female)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold a dumbbell in each hand with an overhand grip, palms facing your body. Step:3 Bend forward at the waist, keeping your back straight and your core engaged. Step:4 Let your arms hang straight down, fully extended, with a slight bend in your elbows. Step:5 Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse bench press', 'dumbbell reverse bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your knees bent. Step:2 Hold a dumbbell in each hand with an overhand grip, palms facing towards your feet. Step:3 Extend your arms straight up towards the ceiling, keeping a slight bend in your elbows. Step:4 Slowly lower the dumbbells towards your chest, allowing your elbows to flare out to the sides. Step:5 Pause for a moment at the bottom, then push the dumbbells back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell cross body hammer curl v. 2', 'dumbbell cross body hammer curl v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your body. Step:2 Keep your elbows close to your torso and your upper arms stationary. Step:3 Exhale and curl the weights while contracting your biceps, bringing the dumbbells as close to your opposite shoulder as possible. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly begin to lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying pronation', 'dumbbell lying pronation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand. Step:2 Rotate your palms so they are facing up. Step:3 Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down. Step:4 Inhale and slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable kneeling triceps extension', 'cable kneeling triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a high pulley and kneel down facing the cable machine. Step:2 Grasp the rope with a neutral grip (palms facing each other) and bring your hands to the sides of your head. Step:3 Keep your elbows close to your head and your upper arms stationary throughout the exercise. Step:4 Extend your forearms by contracting your triceps until your arms are fully extended. Step:5 Pause for a moment, then slowly return to the starting position by bending your elbows. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline one arm fly', 'dumbbell decline one arm fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie down on a decline bench with a dumbbell in one hand, resting it on your thigh. Step:2 Using your thigh to help raise the dumbbell, lift it up to shoulder width with your palm facing your torso. Step:3 Rotate your wrist so that the palm of your hand is facing forward. Step:4 As you breathe in, lower the dumbbell slowly to the side until you feel a stretch in your chest. Step:5 Exhale and use your chest muscles to bring the dumbbell back up to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('straddle planche', 'straddle planche', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and your feet spread wide apart. Step:2 Engage your core and slowly shift your weight forward, bringing your shoulders over your hands. Step:3 Bend your elbows and lower your body towards the ground, keeping your elbows close to your sides. Step:4 Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable hammer curl (with rope)', 'cable hammer curl (with rope)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand upright with your feet shoulder-width apart and a slight bend in your knees. Step:2 Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:4 Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level. Step:5 Hold the contracted position for a brief pause as you squeeze your biceps. Step:6 Inhale and slowly begin to lower the cable rope attachment back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('swimmer kicks v. 2 (male)', 'swimmer kicks v. 2 (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a mat with your arms extended overhead. Step:2 Engage your core and lift your chest and legs off the ground simultaneously. Step:3 Kick your legs up and down in a fluttering motion, as if you were swimming. Step:4 Continue kicking for the desired number of repetitions. Step:5 Lower your chest and legs back down to the starting position.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith machine bicep curl', 'smith machine bicep curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the height of the smith machine bar to be at waist level. Step:2 Stand facing the smith machine with your feet shoulder-width apart. Step:3 Grasp the bar with an underhand grip, hands slightly wider than shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary. Step:5 Exhale and curl the bar up towards your shoulders, contracting your biceps. Step:6 Pause for a moment at the top of the movement, squeezing your biceps. Step:7 Inhale and slowly lower the bar back down to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one leg fly on exercise ball', 'dumbbell one leg fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in each hand, palms facing each other. Step:2 Place one foot on the ground and extend the other leg straight out in front of you. Step:3 Lean forward slightly and bring your arms out to the sides, keeping a slight bend in your elbows. Step:4 Slowly lower the dumbbells down and out to the sides, feeling a stretch in your chest. Step:5 Pause for a moment at the bottom, then squeeze your chest muscles to bring the dumbbells back up to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lying fly', 'cable lying fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the handles to the cables and lie flat on a bench with your feet flat on the ground. Step:2 Hold the handles with your palms facing each other and your arms extended straight above your chest. Step:3 Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest. Step:4 Pause for a moment, then squeeze your chest muscles to bring your arms back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse wrist curl', 'dumbbell reverse wrist curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground. Step:2 Hold a dumbbell in each hand with an overhand grip, palms facing down. Step:3 Rest your forearms on your thighs, allowing your wrists to hang off the edge. Step:4 Slowly curl your wrists upward, bringing the dumbbells towards your body. Step:5 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm pullover on exercise ball', 'dumbbell one arm pullover on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle. Step:2 Hold a dumbbell with one hand and extend your arm straight up above your chest. Step:3 Slowly lower the dumbbell behind your head while keeping your arm straight. Step:4 Pause for a moment, then raise the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline reverse grip push-up', 'incline reverse grip push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Place your hands on the edge of a bench or elevated surface, slightly wider than shoulder-width apart. Step:2 Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels. Step:3 Lower your chest towards the bench by bending your elbows, keeping them close to your sides. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('quads', 'quads', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Lower your body by bending your knees and pushing your hips back as if sitting on a chair. Step:3 Keep your chest up and your back straight. Step:4 Lower yourself until your thighs are parallel to the ground. Step:5 Push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell figure 8', 'kettlebell figure 8', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in one hand. Step:2 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:3 Pass the kettlebell between your legs, switching hands as it reaches the back of your legs. Step:4 As the kettlebell comes forward, pass it to the other hand between your legs. Step:5 Continue passing the kettlebell between your legs in a figure 8 motion. Step:6 Maintain a steady pace and engage your core throughout the exercise. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell high curl', 'dumbbell high curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing forward. Step:2 Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps. Step:3 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cross body crunch', 'cross body crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat on the other side, bringing your left elbow towards your right knee. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable standing rear delt row (with rope)', 'cable standing rear delt row (with rope)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a cable machine with your feet shoulder-width apart. Step:2 Hold the cable attachment with both hands, palms facing each other, and step back to create tension in the cable. Step:3 Keep your back straight and your core engaged. Step:4 Pull the cable towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the movement, then slowly release the cable back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('russian twist', 'russian twist', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your knees bent and feet flat on the floor. Step:2 Lean back slightly while keeping your back straight and your core engaged. Step:3 Hold your hands together in front of your chest or hold a weight if desired. Step:4 Lift your feet off the ground, balancing on your sit bones. Step:5 Twist your torso to the right, bringing your hands or weight towards the right side of your body. Step:6 Pause for a moment, then twist your torso to the left, bringing your hands or weight towards the left side of your body. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell anti gravity press', 'ez barbell anti gravity press', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart and holding the ez barbell with an overhand grip. Step:2 Raise the barbell to shoulder height, keeping your elbows slightly bent and your palms facing forward. Step:3 Press the barbell overhead, extending your arms fully. Step:4 Lower the barbell back to shoulder height and repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('backward jump', 'backward jump', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees slightly and jump backwards, pushing off with both feet. Step:3 Land softly on the balls of your feet, bending your knees to absorb the impact. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell thruster', 'kettlebell thruster', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by standing with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands, palms facing each other. Step:2 Lower into a squat position by bending your knees and pushing your hips back, keeping your chest up and your back straight. Step:3 As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the kettlebell overhead. Step:4 Lock out your arms at the top of the movement, fully extending your elbows. Step:5 Lower the kettlebell back to the starting position by reversing the movement, bending your elbows and lowering the weight back to your chest. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell rack pull', 'barbell rack pull', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a barbell on a rack at knee height. Step:2 Stand with your feet shoulder-width apart, toes pointing slightly outwards. Step:3 Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart. Step:4 Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top. Step:5 Lower the barbell back down to the starting position by bending at the hips and knees. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band seated shoulder press', 'resistance band seated shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a chair or bench with your back straight and feet flat on the ground. Step:2 Hold the resistance band with both hands, palms facing forward, and bring it up to shoulder level. Step:3 Press the band overhead, extending your arms fully. Step:4 Pause for a moment at the top, then slowly lower the band back down to shoulder level. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triceps press', 'triceps press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Extend your arms straight out in front of you, parallel to the ground. Step:3 Bend your elbows and lower your body towards the ground, keeping your upper arms close to your sides. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm bench fly', 'dumbbell one arm bench fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with a dumbbell in one hand, resting it on top of your thigh. Step:2 Lie back on the bench, keeping the dumbbell pressed against your thigh. Step:3 Using your free hand, help lift the dumbbell up to the starting position. Step:4 Hold the dumbbell directly above your shoulder with your arm extended and palm facing inward. Step:5 Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow. Step:6 Pause when your arm is parallel to the ground, then reverse the movement and bring the dumbbell back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch arms and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('arms overhead full sit-up (male)', 'arms overhead full sit-up (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Extend your arms overhead, keeping them straight. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lying one arm rear lateral raise', 'dumbbell lying one arm rear lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor. Step:2 Keep your arm straight and lift the dumbbell out to the side, away from your body. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Step:4 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell press on exercise ball', 'dumbbell press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and dumbbells in each hand, resting on your thighs. Step:2 Slowly walk your feet forward, rolling the exercise ball until your lower back is supported on the ball and your knees are at a 90-degree angle. Step:3 Raise the dumbbells to shoulder height, palms facing forward. Step:4 Press the dumbbells upward until your arms are fully extended. Step:5 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever seated calf press', 'lever seated calf press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the machine so that your shoulders are aligned with the lever pad. Step:2 Place your toes on the lower portion of the platform and position your knees under the lever pad. Step:3 Grasp the handles on the sides of the seat for stability. Step:4 Press the lever pad down by extending your ankles, lifting your heels as high as possible. Step:5 Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell alternate side press', 'dumbbell alternate side press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height. Step:2 Press one dumbbell overhead while keeping the other dumbbell at shoulder height. Step:3 Lower the pressed dumbbell back to shoulder height while pressing the other dumbbell overhead. Step:4 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('low glute bridge on floor', 'low glute bridge on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your arms by your sides, palms facing down. Step:3 Engage your glutes and core, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders. Step:4 Pause for a moment at the top, squeezing your glutes. Step:5 Slowly lower your hips back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('macro style weighted one hand pull up', 'macro style weighted one hand pull up', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:2 Hang from the bar with your arm fully extended and your body straight. Perform with macro intensity. Step:3 Engage your core and pull your body up towards the bar by bending your elbow and squeezing your back muscles. Step:4 Continue pulling until your chin is above the bar. Step:5 Lower your body back down to the starting position with control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverted style smith seated shoulder press', 'inverted style smith seated shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that the handles are at shoulder level. Step:2 Sit on the machine with your back against the pad and your feet flat on the floor. Step:3 Grasp the handles with an overhand grip and lift them off the supports, extending your arms fully. Step:4 Lower the handles down to shoulder level, keeping your elbows slightly bent. Step:5 Press the handles up overhead until your arms are fully extended. Step:6 Pause for a moment at the top, then slowly lower the handles back down to shoulder level. Maintain inverted form throughout. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable low seated row controlled', 'cable low seated row controlled', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the machine with your feet flat on the footrests and your knees slightly bent. Step:2 Grasp the handles with an overhand grip, palms facing down. Step:3 Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows. Maintain controlled form throughout. Step:4 Pull the handles towards your body, squeezing your shoulder blades together. Step:5 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wall style dumbbell pullover hip extension on exercise ball', 'wall style dumbbell pullover hip extension on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and the dumbbell resting on your thighs. Step:2 Slowly walk your feet forward, rolling the exercise ball down your back until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbell with both hands and extend your arms straight up over your chest, keeping a slight bend in your elbows. Step:4 Lower the dumbbell behind your head, keeping your arms straight and maintaining control. Step:5 Pause for a moment, then raise the dumbbell back to the starting position. Step:6 While keeping your arms extended, lift your hips off the ground, squeezing your glutes and engaging your core. Step:7 (wall variation) Lower your hips back down to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable kneeling crunch - gentle variation', 'cable kneeling crunch - gentle variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a high pulley and kneel down facing away from the machine. Step:2 Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides. Step:3 Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs. Step:4 Pause for a moment at the bottom, then slowly return to the starting position. Maintain gentle form throughout. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band alternating v-up with simple', 'band alternating v-up with simple', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Step:2 Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. Step:3 As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other. Focus on simple movement. Step:4 Repeat the movement, alternating the position of your legs with each repetition. Step:5 Continue for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell close grip preacher curl - precision variation', 'ez barbell close grip preacher curl - precision variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher curl bench and place your upper arms on the pad, gripping the ez barbell with an underhand grip. Step:2 Rest your triceps on the pad and fully extend your arms, keeping your back straight. Step:3 Slowly curl the barbell towards your shoulders, contracting your biceps. Step:4 Pause for a moment at the top, squeezing your biceps. Step:5 Lower the barbell back to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions. Emphasize precision control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging pike with intense', 'hanging pike with intense', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up towards the bar, keeping them straight. Step:3 (intense variation) Continue lifting until your body forms a ''V'' shape, with your legs parallel to the ground. Step:4 Hold the position for a moment, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side cable high row (kneeling)', 'side cable high row (kneeling)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a cable machine at chest height. Step:2 Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart. Step:3 Sit back on your heels, keeping your back straight and your core engaged. Step:4 Pull the bar towards your upper abdomen, squeezing your shoulder blades together. Step:5 Pause for a moment at the top of the movement, then slowly release the bar back to the starting position. Step:6 Repeat for the desired number of repetitions. Maintain side form throughout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('blunt cable standing crunch', 'blunt cable standing crunch', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable handle to a high pulley and stand facing away from the machine. Step:2 Hold the handle with both hands and place it behind your head, keeping your elbows bent. Step:3 Stand with your feet shoulder-width apart and your knees slightly bent. Step:4 Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs. Step:5 Pause for a moment at the bottom of the movement, then slowly return to the starting position. Emphasize blunt control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell lying triceps extension double', 'barbell lying triceps extension double', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows. Focus on double movement. Step:4 Pause for a moment at the bottom, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('fierce weighted straight bar dip', 'fierce weighted straight bar dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself between parallel bars with your arms fully extended and your body straight. Step:2 Lower your body by bending your elbows until your upper arms are parallel to the ground. Step:3 Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:4 (fierce variation) Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('slow leg pull in flat bench', 'slow leg pull in flat bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a flat bench with your legs extended straight out in front of you. Step:2 Place your hands on the bench beside your hips for support. Step:3 Engage your abs and lift your legs off the ground, bringing your knees towards your chest. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions. Maintain slow form throughout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable twisting pull with intensified', 'cable twisting pull with intensified', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a cable handle to a low pulley and stand facing the machine. Step:2 Grasp the handle with your left hand and step away from the machine, extending your arm fully. Step:3 Position your feet shoulder-width apart, with your knees slightly bent. Step:4 Keep your back straight and your core engaged throughout the exercise. Step:5 Pull the handle towards your body, rotating your torso to the right as you do so. Step:6 Squeeze your back muscles at the end of the movement. Step:7 Slowly return to the starting position, keeping tension on the cable. Step:8 (intensified variation) Repeat for the desired number of repetitions, then switch sides and perform with your right hand.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('suspended abdominal fallout - inclined variation', 'suspended abdominal fallout - inclined variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a suspension trainer to a high anchor point and adjust the straps to waist height. Step:2 Stand facing away from the anchor point and hold the handles with your arms extended in front of you. Maintain inclined form throughout. Step:3 Lean forward at the waist, keeping your body straight and your core engaged. Step:4 Lower your body as far as you can while maintaining control and tension in your abs. Step:5 Pause for a moment at the bottom, then slowly raise your body back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inclined style pelvic tilt into bridge', 'inclined style pelvic tilt into bridge', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the ground. Step:2 Place your arms by your sides with your palms facing down. Step:3 Engage your glutes and core muscles. Step:4 Tilt your pelvis upward, lifting your hips off the ground. Emphasize inclined control. Step:5 Hold the bridge position for a few seconds. Step:6 Slowly lower your hips back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm press on exercise ball modified', 'dumbbell incline one arm press on exercise ball modified', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground. Step:2 Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball. Step:3 Hold the dumbbell at shoulder height with your palm facing forward. Step:4 Press the dumbbell upward until your arm is fully extended. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Emphasize modified control. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable kneeling rear delt row (with rope) (male) expanded', 'cable kneeling rear delt row (with rope) (male) expanded', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope handle to a low cable pulley and kneel down facing the machine. Step:2 (expanded variation) Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you. Step:3 Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades. Step:4 Squeeze your shoulder blades together at the end of the movement and hold for a brief pause. Step:5 Slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rotated dumbbell pronate-grip triceps extension', 'rotated dumbbell pronate-grip triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your back straight and feet flat on the ground. Step:2 Hold a dumbbell with both hands, palms facing down, and extend your arms straight up overhead. Step:3 Keeping your upper arms close to your head and elbows pointing forward, slowly lower the dumbbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions. Focus on rotated movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45 degrees one leg press pointed', 'sled 45 degrees one leg press pointed', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a 45-degree angle. Step:2 Sit on the sled machine with your back against the pad and your feet on the footplate. Perform with pointed intensity. Step:3 Place one foot on the footplate and extend your leg, pushing the sled away from you. Step:4 Slowly bend your knee and lower the sled back to the starting position. Step:5 Repeat with the other leg. Step:6 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('stretched full planche push-up', 'stretched full planche push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands placed slightly wider than shoulder-width apart. Step:2 Engage your core and lower your body down towards the ground, keeping your elbows close to your sides. Step:3 As you lower yourself, lean your body forward and lift your feet off the ground, balancing on your hands. Perform with stretched intensity. Step:4 Continue to lower your body until your chest is just above the ground. Step:5 Push through your hands and extend your arms to lift your body back up to the starting position. Step:6 Maintain a straight line from your head to your heels throughout the movement. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('calf push stretch with hands against wall elite', 'calf push stretch with hands against wall elite', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall with your feet hip-width apart. Step:2 Place your hands against the wall at shoulder height. Step:3 Step back with one foot, keeping your heel on the ground and your leg straight. Step:4 Bend your front knee slightly and lean forward, feeling a stretch in your calf. Step:5 Hold the stretch for 20-30 seconds. Step:6 Switch legs and repeat the stretch. Focus on elite movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('clock push-up extreme', 'clock push-up extreme', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Step:2 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:3 As you lower, rotate your body to the left, extending your left arm straight out to the side. Focus on extreme movement. Step:4 Push back up to the starting position, while rotating your body to the center. Step:5 Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side. Step:6 Continue alternating sides with each repetition.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever military press with strength', 'lever military press with strength', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your back against the backrest. Step:2 Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart. Step:3 Push the handles upward until your arms are fully extended, but do not lock your elbows. Step:4 (strength variation) Pause for a moment at the top, then slowly lower the handles back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('half knee bends (male) with blunt', 'half knee bends (male) with blunt', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Bend your knees and lower your body down as if you were sitting back into a chair. Emphasize blunt control. Step:3 Keep your chest up and your weight in your heels. Step:4 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dynamic style band side triceps extension', 'dynamic style band side triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down. Step:2 Extend your arms straight out to the sides, keeping them parallel to the ground. Step:3 Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still. Step:4 Pause for a moment, then slowly extend your arms back out to the starting position. Step:5 (dynamic variation) Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball seated triceps stretch wide', 'exercise ball seated triceps stretch wide', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand and extend your arm straight up above your head. Step:3 Bend your elbow and lower the dumbbell behind your head, keeping your upper arm close to your ear. Maintain wide form throughout. Step:4 Hold the stretch for a few seconds, then return to the starting position. Step:5 Repeat with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band underhand pulldown with classic', 'band underhand pulldown with classic', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a high anchor point, such as a pull-up bar or sturdy beam. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart. Emphasize classic control. Step:4 Extend your arms fully overhead, keeping your elbows slightly bent. Step:5 Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest stretch with exercise ball partial', 'chest stretch with exercise ball partial', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your back straight. Step:2 Hold the exercise ball with both hands and extend your arms straight out in front of you. Focus on partial movement. Step:3 Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles. Step:4 Hold the stretch for a few seconds, then slowly return to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted lunge with swing twisted', 'weighted lunge with swing twisted', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a weight in each hand. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 As you lunge forward, swing the weights forward and upward, keeping your arms straight. Step:4 Push off with your right foot and return to the starting position, swinging the weights back down. Step:5 (twisted variation) Repeat with your left foot and continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('controlled band straight back stiff leg deadlift', 'controlled band straight back stiff leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band around your upper legs. Step:2 Hold the band with both hands in front of your thighs, palms facing your body. Step:3 Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground. Focus on controlled movement. Step:4 Feel the stretch in your hamstrings as you lower the band. Step:5 Engage your glutes and hamstrings to lift your body back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('gentle style dumbbell one leg fly on exercise ball', 'gentle style dumbbell one leg fly on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in each hand, palms facing each other. Step:2 Place one foot on the ground and extend the other leg straight out in front of you. Step:3 Lean forward slightly and bring your arms out to the sides, keeping a slight bend in your elbows. Step:4 Slowly lower the dumbbells down and out to the sides, feeling a stretch in your chest. Step:5 (gentle variation) Pause for a moment at the bottom, then squeeze your chest muscles to bring the dumbbells back up to the starting position. Step:6 Repeat for the desired number of repetitions, then switch legs and repeat.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('intense kettlebell two arm row', 'intense kettlebell two arm row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body. Step:2 Bend forward at the hips, keeping your back straight and your core engaged. Step:3 Pull the kettlebells up towards your chest, squeezing your shoulder blades together. Step:4 Pause for a moment at the top, then slowly lower the kettlebells back down to the starting position. Step:5 Repeat for the desired number of repetitions. Maintain intense form throughout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('contracted kettlebell extended range one arm press on floor', 'contracted kettlebell extended range one arm press on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your back on the floor with your knees bent and feet flat on the ground. Step:2 Hold a kettlebell in one hand, with your palm facing towards your feet. Step:3 Extend your arm straight up towards the ceiling, keeping your elbow locked and your wrist straight. Step:4 Slowly lower the kettlebell back down to the starting position, maintaining control throughout the movement. Step:5 Repeat for the desired number of repetitions, then switch to the other arm. Emphasize contracted control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triple style sled one leg calf press on leg press', 'triple style sled one leg calf press on leg press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled. Step:2 Sit on the machine with your back against the backrest and your feet on the sled, shoulder-width apart. Step:3 Place your toes and the balls of your feet on the sled, keeping your heels off. Step:4 Push the sled forward by extending your ankles, keeping your knees slightly bent. Step:5 Pause for a moment at the top, then slowly lower the sled back down by flexing your ankles. Step:6 Repeat for the desired number of repetitions. Perform with triple intensity.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band leg extension declined', 'resistance band leg extension declined', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the resistance band to a sturdy anchor point and secure it around your ankle. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Keeping your core engaged and your upper body stable, extend your leg straight out in front of you. Step:4 Pause for a moment at the top, then slowly return your leg to the starting position. Focus on declined movement. Step:5 Repeat for the desired number of repetitions, then switch legs.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell iron cross - improved variation', 'dumbbell iron cross - improved variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides. Step:2 Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body. Perform with improved intensity. Step:3 Pause for a moment, then slowly lower your arms back down to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('quick feet v. 2 with bent', 'quick feet v. 2 with bent', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your arms by your sides. Step:2 Begin by rapidly moving your feet up and down, as if you were running in place. Step:3 Keep your movements quick and light, focusing on staying on the balls of your feet. Step:4 Continue for the desired duration or number of repetitions. Emphasize bent control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell wide reverse grip bench press horizontal', 'barbell wide reverse grip bench press horizontal', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your back pressed against the bench. Step:2 Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart. Step:3 Lift the barbell off the rack and hold it directly above your chest with your arms fully extended. Step:4 Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight. Focus on horizontal movement. Step:5 Pause for a moment when the barbell touches your chest, then push it back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sissy squat isolation', 'sissy squat isolation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your toes pointing slightly outward. Step:2 Hold onto a stable object for balance if needed. Step:3 Slowly lower your body by bending your knees and leaning back, keeping your torso upright. Step:4 Continue lowering until your thighs are parallel to the ground or as far as you can comfortably go. Step:5 Pause for a moment, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions. Emphasize isolation control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chair leg extended stretch with modified', 'chair leg extended stretch with modified', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the edge of a chair with your back straight and feet flat on the ground. Step:2 Extend one leg straight out in front of you, keeping your heel on the ground. Step:3 Lean forward slightly, feeling a stretch in your quadriceps. Step:4 Hold this position for 20-30 seconds. Focus on modified movement. Step:5 Switch legs and repeat the stretch.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable concentration curl tempo', 'cable concentration curl tempo', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the floor and your knees slightly bent. Step:2 Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh. Focus on tempo movement. Step:3 Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps. Step:4 Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('intense barbell straight leg deadlift', 'intense barbell straight leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your toes pointing forward. Step:2 Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent. Step:4 Lower the barbell until you feel a stretch in your hamstrings. Maintain intense form throughout. Step:5 Engage your hamstrings and glutes to lift the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('precision style lever bent-over row with v-bar', 'precision style lever bent-over row with v-bar', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself facing the machine. Step:2 Grasp the v-bar with an overhand grip, keeping your back straight and your knees slightly bent. Step:3 Pull the v-bar towards your abdomen, squeezing your shoulder blades together. Step:4 Pause for a moment at the top of the movement, then slowly release the weight back to the starting position. Emphasize precision control. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('high style scapula push-up', 'high style scapula push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands directly under your shoulders and your body in a straight line. Step:2 Lower your chest towards the ground, keeping your elbows close to your body. Step:3 As you lower, squeeze your shoulder blades together and push your chest forward. Focus on high movement. Step:4 Pause for a moment at the bottom, then push back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse preacher curl inclined', 'barbell reverse preacher curl inclined', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip. Step:2 Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps. Step:3 Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level. Perform with inclined intensity. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever reverse grip preacher curl with precision', 'lever reverse grip preacher curl with precision', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the leverage machine. Step:2 Grasp the handles with an underhand grip, palms facing up. Step:3 Rest your upper arms on the preacher pad, ensuring your elbows are fully extended. Maintain precision form throughout. Step:4 Keeping your upper arms stationary, exhale and curl the handles towards your shoulders. Step:5 Pause for a moment at the top of the movement, squeezing your biceps. Step:6 Inhale and slowly lower the handles back to the starting position, fully extending your elbows. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('narrow style band jack knife sit-up', 'narrow style band jack knife sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Step:2 Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet. Step:3 Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position. Step:4 Repeat for the desired number of repetitions. Focus on narrow movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('forward lunge (male) with bench', 'forward lunge (male) with bench', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and hands on your hips. Step:2 Take a big step forward with your right foot, lowering your body into a lunge position. Step:3 Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle. Step:4 Push off with your right foot and return to the starting position. Focus on bench movement. Step:5 Repeat with your left leg, alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('alternating bear crawl', 'alternating bear crawl', 'Strength', 'Other', 'Intermediate', 'Step:1 Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Step:2 Lift your knees slightly off the ground, keeping your back flat and your core engaged. Step:3 Move your right hand and left foot forward simultaneously, followed by your left hand and right foot. Step:4 Continue crawling forward, alternating your hand and foot movements. Step:5 Maintain a steady pace and keep your core tight throughout the exercise. Step:6 (alternating variation) Continue for the desired distance or time.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('single style cable standing crunch (with rope attachment)', 'single style cable standing crunch (with rope attachment)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a cable machine at chest height. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Focus on single movement. Step:3 Hold the rope with both hands and bring it behind your head, keeping your elbows bent. Step:4 Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees. Step:5 Pause for a moment at the top of the crunch, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rough band push sit-up', 'rough band push sit-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band securely to a stable anchor point. Step:2 Lie flat on your back with your knees bent and feet flat on the ground. Step:3 Hold the band with both hands and extend your arms straight up towards the ceiling. Focus on rough movement. Step:4 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:5 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('fast style resistance band seated hip abduction', 'fast style resistance band seated hip abduction', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a chair or bench with your back straight and feet flat on the ground. Step:2 Wrap the resistance band around your thighs, just above your knees. Step:3 Place your hands on the sides of the chair or bench for support. Step:4 (fast variation) Engage your abductors (outer thigh muscles) and slowly push your knees apart, against the resistance of the band. Step:5 Pause for a moment at the end of the movement, then slowly bring your knees back together. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pure chin-up', 'pure chin-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Step:2 Engage your core and pull your body up towards the bar, leading with your chest. Emphasize pure control. Step:3 Continue pulling until your chin is above the bar. Step:4 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('light lever standing chest press', 'light lever standing chest press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your feet flat on the ground. Step:2 Grasp the handles with an overhand grip and position your hands at chest level. Maintain light form throughout. Step:3 Push the handles forward until your arms are fully extended, keeping your elbows slightly bent. Step:4 Pause for a moment, then slowly bring the handles back towards your chest, maintaining control throughout the movement. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('resistance band seated shoulder press with declined', 'resistance band seated shoulder press with declined', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a chair or bench with your back straight and feet flat on the ground. Step:2 Hold the resistance band with both hands, palms facing forward, and bring it up to shoulder level. Step:3 Press the band overhead, extending your arms fully. Step:4 Pause for a moment at the top, then slowly lower the band back down to shoulder level. Emphasize declined control. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell prone incline curl with intensive', 'barbell prone incline curl with intensive', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 Lie face down on the bench with your chest and stomach resting against it. Step:3 Hold a barbell with an underhand grip, shoulder-width apart. Step:4 Extend your arms fully, allowing the barbell to hang down towards the floor. Step:5 Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Step:6 Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level. Step:7 (intensive variation) Hold the contracted position for a brief pause as you squeeze your biceps. Step:8 Inhale and slowly begin to lower the barbell back to the starting position. Step:9 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell standing reverse grip curl resistance', 'barbell standing reverse grip curl resistance', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up. Step:2 Keep your elbows close to your torso and your upper arms stationary. Step:3 Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible. Step:4 Hold the contracted position for a brief pause as you squeeze your biceps. Step:5 Inhale and slowly lower the barbell back to the starting position. Step:6 Repeat for the desired number of repetitions. Focus on resistance movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball hip flexor stretch pointed', 'exercise ball hip flexor stretch pointed', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the stability ball on the ground and kneel in front of it. Step:2 Place your right foot on top of the stability ball, with your knee bent at a 90-degree angle. Step:3 Extend your left leg behind you, keeping it straight. Step:4 Lean forward, pushing your hips towards the stability ball, until you feel a stretch in your right hip flexor. Step:5 Hold the stretch for 20-30 seconds, then switch sides and repeat. Emphasize pointed control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rough band hip lift', 'rough band hip lift', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on your back with your knees bent and feet flat on the ground. Step:2 Place a resistance band just above your knees. Step:3 Engage your glutes and core muscles. Step:4 Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top. Step:5 Pause for a moment at the top, then slowly lower your hips back down to the starting position. Step:6 Repeat for the desired number of repetitions. Focus on rough movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('flexible assisted prone hamstring', 'flexible assisted prone hamstring', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a mat or bench with your legs fully extended. Step:2 (flexible variation) Have a partner or use a resistance band to secure your ankles. Step:3 Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline push-up (on box) - active variation', 'incline push-up (on box) - active variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Place your hands on the edge of a box or elevated surface, slightly wider than shoulder-width apart. Step:2 Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels. Step:3 Lower your chest towards the box by bending your elbows, keeping your body in a straight line. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms. Step:5 (active variation) Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell bent arm pullover - powerful variation', 'barbell bent arm pullover - powerful variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet on the floor. Step:2 Hold a barbell with a shoulder-width grip and extend your arms straight above your chest. Step:3 Lower the barbell behind your head while keeping your arms slightly bent. Step:4 Pause for a moment, then raise the barbell back to the starting position. Step:5 Repeat for the desired number of repetitions. Focus on powerful movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('core barbell upright row v. 2', 'core barbell upright row v. 2', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:2 Let the barbell hang in front of your thighs, arms fully extended. Perform with core intensity. Step:3 Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows. Step:4 Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell step up single leg balance with bicep curl - chair variation', 'dumbbell step up single leg balance with bicep curl - chair variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a step or platform with a dumbbell in each hand, palms facing your body. Step:2 Place your right foot on the step, ensuring your entire foot is in contact with the surface. Step:3 Engage your core and push through your right heel to lift your body up onto the step, bringing your left knee up towards your chest. Step:4 At the top of the movement, perform a bicep curl by bending your elbows and bringing the dumbbells towards your shoulders. Step:5 Lower the dumbbells back down and simultaneously lower your left foot back to the ground. Step:6 (chair variation) Repeat the movement on the opposite side, stepping up with your left foot and curling the dumbbells. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band one arm standing low row - lateral variation', 'band one arm standing low row - lateral variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a stable anchor point at waist height. Step:2 Stand facing the anchor point with your feet shoulder-width apart. Step:3 Hold the band with one hand, palm facing inward, and step back to create tension in the band. Step:4 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:5 Pull the band towards your waist, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly release the band back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides. Emphasize lateral control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('endurance style one arm dip', 'endurance style one arm dip', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing away from a bench or chair, with your feet shoulder-width apart. Step:2 Place one hand on the bench or chair behind you, fingers pointing towards your body. Maintain endurance form throughout. Step:3 Extend your legs out in front of you, keeping your heels on the ground. Step:4 Bend your elbows and lower your body towards the ground, keeping your back close to the bench or chair. Step:5 Pause for a moment at the bottom, then push through your palms to straighten your arms and return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides and repeat with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable side bend smooth', 'cable side bend smooth', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and grasp the cable handle with one hand. Step:2 Keep your back straight and your core engaged. Step:3 Slowly bend sideways at the waist, lowering the cable handle towards your knee. Step:4 Pause for a moment, then return to the starting position. Focus on smooth movement. Step:5 Repeat on the other side. Step:6 Alternate sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell decline shrug - rigid variation', 'dumbbell decline shrug - rigid variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a decline bench at a 45-degree angle. Step:2 Lie face down on the bench with your chest and stomach resting against it. Step:3 (rigid variation) Hold a dumbbell in each hand with your arms fully extended towards the floor. Step:4 Keeping your arms straight, raise your shoulders towards your ears as high as possible. Step:5 Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pulse style walk elliptical cross trainer', 'pulse style walk elliptical cross trainer', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the resistance level and incline of the elliptical machine to your desired settings. Step:2 Step onto the pedals of the machine and grip the handles lightly. Step:3 Begin by pushing down with your feet and pulling the handles towards your body. Step:4 Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion. Step:5 Maintain a steady pace and keep your core engaged throughout the exercise. Emphasize pulse control. Step:6 Continue for the desired duration of your cardio workout. Step:7 Gradually decrease the intensity and speed of the machine before stepping off.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('balance cable incline fly', 'balance cable incline fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a low position and attach the handles. Step:2 Sit on an incline bench with your back against the pad and feet flat on the floor. Perform with balance intensity. Step:3 Grasp the handles with an overhand grip and extend your arms straight out in front of you. Step:4 Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Step:5 Pause for a moment at the fully extended position, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cocoons with mega', 'cocoons with mega', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Place your hands behind your head with your elbows pointing outwards. Step:3 Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Step:5 Repeat for the desired number of repetitions. Emphasize mega control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable incline bench row - elite variation', 'cable incline bench row - elite variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley. Step:2 Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent. Step:3 Grasp the cable handle with an overhand grip and extend your arms fully in front of you. Perform with elite intensity. Step:4 Lean forward from your hips while keeping your back straight and your core engaged. Step:5 Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows. Step:6 Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('flexible cable triceps pushdown (v-bar)', 'flexible cable triceps pushdown (v-bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a v-bar attachment to the cable machine at the highest setting. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary throughout the exercise. Step:5 Engage your triceps and exhale as you push the v-bar down until your arms are fully extended. Perform with flexible intensity. Step:6 Pause for a moment at the bottom of the movement, squeezing your triceps. Step:7 Inhale as you slowly return the v-bar to the starting position, maintaining control. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('advanced dumbbell stiff leg deadlift', 'advanced dumbbell stiff leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Step:2 Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing a slight bend in your knees. Focus on advanced movement. Step:3 Lower the dumbbells until you feel a stretch in your hamstrings, then squeeze your glutes and push through your heels to return to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hold style dumbbell alternating seated bicep curl on exercise ball', 'hold style dumbbell alternating seated bicep curl on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing forward and your arms fully extended. Step:3 Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder. Step:4 (hold variation) Inhale and slowly lower the dumbbell back to the starting position. Step:5 Repeat the curl with the other arm. Step:6 Continue alternating curls for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('active style cable pushdown', 'active style cable pushdown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a straight bar to a high pulley cable machine. Step:2 Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees. Step:3 Grasp the bar with an overhand grip, hands shoulder-width apart. Step:4 Keep your elbows close to your sides and your upper arms stationary. Step:5 Exhale and push the bar down until your elbows are fully extended. Step:6 Pause for a moment, then inhale and slowly return the bar to the starting position. Maintain active form throughout. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('stability style band kneeling one arm pulldown', 'stability style band kneeling one arm pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach the band to a sturdy anchor point above your head. Step:2 Kneel down and hold the band with one hand, palm facing down. Step:3 Extend your arm fully overhead, keeping your elbow slightly bent. Step:4 Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage. Step:5 Pause for a moment at the bottom, then slowly release the tension and return to the starting position. Step:6 Repeat for the desired number of repetitions, then switch sides. Perform with stability intensity.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rounded twisted leg raise (female)', 'rounded twisted leg raise (female)', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Bend your knees and lift your legs off the ground, bringing them towards your chest. Emphasize rounded control. Step:3 As you lift your legs, twist your hips to one side, bringing your knees towards your opposite shoulder. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat the movement, this time twisting your hips to the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wide-grip chest dip on high parallel bars - low variation', 'wide-grip chest dip on high parallel bars - low variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Position yourself on the parallel bars with your arms fully extended and your body suspended in the air. Step:2 Lean forward slightly and lower your body by bending your elbows until your chest is just above the bars. Step:3 (low variation) Pause for a moment, then push yourself back up to the starting position by straightening your arms. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable one arm incline press with rigid', 'cable one arm incline press with rigid', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a low pulley position. Step:2 Sit on an incline bench facing away from the cable machine. Step:3 Grasp the handle with one hand and bring it up to shoulder height. Emphasize rigid control. Step:4 Position your feet firmly on the ground and maintain a stable position. Step:5 Press the handle forward and upward, extending your arm fully. Step:6 Pause for a moment at the top, then slowly lower the handle back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball alternating arm ups with fast', 'exercise ball alternating arm ups with fast', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the stability ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in each hand with your palms facing inwards and your arms extended down by your sides. Step:3 Engage your core and slowly lift one arm up towards your shoulder, keeping your elbow slightly bent. Perform with fast intensity. Step:4 Pause for a moment at the top, then slowly lower your arm back down to the starting position. Step:5 Repeat the movement with the other arm. Step:6 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging pike weak', 'hanging pike weak', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up towards the bar, keeping them straight. Step:3 Continue lifting until your body forms a ''V'' shape, with your legs parallel to the ground. Emphasize weak control. Step:4 Hold the position for a moment, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one arm against wall compressed', 'one arm against wall compressed', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall with your feet shoulder-width apart. Step:2 Extend one arm straight out in front of you and place your palm against the wall. Step:3 Engage your core and lean your body forward, keeping your arm straight and your back flat. Maintain compressed form throughout. Step:4 Slowly push against the wall with your palm, activating your lat muscles. Step:5 Hold the position for a few seconds, then release and repeat with the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('ez barbell decline close grip face press - mini variation', 'ez barbell decline close grip face press - mini variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie on a decline bench with your head lower than your feet. Step:2 Grasp the ez barbell with a close grip, palms facing each other. Step:3 Extend your arms straight up above your chest, keeping your elbows close to your body. Step:4 Lower the barbell towards your forehead by bending your elbows. Step:5 Pause for a moment, then press the barbell back up to the starting position. Emphasize mini control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('weighted one hand pull up fast', 'weighted one hand pull up fast', 'Strength', 'Other', 'Intermediate', 'Step:1 Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart. Step:2 Hang from the bar with your arm fully extended and your body straight. Step:3 Engage your core and pull your body up towards the bar by bending your elbow and squeezing your back muscles. Step:4 Continue pulling until your chin is above the bar. Step:5 (fast variation) Lower your body back down to the starting position with control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('incline push up depth jump with complex', 'incline push up depth jump with complex', 'Strength', 'Other', 'Intermediate', 'Step:1 Find an elevated surface, such as a bench or step, and place your hands shoulder-width apart on the edge. Step:2 Step your feet back, keeping your body in a straight line from head to heels. Step:3 Lower your chest towards the edge of the surface, bending your elbows and keeping your body aligned. Maintain complex form throughout. Step:4 Push through your palms to extend your arms and return to the starting position. Step:5 Jump off the edge of the surface, landing softly with your knees slightly bent. Step:6 Repeat the push-up and depth jump for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('pointed cable palm rotational row', 'pointed cable palm rotational row', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a handle to a cable machine at waist height. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the handle with an overhand grip, palms facing down. Step:4 Step back to create tension on the cable, keeping your back straight and knees slightly bent. Emphasize pointed control. Step:5 Pull the handle towards your body, rotating your palms to face upwards as you do so. Step:6 Squeeze your shoulder blades together at the end of the movement. Step:7 Slowly release the handle back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('intermediate style dumbbell preacher curl over exercise ball', 'intermediate style dumbbell preacher curl over exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with an underhand grip, resting your elbow on the exercise ball. Step:3 (intermediate variation) Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder. Step:4 Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('iron cross stretch - deep variation', 'iron cross stretch - deep variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your arms extended out to the sides. Step:2 Raise your legs up towards the ceiling, keeping them straight. Step:3 Slowly lower your legs to one side, aiming to touch the floor with your feet. Step:4 Hold the stretch for a few seconds, then return your legs to the starting position. Step:5 Repeat the stretch on the other side. Maintain deep form throughout. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('all fours squad stretch - elevated variation', 'all fours squad stretch - elevated variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Start on all fours with your hands directly under your shoulders and your knees directly under your hips. Step:2 Extend one leg straight back, keeping your knee bent and your foot flexed. Maintain elevated form throughout. Step:3 Slowly lower your hips towards the ground, feeling a stretch in your quads. Step:4 Hold this position for 20-30 seconds. Step:5 Switch legs and repeat the stretch on the other side.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('isolation assisted seated pectoralis major stretch with stability ball', 'isolation assisted seated pectoralis major stretch with stability ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a stability ball with your feet flat on the ground and your back straight. Step:2 Hold a stability ball with both hands and extend your arms straight out in front of you. Step:3 Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles. Step:4 Hold the stretch for a few seconds, then slowly return to the starting position. Emphasize isolation control. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('one leg squat - expanded variation', 'one leg squat - expanded variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Extend one leg forward, keeping it off the ground. Step:3 Bend your standing leg and lower your body down as if sitting back into a chair. Step:4 Keep your chest up and your back straight. Step:5 Push through your heel to return to the starting position. Step:6 Repeat with the other leg. Maintain expanded form throughout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('targeted style smith close-grip bench press', 'targeted style smith close-grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the bench with your feet flat on the ground. Step:2 Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Step:3 Lower the barbell towards your chest, keeping your elbows close to your body. Focus on targeted movement. Step:4 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm prone hammer curl - macro variation', 'dumbbell one arm prone hammer curl - macro variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on a flat bench with a dumbbell in one hand, palm facing your body and arm fully extended. Step:2 Keep your upper arm stationary and curl the dumbbell towards your shoulder, contracting your biceps. Step:3 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:4 Repeat for the desired number of repetitions, then switch arms. Focus on macro movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up (wall) with static', 'push-up (wall) with static', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing a wall, about arm''s length away. Step:2 Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart. Step:3 Step back a few feet, keeping your body straight and your feet hip-width apart. Step:4 (static variation) Bend your elbows and lower your chest towards the wall, keeping your body in a straight line. Step:5 Push back up to the starting position, straightening your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('fierce style forward lunge (male)', 'fierce style forward lunge (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and hands on your hips. Step:2 Take a big step forward with your right foot, lowering your body into a lunge position. Step:3 Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle. Step:4 Push off with your right foot and return to the starting position. Step:5 (fierce variation) Repeat with your left leg, alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chin-up diagonal', 'chin-up diagonal', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart. Step:2 Engage your core and pull your body up towards the bar, leading with your chest. Step:3 Continue pulling until your chin is above the bar. Step:4 (diagonal variation) Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable judo flip with static', 'cable judo flip with static', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand facing the cable machine with your feet shoulder-width apart. Step:2 Hold the cable handle with both hands at chest level, palms facing down. Step:3 Engage your core and rotate your torso to the right, pulling the cable across your body. Step:4 As you rotate, pivot your back foot and allow your hips to rotate naturally. Emphasize static control. Step:5 Extend your arms fully and finish the movement by flipping the cable handle over your shoulder. Step:6 Return to the starting position by reversing the movement, rotating your torso back to the center. Step:7 Repeat the movement on the opposite side. Step:8 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell over bench one arm wrist curl - strength variation', 'dumbbell over bench one arm wrist curl - strength variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down. Step:2 Rest your forearm on the bench with your wrist hanging off the edge. Step:3 Slowly curl your wrist upwards, bringing the dumbbell towards your forearm. Step:4 Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position. Maintain strength form throughout. Step:5 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lying leg-hip raise - contracted variation', 'lying leg-hip raise - contracted variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs extended and your arms by your sides. Step:2 Place your hands under your glutes for support. Step:3 Engage your core and lift your legs off the ground, raising them towards the ceiling. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Emphasize contracted control. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('prone medicine ball close grip push up', 'prone medicine ball close grip push up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands on the medicine ball, shoulder-width apart. Step:2 Lower your body towards the ground by bending your elbows, keeping them close to your sides. Step:3 Push back up to the starting position, fully extending your arms. Step:4 Repeat for the desired number of repetitions. Maintain prone form throughout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('triceps dip (between benches) - extreme variation', 'triceps dip (between benches) - extreme variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your hands gripping the edge of the bench, fingers pointing forward. Step:2 (extreme variation) Slide your butt off the bench, supporting your weight with your hands. Step:3 Bend your elbows and lower your body towards the ground, keeping your back close to the bench. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('micro style barbell speed squat', 'micro style barbell speed squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Hold the barbell across your upper back, resting it on your traps or rear delts. Step:3 Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair. Step:4 (micro variation) Lower until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Drive through your heels to stand back up, squeezing your glutes at the top. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rough cable decline fly', 'rough cable decline fly', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine to a decline position. Step:2 Stand facing away from the machine with your feet shoulder-width apart. Step:3 Hold the handles with your palms facing forward and your arms extended straight out in front of you. Step:4 Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion. Perform with rough intensity. Step:5 Pause for a moment at the fully extended position, then slowly return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('stability lever narrow grip seated row', 'stability lever narrow grip seated row', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footrests to ensure proper form. Step:2 Sit on the machine with your feet flat on the footrests and your knees slightly bent. Step:3 Grasp the handles with a narrow grip, palms facing each other. Step:4 Keep your back straight and lean slightly forward. Step:5 Pull the handles towards your torso, squeezing your shoulder blades together. Step:6 Pause for a moment at the peak of the movement. Step:7 Slowly release the handles and return to the starting position. Focus on stability movement. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('twisted side-to-side chin', 'twisted side-to-side chin', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Hang from the bar with your arms fully extended and your body relaxed. Step:4 Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight. Step:5 Once your chin is above the bar, lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions. Perform with twisted intensity.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('prone dumbbell upright shoulder external rotation', 'prone dumbbell upright shoulder external rotation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body. Step:2 Raise your arms out to the sides until they are parallel to the ground, keeping your elbows slightly bent. Emphasize prone control. Step:3 Rotate your arms externally, bringing the dumbbells up towards your head while keeping your elbows in the same position. Step:4 Pause for a moment at the top, then slowly lower the dumbbells back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('controlled wrist rollerer', 'controlled wrist rollerer', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a weight to one end of a rope or bar. Step:2 Hold the other end of the rope or bar with both hands, palms facing down. Step:3 Stand with your feet shoulder-width apart and your arms fully extended in front of you. Step:4 Slowly roll the weight up towards your hands by flexing your wrists. Step:5 Pause for a moment at the top, then slowly lower the weight back down to the starting position. Perform with controlled intensity. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell incline bench press seated', 'barbell incline bench press seated', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up an incline bench at a 45-degree angle. Step:2 (seated variation) Lie down on the bench with your feet flat on the ground. Step:3 Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle. Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell sitted alternate leg raise (female) with intermediate', 'barbell sitted alternate leg raise (female) with intermediate', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and hold a barbell across your thighs. Step:2 (intermediate variation) Place your hands on the sides of the bench for support. Step:3 Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground. Step:4 Lower the leg back down and repeat with the other leg. Step:5 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up to side plank - athletic variation', 'push-up to side plank - athletic variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a push-up position with your hands shoulder-width apart and your body in a straight line. Step:2 Lower your body towards the ground by bending your elbows, keeping your core engaged. Step:3 Push back up to the starting position. Emphasize athletic control. Step:4 Shift your weight onto your left hand and rotate your body to the right, lifting your right arm towards the ceiling. Step:5 Hold the side plank position for a few seconds, then return to the starting position. Step:6 Repeat the push-up and side plank on the opposite side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell seated one leg calf raise - hammer grip deep', 'dumbbell seated one leg calf raise - hammer grip deep', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs. Step:2 Place one foot on a raised surface, such as a step or block, with your heel hanging off the edge. Step:3 Hold the dumbbell with a hammer grip, meaning your palms are facing each other and your fingers are wrapped around the handle. Step:4 Keeping your core engaged and your back straight, slowly raise your heel as high as possible by pushing through the ball of your foot. Step:5 Pause for a moment at the top, then slowly lower your heel back down to the starting position. Step:6 (deep variation) Repeat for the desired number of repetitions, then switch to the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('gentle style cable pulldown (pro lat bar)', 'gentle style cable pulldown (pro lat bar)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor. Step:2 Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Sit down and lean back slightly, keeping your chest up and your back straight. Step:4 Pull the bar down towards your chest, squeezing your shoulder blades together. Maintain gentle form throughout. Step:5 Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('inverted style inverse leg curl (on pull-up cable machine)', 'inverted style inverse leg curl (on pull-up cable machine)', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the cable machine so that the ankle straps are at the lowest setting. Step:2 Lie face down on the bench with your legs extended and the ankle straps attached to your feet. Step:3 Hold onto the handles of the bench for stability. Step:4 Bend your knees and curl your legs towards your glutes, squeezing your hamstrings. Step:5 Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position. Step:6 Repeat for the desired number of repetitions. Maintain inverted form throughout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell high bar squat core', 'barbell high bar squat core', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, toes slightly turned out. Step:2 Place the barbell on your upper back, resting it on your traps. Step:3 Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees. Perform with core intensity. Step:4 Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Drive through your heels to stand back up, extending your hips and knees. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sharp style dumbbell sumo pull through', 'sharp style dumbbell sumo pull through', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet wider than shoulder-width apart, toes pointed outwards. Step:2 Hold a dumbbell with both hands in front of your body, arms extended. Step:3 Bend your knees and lower your hips down into a squat position, keeping your back straight. Focus on sharp movement. Step:4 Lower the dumbbell down between your legs, keeping your arms straight. Step:5 Drive through your heels and extend your hips forward, pulling the dumbbell up and in front of your body. Step:6 Squeeze your glutes at the top of the movement, then lower the dumbbell back down between your legs. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('rough cable standing one arm triceps extension', 'rough cable standing one arm triceps extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the cable machine. Step:2 Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground. Step:3 Keep your elbow stationary and close to your body. Step:4 Slowly bend your elbow, lowering the cable handle towards the back of your head. Step:5 Pause for a moment at the bottom of the movement, then extend your arm back to the starting position. Focus on rough movement. Step:6 Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted standing chin-up with focused', 'assisted standing chin-up with focused', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired assistance level. Step:2 (focused variation) Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Keep your chest up and shoulders back, engage your core, and slightly bend your knees. Step:4 Pull your body up by flexing your elbows and driving your elbows down towards your sides. Step:5 Continue pulling until your chin is above the bar. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('single smith shoulder press', 'single smith shoulder press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the smith machine with your feet shoulder-width apart. Step:2 (single variation) Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:3 Lift the bar off the rack and position it at shoulder level, with your elbows bent and palms facing forward. Step:4 Press the bar upward until your arms are fully extended overhead. Step:5 Pause for a moment at the top, then slowly lower the bar back down to shoulder level. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('complete style ez bar lying close grip triceps extension behind head', 'complete style ez bar lying close grip triceps extension behind head', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold the ez barbell with a close grip, palms facing up, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows. Step:4 Pause for a moment, then extend your arms back up to the starting position. Maintain complete form throughout. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith one arm row linear', 'smith one arm row linear', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the height of the smith machine bar to waist level. Step:2 Stand facing the smith machine with your feet shoulder-width apart. Emphasize linear control. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Grasp the bar with one hand using an overhand grip, with your palm facing down. Step:5 Keep your elbow close to your body and pull the bar towards your waist, squeezing your shoulder blades together. Step:6 Pause for a moment at the top of the movement, then slowly lower the bar back to the starting position. Step:7 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted pull-up inclined', 'assisted pull-up inclined', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the machine to your desired weight and height settings. Step:2 Grasp the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang with your arms fully extended and your feet off the ground. Step:4 Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body. Step:5 Continue pulling until your chin is above the handles. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions. Maintain inclined form throughout.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable seated row with reverse', 'cable seated row with reverse', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent. Step:2 Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed. Step:3 Pull the handles towards your body, squeezing your shoulder blades together. Focus on reverse movement. Step:4 Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell hammer curl with traditional', 'dumbbell hammer curl with traditional', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand up straight with a dumbbell in each hand, palms facing your torso. Step:2 Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. Step:3 This will be your starting position. Step:4 Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Step:5 Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Step:6 Hold the contracted position for a brief pause as you squeeze your biceps. Step:7 Then, inhale and slowly begin to lower the dumbbells back to the starting position. Step:8 Repeat for the recommended amount of repetitions. Focus on traditional movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith machine incline tricep extension - straight variation', 'smith machine incline tricep extension - straight variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat of the smith machine so that the bar is at shoulder height. Step:2 Sit on the bench with your back against the pad and your feet flat on the ground. Step:3 Grasp the bar with an overhand grip, slightly wider than shoulder-width apart. Step:4 Extend your arms fully, lifting the bar off the rack and holding it directly above your chest. Focus on straight movement. Step:5 Lower the bar slowly towards your forehead, keeping your elbows close to your head. Step:6 Pause for a moment at the bottom, then push the bar back up to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push-up on lower arms - resistance variation', 'push-up on lower arms - resistance variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a plank position with your forearms on the ground and elbows directly below your shoulders. Step:2 Engage your core and keep your body in a straight line from head to toe. Step:3 Lower your chest towards the ground by bending your elbows, keeping them close to your body. Emphasize resistance control. Step:4 Pause for a moment at the bottom, then push yourself back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sled 45в° leg wide press - blunt variation', 'sled 45в° leg wide press - blunt variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the sled machine to a 45-degree angle. Step:2 Sit on the sled machine with your back against the pad and your feet on the foot platform. Step:3 Position your feet wider than shoulder-width apart. Step:4 Push against the foot platform to extend your legs and straighten your knees. Step:5 Pause for a moment at the end of the movement, then slowly bend your knees to return to the starting position. Maintain blunt form throughout. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell lunge with firm', 'dumbbell lunge with firm', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand. Step:2 Take a step forward with your right foot, lowering your body into a lunge position. Step:3 Keep your back straight and your chest up as you lower your body. Maintain firm form throughout. Step:4 Push through your right heel to return to the starting position. Step:5 Repeat with your left leg. Step:6 Alternate legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('improved sphinx', 'improved sphinx', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the ground with your forearms flat on the floor, elbows directly under your shoulders. Step:2 Engage your core and lift your chest off the ground, keeping your forearms and toes on the floor. Step:3 Hold this position for a few seconds, making sure to keep your neck in a neutral position. Step:4 Slowly lower your chest back down to the starting position. Emphasize improved control. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band seated twist pure', 'band seated twist pure', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on the ground with your legs extended in front of you and your back straight. Step:2 Wrap the band around your waist and hold the ends with both hands. Step:3 Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground. Step:4 Pause for a moment at the end of the twist, then slowly return to the starting position. Step:5 (pure variation) Repeat the twist to the other side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('walk elliptical cross trainer - expanded variation', 'walk elliptical cross trainer - expanded variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the resistance level and incline of the elliptical machine to your desired settings. Step:2 Step onto the pedals of the machine and grip the handles lightly. Step:3 Begin by pushing down with your feet and pulling the handles towards your body. Step:4 Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion. Emphasize expanded control. Step:5 Maintain a steady pace and keep your core engaged throughout the exercise. Step:6 Continue for the desired duration of your cardio workout. Step:7 Gradually decrease the intensity and speed of the machine before stepping off.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('smith bent over row with declined', 'smith bent over row with declined', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up the smith machine with the bar at hip height. Step:2 Stand facing the bar with your feet shoulder-width apart. Step:3 Bend your knees slightly and hinge forward at the hips, keeping your back straight. Step:4 Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:5 Pull the bar towards your lower chest, squeezing your shoulder blades together. Perform with declined intensity. Step:6 Pause for a moment at the top, then slowly lower the bar back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell incline one arm press on exercise ball with extended', 'dumbbell incline one arm press on exercise ball with extended', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground. Step:2 Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball. Perform with extended intensity. Step:3 Hold the dumbbell at shoulder height with your palm facing forward. Step:4 Press the dumbbell upward until your arm is fully extended. Step:5 Pause for a moment at the top, then slowly lower the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch to the other arm.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('athletic style battling ropes', 'athletic style battling ropes', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold one end of the rope in each hand, with your palms facing each other. Step:3 Raise your arms to shoulder height, keeping your elbows slightly bent. Step:4 (athletic variation) Begin making alternating waves with the ropes by rapidly raising and lowering each arm. Step:5 Continue for the desired duration or number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell reverse grip row (female) hold', 'dumbbell reverse grip row (female) hold', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and knees slightly bent. Step:2 Hold a dumbbell in each hand with an overhand grip, palms facing your body. Perform with hold intensity. Step:3 Bend forward at the waist, keeping your back straight and your core engaged. Step:4 Let your arms hang straight down, fully extended, with a slight bend in your elbows. Step:5 Pull the dumbbells up towards your chest, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever narrow grip seated row - strength variation', 'lever narrow grip seated row - strength variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and footrests to ensure proper form. Step:2 Sit on the machine with your feet flat on the footrests and your knees slightly bent. Step:3 Grasp the handles with a narrow grip, palms facing each other. Step:4 Keep your back straight and lean slightly forward. Step:5 Pull the handles towards your torso, squeezing your shoulder blades together. Step:6 Pause for a moment at the peak of the movement. Maintain strength form throughout. Step:7 Slowly release the handles and return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('traditional barbell romanian deadlift', 'traditional barbell romanian deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your toes pointing forward. Step:2 Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Bend at the hips, keeping your back straight and your knees slightly bent. Step:4 Lower the barbell towards the ground, keeping it close to your body. Step:5 Feel the stretch in your hamstrings as you lower the barbell. Step:6 Once you feel a stretch in your hamstrings, push your hips forward and stand up straight. Step:7 Squeeze your glutes at the top of the movement. Step:8 Lower the barbell back down to the starting position and repeat for the desired number of repetitions. Focus on traditional movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('exercise ball one leg prone lower body rotation fierce', 'exercise ball one leg prone lower body rotation fierce', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie face down on the stability ball with your hips resting on the ball and your legs extended straight behind you. Step:2 Place your hands on the ground in front of you for support. Step:3 Engage your glutes and core muscles to stabilize your body. Step:4 Slowly lift one leg off the ground, keeping it straight and parallel to the floor. Step:5 Rotate your leg outward, away from your body, while keeping your hips and upper body stable. Step:6 Pause for a moment at the end of the rotation, then slowly return your leg to the starting position. Step:7 Repeat the rotation with the other leg. Focus on fierce movement. Step:8 Continue alternating legs for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell arnold press - beginner variation', 'kettlebell arnold press - beginner variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height with your palms facing towards you. Step:2 Engage your core and press the kettlebells overhead, rotating your palms to face forward as you extend your arms. Emphasize beginner control. Step:3 Pause at the top of the movement, then slowly lower the kettlebells back to the starting position. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('fluid dumbbell step-up lunge', 'fluid dumbbell step-up lunge', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in front of a step or platform with a dumbbell in each hand, palms facing your sides. Step:2 Place your right foot on the step, ensuring your entire foot is on the surface. Step:3 Push through your right heel and lift your body up onto the step, bringing your left foot up as well. Step:4 (fluid variation) Once both feet are on the step, lower your left foot back down to the starting position, keeping your right foot on the step. Step:5 Repeat the movement, alternating which foot you step up with each time. Step:6 Continue for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('quads complex', 'quads complex', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart. Step:2 Lower your body by bending your knees and pushing your hips back as if sitting on a chair. Step:3 Keep your chest up and your back straight. Step:4 Lower yourself until your thighs are parallel to the ground. Step:5 Push through your heels to return to the starting position. Emphasize complex control. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('lever assisted chin-up with twisted', 'lever assisted chin-up with twisted', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the leverage machine to your desired resistance level. Step:2 Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart. Step:3 Hang with your arms fully extended, keeping your body straight. Step:4 (twisted variation) Engage your back muscles and pull your body up towards the handles, leading with your chest. Step:5 Continue pulling until your chin is above the handles. Step:6 Pause for a moment at the top, then slowly lower your body back down to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('push up on bosu ball with improved', 'push up on bosu ball with improved', 'Strength', 'Other', 'Intermediate', 'Step:1 Place the bosu ball on the ground with the flat side facing up. Step:2 Position yourself in a push-up position with your hands on the outer edges of the bosu ball. Step:3 Engage your core and lower your body down towards the bosu ball by bending your elbows. Focus on improved movement. Step:4 Push yourself back up to the starting position by extending your arms. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dynamic style barbell lying back of the head tricep extension', 'dynamic style barbell lying back of the head tricep extension', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your feet flat on the ground and your head at the end of the bench. Step:2 Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest. Step:3 Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows. Maintain dynamic form throughout. Step:4 Pause for a moment, then extend your arms back up to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('deep smith machine reverse decline close grip bench press', 'deep smith machine reverse decline close grip bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the smith machine to a decline position. Step:2 Lie down on the bench with your feet secured under the foot pads. Step:3 Grasp the barbell with a close grip, slightly narrower than shoulder-width apart. Step:4 Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in. Focus on deep movement. Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging straight leg raise with elevated', 'hanging straight leg raise with elevated', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your legs up in front of you, keeping them straight. Step:3 Continue lifting until your legs are parallel to the ground or as high as you can comfortably go. Maintain elevated form throughout. Step:4 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('upright smith incline bench press', 'upright smith incline bench press', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the bench to a 30-45 degree incline. Step:2 Sit on the bench with your back flat against the pad and feet firmly on the ground. Step:3 Grasp the barbell with an overhand grip slightly wider than shoulder-width apart. Perform with upright intensity. Step:4 Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in. Step:5 Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('extended style inverted row', 'extended style inverted row', 'Strength', 'Other', 'Intermediate', 'Step:1 Set up a bar at waist height or use a suspension trainer. Step:2 Stand facing the bar or suspension trainer, with your feet shoulder-width apart. Step:3 Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart. Step:4 Lean back, keeping your body straight and your heels on the ground. Step:5 Pull your chest towards the bar or handles, squeezing your shoulder blades together. Step:6 Pause for a moment at the top, then slowly lower yourself back to the starting position. Step:7 Repeat for the desired number of repetitions. Perform with extended intensity.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell one arm fly on exercise ball improved', 'dumbbell one arm fly on exercise ball improved', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground. Step:2 Walk your feet forward and roll your body down until your upper back is resting on the exercise ball. Step:3 Extend your arm with the dumbbell straight up above your chest, palm facing inwards. Step:4 Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow. Step:5 Pause for a moment, then squeeze your chest muscles to bring the dumbbell back to the starting position. Step:6 Repeat for the desired number of repetitions, then switch arms. Focus on improved movement.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('hanging straight twisting leg hip raise with compound', 'hanging straight twisting leg hip raise with compound', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your legs straight. Step:2 Engage your core and lift your legs up towards your chest, keeping them straight. Perform with compound intensity. Step:3 Once your legs are parallel to the ground, twist your hips to one side, bringing your legs towards that side. Step:4 Pause for a moment, then return to the starting position. Step:5 Repeat the movement, but this time twist your hips to the opposite side. Step:6 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('fast band straight leg deadlift', 'fast band straight leg deadlift', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and place the band around your feet. Step:2 Hold the band with both hands, palms facing your body, and keep your arms straight. Step:3 Engage your core and maintain a slight bend in your knees. Step:4 Slowly hinge forward at your hips, keeping your back straight and chest lifted. Step:5 Lower the band towards the ground while keeping your legs straight. Step:6 Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position. Step:7 Repeat for the desired number of repetitions. Perform with fast intensity.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable lateral pulldown (with rope attachment) core', 'cable lateral pulldown (with rope attachment) core', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope attachment to the cable machine at a high position. Step:2 Stand facing the machine with your feet shoulder-width apart. Step:3 Grasp the rope with an overhand grip, palms facing each other. Step:4 Keep your back straight and lean slightly back. Step:5 Pull the rope down towards your sides, squeezing your shoulder blades together. Emphasize core control. Step:6 Pause for a moment at the bottom of the movement. Step:7 Slowly release the tension and allow the rope to return to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('dumbbell around pullover - intensive variation', 'dumbbell around pullover - intensive variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on a bench with your head at one end and your feet firmly on the ground. Step:2 Hold a dumbbell with both hands and extend your arms straight above your chest. Perform with intensive intensity. Step:3 Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion. Step:4 Pause for a moment at the bottom, then raise the dumbbell back to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('sit-up with arms on chest with mini', 'sit-up with arms on chest with mini', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your knees bent and feet flat on the ground. Step:2 Cross your arms over your chest. Step:3 Engaging your abs, lift your upper body off the ground towards your knees. Step:4 Pause for a moment at the top, then slowly lower your upper body back down to the starting position. Maintain mini form throughout. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('squared reverse grip machine lat pulldown', 'squared reverse grip machine lat pulldown', 'Strength', 'Other', 'Intermediate', 'Step:1 Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground. Step:2 Grasp the handles with an underhand grip, slightly wider than shoulder-width apart. Step:3 Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back. Step:4 Pull the handles down towards your chest, squeezing your shoulder blades together. Maintain squared form throughout. Step:5 Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('targeted style single leg calf raise (on a dumbbell)', 'targeted style single leg calf raise (on a dumbbell)', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet hip-width apart and hold a dumbbell in one hand. Step:2 Lift one foot off the ground and balance on the other foot. Step:3 Slowly raise your heel as high as possible, using your calf muscles. Emphasize targeted control. Step:4 Pause for a moment at the top, then slowly lower your heel back down. Step:5 Repeat for the desired number of repetitions, then switch to the other leg.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('chest and front of shoulder stretch micro', 'chest and front of shoulder stretch micro', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand tall with your feet shoulder-width apart. Step:2 Extend your arms straight out in front of you at shoulder height. Step:3 Cross your arms in front of your body, with your right arm on top of your left arm. Step:4 Interlace your fingers and press your palms together. Step:5 Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders. Step:6 (micro variation) Hold the stretch for 20-30 seconds, then release. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kettlebell seated press with high', 'kettlebell seated press with high', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your back straight and feet flat on the ground. Step:2 Hold a kettlebell in each hand at shoulder height, palms facing forward. Step:3 Press the kettlebells overhead, fully extending your arms. Focus on high movement. Step:4 Lower the kettlebells back to shoulder height. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell squat (on knees) with pure', 'barbell squat (on knees) with pure', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward. Step:2 Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart. Step:3 Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight. Perform with pure intensity. Step:4 Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go. Step:5 Pause for a moment at the bottom, then push through your heels to return to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('tough cable one arm lateral raise', 'tough cable one arm lateral raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, facing the cable machine. Step:2 Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable. Step:3 Keep your arm straight and slowly raise it out to the side until it is parallel to the ground. Step:4 Pause for a moment at the top, then slowly lower your arm back down to the starting position. Focus on tough movement. Step:5 Repeat for the desired number of repetitions, then switch sides.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('kipping muscle up with triple', 'kipping muscle up with triple', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:2 Engage your core and use a swinging motion to generate momentum. Step:3 As you swing forward, pull your chest towards the bar, using your lats and biceps to initiate the movement. Emphasize triple control. Step:4 Continue the upward motion until your chest reaches the bar, then transition into a dip position by pushing down on the bar and extending your arms. Step:5 Lower yourself back down to the starting position by bending your arms and controlling the descent. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('intermediate style kneeling plank tap shoulder (male)', 'intermediate style kneeling plank tap shoulder (male)', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a kneeling position with your hands on the ground, shoulder-width apart. Step:2 Extend your legs behind you, resting on your toes, and lift your body into a plank position. Step:3 (intermediate variation) Keeping your core engaged and your hips stable, lift one hand off the ground and tap the opposite shoulder. Step:4 Return the hand to the ground and repeat with the other hand. Step:5 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('intensified style kettlebell extended range one arm press on floor', 'intensified style kettlebell extended range one arm press on floor', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying on your back on the floor with your knees bent and feet flat on the ground. Step:2 Hold a kettlebell in one hand, with your palm facing towards your feet. Step:3 Extend your arm straight up towards the ceiling, keeping your elbow locked and your wrist straight. Step:4 Slowly lower the kettlebell back down to the starting position, maintaining control throughout the movement. Step:5 Repeat for the desired number of repetitions, then switch to the other arm. Perform with intensified intensity.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('supine style band alternating v-up', 'supine style band alternating v-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Lie flat on your back with your legs straight and your arms extended overhead, holding the band. Step:2 Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes. Step:3 As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other. Focus on supine movement. Step:4 Repeat the movement, alternating the position of your legs with each repetition. Step:5 Continue for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('assisted standing triceps extension (with towel) with horizontal', 'assisted standing triceps extension (with towel) with horizontal', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and hold a towel with both hands behind your head. Step:2 Keep your elbows close to your ears and your upper arms stationary. Step:3 (horizontal variation) Slowly extend your forearms upward, squeezing your triceps at the top. Step:4 Pause for a moment, then slowly lower the towel back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('wall style dumbbell one arm french press on exercise ball', 'wall style dumbbell one arm french press on exercise ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on an exercise ball with your feet flat on the ground and your back straight. Step:2 Hold a dumbbell in one hand with your palm facing up and your elbow bent at a 90-degree angle. Focus on wall movement. Step:3 Extend your arm straight up towards the ceiling, keeping your elbow stationary. Step:4 Slowly lower the dumbbell back down to the starting position. Step:5 Repeat for the desired number of repetitions, then switch arms.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('side-to-side chin with reverse', 'side-to-side chin with reverse', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and your knees slightly bent. Step:2 Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart. Step:3 Hang from the bar with your arms fully extended and your body relaxed. Step:4 Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight. Perform with reverse intensity. Step:5 Once your chin is above the bar, lower yourself back down to the starting position. Step:6 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('macro style close-grip push-up', 'macro style close-grip push-up', 'Strength', 'Other', 'Intermediate', 'Step:1 Start in a high plank position with your hands placed close together, directly under your shoulders. Step:2 Engage your core and lower your body towards the ground, keeping your elbows close to your sides. Step:3 Push through your palms to extend your arms and return to the starting position. Maintain macro form throughout. Step:4 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('gentle prone twist on stability ball', 'gentle prone twist on stability ball', 'Strength', 'Other', 'Intermediate', 'Step:1 Start by lying face down on a stability ball with your feet shoulder-width apart and your toes touching the ground. Step:2 Place your hands behind your head or cross them over your chest. Step:3 Engage your core muscles and slowly lift your upper body off the ball, keeping your back straight. Step:4 Rotate your torso to one side, bringing your shoulder towards your hip. Keep your hips and legs stable throughout the movement. Step:5 Pause for a moment, then return to the starting position. Step:6 (gentle variation) Repeat the rotation to the other side. Step:7 Continue alternating sides for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable rope incline tricep extension - reverse variation', 'cable rope incline tricep extension - reverse variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a high pulley and adjust the incline bench to a comfortable angle. Step:2 Stand facing away from the pulley with your feet shoulder-width apart. Step:3 Grasp the rope with an overhand grip and extend your arms straight overhead. Step:4 (reverse variation) Keep your elbows close to your head and your upper arms stationary throughout the exercise. Step:5 Lower the rope behind your head by bending your elbows until your forearms touch your biceps. Step:6 Pause for a moment, then extend your arms back to the starting position. Step:7 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('cable squat row (with rope attachment) heavy', 'cable squat row (with rope attachment) heavy', 'Strength', 'Other', 'Intermediate', 'Step:1 Attach a rope to a cable machine at waist height. Step:2 Stand facing the cable machine with your feet shoulder-width apart. Step:3 (heavy variation) Bend your knees and lower your body into a squat position, keeping your back straight and chest up. Step:4 Grasp the rope with an overhand grip, with your hands shoulder-width apart. Step:5 Engage your core and pull the rope towards your body, squeezing your shoulder blades together. Step:6 Keep your elbows close to your body and continue pulling until your hands reach your chest. Step:7 Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position. Step:8 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('band vertical pallof press - seated variation', 'band vertical pallof press - seated variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height. Step:2 Hold the band with both hands and step away from the anchor point, creating tension in the band. Step:3 Position yourself perpendicular to the anchor point, with your side facing the band. Step:4 Extend your arms straight out in front of you, keeping your hands at chest height. Step:5 Engage your core and press the band away from your chest, fully extending your arms. Step:6 Hold the position for a few seconds, then slowly bring the band back towards your chest. Step:7 Repeat for the desired number of repetitions, then switch sides. Perform with seated intensity.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('barbell reverse wrist curl - prone variation', 'barbell reverse wrist curl - prone variation', 'Strength', 'Other', 'Intermediate', 'Step:1 Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down. Step:2 Rest your forearms on your thighs, allowing your wrists to hang off the edge. Step:3 Slowly curl your wrists upward, bringing the barbell towards your body. Emphasize prone control. Step:4 Pause for a moment at the top, then slowly lower the barbell back down to the starting position. Step:5 Repeat for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('firm style hanging oblique knee raise', 'firm style hanging oblique knee raise', 'Strength', 'Other', 'Intermediate', 'Step:1 Hang from a pull-up bar with your arms fully extended and your palms facing away from you. Step:2 Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so. Step:3 Pause for a moment at the top, then slowly lower your legs back down to the starting position. Step:4 Repeat on the other side, twisting your torso in the opposite direction. Step:5 Continue alternating sides for the desired number of repetitions. Emphasize firm control.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('horizontal dumbbell standing alternate overhead press', 'horizontal dumbbell standing alternate overhead press', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward. Step:2 (horizontal variation) Press one dumbbell overhead, fully extending your arm. Step:3 Lower the dumbbell back to shoulder level. Step:4 Repeat with the other arm. Step:5 Continue alternating arms for the desired number of repetitions.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('Explosive Abductors Row', 'Explosive Abductors Row', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in a stable position preparing to perform the ''Explosive Abductors Row''. Step:2 Grab the Weighted securely and set up your stance according to proper form. Step:3 Execute the main movement: focus on controlled motion targeting the abductors. Step:4 Maintain a controlled tempo, exhale during the exertion phase and inhale during the return. Step:5 Keep a neutral spine, engage your core, and avoid locking joints at full extension. Step:6 Repeat for desired repetitions, starting with 8–12 reps for general strength or adjust as needed. Step:7 Secondary muscles engaged: hip flexors. Step:8 After finishing, perform a brief cool-down and stretch the worked muscles.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('Kettlebell Quads Curl', 'Kettlebell Quads Curl', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in a stable position preparing to perform the ''Kettlebell Quads Curl''. Step:2 Grab the Lever (plate loaded) securely and set up your stance according to proper form. Step:3 Execute the main movement: focus on controlled motion targeting the quads. Step:4 Maintain a controlled tempo, exhale during the exertion phase and inhale during the return. Step:5 Keep a neutral spine, engage your core, and avoid locking joints at full extension. Step:6 Repeat for desired repetitions, starting with 8–12 reps for general strength or adjust as needed. Step:7 Secondary muscles engaged: rotator cuff. Step:8 After finishing, perform a brief cool-down and stretch the worked muscles.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
INSERT INTO exercises ("Name", "Description", "Category", "MuscleGroup", "DifficultyLevel", "Instructions", "IsActive", "CreatedByCoachId", "CreatedAt", "UpdatedAt", "EquipmentId", "EquipmentRequired") VALUES ('Decline Triceps Squat', 'Decline Triceps Squat', 'Strength', 'Other', 'Intermediate', 'Step:1 Stand in a stable position preparing to perform the ''Decline Triceps Squat''. Step:2 Grab the Lever (selectorized)  Chest Dip securely and set up your stance according to proper form. Step:3 Execute the main movement: focus on controlled motion targeting the triceps. Step:4 Maintain a controlled tempo, exhale during the exertion phase and inhale during the return. Step:5 Keep a neutral spine, engage your core, and avoid locking joints at full extension. Step:6 Repeat for desired repetitions, starting with 8–12 reps for general strength or adjust as needed. Step:7 Secondary muscles engaged: lower back. Step:8 After finishing, perform a brief cool-down and stretch the worked muscles.', true, 1, NOW(), NOW(), (SELECT "EquipmentId" FROM equipment WHERE "Name" = 'Body Weight' LIMIT 1), 'body weight');
